// Safe localStorage wrappers to prevent DOMException under local file:// protocol
function safeGetItem(key) {
  try {
    return localStorage.getItem(key);
  } catch (e) {
    console.warn("Storage access blocked:", e);
    return null;
  }
}

function safeSetItem(key, value) {
  try {
    localStorage.setItem(key, value);
  } catch (e) {
    console.warn("Storage write blocked:", e);
  }
}

// 3. Storage & Groups Helpers
function loadConfig() {
  const mockModeVal = safeGetItem("aiq_mock_mode");
  state.mockMode = mockModeVal === null ? true : mockModeVal === "true";
  
  const refresh = safeGetItem("aiq_refresh_token") || "";
  const access = safeGetItem("aiq_access_token") || "";
  const expiry = safeGetItem("aiq_token_expiry") || "";
  
  state.apiBaseUrl = safeGetItem("aiq_api_base_url") || "https://api.activeiq.netapp.com/v1";

  // When running via the desktop launcher (localhost/127.0.0.1), automatically
  // route all API calls through the local CORS proxy server instead of calling
  // api.activeiq.netapp.com directly (which WebView2 and browsers both block).
  // The proxy is started by launcher.py on the same port as this page.
  const isLocalhost = (window.location.hostname === 'localhost' ||
                       window.location.hostname === '127.0.0.1' ||
                       window.location.hostname === '');
  state.isRunningViaProxy = isLocalhost;
  if (isLocalhost) {
    // Derive proxy base from current page origin: same host:port, /api path
    state.proxyApiBaseUrl = `${window.location.protocol}//${window.location.host}/api`;
    console.log('[Proxy Mode] API calls routed through local CORS proxy:', state.proxyApiBaseUrl);
  }
  state.syncInterval = parseInt(safeGetItem("aiq_sync_interval") || "0");
  state.lastSync = safeGetItem("aiq_last_sync") || "";
  const wlOnlyVal = safeGetItem("aiq_watchlist_only");
  state.watchlistOnly = wlOnlyVal === "true";
  state.serialNumbers = safeGetItem("aiq_serial_numbers") || "";
  
  // Note: mock mode safeguard removed — server-side /api/harvest reads
  // the refresh token from aiq_config.json, no browser-side token needed.
  
  // Load systems db if exists in local storage
  // v9: runs enrichSystemTelemetry on every loaded system to ensure all fields are
  // fully populated regardless of source (API, import, or previous cached version).
  const schemaVer = safeGetItem("aiq_systems_schema_v13");
  const savedSystems = safeGetItem("aiq_systems_db");
  
  if (savedSystems && schemaVer === "v13") {
    try {
      const parsed = JSON.parse(savedSystems);
      if (Array.isArray(parsed) && parsed.length > 0) {
        // Re-run enrichment on load: fills any fields missing since last schema version
        // and normalises any raw API data that was stored without full enrichment.
        state.systems = parsed.map(s => enrichSystemTelemetry(s));
      } else if (state.mockMode) {
        state.systems = MOCK_SYSTEMS.map(s => enrichSystemTelemetry(s));
        saveSystems();
      }
    } catch (e) {
      console.warn("Failed to parse saved systems:", e);
      if (state.mockMode) {
        state.systems = MOCK_SYSTEMS.map(s => enrichSystemTelemetry(s));
        saveSystems();
      }
    }
  } else {
    // Fresh start or schema version upgrade
    if (state.mockMode) {
      state.systems = MOCK_SYSTEMS.map(s => enrichSystemTelemetry(s));
    } else {
      state.systems = []; // Will be populated by loadProductionData
    }
    safeSetItem("aiq_systems_schema_v13", "v13");
    saveSystems();
  }

  // Pick first system as selected
  if (state.systems.length > 0) {
    state.selectedSystem = state.systems[0];
  }

  // Load groups 
  const savedGroups = safeGetItem("aiq_custom_groups");
  if (savedGroups) {
    try {
      const parsed = JSON.parse(savedGroups);
      state.groups = Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.warn("Failed to parse custom groups:", e);
      state.groups = state.mockMode ? [...DEFAULT_GROUPS] : [];
    }
  } else {
    state.groups = state.mockMode ? [...DEFAULT_GROUPS] : [];
  }

  // Load watchlists — only use mock watchlists in mock mode
  const savedWatchlists = safeGetItem("aiq_watchlists_db");
  if (savedWatchlists) {
    try {
      state.watchlists = JSON.parse(savedWatchlists);
    } catch (e) {
      console.warn("Failed to parse watchlists:", e);
      state.watchlists = state.mockMode ? [...MOCK_WATCHLISTS] : [];
    }
  } else {
    state.watchlists = state.mockMode ? [...MOCK_WATCHLISTS] : [];
  }
  
  return { refresh, access, expiry };
}

function saveConfig(refresh, access, expiry) {
  safeSetItem("aiq_refresh_token", refresh);
  safeSetItem("aiq_access_token", access);
  safeSetItem("aiq_token_expiry", expiry);
}

function saveSystems() {
  safeSetItem("aiq_systems_db", JSON.stringify(state.systems));
  updateSearchSuggestions();
}

function saveGroups() {
  safeSetItem("aiq_custom_groups", JSON.stringify(state.groups));
}

function saveWatchlists() {
  safeSetItem("aiq_watchlists_db", JSON.stringify(state.watchlists));
}

function setMockMode(val) {
  state.mockMode = val;
  safeSetItem("aiq_mock_mode", val.toString());
  updateStatusIndicators();
}

// 4. Token & API Client Logic

/**
 * Returns the base URL to use for all Active IQ API calls.
 *
 * When the dashboard is running via the desktop launcher (served from
 * http://localhost or http://127.0.0.1), every fetch must go through the
 * local CORS proxy server (launcher.py / server.py) rather than calling
 * api.activeiq.netapp.com directly. Both the browser and WebView2 enforce
 * CORS and will block the direct call — but a same-origin call to /api/ is
 * forwarded by the proxy without any browser-level CORS restriction.
 *
 * When running from any other origin (e.g., GitHub Pages, corporate intranet)
 * the configured apiBaseUrl is used as-is.
 */
function getEffectiveApiBaseUrl() {
  if (state.isRunningViaProxy && state.proxyApiBaseUrl) {
    return state.proxyApiBaseUrl;   // e.g.  http://127.0.0.1:8080/api
  }
  return state.apiBaseUrl;          // e.g.  https://api.activeiq.netapp.com/v1
}

async function getValidAccessToken() {
  if (state.mockMode) return "mock-token-abc-123";
  
  const refresh = safeGetItem("aiq_refresh_token");
  const access = safeGetItem("aiq_access_token");
  const expiry = parseFloat(safeGetItem("aiq_token_expiry") || "0");

  if (!refresh) {
    throw new Error("API Refresh Token not configured. Please visit the Settings tab.");
  }

  if (access && expiry > (Date.now() / 1000) + 300) {
    return access;
  }

  const response = await fetch(`${getEffectiveApiBaseUrl()}/tokens/accessToken`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ refresh_token: refresh })
  });

  if (!response.ok) {
    throw new Error("Authentication failed. Please verify your Refresh Token in Settings.");
  }

  const data = await response.json();
  // NetApp returns accessToken (camelCase) and refresh_token
  const newAccess  = data.accessToken  || data.access_token  || "";
  const newRefresh = data.refreshToken || data.refresh_token || refresh;
  const newExpiry  = (Date.now() / 1000) + 3600;
  saveConfig(newRefresh, newAccess, newExpiry.toString());
  return newAccess;
}

// Global API Fetch wrapper — logs every call in detail to the console
async function callActiveIQAPI(endpoint, method = "GET", body = null) {
  if (state.mockMode) {
    return simulateMockAPIResponse(endpoint);
  }

  const token   = await getValidAccessToken();
  // When the endpoint already carries a version prefix (e.g. /v1/clusterview/...)
  // avoid double-versioning against the base URL which already ends in /v1.
  let baseUrl = getEffectiveApiBaseUrl();
  if (/^\/v\d+\//.test(endpoint) && !state.isRunningViaProxy) {
    // Strip trailing /v1 (or /v2, etc.) from the base URL
    baseUrl = baseUrl.replace(/\/v\d+\/?$/, "");
  }
  const fullUrl = `${baseUrl}${endpoint}`;
  console.log(`[AIQ CALL] → ${method} ${fullUrl}`);

  // IMPORTANT: do NOT send Content-Type on GET requests — some NetApp endpoints
  // return HTTP 500 when Content-Type is present on a GET (it's technically invalid).
  const headers = {
    "AuthorizationToken": token,
    "Accept": "application/json",
    ...(method !== "GET" ? { "Content-Type": "application/json" } : {})
  };

  const fetchOpts = { method, headers };
  if (body && method !== "GET") fetchOpts.body = JSON.stringify(body);

  const response = await fetch(fullUrl, fetchOpts);
  console.log(`[AIQ CALL] ← HTTP ${response.status} (${endpoint})`);

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    console.warn(`[AIQ CALL] Error body (${endpoint}):`, text.slice(0, 400));
    throw new Error(`HTTP ${response.status} from ${endpoint}`);
  }

  const data = await response.json();
  if (data && typeof data === "object") {
    const keys = Object.keys(data);
    console.log(`[AIQ CALL] Response keys (${endpoint}):`, keys);
    if (keys.length > 0) {
      const v = data[keys[0]];
      console.log(`[AIQ CALL]   ${keys[0]}:`, Array.isArray(v) ? `Array[${v.length}]` : JSON.stringify(v).slice(0, 150));
    }
  }
  return data;
}





// Global GraphQL fetch client dispatcher
async function callActiveIQGraphQL(query, variables = {}) {
  if (state.mockMode) {
    // Wrap inside a promise to simulate network latency
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve(simulateMockGraphQLResponse(query, variables));
      }, 150);
    });
  }
  
  try {
    const token = await getValidAccessToken();
    // Route through proxy: /api/v2/graphql → https://api.activeiq.netapp.com/v2/graphql
    const graphqlUrl = state.isRunningViaProxy
      ? `${window.location.protocol}//${window.location.host}/api/v2/graphql`
      : "https://api.activeiq.netapp.com/v2/graphql";
    const response = await fetch(graphqlUrl, {
      method: "POST",
      headers: {
        "AuthorizationToken": token,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ query, variables })
    });
    
    if (!response.ok) {
      throw new Error(`GraphQL API returned error: ${response.status} ${response.statusText}`);
    }
    const result = await response.json();
    if (result.errors) {
      throw new Error(result.errors.map(e => e.message).join(", "));
    }
    return result.data;
  } catch (error) {
    console.error("Active IQ GraphQL Fetch Error: ", error);
    throw error;
  }
}

// Local mock resolver simulating dynamic GraphQL resolution
function simulateMockGraphQLResponse(query, variables = {}) {
  let filtered = [...state.systems];
  
  // Extract query filters from variables or query body
  if (variables.customerName) {
    filtered = filtered.filter(s => s.customerName === variables.customerName);
  } else if (variables.serialNumber) {
    filtered = filtered.filter(s => s.serialNumber === variables.serialNumber);
  } else {
    const custMatch = query.match(/customerName:\s*"([^"]+)"/);
    if (custMatch) {
      filtered = filtered.filter(s => s.customerName === custMatch[1]);
    }
    const serialMatch = query.match(/serialNumber:\s*"([^"]+)"/);
    if (serialMatch) {
      filtered = filtered.filter(s => s.serialNumber === serialMatch[1]);
    }
  }
  
  // Clean query string to perform field matching checks
  const cleanQuery = query.replace(/\s+/g, "");
  
  const resultSystems = filtered.map(sys => {
    const resolvedSys = {};
    
    // Select dynamic system fields based on GraphQL selection set query pattern
    if (cleanQuery.includes("serialNumber")) resolvedSys.serialNumber = sys.serialNumber;
    if (cleanQuery.includes("systemName")) resolvedSys.systemName = sys.systemName;
    if (cleanQuery.includes("clusterName")) resolvedSys.clusterName = sys.clusterName;
    if (cleanQuery.includes("customerName")) resolvedSys.customerName = sys.customerName;
    if (cleanQuery.includes("platform")) resolvedSys.platform = sys.platform;
    if (cleanQuery.includes("status")) resolvedSys.status = sys.status;
    if (cleanQuery.includes("ontapVersion")) resolvedSys.ontapVersion = sys.ontapVersion;
    
    if (cleanQuery.includes("contracts")) resolvedSys.contracts = sys.contracts;
    if (cleanQuery.includes("supportCases")) resolvedSys.supportCases = sys.supportCases;
    if (cleanQuery.includes("risks")) resolvedSys.risks = sys.risks;
    if (cleanQuery.includes("projections")) resolvedSys.projections = sys.projections;
    if (cleanQuery.includes("switches")) resolvedSys.switches = sys.switches;
    
    // Default fallback if no fields were parsed
    if (Object.keys(resolvedSys).length === 0) {
      return {
        serialNumber: sys.serialNumber,
        systemName: sys.systemName,
        platform: sys.platform,
        status: sys.status
      };
    }
    return resolvedSys;
  });
  
  return {
    systems: resultSystems
  };
}

function simulateMockAPIResponse(endpoint) {
  if (endpoint.includes("/systems")) {
    const parts = endpoint.split("/");
    if (parts.length > 2) {
      const serial = parts[2];
      return state.systems.find(s => s.serialNumber === serial) || state.systems[0];
    }
    return state.systems;
  }
  return {};
}

// 5. DOM Render Utilities & Charts
let efficiencyChartInstance = null;
let capacityChartInstance = null;
let projectionsChartInstance = null; // Line chart for capacity & performance trends

// ── Chart data fingerprint — avoids destroy/recreate when data is unchanged ───
// renderCharts() is called on every Overview render (filter click, search, auto-sync).
// Skipping the expensive Chart.js teardown+init when the underlying data is
// bit-for-bit identical eliminates the most visible jank in the app.
let _chartDataStamp = null;

function renderCharts() {
  const ctxEff = document.getElementById('efficiencyChart');
  const ctxCap = document.getElementById('capacityChart');

  if (!ctxEff || !ctxCap) return;

  const filteredSystems = getFilteredSystems();

  if (filteredSystems.length === 0) {
    // Data cleared — destroy orphaned instances and reset stamp
    if (efficiencyChartInstance) { efficiencyChartInstance.destroy(); efficiencyChartInstance = null; }
    if (capacityChartInstance)   { capacityChartInstance.destroy();   capacityChartInstance   = null; }
    _chartDataStamp = null;
    return;
  }
  if (typeof Chart === 'undefined') { console.warn('Chart.js not loaded'); return; }

  // Build a lightweight fingerprint of the data that drives both charts.
  // Include serial + physicalUsedTB + usableCapacityTB + fabricPoolTieredTB.
  const _newStamp = filteredSystems.map(s =>
    `${s.serialNumber}:${(s.efficiency.physicalUsedTB||0).toFixed(1)}:${(s.efficiency.usableCapacityTB||0).toFixed(1)}:${(s.efficiency.fabricPoolTieredTB||0).toFixed(1)}`
  ).join('|');
  if (_newStamp === _chartDataStamp && efficiencyChartInstance && capacityChartInstance) return; // data unchanged
  _chartDataStamp = _newStamp;

  if (efficiencyChartInstance) efficiencyChartInstance.destroy();
  if (capacityChartInstance) capacityChartInstance.destroy();

  // ── Donut: fleet capacity utilisation (physical used vs available) ──────────
  // "Available" = sum of (usableCapacityTB - physicalUsedTB), floored at 0.
  // This shows how full the fleet is on actual disk, regardless of efficiency ratio.
  // Efficiency ratio is shown as a text overlay so it isn't distorting the pie.
  const physicalSum  = filteredSystems.reduce((a, s) => a + (s.efficiency.physicalUsedTB  || 0), 0);
  const usableSum    = filteredSystems.reduce((a, s) => a + (s.efficiency.usableCapacityTB || s.efficiency.physicalUsedTB || 0), 0);
  const availableSum = Math.max(0, usableSum - physicalSum);

  // Fleet-average data reduction ratio — weighted by physical capacity.
  // Uses efficiency.dataReductionRatio (numeric, stored by enrichSystemTelemetry).
  // Falls back to parsing efficiency.ratio string for any older cached entries.
  let drrWeightedSum = 0, drrPhysSum = 0;
  filteredSystems.forEach(s => {
    const phys  = s.efficiency.physicalUsedTB || 0;
    let   ratio = s.efficiency.dataReductionRatio || 0;
    if (!ratio) {
      const rStr = (s.efficiency.ratio || '1.0:1').replace(':1', '');
      ratio = parseFloat(rStr) || 1;
    }
    if (ratio < 1) ratio = 1;
    drrWeightedSum += phys * ratio;
    drrPhysSum     += phys;
  });
  const avgDRRNum = drrPhysSum > 0 ? drrWeightedSum / drrPhysSum : 0;
  const avgDRR    = avgDRRNum > 1.05 ? avgDRRNum.toFixed(1) : null;  // only show if meaningful

  efficiencyChartInstance = new Chart(ctxEff, {
    type: 'doughnut',
    data: {
      labels: ['Physical Used (TB)', 'Available Capacity (TB)'],
      datasets: [{
        data: [physicalSum.toFixed(1), availableSum > 0 ? availableSum.toFixed(1) : physicalSum.toFixed(1)],
        backgroundColor: ['rgba(0, 115, 230, 0.8)', 'rgba(0, 200, 120, 0.5)'],
        borderColor: ['#0073e6', '#00c878'],
        borderWidth: 1
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      cutout: '68%',
      plugins: {
        legend: { position: 'bottom', labels: { color: '#f3f4f6', font: { size: 11 } } },
        tooltip: {
          callbacks: {
            label: ctx => {
              const tb = parseFloat(ctx.raw).toFixed(1);
              const pct = usableSum > 0 ? ((parseFloat(ctx.raw) / usableSum) * 100).toFixed(0) : 0;
              return `${ctx.label}: ${tb} TB (${pct}%)`;
            }
          }
        }
      }
    },
    plugins: [{
      id: 'centerText',
      afterDraw(chart) {
        if (!avgDRR) return;
        const { width, height, ctx: c } = chart;
        c.save();
        c.font = `bold ${Math.round(height / 8)}px Inter, sans-serif`;
        c.fillStyle = '#f3f4f6';
        c.textAlign = 'center';
        c.textBaseline = 'middle';
        c.fillText(`${avgDRR}:1`, width / 2, height / 2 - 10);
        c.font = `${Math.round(height / 14)}px Inter, sans-serif`;
        c.fillStyle = '#9ca3af';
        c.fillText('avg reduction', width / 2, height / 2 + Math.round(height / 10));
        c.restore();
      }
    }]
  });

  // ── Bar: top 15 systems by physical used — physical on-flash / FabricPool tiered / available ──
  const barSystems = [...filteredSystems]
    .filter(s => (s.efficiency.physicalUsedTB || 0) > 0)
    .sort((a, b) => b.efficiency.physicalUsedTB - a.efficiency.physicalUsedTB)
    .slice(0, 15);

  // Determine FabricPool participation
  const barFPTiered = barSystems.map(s => parseFloat(((s.efficiency.fabricPoolTieredTB) || 0).toFixed(1)));
  const fpCount     = barFPTiered.filter(v => v > 0).length;
  const anyFP       = fpCount > 0;

  // Physical on-flash = physicalUsedTB minus what's already tiered (FabricPool tiered is cold blocks
  // that have been moved off-flash; the physicalUsedTB field in our mock data represents total logical
  // footprint. We keep the bar split as: [on-flash physical] + [tiered] + [available])
  const barOnFlash = barSystems.map((s, i) => {
    const total = parseFloat((s.efficiency.physicalUsedTB || 0).toFixed(1));
    return parseFloat(Math.max(0, total - barFPTiered[i]).toFixed(1));
  });
  const barAvail = barSystems.map(s => {
    const usable = s.efficiency.usableCapacityTB || s.efficiency.physicalUsedTB || 0;
    return parseFloat(Math.max(0, usable - (s.efficiency.physicalUsedTB || 0)).toFixed(1));
  });

  // Update card title dynamically
  const capCardTitle = ctxCap.closest('.chart-card')?.querySelector('.card-title');
  if (capCardTitle) {
    capCardTitle.innerHTML = anyFP
      ? `Storage Capacity by System <span style="font-size:0.75rem;font-weight:400;color:var(--text-secondary);margin-left:6px;">· top 15 · <span style="color:#2dd4bf;">&#9632;</span> incl. FabricPool tiering</span>`
      : `Storage Capacity by System <span style="font-size:0.75rem;font-weight:400;color:var(--text-secondary);margin-left:6px;">· top 15 · no FabricPool in view</span>`;
  }

  const barDatasets = [
    {
      label: 'Physical On-Flash (TB)',
      data: barOnFlash,
      backgroundColor: 'rgba(0, 115, 230, 0.82)',
      borderColor: '#0073e6',
      borderWidth: 1,
      stack: 'cap'
    },
    {
      label: anyFP ? `FabricPool Tiered (TB) — ${fpCount} system${fpCount > 1 ? 's' : ''}` : 'FabricPool Tiered (TB)',
      data: barFPTiered,
      backgroundColor: 'rgba(45, 212, 191, 0.75)',
      borderColor: '#2dd4bf',
      borderWidth: 1,
      stack: 'cap'
    },
    {
      label: 'Available Capacity (TB)',
      data: barAvail,
      backgroundColor: 'rgba(0, 200, 120, 0.32)',
      borderColor: '#00c878',
      borderWidth: 1,
      stack: 'cap'
    }
  ];

  capacityChartInstance = new Chart(ctxCap, {
    type: 'bar',
    data: {
      labels: barSystems.map(s => (s.clusterName || s.systemName || '').replace(/-0[12]$/, '')),
      datasets: barDatasets
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      scales: {
        x: {
          stacked: true,
          ticks: { color: '#9ca3af', maxRotation: 40, font: { size: 10 } },
          grid: { color: 'rgba(255,255,255,0.04)' }
        },
        y: {
          stacked: true,
          min: 0,
          ticks: {
            color: '#9ca3af',
            callback: v => v >= 1000 ? (v / 1000).toFixed(1) + 'k' : v
          },
          grid: { color: 'rgba(255,255,255,0.04)' },
          title: { display: true, text: 'Storage (TB)', color: '#9ca3af', font: { size: 11 } }
        }
      },
      plugins: {
        legend: {
          position: 'bottom',
          labels: {
            color: '#f3f4f6',
            font: { size: 11 },
            // Hide FabricPool legend entry when none of the systems have it
            filter: item => !(item.text.startsWith('FabricPool') && !anyFP)
          }
        },
        tooltip: {
          callbacks: {
            label: ctx => {
              const i = ctx.dataIndex;
              const total = barOnFlash[i] + barFPTiered[i] + barAvail[i];
              const utilPct = total > 0 ? ((( barOnFlash[i] + barFPTiered[i]) / total) * 100).toFixed(0) : 0;
              if (ctx.datasetIndex === 0) {
                return `On-Flash: ${ctx.parsed.y.toFixed(1)} TB  (${utilPct}% utilised)`;
              } else if (ctx.datasetIndex === 1) {
                return barFPTiered[i] > 0
                  ? `FabricPool Tiered: ${ctx.parsed.y.toFixed(1)} TB (cold data moved to cloud)`
                  : `FabricPool: not enabled on this system`;
              } else {
                return `Available: ${ctx.parsed.y.toFixed(1)} TB`;
              }
            },
            afterBody: (items) => {
              if (!items.length) return [];
              const i = items[0].dataIndex;
              const hasFP = barFPTiered[i] > 0;
              return hasFP ? [] : ['  ↳ No FabricPool tiering configured'];
            }
          }
        }
      }
    }
  });
}

// ── getFilteredSystems memo cache ───────────────────────────────────────────
// This function is called 6-12 times per render cycle across KPI cards, the
// overview table, charts, system selectors, and all three detail tabs.
// Result is cached per unique {filterType, filterValue, searchQuery, kpiFilter,
// systemCount}. Returning .slice() copies lets callers sort/mutate freely
// without corrupting the cache.
let _gfsKeyIncl = null, _gfsResIncl = null; // full filter (includes KPI drill-down)
let _gfsKeyExcl = null, _gfsResExcl = null; // KPI-excluded (used by updateOverviewKpis)

function getFilteredSystems(excludeKpiFilter = false) {
  const _baseStamp = `${state.activeFilterType}|${state.activeFilterValue || ''}|${state.activeSearchQuery || ''}|${state.systems.length}`;
  const _stamp = excludeKpiFilter ? _baseStamp : _baseStamp + '|' + (state.activeKpiFilter || 'NONE');

  // Return cached copy if stamp matches
  if (excludeKpiFilter) {
    if (_stamp === _gfsKeyExcl && _gfsResExcl) return _gfsResExcl.slice();
  } else {
    if (_stamp === _gfsKeyIncl && _gfsResIncl) return _gfsResIncl.slice();
  }

  let filtered = state.systems;

  // 1. Sidebar customer/group/watchlist filters
  if (state.activeFilterType === "CUSTOMER") {
    filtered = state.systems.filter(s => s.customerName === state.activeFilterValue);
  } else if (state.activeFilterType === "GROUP") {
    const group = state.groups.find(g => g.id === state.activeFilterValue);
    if (group) {
      filtered = state.systems.filter(s => group.systemSerials.includes(s.serialNumber));
    }
  } else if (state.activeFilterType === "WATCHLIST") {
    const wl = state.watchlists.find(w => w.id === state.activeFilterValue);
    if (wl) {
      filtered = state.systems.filter(s => wl.systemSerials.includes(s.serialNumber));
    }
  }

  // 2. Main Search Query filter (multi-term support)
  const query = (state.activeSearchQuery || "").toLowerCase().trim();
  if (query) {
    const terms = query.split(",").map(t => t.trim()).filter(t => t.length > 0);
    filtered = filtered.filter(sys => {
      return terms.some(term => 
        sys.systemName.toLowerCase().includes(term) || 
        sys.serialNumber.toLowerCase().includes(term) ||
        sys.clusterName.toLowerCase().includes(term) ||
        sys.customerName.toLowerCase().includes(term) ||
        (sys.platform || "").toLowerCase().includes(term)
      );
    });
  }

  // 3. KPI Card Drill-Down filter (except when calculating the KPI values themselves)
  if (!excludeKpiFilter && state.activeKpiFilter && state.activeKpiFilter !== "NONE") {
    if (state.activeKpiFilter === "CRITICAL") {
      filtered = filtered.filter(s => s.status === "critical" || s.risks.some(r => r.severity === "critical"));
    } else if (state.activeKpiFilter === "WARNING") {
      filtered = filtered.filter(s => s.status === "warning" || s.risks.some(r => r.severity === "high" || r.severity === "medium"));
    } else if (state.activeKpiFilter === "CONTRACT") {
      filtered = filtered.filter(s => s.contracts.daysRemaining <= 90);
    }
  }

  // Store in cache and return a copy (callers may sort/mutate independently)
  if (excludeKpiFilter) { _gfsKeyExcl = _stamp; _gfsResExcl = filtered; }
  else { _gfsKeyIncl = _stamp; _gfsResIncl = filtered; }
  return filtered.slice();
}

function updateOverviewKpis() {
  const filtered = getFilteredSystems(true); // Exclude activeKpiFilter to calculate accurate KPI counts
  const totalSystems = filtered.length;
  const criticalRisksCount = filtered.reduce((acc, sys) => 
    acc + sys.risks.filter(r => r.severity === 'critical').length, 0);
  const warningRisksCount = filtered.reduce((acc, sys) => 
    acc + sys.risks.filter(r => r.severity === 'high' || r.severity === 'medium').length, 0);
  const expiringContracts = filtered.filter(sys => sys.contracts.daysRemaining <= 90).length;

  document.getElementById("kpiTotalSystems").innerText = totalSystems;
  document.getElementById("kpiCriticalRisks").innerText = criticalRisksCount;
  document.getElementById("kpiWarningRisks").innerText = warningRisksCount;
  document.getElementById("kpiContracts").innerText = expiringContracts;
  
  document.getElementById("kpiTotalSystems").style.color = "var(--text-primary)";
  document.getElementById("kpiCriticalRisks").style.color = criticalRisksCount > 0 ? "var(--status-critical)" : "var(--status-normal)";
  document.getElementById("kpiWarningRisks").style.color = warningRisksCount > 0 ? "var(--status-warning)" : "var(--status-normal)";
  document.getElementById("kpiContracts").style.color = expiringContracts > 0 ? "var(--status-warning)" : "var(--status-normal)";
}

function setKpiFilter(filterType) {
  if (state.activeKpiFilter === filterType) {
    state.activeKpiFilter = "NONE"; // toggle off
  } else {
    state.activeKpiFilter = filterType;
  }
  
  // Update visual card active highlight states
  const cards = {
    "ALL": "kpiCardAll",
    "CRITICAL": "kpiCardCritical",
    "WARNING": "kpiCardWarning",
    "CONTRACT": "kpiCardContract"
  };
  
  Object.keys(cards).forEach(key => {
    const el = document.getElementById(cards[key]);
    if (!el) return;
    if (state.activeKpiFilter === key) {
      el.classList.add("active");
    } else {
      el.classList.remove("active");
    }
  });

  // Re-render overview table and switch/update tabs accordingly
  renderOverviewTable();
}

function sortTable(tableId, key) {
  if (arguments.length === 1) {
    key = tableId;
    tableId = "overview";
  }

  const keyProp = `${tableId}SortKey`;
  const orderProp = `${tableId}SortOrder`;
  
  if (state[keyProp] === key) {
    state[orderProp] = state[orderProp] === "asc" ? "desc" : "asc";
  } else {
    state[keyProp] = key;
    state[orderProp] = "asc";
  }

  if (tableId === "overview") {
    renderOverviewTable();
  } else if (tableId === "tamRisks" || tableId === "tamSwitches" || tableId === "tamSecurity") {
    renderTAMTab._lastFP = null; // sort change must force a full re-render of deferred sections
    renderTAMTab();
  } else if (tableId === "samCases" || tableId === "samFieldActions") {
    renderSAMTab();
  }
}

function updateSortIndicatorsGeneric(tableId, headersMap) {
  const activeKey = state[`${tableId}SortKey`] || "";
  const activeOrder = state[`${tableId}SortOrder`] || "asc";
  
  Object.keys(headersMap).forEach(key => {
    const el = document.getElementById(headersMap[key]);
    if (!el) return;
    if (activeKey === key) {
      el.innerText = activeOrder === "asc" ? " ▲" : " ▼";
      el.style.opacity = "1";
      el.style.color = "var(--accent-cyan)";
    } else {
      el.innerText = " ↕";
      el.style.opacity = "0.3";
      el.style.color = "inherit";
    }
  });
}

function updateSortIndicators() {
  updateSortIndicatorsGeneric("overview", {
    "systemName": "sort-systemName",
    "serialNumber": "sort-serialNumber",
    "clusterName": "sort-clusterName",
    "customerName": "sort-customerName",
    "platform": "sort-platform",
    "status": "sort-status",
    "contracts.endDate": "sort-contracts-endDate"
  });

  updateSortIndicatorsGeneric("tamRisks", {
    "severity": "sort-tamRisks-severity",
    "category": "sort-tamRisks-category",
    "systemName": "sort-tamRisks-systemName",
    "description": "sort-tamRisks-description"
  });

  updateSortIndicatorsGeneric("tamSwitches", {
    "systemName": "sort-tamSwitches-systemName",
    "model": "sort-tamSwitches-model",
    "type": "sort-tamSwitches-type",
    "firmware": "sort-tamSwitches-firmware",
    "status": "sort-tamSwitches-status"
  });

  updateSortIndicatorsGeneric("tamSecurity", {
    "id": "sort-tamSecurity-id",
    "title": "sort-tamSecurity-title",
    "severity": "sort-tamSecurity-severity",
    "status": "sort-tamSecurity-status"
  });

  updateSortIndicatorsGeneric("samCases", {
    "id": "sort-samCases-id",
    "title": "sort-samCases-title",
    "severity": "sort-samCases-severity",
    "status": "sort-samCases-status",
    "createdDate": "sort-samCases-createdDate"
  });

  updateSortIndicatorsGeneric("samFieldActions", {
    "id": "sort-samFieldActions-id",
    "title": "sort-samFieldActions-title"
  });
}

function sortDataList(list, sortKey, sortOrder) {
  if (!list || !Array.isArray(list)) return;
  list.sort((a, b) => {
    let valA = a;
    let valB = b;

    const keys = sortKey.split(".");
    keys.forEach(k => {
      if (valA) valA = valA[k];
      if (valB) valB = valB[k];
    });

    const strA = valA ? valA.toString().toLowerCase().trim() : "";
    const strB = valB ? valB.toString().toLowerCase().trim() : "";

    const priority = { 
      "critical": 1, "s1": 1, "s1 - critical": 1,
      "high": 2, "s2": 2, "s2 - high": 2, "warning": 2,
      "medium": 3, "s3": 3, "s3 - medium": 3,
      "low": 4, "s4": 4, "s4 - low": 4, "normal": 4, "healthy": 4, "optimal": 4
    };

    let usePriority = false;
    if (sortKey === "status" || sortKey === "severity") {
      if (priority[strA] !== undefined || priority[strB] !== undefined) {
        usePriority = true;
      }
    }

    if (usePriority) {
      const priorityA = priority[strA] !== undefined ? priority[strA] : 99;
      const priorityB = priority[strB] !== undefined ? priority[strB] : 99;
      if (priorityA < priorityB) return sortOrder === "asc" ? -1 : 1;
      if (priorityA > priorityB) return sortOrder === "asc" ? 1 : -1;
      return 0;
    }

    if (valA === undefined || valA === null) valA = "";
    if (valB === undefined || valB === null) valB = "";

    if (typeof valA === "string") valA = valA.toLowerCase();
    if (typeof valB === "string") valB = valB.toLowerCase();

    if (valA < valB) return sortOrder === "asc" ? -1 : 1;
    if (valA > valB) return sortOrder === "asc" ? 1 : -1;
    return 0;
  });
}


// ═══════════════════════════════════════════════════════════════════════════════
// ENRICHMENT ENGINE
// Autonomous public-source enrichment for version data and CVEs.
// Queries /api/enrich (server.py) which fetches NVD, NetApp PSIRT, and
// docs.netapp.com — all public sources. No customer data ever leaves the tool.
// ═══════════════════════════════════════════════════════════════════════════════
const enrichmentEngine = {
  // In-session memory cache: "type:id" → data object
  _cache: new Map(),
  // Track in-flight requests to avoid duplicate fetches
  _inflight: new Set(),
  // Log of everything enriched this session
  _log: [],
  // Running count of successfully enriched fields
  _count: 0,

  // ── Core fetch ──────────────────────────────────────────────────────────────
  // Version enrichment (ontap-version, sg-version, santricity-version) is
  // CACHE-ONLY on the server — the background thread does the actual fetching.
  // The server returns {status:'pending'} on cache miss; we return null and let
  // syncFromServer populate the cache after the next sync.
  async enrich(type, id) {
    if (!id || !type) return null;
    const key = `${type}:${id}`;
    if (this._cache.has(key)) return this._cache.get(key);
    if (this._inflight.has(key)) {
      for (let i = 0; i < 15; i++) {
        await new Promise(r => setTimeout(r, 300));
        if (this._cache.has(key)) return this._cache.get(key);
      }
      return null;
    }
    this._inflight.add(key);
    try {
      const url = `/api/enrich?type=${encodeURIComponent(type)}&id=${encodeURIComponent(id)}`;
      const resp = await fetch(url, { cache: 'no-store' });
      if (!resp.ok) return null;
      const json = await resp.json();
      if (json.status === 'pending') {
        // Background thread hasn't enriched this version yet — return sentinel
        return { _pending: true };
      }
      if (json.status === 'ok' && json.data) {
        this._cache.set(key, json.data);
        this._log.push({
          type, id,
          source: json.source || 'unknown',
          cached: json.cached || false,
          fetched_at: json.fetched_at || new Date().toISOString(),
          data: json.data
        });
        this._count++;
        this._updateBadge();
        return json.data;
      }
    } catch (e) {
      // Network unavailable or server not running — fail silently
    } finally {
      this._inflight.delete(key);
    }
    return null;
  },

  // ── Typed helpers ────────────────────────────────────────────────────────────
  async enrichCVE(cveId)         { return this.enrich('cve', cveId); },
  async enrichAdvisory(ntapId)   { return this.enrich('ntap-advisory', ntapId); },
  async enrichONTAP(version)     { return this.enrich('ontap-version', version); },
  async enrichSG(version)        { return this.enrich('sg-version', version); },
  async enrichSANtricity(version){ return this.enrich('santricity-version', version); },

  // Dispatch by platform type
  async enrichVersion(sys) {
    const ver = sys.ontapVersion || sys.osVersion || '';
    if (!ver) return null;
    const model = (sys.platform || sys.model || '').toLowerCase();
    if (model.includes('storagegrid') || model.includes('sg60') || model.includes('sg61') || model.includes('sg10')) {
      return this.enrichSG(ver);
    } else if (model.includes('e-series') || model.includes('ef6') || model.includes('ef3') || model.includes('e5700') || model.includes('e2800')) {
      return this.enrichSANtricity(ver);
    } else {
      return this.enrichONTAP(ver);
    }
  },

  // ── Badge updater ───────────────────────────────────────────────────────────
  _updateBadge() {
    const badge = document.getElementById('enrichBadge');
    const text  = document.getElementById('enrichBadgeText');
    if (!badge || !text) return;
    const cveCount = this._log.filter(e => e.type === 'cve').length;
    const verCount = this._log.filter(e => e.type.includes('version')).length;
    let label = `${this._count} enriched`;
    if (verCount > 0 && cveCount > 0) label = `${verCount} versions · ${cveCount} CVEs`;
    else if (verCount > 0) label = `${verCount} version${verCount > 1 ? 's' : ''} enriched`;
    else if (cveCount > 0) label = `${cveCount} CVE${cveCount > 1 ? 's' : ''} enriched`;
    text.textContent = label;
    badge.style.display = 'flex';
  },

  // ── UI: inject version enrichment into a DOM element ────────────────────────
  // Call with the system object and the container element that should receive
  // the enrichment block. Inserts below existing content, non-destructively.
  async injectVersionEnrichment(sys, containerEl) {
    if (!containerEl) return;
    const existingId = `enrich-block-${sys.serialNumber}`;
    if (document.getElementById(existingId)) return; // already injected

    // Show minimal placeholder — don't promise a spinner since data may be pending
    const placeholder = document.createElement('div');
    placeholder.id = existingId;
    placeholder.style.cssText = 'margin-top:8px; font-size:0.71rem; color:var(--text-muted); display:flex; align-items:center; gap:6px;';
    placeholder.innerHTML = `<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#2dd4bf" stroke-width="2.5" class="spin-anim"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg> <span>Loading version intel…</span>`;
    containerEl.appendChild(placeholder);

    const data = await this.enrichVersion(sys);

    // Pending: background thread hasn't enriched this version yet
    if (data && data._pending) {
      placeholder.innerHTML = `<span style="color:var(--text-muted); font-style:italic;">⏳ Version intel will be ready after the next sync. Trigger a sync to fetch version-specific issues from public sources.</span>`;
      return;
    }

    if (!data) { placeholder.remove(); return; }

    const issues      = (data.knownIssues       || []).slice(0, 5);
    const fixed       = (data.fixedIssues        || []).slice(0, 3);
    const whatsNew    = (data.whatsNew           || []).slice(0, 3);
    const cves        = (data.relatedCVEs        || []).slice(0, 6);
    const advisories  = (data.relatedAdvisories  || []).slice(0, 4);
    const bugs        = (data.relatedBugs        || []).slice(0, 4);
    const motivation  = data.upgradeMotivation   || '';
    const sources     = data.sources             || [];

    // Severity color helpers
    const cvssColor = s => (s >= 9 ? '#ef4444' : s >= 7 ? '#f59e0b' : s >= 4 ? '#eab308' : '#22c55e');
    const sevBadge  = (sev, score) => {
      const col = score != null ? cvssColor(score) : '#6b7280';
      return `<span style="background:${col}22; color:${col}; border:1px solid ${col}44; border-radius:3px; padding:1px 5px; font-size:0.65rem; font-weight:700; margin-left:4px;">${score != null ? score + ' ' : ''}${sev || ''}</span>`;
    };

    let html = `<div style="margin-top:12px; padding:10px 12px; border-radius:8px; background:rgba(45,212,191,0.05); border:1px solid rgba(45,212,191,0.18); font-size:0.72rem; line-height:1.55;">`;

    // ── Header ───────────────────────────────────────────────────────────────
    html += `<div style="font-weight:700; color:#2dd4bf; margin-bottom:6px; display:flex; align-items:center; gap:5px; flex-wrap:wrap;">`;
    html += `<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><circle cx="11" cy="11" r="8"/><path d="M21 21l-4.35-4.35"/></svg>`;
    html += `Version Intel · ${data.version || sys.ontapVersion || 'N/A'} (${data.platform || 'ONTAP'})`;
    if (sources.length > 0) {
      sources.forEach(s => {
        html += `<span style="font-weight:400; color:var(--text-muted); background:rgba(255,255,255,0.05); border:1px solid rgba(255,255,255,0.1); border-radius:3px; padding:1px 5px; font-size:0.63rem;">${s}</span>`;
      });
    }
    html += `</div>`;

    // ── Known Issues ─────────────────────────────────────────────────────────
    if (issues.length > 0) {
      html += `<div style="color:#f59e0b; font-weight:600; margin-bottom:3px;">⚠ ${issues.length} Known Issue${issues.length > 1 ? 's' : ''} (Release Notes):</div>`;
      html += `<ul style="margin:0 0 8px 14px; padding:0; color:var(--text-secondary);">`;
      html += issues.map(i => `<li style="margin-bottom:3px;">${i.substring(0,140)}${i.length>140?'…':''}</li>`).join('');
      html += `</ul>`;
    }

    // ── Fixed Issues ─────────────────────────────────────────────────────────
    if (fixed.length > 0) {
      html += `<div style="color:#22c55e; font-weight:600; margin-bottom:3px;">✓ ${fixed.length} Fixed in This Release:</div>`;
      html += `<ul style="margin:0 0 8px 14px; padding:0; color:var(--text-secondary);">`;
      html += fixed.map(f => `<li style="margin-bottom:3px;">${f.substring(0,140)}${f.length>140?'…':''}</li>`).join('');
      html += `</ul>`;
    }

    // ── What's New ────────────────────────────────────────────────────────────
    if (whatsNew.length > 0) {
      html += `<div style="color:#60a5fa; font-weight:600; margin-bottom:3px;">✦ What's New:</div>`;
      html += `<ul style="margin:0 0 8px 14px; padding:0; color:var(--text-secondary);">`;
      html += whatsNew.map(w => `<li style="margin-bottom:3px;">${w.substring(0,140)}${w.length>140?'…':''}</li>`).join('');
      html += `</ul>`;
    }

    // ── NVD CVEs ──────────────────────────────────────────────────────────────
    if (cves.length > 0) {
      html += `<div style="color:#ef4444; font-weight:600; margin-bottom:3px; border-top:1px solid rgba(255,255,255,0.07); padding-top:6px; margin-top:2px;">🔴 ${cves.length} CVE${cves.length>1?'s':''} from NVD:</div>`;
      html += cves.map(c => {
        const score = c.cvss != null ? parseFloat(c.cvss) : null;
        return `<div style="display:flex; align-items:flex-start; gap:6px; margin-bottom:5px; padding:4px 6px; background:rgba(239,68,68,0.06); border-radius:4px;">
          <span style="font-weight:700; color:#ef4444; white-space:nowrap; font-size:0.7rem;">${c.id}</span>
          ${sevBadge(c.severity, score)}
          <span style="color:var(--text-secondary); flex:1;">${(c.description||'').substring(0,160)}${(c.description||'').length>160?'…':''}</span>
          ${c.publishedDate ? `<span style="color:var(--text-muted); white-space:nowrap; font-size:0.65rem;">${c.publishedDate}</span>` : ''}
        </div>`;
      }).join('');
    }

    // ── PSIRT Advisories ──────────────────────────────────────────────────────
    if (advisories.length > 0) {
      html += `<div style="color:#f97316; font-weight:600; margin-bottom:3px; border-top:1px solid rgba(255,255,255,0.07); padding-top:6px; margin-top:2px;">🔒 ${advisories.length} PSIRT Advisory/Advisories:</div>`;
      html += advisories.map(a =>
        `<div style="margin-bottom:4px; padding:4px 6px; background:rgba(249,115,22,0.06); border-radius:4px;">
          <a href="${a.link||'#'}" target="_blank" style="color:#f97316; font-weight:600; font-size:0.7rem; text-decoration:none;">${a.id}</a>
          <span style="color:var(--text-secondary); margin-left:6px;">${(a.title||'').substring(0,120)}</span>
        </div>`
      ).join('');
    }

    // ── Bugs Online ───────────────────────────────────────────────────────────
    if (bugs.length > 0) {
      html += `<div style="color:#a78bfa; font-weight:600; margin-bottom:3px; border-top:1px solid rgba(255,255,255,0.07); padding-top:6px; margin-top:2px;">🐛 ${bugs.length} Bug${bugs.length>1?'s':''} (Bugs Online):</div>`;
      html += bugs.map(b =>
        `<div style="margin-bottom:4px; padding:4px 6px; background:rgba(167,139,250,0.06); border-radius:4px;">
          <a href="${b.link||'#'}" target="_blank" style="color:#a78bfa; font-weight:600; font-size:0.7rem; text-decoration:none;">${b.id}</a>
          <span style="color:var(--text-secondary); margin-left:6px;">${(b.title||'').substring(0,120)}</span>
        </div>`
      ).join('');
    }

    // ── No findings ───────────────────────────────────────────────────────────
    if (!issues.length && !cves.length && !advisories.length && !bugs.length) {
      html += `<div style="color:var(--status-normal); font-style:italic;">✓ No known issues, CVEs, or advisories found in public sources for this version.</div>`;
    }

    // ── Upgrade motivation summary ────────────────────────────────────────────
    if (motivation) {
      html += `<div style="color:var(--text-secondary); border-top:1px solid rgba(255,255,255,0.06); padding-top:5px; margin-top:6px;">💡 ${motivation}</div>`;
    }

    html += `</div>`;
    placeholder.outerHTML = html;
  },

  // ── UI: enrich a CVE entry and update DOM ───────────────────────────────────
  async injectCVEEnrichment(cveId, containerEl) {
    if (!containerEl || !cveId || !cveId.match(/^CVE-\d{4}-\d+$/i)) return;
    const data = await this.enrichCVE(cveId);
    if (!data || data.status === 'not_found') return;

    // Update CVSS if it's showing N/A
    const cvssEl = containerEl.querySelector('[data-enrich-cvss]');
    if (cvssEl && data.cvss) {
      cvssEl.textContent = `${data.cvss} ${data.severity || ''}`;
      cvssEl.style.color = data.cvss >= 9 ? 'var(--status-critical)' : data.cvss >= 7 ? '#f59e0b' : 'var(--text-secondary)';
    }
    // Update description if it's showing N/A or generic
    const descEl = containerEl.querySelector('[data-enrich-desc]');
    if (descEl && data.description) {
      descEl.textContent = data.description.substring(0, 300) + (data.description.length > 300 ? '…' : '');
    }
    // Update published date
    const dateEl = containerEl.querySelector('[data-enrich-date]');
    if (dateEl && data.publishedDate) dateEl.textContent = data.publishedDate;
    // Affected versions
    const affEl = containerEl.querySelector('[data-enrich-affected]');
    if (affEl && data.affectedVersions) affEl.textContent = data.affectedVersions;
  },

  // ── Sync from server: pre-load SQLite cache + fill any gaps ─────────────────
  // Called after every harvest completes (cached or live).
  // 1. Loads all cached enrichment entries from server SQLite → populates _cache
  // 2. Identifies versions in current systems list not yet cached → enrich them
  async syncFromServer(systems) {
    try {
      // Step 1: pre-load the dump
      const resp = await fetch('/api/enrich/dump', { cache: 'no-store' });
      if (resp.ok) {
        const json = await resp.json();
        if (json.status === 'ok' && json.entries) {
          let preloaded = 0;
          for (const [key, entry] of Object.entries(json.entries)) {
            if (!this._cache.has(key) && entry.data) {
              this._cache.set(key, entry.data);
              // Also add to log if not already present
              const [type, ...idParts] = key.split(':');
              const id = idParts.join(':');
              if (!this._log.find(e => e.type === type && e.id === id)) {
                this._log.push({
                  type, id,
                  source: entry.source || 'sqlite-cache',
                  cached: true,
                  fetched_at: entry.fetched_at || '',
                  data: entry.data
                });
                this._count++;
              }
              preloaded++;
            }
          }
          if (preloaded > 0) {
            console.log(`[ENRICH] Pre-loaded ${preloaded} enrichment entries from server cache.`);
            this._updateBadge();
          }
        }
      }
    } catch (e) {
      // Server not running or dump failed — ignore silently
      return;
    }

    // Step 2: log which versions are not yet cached (background thread handles fetching)
    // We do NOT call /api/enrich per-version here — those calls would block the
    // single-threaded server. The _enrich_all_versions thread does the actual work.
    if (!systems || systems.length === 0) return;
    const uncached = [];
    for (const sys of systems) {
      const ver = sys.ontapVersion || sys.osVersion || '';
      if (!ver || ver.length < 4) continue;
      const model = (sys.platform || sys.model || '').toLowerCase();
      let etype = 'ontap-version';
      if (model.includes('storagegrid') || model.includes('sg60') || model.includes('sg61')) etype = 'sg-version';
      else if (model.includes('e-series') || model.includes('ef6') || model.includes('e5700') || model.includes('e2800')) etype = 'santricity-version';
      const key = `${etype}:${ver}`;
      if (!this._cache.has(key)) uncached.push({ etype, ver, key });
    }
    const seen = new Set();
    const toFetch = uncached.filter(u => { if (seen.has(u.key)) return false; seen.add(u.key); return true; });
    if (toFetch.length > 0) {
      console.log(`[ENRICH] ${toFetch.length} version(s) pending background enrichment: ${toFetch.map(u => u.ver).join(', ')}`);
    }
  }
};

// ── Enrichment log modal ─────────────────────────────────────────────────────
function showEnrichLog() {
  const log = enrichmentEngine._log;
  if (log.length === 0) { alert('No enrichment data fetched yet this session.'); return; }

  const rows = log.map(e => {
    const timeStr = e.fetched_at ? new Date(e.fetched_at).toLocaleTimeString() : '—';
    const cacheStr = e.cached ? '📦 cached' : '🌐 live';
    let summary = '';
    if (e.type.includes('version') && e.data) {
      const ki  = (e.data.knownIssues      || []).length;
      const wn  = (e.data.whatsNew         || []).length;
      const cv  = (e.data.relatedCVEs      || []).length;
      const adv = (e.data.relatedAdvisories|| []).length;
      const bg  = (e.data.relatedBugs      || []).length;
      const parts = [];
      if (ki  > 0) parts.push(`${ki} known issue${ki>1?'s':''}`);
      if (cv  > 0) parts.push(`${cv} CVE${cv>1?'s':''}`);
      if (adv > 0) parts.push(`${adv} advisory/advisories`);
      if (bg  > 0) parts.push(`${bg} bug${bg>1?'s':''}`);
      if (wn  > 0) parts.push(`${wn} what's-new`);
      summary = parts.length ? parts.join(' · ') : '✓ clean';
    } else if (e.type === 'cve' && e.data) {
      summary = `CVSS ${e.data.cvss || 'N/A'} ${e.data.severity || ''}`;
    }
    return `<tr style="border-bottom:1px solid rgba(255,255,255,0.05);">
      <td style="padding:5px 8px; color:#2dd4bf; font-family:monospace; font-size:0.75rem;">${e.id}</td>
      <td style="padding:5px 8px; color:var(--text-secondary); font-size:0.72rem;">${e.type}</td>
      <td style="padding:5px 8px; color:var(--text-secondary); font-size:0.72rem;">${e.source}</td>
      <td style="padding:5px 8px; color:var(--text-muted); font-size:0.72rem;">${cacheStr}</td>
      <td style="padding:5px 8px; color:var(--text-secondary); font-size:0.72rem;">${summary}</td>
      <td style="padding:5px 8px; color:var(--text-muted); font-size:0.72rem;">${timeStr}</td>
    </tr>`;
  }).join('');

  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:9999;display:flex;align-items:center;justify-content:center;';
  modal.innerHTML = `
    <div style="background:var(--bg-card);border:1px solid var(--border-color);border-radius:var(--radius);padding:24px;max-width:860px;width:95%;max-height:80vh;overflow:auto;position:relative;">
      <button onclick="this.closest('[style*=fixed]').remove()" style="position:absolute;top:12px;right:14px;background:none;border:none;color:var(--text-secondary);font-size:1.2rem;cursor:pointer;">✕</button>
      <div style="font-size:1rem;font-weight:700;color:#2dd4bf;margin-bottom:4px;">🔍 Enrichment Log</div>
      <div style="font-size:0.75rem;color:var(--text-muted);margin-bottom:16px;">Data fetched this session from public sources (NVD, docs.netapp.com, security.netapp.com). No customer data was transmitted.</div>
      <table style="width:100%;border-collapse:collapse;">
        <thead>
          <tr style="border-bottom:1px solid rgba(255,255,255,0.1);">
            <th style="padding:4px 8px;text-align:left;font-size:0.7rem;color:var(--text-muted);text-transform:uppercase;">ID</th>
            <th style="padding:4px 8px;text-align:left;font-size:0.7rem;color:var(--text-muted);text-transform:uppercase;">Type</th>
            <th style="padding:4px 8px;text-align:left;font-size:0.7rem;color:var(--text-muted);text-transform:uppercase;">Source</th>
            <th style="padding:4px 8px;text-align:left;font-size:0.7rem;color:var(--text-muted);text-transform:uppercase;">Origin</th>
            <th style="padding:4px 8px;text-align:left;font-size:0.7rem;color:var(--text-muted);text-transform:uppercase;">Summary</th>
            <th style="padding:4px 8px;text-align:left;font-size:0.7rem;color:var(--text-muted);text-transform:uppercase;">Time</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
}

function renderOverviewTable() {
  const tbody = document.getElementById("overviewTableBody");
  if (!tbody) return;
  tbody.innerHTML = "";

  const filteredSystems = getFilteredSystems();

  // Sort filteredSystems based on state.overviewSortKey and state.overviewSortOrder
  const sortKey = state.overviewSortKey || "systemName";
  const sortOrder = state.overviewSortOrder || "asc";

  sortDataList(filteredSystems, sortKey, sortOrder);

  // Update visual sort indicators on table headers
  updateSortIndicators();

  if (filteredSystems.length === 0) {
    tbody.innerHTML = `<tr><td colspan="7" style="text-align: center; color: var(--text-muted);">No matching systems found.</td></tr>`;
    return;
  }

  filteredSystems.forEach(sys => {
    const tr = document.createElement("tr");
    tr.style.cursor = "pointer";
    tr.onclick = () => selectSystem(sys.serialNumber);
    
    let statusBadge = `<span class="badge normal">Healthy</span>`;
    if (sys.status === "critical") statusBadge = `<span class="badge critical">Critical</span>`;
    else if (sys.status === "warning") statusBadge = `<span class="badge warning">Warning</span>`;

    const endDateShort = (sys.contracts.endDate || '').split('T')[0] || sys.contracts.endDate;
    let contractText = `${endDateShort} (${sys.contracts.daysRemaining}d)`;
    if (sys.contracts.daysRemaining < 0) {
      contractText = `<span style="color: var(--status-critical); font-weight: 600;">Expired (${Math.abs(sys.contracts.daysRemaining)}d ago)</span>`;
    } else if (sys.contracts.daysRemaining <= 90) {
      contractText = `<span style="color: var(--status-warning); font-weight: 600;">${endDateShort} (${sys.contracts.daysRemaining}d)</span>`;
    }

    let nameHtml = sys.systemName;
    if (sys.supportCases && sys.supportCases.length > 0) {
      nameHtml += ` <span class="badge warning" style="font-size: 0.65rem; padding: 2px 4px; vertical-align: middle; margin-left: 4px; background-color: var(--status-info); border-color: rgba(0, 230, 118, 0.2); cursor: pointer;" onclick="navigateToSupportCases('SYSTEM', '${sys.serialNumber}', event)" data-tooltip="Click to view active support cases for this system">✉ ${sys.supportCases.length} Open</span>`;
    }

    tr.innerHTML = `
      <td style="font-weight: 600; color: var(--accent-cyan);">${nameHtml}</td>
      <td>
        <code class="copyable-code" onclick="copyToClipboard('${sys.serialNumber}', event)" title="Click to copy Serial Number">
          ${sys.serialNumber}
          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
        </code>
      </td>
      <td>${sys.clusterName}</td>
      <td>${sys.customerName}</td>
      <td>${sys.platform}</td>
      <td>${statusBadge}</td>
      <td>${contractText}</td>
    `;
    tbody.appendChild(tr);
  });
}

function selectSystem(serial) {
  const found = state.systems.find(s => s.serialNumber === serial);
  if (found) {
    state.selectedSystem = found;
    state.selectedTAMSerials = [serial];
    switchTab("tam"); // Switch to Technical Audit details on system click
  }
}

// ── populateSystemSelectors dirty guard ─────────────────────────────────────
// Called at the top of renderTAMTab(), renderSAMTab(), renderCSMTab() — meaning
// every tab switch rebuilds 3 full selector widgets (SAM <select>, CSM <select>,
// TAM checkbox dropdown). Stamp guard skips the DOM work when scope is unchanged.
let _selectorStamp = null;

function populateSystemSelectors() {
  const currentFiltered = getFilteredSystems();
  
  // ── State fixups (always run — correct selectedSystem / TAM serials) ─────
  const hasSelectedSystem = state.selectedSystem && typeof state.selectedSystem === 'object';
  const selectedSerial = hasSelectedSystem ? state.selectedSystem.serialNumber : null;
  
  if (currentFiltered.length > 0) {
    const isStillInScope = selectedSerial && currentFiltered.some(s => s.serialNumber === selectedSerial);
    if (!isStillInScope) state.selectedSystem = currentFiltered[0];
  } else {
    state.selectedSystem = null;
  }
  
  // Initialize tab selectors if undefined
  if (state.selectedSAMSystemSerial === undefined) state.selectedSAMSystemSerial = "ALL";
  if (state.selectedCSMSystemSerial === undefined) state.selectedCSMSystemSerial = "ALL";
  
  // Prune/initialize selectedTAMSerials based on current scope
  const allSerialsInScope = currentFiltered.map(s => s.serialNumber);
  if (!state.selectedTAMSerials) state.selectedTAMSerials = [];
  
  const hasTAMFilterMismatch = state.selectedTAMSerials.some(ser => !allSerialsInScope.includes(ser)) || 
                                (state.selectedTAMSerials.length === 0 && currentFiltered.length > 0);
  if (hasTAMFilterMismatch) state.selectedTAMSerials = [...allSerialsInScope];

  // ── Dirty guard: skip expensive DOM dropdown rebuilds if scope/selection unchanged
  const _selStamp = allSerialsInScope.join(',') + '|' + state.selectedSAMSystemSerial + '|' + state.selectedCSMSystemSerial + '|' + state.selectedTAMSerials.join(',');
  if (_selStamp === _selectorStamp) return;
  _selectorStamp = _selStamp;
  
  // Populate SAM System Selector
  const samSelect = document.getElementById("samSystemSelect");
  if (samSelect) {
    samSelect.innerHTML = "";
    if (currentFiltered.length > 0) {
      const grpPortfolio = document.createElement("optgroup");
      grpPortfolio.label = "Portfolio View";
      const optAll = document.createElement("option");
      optAll.value = "ALL";
      optAll.innerText = `All Systems (Account View - ${currentFiltered.length} nodes)`;
      if (state.selectedSAMSystemSerial === "ALL") optAll.selected = true;
      grpPortfolio.appendChild(optAll);
      samSelect.appendChild(grpPortfolio);
      
      const uniqueClusters = [...new Set(currentFiltered.map(s => s.clusterName))];
      if (uniqueClusters.length > 0) {
        const grpClusters = document.createElement("optgroup");
        grpClusters.label = "Clusters (Aggregated)";
        uniqueClusters.forEach(clusterName => {
          const clusterNodes = currentFiltered.filter(s => s.clusterName === clusterName);
          const opt = document.createElement("option");
          opt.value = `CLUSTER:${clusterName}`;
          opt.innerText = `Cluster: ${clusterName} (${clusterNodes.length} nodes)`;
          if (state.selectedSAMSystemSerial === `CLUSTER:${clusterName}`) opt.selected = true;
          grpClusters.appendChild(opt);
        });
        samSelect.appendChild(grpClusters);
      }
      
      const grpNodes = document.createElement("optgroup");
      grpNodes.label = "Nodes (Individual)";
      currentFiltered.forEach(sys => {
        const opt = document.createElement("option");
        opt.value = `NODE:${sys.serialNumber}`;
        opt.innerText = `Node: ${sys.systemName} (${sys.platform})`;
        if (state.selectedSAMSystemSerial === `NODE:${sys.serialNumber}` || state.selectedSAMSystemSerial === sys.serialNumber) opt.selected = true;
        grpNodes.appendChild(opt);
      });
      samSelect.appendChild(grpNodes);
    }
    samSelect.onchange = (e) => {
      const val = e.target.value;
      state.selectedSAMSystemSerial = val;
      if (val !== "ALL" && !val.startsWith("CLUSTER:")) {
        const serial = val.startsWith("NODE:") ? val.substring(5) : val;
        const found = state.systems.find(s => s.serialNumber === serial);
        if (found) state.selectedSystem = found;
      }
      switchTab("sam");
    };
  }

  // Populate CSM System Selector
  const csmSelect = document.getElementById("csmSystemSelect");
  if (csmSelect) {
    csmSelect.innerHTML = "";
    if (currentFiltered.length > 0) {
      const grpPortfolio = document.createElement("optgroup");
      grpPortfolio.label = "Portfolio View";
      const optAll = document.createElement("option");
      optAll.value = "ALL";
      optAll.innerText = `All Systems (Account View - ${currentFiltered.length} nodes)`;
      if (state.selectedCSMSystemSerial === "ALL") optAll.selected = true;
      grpPortfolio.appendChild(optAll);
      csmSelect.appendChild(grpPortfolio);
      
      const uniqueClusters = [...new Set(currentFiltered.map(s => s.clusterName))];
      if (uniqueClusters.length > 0) {
        const grpClusters = document.createElement("optgroup");
        grpClusters.label = "Clusters (Aggregated)";
        uniqueClusters.forEach(clusterName => {
          const clusterNodes = currentFiltered.filter(s => s.clusterName === clusterName);
          const opt = document.createElement("option");
          opt.value = `CLUSTER:${clusterName}`;
          opt.innerText = `Cluster: ${clusterName} (${clusterNodes.length} nodes)`;
          if (state.selectedCSMSystemSerial === `CLUSTER:${clusterName}`) opt.selected = true;
          grpClusters.appendChild(opt);
        });
        csmSelect.appendChild(grpClusters);
      }
      
      const grpNodes = document.createElement("optgroup");
      grpNodes.label = "Nodes (Individual)";
      currentFiltered.forEach(sys => {
        const opt = document.createElement("option");
        opt.value = `NODE:${sys.serialNumber}`;
        opt.innerText = `Node: ${sys.systemName} (${sys.platform})`;
        if (state.selectedCSMSystemSerial === `NODE:${sys.serialNumber}` || state.selectedCSMSystemSerial === sys.serialNumber) opt.selected = true;
        grpNodes.appendChild(opt);
      });
      csmSelect.appendChild(grpNodes);
    }
    csmSelect.onchange = (e) => {
      const val = e.target.value;
      state.selectedCSMSystemSerial = val;
      if (val !== "ALL" && !val.startsWith("CLUSTER:")) {
        const serial = val.startsWith("NODE:") ? val.substring(5) : val;
        const found = state.systems.find(s => s.serialNumber === serial);
        if (found) state.selectedSystem = found;
      }
      switchTab("csm");
    };
  }

  // Render custom multi-select checkbox dropdown for Technical Audit
  const customDropdown = document.getElementById("tamMultiSelectDropdown");
  if (customDropdown) {
    customDropdown.innerHTML = "";
    
    if (currentFiltered.length === 0) {
      customDropdown.innerHTML = `<div style="padding: 8px 12px; font-size: 0.8rem; color: var(--text-muted);">No systems in current scope.</div>`;
    } else {
      // Select All Option
      const selectAllDiv = document.createElement("div");
      selectAllDiv.style.padding = "6px 12px";
      selectAllDiv.style.display = "flex";
      selectAllDiv.style.alignItems = "center";
      selectAllDiv.style.gap = "8px";
      selectAllDiv.style.cursor = "pointer";
      selectAllDiv.style.borderBottom = "1px solid var(--border-color)";
      selectAllDiv.style.background = "rgba(255, 255, 255, 0.02)";
      
      const allSelected = allSerialsInScope.length > 0 && allSerialsInScope.every(ser => state.selectedTAMSerials.includes(ser));
      
      selectAllDiv.innerHTML = `
        <input type="checkbox" id="chk_tam_all" ${allSelected ? 'checked' : ''} style="cursor: pointer;">
        <label for="chk_tam_all" style="cursor: pointer; font-weight: 700; font-size: 0.8rem; flex: 1;">Select All Systems</label>
      `;
      selectAllDiv.onclick = (e) => e.stopPropagation();
      
      const selectAllChk = selectAllDiv.querySelector("input");
      selectAllChk.onchange = (e) => {
        if (e.target.checked) {
          state.selectedTAMSerials = [...allSerialsInScope];
        } else {
          state.selectedTAMSerials = [];
        }
        updateTAMSelectLabel();
        renderTAMTab();
      };
      customDropdown.appendChild(selectAllDiv);
      
      // Group systems by cluster
      const clustersMap = new Map();
      currentFiltered.forEach(sys => {
        if (!clustersMap.has(sys.clusterName)) {
          clustersMap.set(sys.clusterName, []);
        }
        clustersMap.get(sys.clusterName).push(sys);
      });
      
      clustersMap.forEach((nodes, clusterName) => {
        const clusterDiv = document.createElement("div");
        clusterDiv.style.padding = "6px 12px";
        clusterDiv.style.background = "rgba(0, 229, 255, 0.02)";
        clusterDiv.style.borderBottom = "1px solid rgba(255, 255, 255, 0.05)";
        clusterDiv.style.display = "flex";
        clusterDiv.style.alignItems = "center";
        clusterDiv.style.gap = "8px";
        clusterDiv.style.cursor = "pointer";
        
        const nodeSerials = nodes.map(n => n.serialNumber);
        const allClusterNodesChecked = nodeSerials.every(ser => state.selectedTAMSerials.includes(ser));
        
        clusterDiv.innerHTML = `
          <input type="checkbox" id="chk_cluster_${clusterName}" ${allClusterNodesChecked ? 'checked' : ''} style="cursor: pointer;">
          <label for="chk_cluster_${clusterName}" style="cursor: pointer; font-weight: 600; font-size: 0.8rem; color: var(--accent-cyan); flex: 1;">
            Cluster: ${clusterName}
          </label>
        `;
        clusterDiv.onclick = (e) => e.stopPropagation();
        
        const clusterChk = clusterDiv.querySelector("input");
        clusterChk.onchange = (e) => {
          if (e.target.checked) {
            nodeSerials.forEach(ser => {
              if (!state.selectedTAMSerials.includes(ser)) {
                state.selectedTAMSerials.push(ser);
              }
            });
          } else {
            state.selectedTAMSerials = state.selectedTAMSerials.filter(ser => !nodeSerials.includes(ser));
          }
          updateTAMSelectLabel();
          renderTAMTab();
        };
        customDropdown.appendChild(clusterDiv);
        
        nodes.forEach(sys => {
          const itemDiv = document.createElement("div");
          itemDiv.style.padding = "6px 12px 6px 28px";
          itemDiv.style.display = "flex";
          itemDiv.style.alignItems = "center";
          itemDiv.style.gap = "8px";
          itemDiv.style.cursor = "pointer";
          
          const isChecked = state.selectedTAMSerials.includes(sys.serialNumber);
          
          itemDiv.innerHTML = `
            <input type="checkbox" value="${sys.serialNumber}" id="chk_tam_${sys.serialNumber}" ${isChecked ? 'checked' : ''} style="cursor: pointer;">
            <label for="chk_tam_${sys.serialNumber}" style="cursor: pointer; font-size: 0.8rem; flex: 1;">Node: ${sys.systemName} (${sys.platform})</label>
          `;
          itemDiv.onclick = (e) => e.stopPropagation();
          
          const chk = itemDiv.querySelector("input");
          chk.onchange = (e) => {
            const serial = sys.serialNumber;
            if (e.target.checked) {
              if (!state.selectedTAMSerials.includes(serial)) {
                state.selectedTAMSerials.push(serial);
              }
            } else {
              state.selectedTAMSerials = state.selectedTAMSerials.filter(s => s !== serial);
            }
            updateTAMSelectLabel();
            renderTAMTab();
          };
          customDropdown.appendChild(itemDiv);
        });
      });
  }
}

updateTAMSelectLabel();
}

function toggleTAMMultiSelect(event) {
  if (event) event.stopPropagation();
  const dropdown = document.getElementById("tamMultiSelectDropdown");
  if (!dropdown) return;
  dropdown.style.display = dropdown.style.display === "none" ? "block" : "none";
}

function updateTAMSelectLabel() {
  const label = document.getElementById("tamMultiSelectLabel");
  if (!label) return;
  const currentFiltered = getFilteredSystems();
  const allSerialsInScope = currentFiltered.map(s => s.serialNumber);
  const activeInScope = state.selectedTAMSerials.filter(ser => allSerialsInScope.includes(ser));
  
  if (activeInScope.length === 0) {
    label.innerText = "No Systems Selected";
  } else if (activeInScope.length === allSerialsInScope.length) {
    label.innerText = `All Systems (${activeInScope.length})`;
  } else if (activeInScope.length === 1) {
    const sys = currentFiltered.find(s => s.serialNumber === activeInScope[0]);
    label.innerText = sys ? sys.systemName : "1 System Selected";
  } else {
    label.innerText = `${activeInScope.length} Systems Selected`;
  }
}

