// ─────────────────────────────────────────────────────────────────────────────
// NetApp Security Bulletins & Known Issues Database
// MIGRATED: All advisory data now lives in security_bulletins.json
//   → Loaded at startup via loadDynamicBulletins() → GET /api/bulletins
//   → Add new entries: POST /api/bulletins  OR  edit security_bulletins.json
// Format: { id, cve[], cvss, severity, category, title, description,
//           affectedProducts[], affectedVersions{}, fixedVersions{},
//           mitigation, published, link }
// ─────────────────────────────────────────────────────────────────────────────
let NETAPP_SECURITY_BULLETIN_DB = []; // Populated at startup from security_bulletins.json

// Helper: Robust numeric version comparison. Returns true if ver < limit.
// Supports "9.x", "9.x.y", and "9.x.yPn" formats.
function versionLt(ver, limit) {
  const parse = (v) => {
    const m = (v || '').replace(/^(ontap|storagegrid|santricity os)\s*/i, '').trim().match(/^(\d+)\.(\d+)(?:\.(\d+))?(?:P(\d+))?/i);
    if (!m) return [0, 0, 0, 0];
    return [
      parseInt(m[1]),
      parseInt(m[2]),
      m[3] ? parseInt(m[3]) : 0,
      m[4] ? parseInt(m[4]) : 0
    ];
  };
  const vm = parse(ver);
  const lm = parse(limit);
  for (let i = 0; i < 4; i++) {
    if (vm[i] < lm[i]) return true;
    if (vm[i] > lm[i]) return false;
  }
  return false;
}

// Dynamic bulletin loader — fetches security_bulletins.json from the local
// server via GET /api/bulletins and populates NETAPP_SECURITY_BULLETIN_DB.
// This is the ONLY source of advisory data — there is no hardcoded fallback.
// If the server is unavailable, the DB stays empty and the UI shows a warning.
// ─────────────────────────────────────────────────────────────────────────────
async function loadDynamicBulletins() {
  try {
    const res = await fetch('/api/bulletins', { cache: 'no-store' });
    if (!res.ok) { throw new Error(`HTTP ${res.status}`); }
    const data = await res.json();
    const remote = Array.isArray(data.bulletins) ? data.bulletins : [];

    // Merge into in-memory DB.
    // 'added'   = entries in the file not yet in memory (happens every page load on startup).
    // 'todayNew' = entries whose _addedAt is today — genuinely new from the latest scan.
    // The UI badge only shows todayNew so it doesn't falsely alert on every startup.
    const today = new Date().toISOString().slice(0, 10);
    const idToIdx = {};
    NETAPP_SECURITY_BULLETIN_DB.forEach((b, i) => { if (b.id) idToIdx[b.id] = i; });
    let added = 0, updated = 0, todayNew = 0;
    for (const entry of remote) {
      if (!entry.id) continue;
      if (entry.id in idToIdx) {
        NETAPP_SECURITY_BULLETIN_DB[idToIdx[entry.id]] = entry;
        updated++;
      } else {
        idToIdx[entry.id] = NETAPP_SECURITY_BULLETIN_DB.length;
        NETAPP_SECURITY_BULLETIN_DB.push(entry);
        added++;
        // Only flag as 'new today' if the scan stamped it with today's date
        if (entry._addedAt === today) todayNew++;
      }
    }

    // Invalidate memoize cache so new entries are picked up immediately
    _secBulletinCache.clear();

    state.bulletinDbMeta = {
      lastUpdated:  data.lastUpdated || null,
      serverCount:  remote.length,
      totalCount:   NETAPP_SECURITY_BULLETIN_DB.length,
      added, updated, todayNew,
      source: 'server'
    };

    if (todayNew > 0) {
      console.log(`[AIQ Security] ${todayNew} new advisor${todayNew === 1 ? 'y' : 'ies'} added today — total ${NETAPP_SECURITY_BULLETIN_DB.length}`);
    } else {
      console.log(`[AIQ Security] Advisory DB loaded: ${NETAPP_SECURITY_BULLETIN_DB.length} entries (${added} merged from file, ${updated} already in memory)`);
    }
  } catch (err) {
    // Server unavailable — no fallback. DB stays empty; UI shows warning.
    state.bulletinDbMeta = {
      lastUpdated: null, serverCount: 0,
      totalCount: 0,
      added: 0, updated: 0, source: 'unavailable'
    };
    console.warn(`[AIQ Security] /api/bulletins unavailable — security advisory DB is empty. Start the server to load advisories. Error: ${err.message}`);
  }
  _updateBulletinDbIndicator();
}

function _updateBulletinDbIndicator() {
  const el = document.getElementById('bulletinDbStatus');
  if (!el) return;
  const m = state.bulletinDbMeta || {};
  const count = m.totalCount || NETAPP_SECURITY_BULLETIN_DB.length;
  const date  = m.lastUpdated ? ` · updated ${m.lastUpdated}` : '';
  const newBadge = m.added > 0 ? ` <span style="color:var(--status-critical);font-weight:700">+${m.added} new</span>` : '';

  let src, color;
  if (m.source === 'server') {
    src   = '✅ live database';
    color = 'var(--accent-cyan)';
  } else if (m.source === 'unavailable') {
    src   = '⚠️ server offline — no advisories loaded';
    color = 'var(--status-warning, #f59e0b)';
  } else {
    src   = '⏳ loading…';
    color = 'var(--text-secondary)';
  }

  el.innerHTML = `<span style="color:${color}">${src}</span> · ${count} advisories${date}${newBadge}`;
}

// ─────────────────────────────────────────────────────────────────────────────
// refreshSecurityAdvisoryDB()
// Wired to the "🛡️ Refresh Security Advisory DB" button in the Sync panel.
// Calls GET /api/bulletins/scan on the server, which:
//   1. Scrapes security.netapp.com for all NTAP advisory IDs
//   2. Fetches detail + NVD CVSS for any IDs not already in the DB
//   3. Atomically writes updated security_bulletins.json
// Then reloads the in-memory DB via loadDynamicBulletins() and re-renders.
// ─────────────────────────────────────────────────────────────────────────────
async function refreshSecurityAdvisoryDB() {
  const btn      = document.getElementById('securityDbRefreshBtn');
  const iconEl   = document.getElementById('securityDbRefreshIcon');
  const textEl   = document.getElementById('securityDbRefreshText');
  const statusEl = document.getElementById('bulletinDbStatus');

  // ── Enter loading state ───────────────────────────────────────────────────
  if (btn)    { btn.disabled = true; btn.style.opacity = '0.7'; btn.style.cursor = 'not-allowed'; }
  if (iconEl) { iconEl.textContent = '⏳'; }
  if (textEl) { textEl.textContent = 'Scanning advisories…'; }

  // Show live elapsed timer in the status indicator
  let elapsed = 0;
  const timer = setInterval(() => {
    elapsed++;
    if (statusEl) {
      statusEl.innerHTML = `<span style="color:var(--accent-cyan)">🔄 Scanning PSIRT + NVD…</span> · ${elapsed}s elapsed`;
    }
    if (textEl) { textEl.textContent = `Scanning… (${elapsed}s)`; }
  }, 1000);

  try {
    // ── Call the server scan endpoint ─────────────────────────────────────
    // This is a synchronous HTTP call that may take 30-90s depending on how
    // many new advisories are found. The server scrapes security.netapp.com
    // and NVD, then writes atomically to security_bulletins.json before responding.
    const res = await fetch('/api/bulletins/scan', { cache: 'no-store' });
    clearInterval(timer);

    if (!res.ok) {
      const errData = await res.json().catch(() => ({}));
      throw new Error(errData.error || `HTTP ${res.status}`);
    }

    const result = await res.json();
    // result = { added, updated, total, scanned, errors, newIds }

    // ── Reload in-memory DB from the now-updated file ─────────────────────
    await loadDynamicBulletins();

    // ── Show result toast ─────────────────────────────────────────────────
    const msg = result.added > 0
      ? `✅ ${result.added} new advisor${result.added === 1 ? 'y' : 'ies'} added (${result.total} total · ${result.scanned} scanned)`
      : `✅ Already up to date — ${result.total} advisories, ${result.scanned} scanned, no new entries`;

    console.log(`[AIQ Security] Scan complete: +${result.added} new, ${result.scanned} scanned, ${result.total} total`);
    showToast(msg, result.added > 0 ? 'success' : 'info');

    if (result.errors > 0) {
      console.warn(`[AIQ Security] Scan had ${result.errors} fetch error(s) — some advisories may be incomplete`);
    }

  } catch (err) {
    clearInterval(timer);
    console.error('[AIQ Security] Scan failed:', err);
    if (statusEl) {
      statusEl.innerHTML = `<span style="color:var(--status-warning,#f59e0b)">⚠️ Scan failed — ${err.message}</span>`;
    }
    showToast(`⚠️ Advisory scan failed: ${err.message}`, 'error');
  } finally {
    // ── Restore button ────────────────────────────────────────────────────
    if (btn)    { btn.disabled = false; btn.style.opacity = ''; btn.style.cursor = ''; }
    if (iconEl) { iconEl.textContent = '🛡️'; }
    if (textEl) { textEl.textContent = 'Refresh Security Advisory DB'; }
  }
}

// Called during enrichSystemTelemetry() for live and mock systems
// Returns array of {id, cve, cvss, severity, title, status, mitigation, link}
// ─────────────────────────────────────────────────────────────────────────────
// ─── Security bulletin result cache — keyed by "version|platform" ────────────
// getApplicableSecurityBulletins() iterates the entire NETAPP_SECURITY_BULLETIN_DB
// on every call. With 13+ systems × multiple renders per session, memoizing this
// function eliminates the single biggest synchronous work block per render cycle.
const _secBulletinCache = new Map();

function getApplicableSecurityBulletins(ontapVersion, platformType) {
  const _cacheKey = (ontapVersion || '') + '|' + (platformType || '');
  if (_secBulletinCache.has(_cacheKey)) return _secBulletinCache.get(_cacheKey);
  if (!ontapVersion) return [];

  const results = [];
  const pType = (platformType || '').toLowerCase();
  const isStorageGrid = pType.includes('storagegrid') || pType.includes('sg');
  const isSnapCenter  = pType.includes('snapcenter');
  const isTrident     = pType.includes('trident');

  // Normalise version string: e.g. "ONTAP 9.16.1P7" → "9.16.1P7"
  const vRaw = ontapVersion.replace(/^(ontap|storagegrid|santricity os)\s*/i, '').trim();
  // Parse base + patch: "9.16.1P7" → base="9.16.1", patch=7
  const vMatch = vRaw.match(/^(\d+\.\d+\.\d+)(?:P(\d+))?/i);
  if (!vMatch) return [];
  const base  = vMatch[1];  // e.g. "9.16.1"
  const patch = vMatch[2] ? parseInt(vMatch[2]) : 0;

  for (const advisory of NETAPP_SECURITY_BULLETIN_DB) {
    // Skip platform-irrelevant advisories
    const prods = advisory.affectedProducts || [];
    if (isStorageGrid && !prods.some(p => p.toLowerCase().includes('storagegrid'))) continue;
    if (isSnapCenter  && !prods.some(p => p.toLowerCase().includes('snapcenter'))) continue;
    if (isTrident     && !prods.some(p => p.toLowerCase().includes('trident'))) continue;
    // For ONTAP systems, skip StorageGRID/SnapCenter-only entries
    if (!isStorageGrid && !isSnapCenter && !isTrident) {
      if (prods.length > 0 && !prods.some(p => p.toLowerCase().includes('ontap') || p.toLowerCase().includes('netapp products'))) continue;
    }

    // Check version ranges
    const ranges = (advisory.affectedVersions && advisory.affectedVersions.ontap) || [];
    let applicable = false;
    for (const range of ranges) {
      if (!range.from || !range.to) { applicable = true; break; } // open-ended
      if (range.to.toLowerCase().includes('current') || range.to.toLowerCase().includes('check')) {
        // Affected through current — always flag
        if (!versionLt(base + 'P' + patch, range.from)) { applicable = true; break; }
      } else {
        // Affected: base >= range.from AND (base + patch) < range.to (exclusive upper)
        if (!versionLt(base + 'P' + patch, range.from) && versionLt(base + 'P' + patch, range.to)) {
          applicable = true; break;
        }
      }
    }
    if (ranges.length === 0) applicable = true; // no version range = all versions

    if (applicable) {
      const fixedArr = (advisory.fixedVersions && (advisory.fixedVersions.ontap || advisory.fixedVersions.storagegrid || advisory.fixedVersions.snapcenter || advisory.fixedVersions.trident)) || [];
      results.push({
        id:         advisory.cve ? advisory.cve[0] : advisory.id,
        ntapId:     advisory.id,
        cve:        advisory.cve ? advisory.cve.join(', ') : 'N/A',
        cvss:       advisory.cvss,
        title:      advisory.title,
        category:   advisory.category,
        severity:   advisory.severity,
        status:     'Vulnerable — Action Required',
        mitigation: advisory.mitigation,
        fixedIn:    fixedArr.join(' / '),
        published:  advisory.published,
        link:       advisory.link
      });
    }
  }
  const sevRank = { critical: 0, high: 1, medium: 2, low: 3 };
  results.sort((a, b) => (sevRank[a.severity] ?? 4) - (sevRank[b.severity] ?? 4));
  _secBulletinCache.set(_cacheKey, results);
  return results;
}

