function getOntapHopInfo(from, to) {
  let steps = [
    "1. Download target ONTAP " + to + " image from the NetApp Support site.",
    "2. Run cluster pre-upgrade validation command: <code>cluster image validate -version " + to + "</code>.",
    "3. Apply OS update non-disruptively: <code>cluster image update -version " + to + "</code>."
  ];
  let recommendations = [
    "Run <code>system health alert show</code> to verify no active hardware alerts are present.",
    "Generate a configuration backup: <code>system configuration backup create -node * -backup-name pre_upgrade_" + from.replace(/\./g, "_") + "</code>.",
    "Verify network path redundancy using <code>network port show</code>."
  ];
  let considerations = [
    "ONTAP upgrades are non-disruptive (NDU) on HA pairs. Node failovers reload controllers sequentially.",
    "Cross-reference switch and disk shelf firmware compatibility tables on the NetApp Interoperability Matrix Tool (IMT)."
  ];
  let docLink = "https://docs.netapp.com/us-en/ontap/upgrade/index.html";

  if (to === "9.7") {
    recommendations.push("WAFL metadata format upgrade will automatically occur. Ensure aggregates have > 15% free capacity prior to starting.");
    considerations.push("ONTAP 9.7 enforces secure management protocols by default. Legacy TLS 1.0/1.1 API connections will be rejected.");
  } else if (to === "9.8") {
    steps.push("Upgrade cluster switch firmwares to support newer internal link speed configurations.");
    considerations.push("ONTAP 9.8 introduces simplified volume placement policies and unified interface improvements.");
  } else if (to === "9.10.1" || to === "9.12.1") {
    recommendations.push("Confirm that VMware ESXi hosts connecting via iSCSI/FCP use the <code>VMW_PSP_RR</code> round-robin storage path policy with IOPS limit = 1.");
    considerations.push("Review cipher configurations. All deprecated, weak TLS ciphers are disabled.");
  } else if (to === "9.14.1" || to === "9.16.1") {
    steps.push("Verify that all hardware controller node models in the cluster support ONTAP " + to + " (refer to hardware compatibility matrix).");
    considerations.push("ONTAP REST API v2 endpoints are active. Verify external automation tools or scripts compatibility.");
  }
  
  return { from, to, steps, recommendations, considerations, docLink };
}

function getStoragegridHopInfo(from, to) {
  let steps = [
    "1. Download StorageGRID software update package (version " + to + ") and recovery package from NetApp Support.",
    "2. Log in to the Primary Admin Node. Navigate to Maintenance > System > Software Update.",
    "3. Upload the update package and recovery package, then click 'Apply'."
  ];
  let recommendations = [
    "Generate a new grid recovery package before start: select Maintenance > Recovery Package and download the file.",
    "Ensure all grid storage and API gateway nodes are online and reporting normal telemetry."
  ];
  let considerations = [
    "StorageGRID major upgrades must be performed sequentially. Skipping major versions (e.g. 11.4 to 11.6 directly) is unsupported.",
    "The software update process is rolling. Services remain active, but API calls might failover between gateway nodes during container restarts."
  ];
  let docLink = "https://docs.netapp.com/us-en/storagegrid-" + to.replace(/\./g, "").slice(0, 3) + "/upgrade/index.html";
  if (to.startsWith("11.9")) docLink = "https://docs.netapp.com/us-en/storagegrid-119/upgrade/index.html";
  
  if (to === "11.5") {
    considerations.push("Underlying Cassandra database schemas are restructured. Storage nodes will consume higher CPU during indexing.");
  } else if (to === "11.7") {
    recommendations.push("Verify S3 client API integration compatibility (verify Swift deprecation markers if applicable).");
  } else if (to.startsWith("11.9")) {
    considerations.push("Review TLS certificate signing requirements. StorageGRID 11.9 enforces strict client-side cert handshakes.");
  }
  
  return { from, to, steps, recommendations, considerations, docLink };
}

function getSantricityHopInfo(from, to) {
  let steps = [
    "1. Download SANtricity OS controller firmware package " + to + " and NVSRAM file from NetApp Support.",
    "2. Access SANtricity System Manager or Unified Manager.",
    "3. Go to Support > Upgrade Center > SANtricity OS Software Upgrade. Upload both firmware and NVSRAM files, then select 'Upgrade'."
  ];
  let recommendations = [
    "Run drive diagnostics to ensure all disk drives in pools/volume groups are in optimal state.",
    "Ensure both Controller A and Controller B report optimal state and battery units are fully charged."
  ];
  let considerations = [
    "Firmware reload is non-disruptive on dual-controller configurations. Firmware is activated on one controller, reboots, then syncs with the partner.",
    "Single-controller shelf configurations require scheduling an offline maintenance window."
  ];
  let docLink = "https://docs.netapp.com/us-en/e-series/upgrade-santricity.html";

  if (to === "11.50") {
    steps.push("Note: SANtricity 11.50 implements the embedded REST API server. Legacy Web Services proxy configurations require reconfiguration.");
  } else if (to === "11.70" || to === "11.75") {
    considerations.push("Verify BBU backup battery units status. A degraded BBU will disable write caching during update, causing significant latency spikes.");
  } else if (to.startsWith("11.80")) {
    recommendations.push("Inspect SSD drive wear life reports to identify any drives nearing 90% write endurance limits prior to reload.");
  }
  
  return { from, to, steps, recommendations, considerations, docLink };
}

// Memoize calculateUpgradePath — called in 6 separate loop contexts (TAM tab,
// action plan, export functions) with no prior caching. The same (platform,
// currentVersion, targetVersion) triple may appear many times per render.
const _upgradePathCache = new Map();

function calculateUpgradePath(platform, currentVersion, targetVersion) {
  const _cacheKey = `${platform}|${currentVersion}|${targetVersion}`;
  if (_upgradePathCache.has(_cacheKey)) return _upgradePathCache.get(_cacheKey);

  const p = (platform || "").toLowerCase();
  let type = "ontap";
  if (p.includes("storagegrid")) type = "storagegrid";
  else if (p.includes("e-series") || p.includes("ef600") || p.includes("ef50") || p.includes("ef80") || p.includes("e5700") || p.includes("e4000") || p.includes("santricity")) type = "santricity";
  
  // Clean versions (remove prefixes)
  let cleanCurrent = currentVersion.replace(/^(ontap|santricity os|storagegrid|nx-os|fabric os|fos)\s+/i, "").trim();
  let cleanTarget = targetVersion.replace(/^(ontap|santricity os|storagegrid|nx-os|fabric os|fos)\s+/i, "").trim();
  
  // Strip patch designations (like P4) for path finding index matches
  let currentBase = cleanCurrent.split("P")[0].trim();
  let targetBase = cleanTarget.split("P")[0].trim();
  
  if (currentBase === targetBase) { _upgradePathCache.set(_cacheKey, []); return []; }
  
  const hops = [];
  
  if (type === "ontap") {
    const vList = SOFTWARE_VERSION_DATABASES.ontap;
    
    // Map currentBase/targetBase to closest matching element in database
    let startIndex = vList.findIndex(v => v === currentBase || currentBase.startsWith(v));
    let endIndex = vList.findIndex(v => v === targetBase || targetBase.startsWith(v));
    
    if (startIndex === -1 || endIndex === -1) {
      return [{
        from: cleanCurrent,
        to: cleanTarget,
        steps: [
          "1. Download target ONTAP OS image from NetApp Support.",
          "2. Validate cluster readiness: <code>cluster image validate -version " + cleanTarget + "</code>.",
          "3. Perform non-disruptive upgrade (NDU): <code>cluster image update -version " + cleanTarget + "</code>."
        ],
        recommendations: [
          "Run <code>system health alert show</code> and verify HA status.",
          "Generate cluster configuration backup prior to start."
        ],
        considerations: [
          "Verify third-party driver compatibility (VMware host PSP round robin settings).",
          "Ensure switch and shelf firmwares align with NetApp IMT matrix."
        ],
        docLink: "https://docs.netapp.com/us-en/ontap/upgrade/index.html"
      }];
    }
    if (startIndex >= endIndex) {
      return [];
    }
    
    let currentIdx = startIndex;
    while (currentIdx < endIndex) {
      let nextIdx = currentIdx;
      const curVer = vList[currentIdx];
      
      if (["9.3", "9.4", "9.5", "9.6"].includes(curVer)) {
        // Must upgrade through 9.7 first
        nextIdx = vList.indexOf("9.7");
      } else if (curVer === "9.7") {
        // Must go to 9.8
        nextIdx = vList.indexOf("9.8");
      } else {
        // Can skip one release, so max jump of 2 minor versions forward
        nextIdx = Math.min(endIndex, currentIdx + 2);
      }
      
      // Fallback if index lookup fails
      if (nextIdx <= currentIdx) nextIdx = currentIdx + 1;
      
      const vFrom = vList[currentIdx];
      const vTo = vList[nextIdx];
      
      // Append target patch designator to the last hop if applicable
      const displayTo = (nextIdx === endIndex) ? cleanTarget : vTo;
      
      hops.push(getOntapHopInfo(vFrom, displayTo));
      currentIdx = nextIdx;
    }
  } else if (type === "storagegrid") {
    const vList = SOFTWARE_VERSION_DATABASES.storagegrid;
    let startIndex = vList.findIndex(v => v === currentBase || currentBase.startsWith(v));
    let endIndex = vList.findIndex(v => v === targetBase || targetBase.startsWith(v));
    
    if (startIndex === -1 || endIndex === -1) {
      return [{
        from: cleanCurrent,
        to: cleanTarget,
        steps: [
          "1. Download target StorageGRID update file and recovery package from NetApp support.",
          "2. Upload package in Maintenance > Software Update.",
          "3. Apply grid-wide rolling updates."
        ],
        recommendations: [
          "Generate and download StorageGRID recovery package before starting software update.",
          "Verify all storage nodes are online and functioning normally."
        ],
        considerations: [
          "Upgrades must be performed sequentially. You cannot skip major version releases.",
          "Services remain active, but transient failovers occur as nodes reload."
        ],
        docLink: "https://docs.netapp.com/us-en/storagegrid-119/upgrade/index.html"
      }];
    }
    if (startIndex >= endIndex) {
      return [];
    }
    
    for (let i = startIndex; i < endIndex; i++) {
      const vFrom = vList[i];
      const vTo = vList[i+1];
      const displayTo = (i+1 === endIndex) ? cleanTarget : vTo;
      hops.push(getStoragegridHopInfo(vFrom, displayTo));
    }
  } else if (type === "santricity") {
    const vList = SOFTWARE_VERSION_DATABASES.santricity;
    let startIndex = vList.findIndex(v => v === currentBase || currentBase.startsWith(v));
    let endIndex = vList.findIndex(v => v === targetBase || targetBase.startsWith(v));
    
    if (startIndex === -1 || endIndex === -1) {
      return [{
        from: cleanCurrent,
        to: cleanTarget,
        steps: [
          "1. Download SANtricity OS controller firmware package and NVSRAM from NetApp Support.",
          "2. Go to Support > Upgrade Center > SANtricity OS Software Upgrade.",
          "3. Upload firmware and NVSRAM and apply update."
        ],
        recommendations: [
          "Check SAN multipathing configuration on client hosts.",
          "Verify drive health diagnostics."
        ],
        considerations: [
          "Requires dual-controller configuration for non-disruptive execution.",
          "Verify host compatibility in IMT."
        ],
        docLink: "https://docs.netapp.com/us-en/e-series/upgrade-santricity.html"
      }];
    }
    
    if (startIndex >= endIndex) {
      return [];
    }
    
    let currentIdx = startIndex;
    while (currentIdx < endIndex) {
      let nextIdx = currentIdx;
      const curVer = vList[currentIdx];
      
      if (["11.30", "11.40"].includes(curVer)) {
        nextIdx = vList.indexOf("11.50");
      } else if (curVer === "11.50" || curVer === "11.60") {
        nextIdx = vList.indexOf("11.70");
      } else {
        nextIdx = endIndex;
      }
      
      if (nextIdx <= currentIdx) nextIdx = currentIdx + 1;
      
      const vFrom = vList[currentIdx];
      const vTo = vList[nextIdx];
      const displayTo = (nextIdx === endIndex) ? cleanTarget : vTo;
      
      hops.push(getSantricityHopInfo(vFrom, displayTo));
      currentIdx = nextIdx;
    }
  }
  
  _upgradePathCache.set(_cacheKey, hops);
  return hops;
}

function getLatestSupportedVersion(platform) {
  const p = (platform || "").toLowerCase();
  if (p.includes("storagegrid")) {
    const db = SOFTWARE_VERSION_DATABASES.storagegrid;
    return "StorageGRID " + db[db.length - 1];
  } else if (p.includes("e-series") || p.includes("ef600") || p.includes("ef50") || p.includes("ef80") || p.includes("e5700") || p.includes("e4000") || p.includes("santricity")) {
    const db = SOFTWARE_VERSION_DATABASES.santricity;
    return "SANtricity OS " + db[db.length - 1];
  } else if (p.includes("cisco") || p.includes("mds") || p.includes("nexus")) {
    return "NX-OS 9.3(12)";
  } else if (p.includes("brocade") || p.includes("switch")) {
    return "Fabric OS (FOS) 9.2.1";
  } else {
    const db = SOFTWARE_VERSION_DATABASES.ontap;
    return "ONTAP " + db[db.length - 1] + "";
  }
}

// ── linkify(text) ────────────────────────────────────────────────────────────
// Converts plain-text step/recommendation strings into rich HTML, making all
// embedded URLs, NetApp doc references, CVE IDs, TR numbers, and advisory IDs
// clickable links. Safe to call on authored (non-user-input) strings only.
function linkify(text) {
  if (!text) return '';
  const s = a => `style="color:var(--accent-cyan);text-decoration:underline;"`;
  const w = a => `style="color:var(--status-warning);text-decoration:underline;"`;

  // ── Pre-sanitize: the AIQ API often embeds raw HTML <a> tags in recommendation
  // text (e.g. `firmware <a href="https://my..." target="_blank">here</a>`).
  // Running the URL regex over already-linked HTML produces nested <a> tags or,
  // when the text is truncated mid-tag, exposes raw `" target="_blank">here`
  // as visible plain text. Strip existing anchor tags first so linkify() only
  // ever works on plain text input.
  //   <a href="URL" ...>label</a>  →  label (URL)
  //   <a href="URL" ...>URL</a>    →  URL   (avoid "URL (URL)" duplicate)
  let clean = text.replace(/<a\s+[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi,
    (match, url, label) => {
      const lbl = label.trim().replace(/<[^>]+>/g, ''); // strip any nested tags in label
      // If the label IS the URL (or is empty), just emit the URL once
      return (lbl === url || !lbl) ? url : `${lbl} (${url})`;
    }
  );
  // Strip any remaining HTML tags (img, span, strong, etc.) from the plain text
  clean = clean.replace(/<[^>]+>/g, '');

  return clean
    // Raw https URLs — must come first so later patterns don't double-process
    .replace(/(https?:\/\/[^\s<>"']+)/g,
      '<a href="$1" target="_blank" ' + s() + ' onclick="window.open(this.href,\'_blank\');return false;">$1</a>')
    // TR-XXXX NetApp technical reports
    .replace(/\bTR-(\d{4})\b/g,
      '<a href="https://www.netapp.com/search/#q=TR-$1&t=Resources" target="_blank" ' + s() + '>TR-$1</a>')
    // NTAP advisory IDs  NTAP-20260112-0001
    .replace(/\b(NTAP-\d{8}-\d{4})\b/gi,
      '<a href="https://security.netapp.com/advisory/$1/" target="_blank" ' + w() + '>$1</a>')
    // CVE IDs
    .replace(/\b(CVE-\d{4}-\d+)\b/g,
      '<a href="https://security.netapp.com/advisory/?q=$1" target="_blank" ' + w() + '>$1</a>')
    // Microsoft KB numbers  KB5073381
    .replace(/\b(KB\d{7,})\b/g,
      '<a href="https://support.microsoft.com/search/results?query=$1" target="_blank" ' + s() + '>$1</a>')
    // IMT references
    .replace(/\b(IMT|Interoperability Matrix(?:\s+Tool)?)\b/g,
      '<a href="https://imt.netapp.com/matrix/" target="_blank" ' + s() + '>$1</a>');
}

// ── getSwitchFirmwareLink(model) ──────────────────────────────────────────────
// Returns { label, url } for firmware downloads per switch model family.
function getSwitchFirmwareLink(model) {
  const m = (model || '').toLowerCase();
  if (m.includes('nexus 93') || m.includes('nexus 97') || m.includes('9336') || m.includes('9364') || m.includes('9332') || m.includes('nx-os')) {
    return { label: 'Cisco NX-OS Download', url: 'https://software.cisco.com/download/home/280275056' };
  }
  if (m.includes('mds') || m.includes('cisco mds')) {
    return { label: 'Cisco MDS Firmware Download', url: 'https://software.cisco.com/download/home/280283452' };
  }
  if (m.includes('brocade') || m.includes('g620') || m.includes('g630') || m.includes('g720') || m.includes('fos') || m.includes('fabric os')) {
    return { label: 'Brocade FOS Download', url: 'https://www.broadcom.com/support/fibre-channel-networking/software-downloads' };
  }
  if (m.includes('bes-53248') || m.includes('efos') || m.includes('broadcom')) {
    return { label: 'EFOS Firmware (mysupport)', url: 'https://mysupport.netapp.com/site/products/all/details/broadcom-cluster-switches/downloads-tab' };
  }
  if (m.includes('nvidia') || m.includes('sn2100') || m.includes('cumulus')) {
    return { label: 'NVIDIA SN2100 Firmware', url: 'https://mysupport.netapp.com/site/products/all/details/nvidia-cluster-switches/downloads-tab' };
  }
  // Generic cluster switch fallback
  return { label: 'NetApp Switch Downloads', url: 'https://mysupport.netapp.com/site/downloads' };
}

// ── getSwitchIMTLink(model) ───────────────────────────────────────────────────
function getSwitchIMTLink(ontapVersion) {
  return `https://imt.netapp.com/matrix/#search&searchByProductIdAndFamilyName=search&productNameForSearch=switch&userSelectedTargetFamilyList=ONTAP&userSelectedTargetProductList=ONTAP+${encodeURIComponent(ontapVersion || '9.16.1')}`;
}

function getRiskSafetyTier(r) {
  const desc = (r.description || "").toLowerCase();
  const cat = (r.category || "").toLowerCase();
  const rec = (r.recommendation || "").toLowerCase();
  
  if (desc.includes("delete") || desc.includes("destroy") || desc.includes("sanitize") || desc.includes("remove volume") || desc.includes("disable arp") || desc.includes("disable mav") || rec.includes("delete") || rec.includes("destroy")) {
    return "Destructive or Irreversible";
  }
  if (desc.includes("upgrade") || desc.includes("firmware") || desc.includes("takeover") || desc.includes("giveback") || desc.includes("reboot") || desc.includes("switchover") || desc.includes("switchback") || desc.includes("replace") || rec.includes("upgrade") || rec.includes("firmware") || rec.includes("reboot") || rec.includes("replace")) {
    return "Disruptive but Data-Safe";
  }
  return "Non-Disruptive";
}

// ── Risk group collapsible toggle ─────────────────────────────────────────────
// Called from onclick on system-level header rows in the TAM risks table.
function toggleRiskGroup(groupId, headerRow) {
  const drilldown = document.getElementById(groupId);
  if (!drilldown) return;
  const expanded = headerRow.dataset.expanded === 'true';
  const chevron  = headerRow.querySelector('.risk-chevron');

  if (expanded) {
    drilldown.style.display = 'none';
    headerRow.dataset.expanded = 'false';
    if (chevron) { chevron.style.transform = ''; chevron.textContent = '▶'; }
  } else {
    drilldown.style.display = '';
    headerRow.dataset.expanded = 'true';
    if (chevron) { chevron.style.transform = 'rotate(90deg)'; chevron.textContent = '▶'; }
  }
}

// ── Expand / Collapse All risk groups at once ──────────────────────────────────
function toggleAllRiskGroups(btn) {
  const expanding = btn.dataset.expanded !== 'true';
  btn.dataset.expanded = expanding ? 'true' : 'false';
  btn.textContent = expanding ? '⊟ Collapse All' : '⊞ Expand All';

  document.querySelectorAll('.risk-system-header').forEach(headerRow => {
    const groupId  = headerRow.dataset.group;
    const drilldown = groupId ? document.getElementById(groupId) : null;
    const chevron   = headerRow.querySelector('.risk-chevron');
    if (!drilldown) return;
    if (expanding) {
      drilldown.style.display = '';
      headerRow.dataset.expanded = 'true';
      if (chevron) { chevron.style.transform = 'rotate(90deg)'; }
    } else {
      drilldown.style.display = 'none';
      headerRow.dataset.expanded = 'false';
      if (chevron) { chevron.style.transform = ''; }
    }
  });
}

// ── Security bulletin secondary-tier toggle ────────────────────────────────────
// Shows / hides the Medium/Low/Info bulletin rows. On first expansion, fires
// the deferred CVE enrichment batch so those rows get NVD data on demand.
function toggleBulletinSecondary(btn) {
  const group   = document.getElementById('bulletin-secondary-group');
  const chevron = document.getElementById('bulletin-secondary-chevron');
  const label   = document.getElementById('bulletin-secondary-label');
  if (!group) return;

  const expanded = group.style.display !== 'none';
  if (expanded) {
    group.style.display = 'none';
    if (chevron) chevron.textContent = '▶';
    if (btn) { btn.dataset.expanded = 'false'; btn.textContent = (label ? label.textContent.replace('Hide', 'Show') : 'Show lower-severity advisories ▼'); }
    if (label) label.textContent = label.textContent.replace('Hide', 'Show');
  } else {
    group.style.display = '';
    if (chevron) chevron.textContent = '▼';
    if (label) label.textContent = label.textContent.replace('Show', 'Hide').replace('▼', '▲');
    if (btn) btn.dataset.expanded = 'true';

    // Fire deferred CVE enrichment on first open only
    if (window._deferredBulletinEnrich && window._deferredBulletinEnrich.length > 0) {
      const queue = window._deferredBulletinEnrich;
      window._deferredBulletinEnrich = []; // clear so it only runs once
      const batchSize = 5, delayMs = 100;
      for (let i = 0; i < queue.length; i += batchSize) {
        const chunk = queue.slice(i, i + batchSize);
        setTimeout(() => {
          chunk.forEach(({ rowId, cveId }) => {
            const rowEl = document.getElementById(rowId);
            if (rowEl && typeof enrichmentEngine !== 'undefined') {
              enrichmentEngine.injectCVEEnrichment(cveId, rowEl);
            }
          });
        }, Math.floor(i / batchSize) * delayMs);
      }
    }
  }
}

function openRemediationModal(riskId) {

  let risk = null;
  let ownerSys = null;
  for (const s of state.systems) {
    if (s.risks) {
      risk = s.risks.find(r => String(r.id) === String(riskId));
      if (risk) {
        ownerSys = s;
        break;
      }
    }
  }
  if (!risk) return;
  // Ensure remediationPlan exists
  if (!risk.remediationPlan) {
    risk.remediationPlan = {
      cause: risk.description || 'Risk identified by Active IQ.',
      impact: risk.recommendation || 'Review and remediate.',
      steps: ['1. Review the risk details in Active IQ Digital Advisor.', '2. Follow the recommended corrective actions.'],
      options: [],
      thirdParty: 'N/A'
    };
  }

  const modal = document.getElementById("remediationModal");
  if (!modal) return;

  const safetyTier = getRiskSafetyTier(risk);
  let safetyColor = "var(--status-normal)";
  if (safetyTier.includes("Destructive")) safetyColor = "var(--status-critical)";
  else if (safetyTier.includes("Disruptive")) safetyColor = "var(--status-warning)";

  document.getElementById("modalRiskTitle").innerText = `Remediation Plan: ${risk.category} Risk`;
  
  // Display safety tier in description
  document.getElementById("modalRiskDesc").innerHTML = `${risk.description}
    <div style="margin-top: 10px; background: rgba(255,255,255,0.03); border: 1px solid var(--border-color); padding: 8px 12px; border-radius: var(--radius-sm); font-size: 0.8rem; display: flex; align-items: center; gap: 8px;">
      <span style="color: var(--text-muted); font-weight: 600;">Safety Tier:</span>
      <span style="background: ${safetyColor}; color: #fff; font-size: 0.68rem; padding: 2px 6px; border-radius: var(--radius-sm); font-weight: bold; text-transform: uppercase; letter-spacing: 0.5px;">${safetyTier}</span>
    </div>`;

  document.getElementById("modalDetailCause").innerHTML = linkify(risk.remediationPlan.cause);
  document.getElementById("modalDetailImpact").innerHTML = linkify(risk.remediationPlan.impact);
  
  const stepsList = document.getElementById("modalDetailSteps");
  stepsList.innerHTML = "";
  risk.remediationPlan.steps.forEach(step => {
    const li = document.createElement("li");
    li.innerHTML = linkify(step);
    li.style.marginBottom = "8px";
    li.style.lineHeight = "1.5";
    stepsList.appendChild(li);
  });

  const optionsList = document.getElementById("modalDetailOptions");
  optionsList.innerHTML = "";
  risk.remediationPlan.options.forEach(opt => {
    const li = document.createElement("li");
    li.innerHTML = linkify(opt);
    li.style.marginBottom = "6px";
    li.style.lineHeight = "1.5";
    optionsList.appendChild(li);
  });

  document.getElementById("modalDetailThirdParty").innerHTML = linkify(risk.remediationPlan.thirdParty);

  // ── Reference Links footer ────────────────────────────────────────────────
  // Build a set of contextually relevant reference links for this risk type
  const refLinksEl = document.getElementById("modalReferenceLinks");
  if (refLinksEl) {
    const cat = (risk.category || '').toLowerCase();
    const desc = (risk.description || '').toLowerCase();
    const links = [];

    // Always add KB search
    links.push({ label: '🔍 NetApp KB Search', url: buildKBSearchURL(risk.description, risk.category) });

    // CVE / Security
    const cveMatch = (risk.description || '').match(/CVE-\d{4}-\d+/);
    if (cveMatch) {
      links.push({ label: `🛡 PSIRT: ${cveMatch[0]}`, url: `https://security.netapp.com/advisory/?q=${cveMatch[0]}` });
      links.push({ label: '📋 NVD Entry', url: `https://nvd.nist.gov/vuln/detail/${cveMatch[0]}` });
    } else if (cat.includes('security') || desc.includes('vulnerability')) {
      links.push({ label: '🛡 NetApp PSIRT Advisories', url: 'https://security.netapp.com/advisory/' });
      links.push({ label: '📄 ONTAP Security Hardening TR-4569', url: 'https://www.netapp.com/pdf.html?item=/media/10674-tr4569pdf.pdf' });
    }

    // Software / Firmware upgrade
    if (cat.includes('software') || cat.includes('firmware') || desc.includes('upgrade') || desc.includes('version')) {
      links.push({ label: '⬇ NetApp Software Downloads', url: 'https://mysupport.netapp.com/site/downloads' });
      links.push({ label: '✅ IMT Compatibility Matrix', url: 'https://imt.netapp.com/matrix/' });
      links.push({ label: '📖 ONTAP Upgrade Guide', url: 'https://docs.netapp.com/us-en/ontap/upgrade/index.html' });
    }

    // Shelf / IOM / NSM firmware
    if (desc.includes('iom') || desc.includes('nsm') || desc.includes('shelf')) {
      links.push({ label: '⬇ Shelf Firmware Downloads', url: 'https://mysupport.netapp.com/site/downloads/firmware/disk-shelf-firmware' });
      links.push({ label: '📖 Shelf Firmware Upgrade Docs', url: 'https://docs.netapp.com/us-en/ontap/disks-aggregates/shelf-firmware-upgrade-manual-disk-task.html' });
    }

    // Disk / DQP
    if (desc.includes('dqp') || desc.includes('disk qualif') || desc.includes('disk firmware')) {
      links.push({ label: '⬇ DQP Download', url: 'https://mysupport.netapp.com/site/downloads/firmware/disk' });
    }

    // Switch firmware
    if (cat.includes('switch') || desc.includes('nx-os') || desc.includes('fos') || desc.includes('efos')) {
      const swLink = getSwitchFirmwareLink(risk.description);
      links.push({ label: `⬇ ${swLink.label}`, url: swLink.url });
      links.push({ label: '✅ Switch IMT', url: 'https://imt.netapp.com/matrix/' });
    }

    // Hardware / FRU
    if (cat.includes('hardware') || desc.includes('fru') || desc.includes('path') || desc.includes('cable')) {
      links.push({ label: '🔧 NetApp Support Portal', url: 'https://mysupport.netapp.com/site/global/dashboard' });
    }

    // MetroCluster
    if (desc.includes('metrocluster') || desc.includes('mcc') || desc.includes('isl')) {
      links.push({ label: '📖 MetroCluster Docs', url: 'https://docs.netapp.com/us-en/ontap-metrocluster/' });
      links.push({ label: '📄 MetroCluster Deep Dive TR-4517', url: 'https://www.netapp.com/search/#q=TR-4517&t=Resources' });
    }

    // StorageGRID
    if (cat.includes('storagegrid') || desc.includes('storagegrid')) {
      links.push({ label: '📖 StorageGRID Upgrade Docs', url: 'https://docs.netapp.com/us-en/storagegrid/upgrade/index.html' });
    }

    // SANtricity / E-Series
    if (cat.includes('santricity') || cat.includes('e-series') || desc.includes('santricity')) {
      links.push({ label: '📖 SANtricity Upgrade Docs', url: 'https://docs.netapp.com/us-en/e-series/upgrade-santricity.html' });
    }

    if (links.length > 0) {
      refLinksEl.style.display = 'block';
      refLinksEl.innerHTML = `
        <div style="font-weight:600;font-size:0.78rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;">Reference Links</div>
        <div style="display:flex;flex-wrap:wrap;gap:8px;">
          ${links.map(l => `<a href="${l.url}" target="_blank" onclick="window.open(this.href,'_blank');return false;"
            style="display:inline-flex;align-items:center;gap:4px;font-size:0.75rem;color:var(--accent-cyan);
                   background:rgba(0,188,212,0.07);border:1px solid rgba(0,188,212,0.2);
                   padding:4px 10px;border-radius:var(--radius-sm);text-decoration:none;white-space:nowrap;"
            onmouseover="this.style.background='rgba(0,188,212,0.15)'" onmouseout="this.style.background='rgba(0,188,212,0.07)'">${l.label}</a>`).join('')}
        </div>`;
    } else {
      refLinksEl.style.display = 'none';
    }
  }

  const contextSection = document.getElementById("modalUpgradeContextSection");
  const contextText = document.getElementById("modalDetailUpgradeContext");
  if (contextSection && contextText) {
    if (ownerSys && (risk.category === "Software" || risk.category === "Firmware")) {
      const minVer = ownerSys.upgrades ? ownerSys.upgrades.targetVersion : "Unknown";
      const latestVer = getLatestSupportedVersion(ownerSys.platform);
      contextText.innerHTML = `
        Platform Type: <strong>${ownerSys.platform}</strong><br>
        Current OS/Firmware Version: <strong style="color: var(--text-muted);">${ownerSys.ontapVersion}</strong><br>
        Minimum Required Version (to resolve this issue): <strong style="color: var(--accent-cyan);">${minVer}</strong><br>
        Latest Supported OS Version for Platform: <strong style="color: var(--status-normal);">${latestVer}</strong>
      `;
      contextSection.style.display = "block";
    } else {
      contextSection.style.display = "none";
    }
  }

  const kbBtn = document.getElementById("modalKbLink");
  kbBtn.href = buildKBSearchURL(risk.description, risk.category);

  modal.style.display = "flex";
}

function closeRemediationModal() {
  const modal = document.getElementById("remediationModal");
  if (modal) modal.style.display = "none";
}

function renderTAMTab() {
  populateSystemSelectors();
  
  const currentFiltered = getFilteredSystems();
  const allSerialsInScope = currentFiltered.map(s => s.serialNumber);
  
  // Prune/initialize active serials
  const activeSerials = (state.selectedTAMSerials || []).filter(ser => allSerialsInScope.includes(ser));

  // ── Dirty-stamp guard ─────────────────────────────────────────────────────
  // renderTAMTab() is invoked on every search keystroke (switchTab→handleSearch),
  // every auto-sync tick, and every filter change while the TAM tab is active.
  // With 20+ systems this is the primary browser-hang trigger on this page.
  // Skip the full re-render when selection, active node, and system count are unchanged.
  const _tamFP = activeSerials.slice().sort().join(',') + '|' +
                 (state.activeVisualizerNodeSerial || '') + '|' +
                 (state.systems ? state.systems.length : 0);
  if (renderTAMTab._lastFP === _tamFP) return;
  renderTAMTab._lastFP = _tamFP;
  
  if (activeSerials.length === 0) {
    document.getElementById("tamRisksTableBody").innerHTML = `<tr><td colspan="4" style="text-align: center; color: var(--text-muted);">No systems selected in current scope.</td></tr>`;
    document.getElementById("tamUpgradeContainer").innerHTML = "";
    document.getElementById("tamSecurityBulletinsBody").innerHTML = `<tr><td colspan="4" style="text-align: center; color: var(--text-muted);">No bulletins.</td></tr>`;
    document.getElementById("tamSwitchesTableBody").innerHTML = `<tr><td colspan="6" style="text-align: center; color: var(--text-muted);">No switch components monitored.</td></tr>`;
    document.getElementById("tamActiveSystem").innerHTML = `<strong>No Systems Selected</strong>`;
    return;
  }
  
  const selectedSystems = state.systems.filter(s => activeSerials.includes(s.serialNumber));
  
  // Render active systems list description and physical cabling node layout
  const visualCard = document.getElementById("tamNodeVisualCard");
  const eseriesCard = document.getElementById("tamEseriesVisualCard");
  const svmCard = document.getElementById("tamSvmCard");
  
  if (selectedSystems.length > 0) {
    if (visualCard) {
      visualCard.style.display = "block";
    }
    
    if (!state.activeVisualizerNodeSerial || !activeSerials.includes(state.activeVisualizerNodeSerial)) {
      state.activeVisualizerNodeSerial = selectedSystems[0].serialNumber;
    }
    
    const activeSys = selectedSystems.find(s => s.serialNumber === state.activeVisualizerNodeSerial) || selectedSystems[0];
    renderNodeVisualLayout(selectedSystems, activeSys);
    
    const isEseries = activeSys && (activeSys.santricityVersion !== undefined || activeSys.platform.includes("E-Series"));
    if (eseriesCard) {
      if (isEseries) {
        eseriesCard.style.display = "block";
        renderEseriesHardwareAudit(activeSys);
      } else {
        eseriesCard.style.display = "none";
      }
    }

    if (svmCard) {
      const svms = getSystemSvms(activeSys);
      if (svms && svms.length > 0) {
        svmCard.style.display = "block";
        renderSvmSecurityAudit(activeSys);
      } else {
        svmCard.style.display = "none";
      }
    }
  } else {
    if (visualCard) visualCard.style.display = "none";
    if (eseriesCard) eseriesCard.style.display = "none";
    if (svmCard) svmCard.style.display = "none";
  }

  // Update header text
  if (selectedSystems.length === 1) {
    const sys = selectedSystems[0];
    const osLabel = sys.santricityVersion ? "SANtricity OS" : "ONTAP";
    const osVer = sys.santricityVersion ? sys.santricityVersion : sys.ontapVersion;
    
    document.getElementById("tamActiveSystem").innerHTML = `
      <strong>System</strong>: ${sys.systemName} (S/N: <code class="copyable-code" onclick="copyToClipboard('${sys.serialNumber}', event)" title="Click to copy Serial Number">${sys.serialNumber} <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg></code>) | <strong>${osLabel}</strong>: ${osVer}
    `;
  } else if (selectedSystems.length > 1) {
    const names = selectedSystems.map(s => s.systemName).join(", ");
    document.getElementById("tamActiveSystem").innerHTML = `
      <strong>Selected Systems (${selectedSystems.length})</strong>: <span style="font-size: 0.8rem; color: var(--text-primary);">${names}</span>
    `;
  }

  // ── Autonomous version enrichment (lazy, non-blocking) ──────────────────────
  // For single-system view: fetch release notes and inject below version header
  if (selectedSystems.length === 1) {
    const sys = selectedSystems[0];
    const headerEl = document.getElementById('tamActiveSystem');
    if (headerEl) {
      enrichmentEngine.injectVersionEnrichment(sys, headerEl);
    }
  }

  // ── Skeleton loaders — show immediately while heavy sections are deferred ──
  // The risks, upgrades, switches, and bulletin tables are built inside a
  // requestAnimationFrame → setTimeout(0) block so the node-visual card, header,
  // SVM panel, and E-Series panel can paint FIRST. This eliminates the
  // "page freezes for 1-3 s on first TAM tab switch" hang with 20+ systems.
  const _tamSkRow = (cols, msg = 'Loading\u2026') =>
    `<tr><td colspan="${cols}" style="padding:20px;text-align:center;">`+
    `<span style="color:var(--text-muted);font-size:0.8rem;opacity:0.6;">${msg}</span>`+
    `</td></tr>`;
  document.getElementById('tamRisksTableBody').innerHTML        = _tamSkRow(4, 'Loading risks\u2026');
  document.getElementById('tamUpgradeContainer').innerHTML      =
    `<div style="padding:20px;text-align:center;color:var(--text-muted);font-size:0.8rem;opacity:0.6;">Loading upgrade roadmap\u2026</div>`;
  document.getElementById('tamSwitchesTableBody').innerHTML     = _tamSkRow(6, 'Loading switch data\u2026');
  document.getElementById('tamSecurityBulletinsBody').innerHTML = _tamSkRow(4, 'Loading advisories\u2026');

  // Capture local for closure (selectedSystems is in scope but explicit capture
  // makes the intent clear and prevents accidental re-binding issues).
  const _tamSelectedSystems = selectedSystems;

  // Defer the 4 heavy table sections. The outer requestAnimationFrame lets the
  // browser paint the visual layout card first; the inner setTimeout(0) then
  // yields to the event loop one more time before the innerHTML builds begin.
  requestAnimationFrame(() => setTimeout(() => { // ── BEGIN DEFERRED SECTIONS ──
  const selectedSystems = _tamSelectedSystems; // restore in deferred scope

  // ── Compile Combined Risks — grouped by system with collapsible drilldown ──
  // Groups risks per system to keep initial DOM at N rows (systems) not N×M (all risks).
  // Each system row shows severity pill counts; click expands per-risk detail rows.
  const risksBySystem = {};
  selectedSystems.forEach(sys => {
    const risks = sys.risks || [];
    if (risks.length > 0) {
      risksBySystem[sys.systemName] = {
        systemName: sys.systemName,
        platform:   sys.platform   || '',
        version:    sys.ontapVersion || sys.santricityVersion || '',
        risks: risks.map(r => ({ ...r, systemName: sys.systemName }))
      };
    }
  });

  const SEV_ORDER = { critical: 0, high: 1, medium: 2, low: 3, info: 4 };
  const worstSeverity = (risks) => {
    let w = 99;
    risks.forEach(r => { const s = SEV_ORDER[r.severity?.toLowerCase()] ?? 5; if (s < w) w = s; });
    return w;
  };

  // Sort system groups: worst severity first, then alphabetically
  const sortedSystemNames = Object.keys(risksBySystem).sort((a, b) => {
    const wa = worstSeverity(risksBySystem[a].risks);
    const wb = worstSeverity(risksBySystem[b].risks);
    return wa !== wb ? wa - wb : a.localeCompare(b);
  });

  const sevBadgeHtml = (sev) => {
    const s = (sev || '').toLowerCase();
    if (s === 'critical') return `<span class="badge critical">Critical</span>`;
    if (s === 'high')     return `<span class="badge critical">High</span>`;
    if (s === 'medium')   return `<span class="badge warning">Medium</span>`;
    if (s === 'low')      return `<span class="badge info">Low</span>`;
    return `<span class="badge info">${sev}</span>`;
  };

  const totalRisks = Object.values(risksBySystem).reduce((s, g) => s + g.risks.length, 0);

  // Inject hover CSS once (avoids inline onmouseover/onmouseout on every row)
  if (!document.getElementById('_tamRiskHoverStyle')) {
    const _s = document.createElement('style');
    _s.id = '_tamRiskHoverStyle';
    _s.textContent =
      '.tam-risk-sys-hdr:hover{background:rgba(255,255,255,0.03)!important}' +
      '.tam-risk-detail-row:hover td{background:rgba(255,255,255,0.02)!important}';
    document.head.appendChild(_s);
  }

  if (totalRisks === 0) {
    document.getElementById('tamRisksTableBody').innerHTML =
      `<tr><td colspan="4" style="text-align:center;color:var(--text-muted);padding:24px;">
        ✓ No active technical risks found. All selected systems are fully compliant.
       </td></tr>`;
  } else {
    // Build header controls row
    const controlsHtml = `
      <tr class="risk-controls-row">
        <td colspan="4" style="padding:8px 12px;background:rgba(255,255,255,0.015);border-bottom:1px solid var(--border-color);">
          <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;">
            <span style="font-size:0.78rem;color:var(--text-muted);">
              <strong style="color:var(--text-primary);">${sortedSystemNames.length}</strong> systems
              · <strong style="color:var(--text-primary);">${totalRisks}</strong> total risks
              · grouped by system — click a row to expand
            </span>
            <button onclick="toggleAllRiskGroups(this)"
              style="font-size:0.72rem;padding:3px 10px;border:1px solid var(--border-color);
                     background:rgba(255,255,255,0.04);color:var(--text-secondary);
                     border-radius:var(--radius-sm);cursor:pointer;"
              data-expanded="false">⊞ Expand All</button>
          </div>
        </td>
      </tr>`;

    let riskRows = controlsHtml;

    sortedSystemNames.forEach((sysName, sysIdx) => {
      const grp    = risksBySystem[sysName];
      const risks  = grp.risks;
      const counts = { critical: 0, high: 0, medium: 0, low: 0 };
      risks.forEach(r => {
        const s = (r.severity || '').toLowerCase();
        if (counts[s] !== undefined) counts[s]++;
      });
      const worst = worstSeverity(risks);
      const groupId = `risk-group-${sysIdx}`;

      // Severity pill mini-summary
      const pills = [];
      if (counts.critical) pills.push(`<span style="background:rgba(248,113,113,0.18);color:#f87171;border:1px solid rgba(248,113,113,0.35);border-radius:8px;padding:1px 7px;font-size:0.68rem;font-weight:700;">🔴 ${counts.critical} Crit</span>`);
      if (counts.high)     pills.push(`<span style="background:rgba(251,146,60,0.18);color:#fb923c;border:1px solid rgba(251,146,60,0.35);border-radius:8px;padding:1px 7px;font-size:0.68rem;font-weight:700;">🟠 ${counts.high} High</span>`);
      if (counts.medium)   pills.push(`<span style="background:rgba(251,191,36,0.15);color:#fbbf24;border:1px solid rgba(251,191,36,0.3);border-radius:8px;padding:1px 7px;font-size:0.68rem;font-weight:700;">🟡 ${counts.medium} Med</span>`);
      if (counts.low)      pills.push(`<span style="background:rgba(96,165,250,0.15);color:#60a5fa;border:1px solid rgba(96,165,250,0.3);border-radius:8px;padding:1px 7px;font-size:0.68rem;font-weight:700;">🔵 ${counts.low} Low</span>`);

      // Left accent colour by worst severity
      const accentColor = worst === 0 ? '#f87171' : worst === 1 ? '#fb923c' : worst === 2 ? '#fbbf24' : '#60a5fa';

      // System summary row (always visible)
      riskRows += `
        <tr class="risk-system-header" onclick="toggleRiskGroup('${groupId}', this)"
          style="cursor:pointer;border-left:3px solid ${accentColor};transition:background 0.2s;"
          onmouseover="this.style.background='rgba(255,255,255,0.03)'"
          onmouseout="this.style.background=''"
          data-group="${groupId}" data-expanded="false">
          <td colspan="3" style="padding:12px 14px;">
            <div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap;">
              <span style="font-weight:700;font-size:0.92rem;color:var(--text-primary);">${sysName}</span>
              ${grp.platform ? `<span style="font-size:0.72rem;color:var(--text-muted);font-family:monospace;">${grp.platform}</span>` : ''}
              ${grp.version  ? `<span style="font-size:0.72rem;color:var(--text-muted);">ONTAP ${grp.version}</span>` : ''}
              <div style="display:flex;gap:5px;flex-wrap:wrap;">${pills.join('')}</div>
            </div>
          </td>
          <td style="padding:12px 14px;text-align:right;white-space:nowrap;">
            <span style="font-size:0.75rem;color:var(--text-muted);">${risks.length} risk${risks.length !== 1 ? 's' : ''}</span>
            <span class="risk-chevron" style="margin-left:8px;font-size:0.85rem;color:var(--text-muted);transition:transform 0.2s;display:inline-block;">▶</span>
          </td>
        </tr>`;

      // Drilldown tbody (hidden by default)
      riskRows += `<tr id="${groupId}" style="display:none;">
        <td colspan="4" style="padding:0;">
          <table style="width:100%;border-collapse:collapse;background:rgba(0,0,0,0.15);">`;

      // Sort individual risks by severity, then description
      const sortedRisks = [...risks].sort((a, b) => {
        const sa = SEV_ORDER[(a.severity || '').toLowerCase()] ?? 5;
        const sb = SEV_ORDER[(b.severity || '').toLowerCase()] ?? 5;
        return sa !== sb ? sa - sb : (a.description || '').localeCompare(b.description || '');
      });

      sortedRisks.forEach(r => {
        riskRows += `
          <tr style="border-top:1px solid rgba(255,255,255,0.04);"
            onmouseover="this.style.background='rgba(255,255,255,0.02)'"
            onmouseout="this.style.background=''">
            <td style="padding:10px 14px 10px 24px;width:110px;vertical-align:top;">${sevBadgeHtml(r.severity)}</td>
            <td style="padding:10px 8px;width:160px;vertical-align:top;">
              <div style="font-weight:600;font-size:0.82rem;">${r.category}</div>
              ${r.subCategory ? `<div style="font-size:0.7rem;color:var(--text-muted);margin-top:2px;">${r.subCategory}</div>` : ''}
            </td>
            <td style="padding:10px 8px;vertical-align:top;">
              <div style="font-weight:500;margin-bottom:4px;font-size:0.85rem;">
                ${r.advisoryUrl
                  ? `<a href="${r.advisoryUrl}" target="_blank" onclick="window.open(this.href,'_blank');return false;">
                       ${r.description} <span style="font-size:0.65rem;color:var(--accent-cyan);vertical-align:middle;margin-left:3px;">↗</span>
                     </a>`
                  : (r.description || '')}
              </div>
              <div style="font-size:0.8rem;color:var(--text-secondary);line-height:1.45;">${r.recommendation || ''}</div>
            </td>
            <td style="padding:10px 14px;vertical-align:top;white-space:nowrap;">
              <div style="display:flex;flex-direction:column;gap:6px;">
                <button class="action-btn" style="font-size:0.72rem;padding:5px 10px;"
                  onclick="openRemediationModal(${r.id})"
                  data-tooltip="View detailed step-by-step remediation plan for this risk.">Plan</button>
                <a class="external-link" style="font-size:0.72rem;"
                  href="${buildKBSearchURL(r.description, r.category)}" target="_blank"
                  onclick="window.open(this.href,'_blank');return false;">KB Search</a>
              </div>
            </td>
          </tr>`;
      });

      riskRows += `</table></td></tr>`;
    });

    document.getElementById('tamRisksTableBody').innerHTML = riskRows;
  }
  
  // Compile Combined OS Upgrades
  const upgradeBox = document.getElementById("tamUpgradeContainer");
  upgradeBox.innerHTML = "";
  
  const upgradeItems = [];
  selectedSystems.forEach(sys => {
    if (sys.upgrades && sys.upgrades.targetVersion !== "Up to Date") {
      upgradeItems.push({
        systemName: sys.systemName,
        currentVersion: sys.santricityVersion ? sys.santricityVersion : sys.ontapVersion,
        targetVersion: sys.upgrades.targetVersion,
        urgency: sys.upgrades.urgency,
        benefits: sys.upgrades.benefits,
        platform: sys.platform
      });
    }
  });
  
  if (upgradeItems.length === 0) {
    upgradeBox.innerHTML = `
      <h3 style="color: var(--status-normal); margin-bottom: 12px;">✓ Systems Up to Date</h3>
      <p style="font-size: 0.9rem; color: var(--text-secondary);">All ${selectedSystems.length} selected systems are currently running fully supported, stable releases. No upgrades required.</p>
    `;
  } else {
    // ─── Collapsible system cards for Recommended OS Upgrades ─────────────────
    let upgradeHtml = '<div style="display:flex;justify-content:space-between;align-items:center;' +
      'margin-bottom:16px;border-bottom:1px solid var(--border-color);padding-bottom:10px;">' +
      '<h3 style="font-size:1.05rem;margin:0;">Recommended OS Upgrades</h3>' +
      '<button id="upgradeExpandToggle" data-state="closed"' +
      ' onclick="(function(){' +
        'var cards=document.querySelectorAll(\'.upgrade-detail-body\');' +
        'var chevrons=document.querySelectorAll(\'.upgrade-chevron\');' +
        'var btn=document.getElementById(\'upgradeExpandToggle\');' +
        'var expanding=btn.dataset.state!==\'open\';' +
        'cards.forEach(function(c){c.style.display=expanding?\'block\':\'none\';});' +
        'chevrons.forEach(function(ch){ch.style.transform=expanding?\'rotate(90deg)\':\'rotate(0deg)\';});' +
        'btn.dataset.state=expanding?\'open\':\'closed\';' +
        'btn.textContent=expanding?\'\u2296 Collapse All\':\'\u2295 Expand All\';' +
      '})()"' +
      ' style="font-size:0.75rem;padding:5px 12px;background:rgba(255,255,255,0.06);' +
        'border:1px solid rgba(255,255,255,0.12);border-radius:6px;' +
        'color:var(--text-secondary);cursor:pointer;transition:background 0.15s;">' +
      '\u2295 Expand All</button></div>';

    upgradeItems.forEach((item, itemIdx) => {
      const latestVer  = getLatestSupportedVersion(item.platform);
      const hops       = calculateUpgradePath(item.platform, item.currentVersion, item.targetVersion);
      const isMultiHop = hops.length > 1;
      const cardId     = 'upgradeCard_' + itemIdx;

      // ── Hop summary pills (shown in collapsed header) ─────────────────────
      let hopPillsHtml = '';
      if (hops.length > 0) {
        const arrow = '<span style="color:var(--text-muted);font-size:0.7rem;margin:0 2px;">&rarr;</span>';
        const vPills = hops.map((h, i) => {
          const isLast = (i === hops.length - 1);
          return '<span style="padding:1px 7px;border-radius:10px;font-size:0.7rem;font-weight:600;' +
                   'background:rgba(45,212,191,0.1);border:1px solid rgba(45,212,191,0.25);color:var(--accent-cyan);">' +
                   h.from + '</span>' + arrow +
                 (isLast
                   ? '<span style="padding:1px 7px;border-radius:10px;font-size:0.7rem;font-weight:600;' +
                       'background:rgba(45,212,191,0.18);border:1px solid rgba(45,212,191,0.4);color:var(--accent-cyan);">' +
                       h.to + '</span>'
                   : '');
        }).join(arrow);
        hopPillsHtml =
          '<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-top:5px;">' +
          (isMultiHop
            ? '<span style="display:inline-flex;align-items:center;gap:4px;padding:1px 8px;border-radius:10px;' +
                'font-size:0.68rem;font-weight:700;background:rgba(251,191,36,0.12);' +
                'border:1px solid rgba(251,191,36,0.3);color:var(--status-warning);">' +
                '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">' +
                '<path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path>' +
                '<line x1="12" y1="9" x2="12" y2="13"></line><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>' +
                hops.length + '-hop sequence</span>'
            : '') +
          '<span style="font-size:0.72rem;color:var(--text-muted);">' + vPills + '</span></div>';
      }

      // ── Full hop detail (hidden until expanded) ───────────────────────────
      let hopDetailHtml = '';
      if (isMultiHop) {
        hopDetailHtml +=
          '<div style="font-size:0.78rem;font-weight:600;color:var(--status-warning);' +
            'display:flex;align-items:center;gap:6px;margin-bottom:8px;">' +
          '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">' +
          '<path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path>' +
          '<line x1="12" y1="9" x2="12" y2="13"></line><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>' +
          'Multi-hop Upgrade Sequence Required:</div>';
      }

      hops.forEach((hop, idx) => {
        hopDetailHtml +=
          '<div style="margin-top:10px;padding:12px;background:rgba(255,255,255,0.015);' +
            'border-left:3px solid var(--accent-cyan);border-radius:var(--radius-sm);">' +
          '<div style="font-weight:700;font-size:0.8rem;color:var(--accent-cyan);margin-bottom:8px;' +
            'display:flex;align-items:center;gap:6px;">' +
          '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">' +
          '<polyline points="9 18 15 12 9 6"></polyline></svg>' +
          'Hop ' + (idx + 1) + ': ' + hop.from + ' &rarr; ' + hop.to + '</div>' +
          '<div style="font-size:0.74rem;color:var(--text-secondary);line-height:1.45;">' +
          '<div style="margin-bottom:4px;"><strong style="color:var(--text-primary);">Procedure:</strong></div>' +
          '<ul style="margin:0 0 8px 0;padding-left:16px;display:flex;flex-direction:column;gap:2px;">' +
            hop.steps.map(s => '<li>' + s + '</li>').join('') +
          '</ul>' +
          '<div style="margin-bottom:4px;"><strong style="color:var(--status-warning);">Pre-upgrade Recommendations:</strong></div>' +
          '<ul style="margin:0 0 8px 0;padding-left:16px;display:flex;flex-direction:column;gap:2px;">' +
            hop.recommendations.map(r => '<li>' + r + '</li>').join('') +
          '</ul>' +
          '<div style="margin-bottom:4px;"><strong style="color:var(--text-muted);">Important Considerations:</strong></div>' +
          '<ul style="margin:0 0 8px 0;padding-left:16px;display:flex;flex-direction:column;gap:2px;">' +
            hop.considerations.map(c => '<li>' + c + '</li>').join('') +
          '</ul>' +
          '<div style="margin-top:8px;">' +
          '<a href="' + hop.docLink + '" target="_blank"' +
            ' style="color:var(--accent-cyan);font-weight:600;text-decoration:none;display:inline-flex;align-items:center;gap:4px;">' +
            'View Upgrade Guide ' +
            '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">' +
            '<path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path>' +
            '<polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>' +
          '</a></div></div></div>';
      });

      // ── Assemble collapsible card ─────────────────────────────────────────
      upgradeHtml +=
        '<div id="' + cardId + '" style="margin-bottom:8px;border:1px solid rgba(255,255,255,0.07);border-radius:10px;overflow:hidden;">' +

        // Header / summary row
        '<div onclick="(function(){' +
            'var body=document.getElementById(\'' + cardId + '_body\');' +
            'var chevron=document.getElementById(\'' + cardId + '_chevron\');' +
            'var open=body.style.display!==\'none\';' +
            'body.style.display=open?\'none\':\'block\';' +
            'chevron.style.transform=open?\'rotate(0deg)\':\'rotate(90deg)\';' +
          '})()"' +
          ' style="display:flex;align-items:center;justify-content:space-between;padding:11px 14px;' +
            'cursor:pointer;background:rgba(255,255,255,0.03);transition:background 0.15s;user-select:none;"' +
          ' onmouseover="this.style.background=\'rgba(255,255,255,0.06)\'"' +
          ' onmouseout="this.style.background=\'rgba(255,255,255,0.03)\'">' +

          // Left side: chevron + name + version summary + hop pills
          '<div style="display:flex;align-items:center;gap:10px;min-width:0;flex:1;">' +
            '<svg id="' + cardId + '_chevron" class="upgrade-chevron"' +
              ' width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"' +
              ' style="flex-shrink:0;transition:transform 0.2s;color:var(--text-muted);">' +
              '<polyline points="9 18 15 12 9 6"></polyline></svg>' +
            '<div style="min-width:0;">' +
              '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">' +
                '<strong style="color:var(--text-primary);font-size:0.88rem;white-space:nowrap;">' + item.systemName + '</strong>' +
                '<span style="font-size:0.72rem;color:var(--text-muted);white-space:nowrap;">(' + item.platform + ')</span>' +
                '<span class="badge warning" style="font-size:0.65rem;padding:1px 7px;">' + item.urgency + '</span>' +
              '</div>' +
              '<div style="font-size:0.75rem;color:var(--text-secondary);margin-top:3px;">' +
                '<span style="color:var(--text-muted);">' + item.currentVersion + '</span>' +
                '<span style="color:var(--text-muted);margin:0 4px;">&rarr;</span>' +
                '<span style="color:var(--accent-cyan);font-weight:600;">' + item.targetVersion + '</span>' +
                '<span style="color:var(--text-muted);margin:0 5px;">|</span>' +
                '<span style="color:var(--text-muted);">Latest: </span>' +
                '<span style="color:var(--status-normal);font-weight:600;">' + latestVer + '</span>' +
              '</div>' +
              hopPillsHtml +
            '</div>' +
          '</div>' +

          // Right side: hop count
          '<div style="flex-shrink:0;margin-left:12px;font-size:0.7rem;color:var(--text-muted);">' +
            (hops.length > 0 ? hops.length + ' hop' + (hops.length > 1 ? 's' : '') : 'direct') +
          '</div>' +
        '</div>' +

        // Collapsible detail body
        '<div id="' + cardId + '_body" class="upgrade-detail-body" style="display:none;">' +
          '<div style="padding:14px 16px 16px;border-top:1px solid rgba(255,255,255,0.05);background:rgba(0,0,0,0.15);">' +
            '<p style="font-size:0.78rem;color:var(--text-secondary);margin:0 0 10px 0;line-height:1.4;">' + item.benefits + '</p>' +
            (hopDetailHtml || '<p style="font-size:0.78rem;color:var(--text-muted);">Direct upgrade \u2014 no intermediate hops required.</p>') +
          '</div>' +
        '</div>' +
      '</div>';
    });

    upgradeBox.innerHTML = upgradeHtml;
  }
  
  // Compile Combined Switch Validation
  let switchRows = "";
  const allSwitches = [];
  selectedSystems.forEach(sys => {
    const sws = getSystemSwitches(sys);
    sws.forEach(sw => {
      allSwitches.push({ ...sw, systemName: sys.systemName });
    });
  });

  sortDataList(allSwitches, state.tamSwitchesSortKey, state.tamSwitchesSortOrder);

  if (allSwitches.length === 0) {
    switchRows = `<tr><td colspan="6" style="text-align: center; color: var(--text-muted);">No switch components monitored for these platforms.</td></tr>`;
  } else {
    allSwitches.forEach(sw => {
      let statusBadge = `<span class="badge normal">Optimal</span>`;
      if (sw.status === "Critical") statusBadge = `<span class="badge critical">Critical</span>`;
      else if (sw.status === "Warning") statusBadge = `<span class="badge warning">Warning</span>`;

      // Firmware download link — vendor-specific
      const fwLink = getSwitchFirmwareLink(sw.model);
      // System context for IMT — try to pull from first selected system's ONTAP version
      const activeSysForIMT = (selectedSystems && selectedSystems[0]) ? (selectedSystems[0].ontapVersion || '9.16.1') : '9.16.1';
      const imtLink = getSwitchIMTLink(activeSysForIMT);

      let actionText = `Switch matches validated baseline. <a href="${imtLink}" target="_blank" style="color:var(--accent-cyan);text-decoration:underline;" onclick="window.open(this.href,'_blank');return false;">Verify in IMT ↗</a>`;
      if (sw.status === "Warning") {
        actionText = `Plan firmware update to target release: <strong style="color:var(--accent-cyan);">${sw.targetFirmware}</strong>. &nbsp;
          <a href="${fwLink.url}" target="_blank" style="color:var(--accent-cyan);text-decoration:underline;font-weight:600;" onclick="window.open(this.href,'_blank');return false;">⬇ ${fwLink.label} ↗</a> &nbsp;
          <a href="${imtLink}" target="_blank" style="color:var(--accent-cyan);text-decoration:underline;" onclick="window.open(this.href,'_blank');return false;">✅ IMT ↗</a>`;
      } else if (sw.status === "Critical") {
        actionText = `<strong style="color:var(--status-critical);">⚠ Immediate action:</strong> Install <strong>${sw.targetFirmware}</strong> to resolve bug or security vulnerability. &nbsp;
          <a href="${fwLink.url}" target="_blank" style="color:var(--status-critical);text-decoration:underline;font-weight:600;" onclick="window.open(this.href,'_blank');return false;">⬇ ${fwLink.label} ↗</a> &nbsp;
          <a href="${imtLink}" target="_blank" style="color:var(--accent-cyan);text-decoration:underline;" onclick="window.open(this.href,'_blank');return false;">✅ IMT ↗</a>`;
      }

      switchRows += `
        <tr>
          <td><strong style="color: var(--text-primary); font-size: 0.85rem;">${sw.systemName}</strong></td>
          <td>
            <div style="font-weight: 600; font-size: 0.85rem; color: var(--text-primary);">${sw.model}</div>
            <div style="font-size: 0.72rem; color: var(--text-muted); font-family: monospace;">S/N: ${sw.serialNumber}</div>
          </td>
          <td><span style="font-size: 0.8rem; font-weight: 500;">${sw.type}</span></td>
          <td>
            <div style="font-size: 0.8rem; color: var(--text-secondary);">Current: <code style="color: var(--text-muted);">${sw.firmware}</code></div>
            <div style="font-size: 0.8rem; color: var(--accent-cyan);">Target: <code style="color: var(--accent-cyan); font-weight: 600;">${sw.targetFirmware}</code></div>
            <div style="margin-top:4px;">
              <a href="${fwLink.url}" target="_blank"
                 style="font-size:0.68rem;color:var(--accent-cyan);text-decoration:underline;"
                 onclick="window.open(this.href,'_blank');return false;">⬇ ${fwLink.label}</a>
            </div>
          </td>
          <td>${statusBadge}</td>
          <td>
            <div style="font-size: 0.8rem; color: var(--text-primary); margin-bottom: 4px;">${linkify(sw.validationDetails)}</div>
            <div style="font-size: 0.78rem; color: var(--text-secondary);">${actionText}</div>
          </td>
        </tr>
      `;
    });
  }
  document.getElementById("tamSwitchesTableBody").innerHTML = switchRows;
  
  // ── Compile Combined Security & Technical Bulletins — severity-tiered display ──
  // Critical + High: always rendered as full rows (high-priority, always visible).
  // Medium / Low / Info: collapsed into a single summary row to reduce initial DOM.
  // CVE enrichment is batched (5 per 100ms) to avoid a burst of simultaneous fetches.
  const allBulletins = [];
  selectedSystems.forEach(sys => {
    if (sys.securityBulletins) {
      sys.securityBulletins.forEach(b => {
        allBulletins.push({ ...b, systemName: sys.systemName });
      });
    }
  });

  sortDataList(allBulletins, state.tamSecuritySortKey, state.tamSecuritySortOrder);

  const BUL_SEV_TIER = (sev) => {
    const s = (sev || '').toLowerCase();
    return (s === 'critical' || s === 'high') ? 'primary' : 'secondary';
  };

  const buildBulletinRow = (b, bIdx) => {
    let bBadge = `<span class="badge warning">${b.severity}</span>`;
    if (b.severity === 'critical') bBadge = `<span class="badge critical">Critical</span>`;
    else if (b.severity === 'high') bBadge = `<span class="badge critical">High</span>`;

    const psirtUrl = (b.id && /^NTAP-/i.test(b.id))
      ? `https://security.netapp.com/advisory/${b.id.toLowerCase()}/`
      : (b.link || 'https://security.netapp.com/advisory/');
    const cveId  = b.cve || (b.id && /^CVE-/i.test(b.id) ? b.id : null);
    const nvdUrl = cveId ? `https://nvd.nist.gov/vuln/detail/${cveId}` : null;

    const advisoryIdCell = `
      <a href="${psirtUrl}" target="_blank"
         style="color:var(--accent-cyan);font-family:monospace;font-weight:700;text-decoration:underline;"
         onclick="window.open(this.href,'_blank');return false;">${b.id} ↗</a>`;

    const cveDisplay = cveId
      ? `<div style="font-size:0.68rem;margin-top:2px;">
           <a href="${nvdUrl}" target="_blank"
              style="color:var(--status-warning);text-decoration:underline;"
              onclick="window.open(this.href,'_blank');return false;">${cveId} (NVD ↗)</a>
         </div>`
      : '';

    const fixedLink = b.fixedIn
      ? `<div style="font-size:0.7rem;color:var(--status-normal);margin-top:4px;">Fixed in: <strong>${b.fixedIn}</strong> &nbsp;
           <a href="https://mysupport.netapp.com/site/downloads" target="_blank"
              style="color:var(--status-normal);text-decoration:underline;font-size:0.65rem;"
              onclick="window.open(this.href,'_blank');return false;">⬇ Download</a>
         </div>`
      : '';

    const rowId = `bulletin-row-${bIdx}-${(b.id || '').replace(/[^a-z0-9]/gi, '-')}`;
    return { rowId, cveId, html: `
      <tr id="${rowId}">
        <td>
          ${advisoryIdCell}
          <div style="font-size:0.7rem;color:var(--text-muted);margin-top:2px;">${b.systemName}</div>
          ${b.cvss == null && cveId
            ? `<div style="font-size:0.68rem;color:var(--text-muted);margin-top:2px;">CVSS: <span data-enrich-cvss style="color:var(--text-muted)">fetching…</span></div>`
            : `<div style="font-size:0.68rem;color:var(--text-muted);margin-top:2px;">CVSS: ${b.cvss != null ? b.cvss : 'N/A'}</div>`}
          ${b.publishedDate || b.published
            ? `<div style="font-size:0.68rem;color:var(--text-muted);" data-enrich-date>${b.publishedDate || b.published}</div>`
            : `<div style="font-size:0.68rem;color:var(--text-muted);" data-enrich-date></div>`}
          ${cveDisplay}
        </td>
        <td>
          <div style="font-weight:600;font-size:0.85rem;margin-bottom:4px;color:var(--text-primary);">${b.title}</div>
          <div style="font-size:0.8rem;color:var(--text-secondary);line-height:1.3;" data-enrich-desc>${linkify(b.mitigation || '')}</div>
          ${fixedLink}
          ${cveId ? `<div style="font-size:0.68rem;color:var(--text-muted);margin-top:2px;">Affected: <span data-enrich-affected>${b.fixedIn ? 'See advisory' : 'Fetching…'}</span></div>` : ''}
        </td>
        <td>${bBadge}</td>
        <td><code style="color:var(--status-warning);font-size:0.78rem;">${b.status}</code></td>
      </tr>`
    };
  };

  let bulletinRows = '';
  const enrichQueue = []; // {rowId, cveId} — processed in batches after paint

  if (allBulletins.length === 0) {
    bulletinRows = `<tr><td colspan="4" style="text-align:center;color:var(--text-muted);padding:24px;">No active security advisories mapped.</td></tr>`;
  } else {
    const primaryBulletins   = allBulletins.filter(b => BUL_SEV_TIER(b.severity) === 'primary');
    const secondaryBulletins = allBulletins.filter(b => BUL_SEV_TIER(b.severity) === 'secondary');

    // Controls bar
    bulletinRows += `
      <tr>
        <td colspan="4" style="padding:8px 12px;background:rgba(255,255,255,0.015);border-bottom:1px solid var(--border-color);">
          <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;">
            <span style="font-size:0.78rem;color:var(--text-muted);">
              <strong style="color:#f87171;">${primaryBulletins.length}</strong> Critical/High
              ${secondaryBulletins.length ? `· <strong style="color:var(--text-secondary);">${secondaryBulletins.length}</strong> Medium/Low/Info` : ''}
              · <strong style="color:var(--text-primary);">${allBulletins.length}</strong> total
            </span>
            ${secondaryBulletins.length ? `
              <button onclick="toggleBulletinSecondary(this)"
                style="font-size:0.72rem;padding:3px 10px;border:1px solid var(--border-color);
                       background:rgba(255,255,255,0.04);color:var(--text-secondary);
                       border-radius:var(--radius-sm);cursor:pointer;" data-expanded="false">
                Show ${secondaryBulletins.length} lower-severity advisories ▼
              </button>` : ''}
          </div>
        </td>
      </tr>`;

    // ── TIER 1: Critical + High — always visible ──
    if (primaryBulletins.length === 0) {
      bulletinRows += `<tr><td colspan="4" style="text-align:center;color:var(--status-normal);padding:16px;font-size:0.85rem;">
        ✓ No Critical or High severity advisories for selected systems.</td></tr>`;
    } else {
      primaryBulletins.forEach((b, i) => {
        const globalIdx = allBulletins.indexOf(b);
        const { rowId, cveId, html } = buildBulletinRow(b, globalIdx);
        bulletinRows += html;
        if (cveId) enrichQueue.push({ rowId, cveId });
      });
    }

    // ── TIER 2: Medium / Low / Info — collapsed behind a toggle row ──
    if (secondaryBulletins.length > 0) {
      // Separator toggle row
      bulletinRows += `
        <tr id="bulletin-secondary-toggle" onclick="toggleBulletinSecondary(this.querySelector('button'))"
          style="cursor:pointer;background:rgba(255,255,255,0.015);"
          onmouseover="this.style.background='rgba(255,255,255,0.03)'"
          onmouseout="this.style.background='rgba(255,255,255,0.015)'">
          <td colspan="4" style="padding:10px 14px;text-align:center;">
            <button style="background:none;border:none;color:var(--text-secondary);font-size:0.8rem;cursor:pointer;display:flex;align-items:center;gap:8px;margin:0 auto;">
              <span id="bulletin-secondary-chevron">▶</span>
              <span id="bulletin-secondary-label">${secondaryBulletins.length} Medium / Low / Informational advisories — click to expand</span>
            </button>
          </td>
        </tr>`;

      // Hidden secondary rows container
      bulletinRows += `<tr id="bulletin-secondary-group" style="display:none;">
        <td colspan="4" style="padding:0;">
          <table style="width:100%;border-collapse:collapse;background:rgba(0,0,0,0.1);">`;

      secondaryBulletins.forEach((b, i) => {
        const globalIdx = allBulletins.indexOf(b);
        const { rowId, cveId, html } = buildBulletinRow(b, globalIdx);
        bulletinRows += html;
        if (cveId) enrichQueue.push({ rowId, cveId, deferred: true });
      });

      bulletinRows += `</table></td></tr>`;
    }
  }

  document.getElementById('tamSecurityBulletinsBody').innerHTML = bulletinRows;

  // ── CVE enrichment: batched queue — 5 per 100ms to avoid fetch burst ─────
  // Only enrich primary (visible) rows immediately; deferred rows enriched on expand.
  const primaryEnrich   = enrichQueue.filter(e => !e.deferred);
  const deferredEnrich  = enrichQueue.filter(e =>  e.deferred);

  const runEnrichBatch = (items, batchSize = 5, delayMs = 100) => {
    for (let i = 0; i < items.length; i += batchSize) {
      const chunk = items.slice(i, i + batchSize);
      setTimeout(() => {
        chunk.forEach(({ rowId, cveId }) => {
          const rowEl = document.getElementById(rowId);
          if (rowEl) enrichmentEngine.injectCVEEnrichment(cveId, rowEl);
        });
      }, Math.floor(i / batchSize) * delayMs);
    }
  };

  // Primary rows: enrich after first paint (slight delay to unblock render)
  setTimeout(() => runEnrichBatch(primaryEnrich), 80);

  // Secondary rows: enrich lazily on first expansion via stored queue
  window._deferredBulletinEnrich = deferredEnrich;

  updateSortIndicators();
  }, 0)); // ── END DEFERRED SECTIONS (requestAnimationFrame → setTimeout) ──
}

function getSystemSwitches(sys) {
  if (sys.switches && sys.switches.length > 0) return sys.switches;
  
  const seed = parseInt(sys.serialNumber) || 0;
  const switches = [];
  
  if (sys.platform.includes("MetroCluster")) {
    switches.push({
      type: "MetroCluster Back-end",
      model: sys.platform.includes("IP") ? "Cisco Nexus 9336C-FX2" : "Brocade G620 FC",
      serialNumber: `SW-MC-${sys.serialNumber.substring(6)}A`,
      firmware: seed % 3 === 0 ? "9.3(8)" : "9.3(12)",
      targetFirmware: "9.3(12)",
      status: seed % 3 === 0 ? "Warning" : "Optimal",
      ipAddress: `192.168.50.100`,
      validationDetails: seed % 3 === 0 ? "Firmware drift: NX-OS 9.3(8) is below the minimum Interoperability Matrix Tool (IMT) validated version." : "Optimal connection."
    });
    switches.push({
      type: "Cluster Interconnect",
      model: "Cisco Nexus 3132Q-V",
      serialNumber: `SW-CI-${sys.serialNumber.substring(6)}B`,
      firmware: "9.3(12)",
      targetFirmware: "9.3(12)",
      status: "Optimal",
      ipAddress: `192.168.50.120`,
      validationDetails: "Optimal connection."
    });
    switches.push({
      type: "Front-end Storage",
      model: "Cisco MDS 9148T",
      serialNumber: `SW-FE-${sys.serialNumber.substring(6)}C`,
      firmware: seed % 4 === 0 ? "8.4(2)" : "9.2(2)",
      targetFirmware: "9.2(2)",
      status: seed % 4 === 0 ? "Warning" : "Optimal",
      ipAddress: `10.10.20.150`,
      validationDetails: seed % 4 === 0 ? "Firmware warning: MDS-OS v8.4(2) contains security vulnerability CVE-2023-20092. Upgrade advised." : "Optimal connection."
    });
  } else if (sys.platform.includes("On-Prem") || sys.platform.includes("FAS") || sys.platform.includes("AFF")) {
    switches.push({
      type: "Cluster Interconnect",
      model: seed % 5 === 0 ? "Broadcom BES-53248" : "Cisco Nexus 3132Q-V",
      serialNumber: `SW-CI-${sys.serialNumber.substring(6)}A`,
      firmware: seed % 5 === 0 ? "EFOS 3.4.4.6" : "NX-OS 9.3(10)",
      targetFirmware: seed % 5 === 0 ? "EFOS 3.8.0.2" : "NX-OS 9.3(12)",
      status: seed % 5 === 0 ? "Warning" : (seed % 7 === 0 ? "Critical" : "Optimal"),
      ipAddress: `192.168.60.100`,
      validationDetails: seed % 5 === 0 
        ? "Firmware drift detected: EFOS 3.4 is out of sync." 
        : (seed % 7 === 0 ? "Critical Bug Alert: NX-OS 9.3(10) has a memory leak in ports telemetry. Urgent upgrade required." : "Optimal connection.")
    });
    switches.push({
      type: "Front-end Data",
      model: "Cisco Nexus 93180YC-FX",
      serialNumber: `SW-FE-${sys.serialNumber.substring(6)}B`,
      firmware: "9.3(12)",
      targetFirmware: "9.3(12)",
      status: "Optimal",
      ipAddress: `10.10.10.100`,
      validationDetails: "Optimal connection."
    });
  } else if (sys.platform.includes("StorageGRID")) {
    switches.push({
      type: "Grid Network",
      model: "Cisco Nexus 93180YC-FX",
      serialNumber: `SW-GRID-${sys.serialNumber.substring(6)}A`,
      firmware: seed % 6 === 0 ? "9.3(8)" : "9.3(12)",
      targetFirmware: "9.3(12)",
      status: seed % 6 === 0 ? "Warning" : "Optimal",
      ipAddress: `10.50.10.100`,
      validationDetails: seed % 6 === 0 ? "Firmware warning: upgrade NX-OS to address grid MTU packet loss bugs." : "Optimal connection."
    });
  }
  
  return switches;
}

function getSystemIntegrations(sys) {
  if (sys.integrations) return sys.integrations;
  
  const seed = parseInt(sys.serialNumber) || 0;
  
  let virtualization = { type: "None", version: "", status: "Not Configured", plugin: "None", multipathing: "None" };
  let database = { type: "None", version: "", status: "Not Configured", details: "None" };
  let backup = { type: "None", version: "", status: "Not Configured", details: "None" };
  
  const modVal = seed % 5;
  
  if (sys.platform.includes("StorageGRID")) {
    virtualization = {
      type: "OpenStack Swift Object",
      version: "Bobcat (v28.0)",
      status: "Optimal",
      plugin: "StorageGRID Keystone integration",
      multipathing: "N/A (HTTPS Object)"
    };
    database = {
      type: "Apache Spark / Hadoop S3A",
      version: "v3.5.0",
      status: "Configured",
      details: "S3A connector configured for high-concurrency object access"
    };
    backup = {
      type: "Commvault Metallic SaaS",
      version: "SaaS Enterprise",
      status: "Optimal",
      details: "S3 Object lock enabled for WORM compliance storage tier"
    };
  } else if (modVal === 0) {
    virtualization = {
      type: "VMware vSphere",
      version: "8.0 Update 2",
      status: "Optimal",
      plugin: "ONTAP Tools for VMware (VASA v10.1)",
      multipathing: "VMW_PSP_RR (Round Robin)"
    };
    database = {
      type: "Oracle Database (RAC)",
      version: "19c (19.21)",
      status: "Configured (dNFS)",
      details: "Direct NFS client active on 25GbE network channels"
    };
    backup = {
      type: "Commvault IntelliSnap",
      version: "v11.32 SP3",
      status: "Optimal",
      details: "IntelliSnap NetApp engine configured with hardware snapshots"
    };
  } else if (modVal === 1) {
    virtualization = {
      type: "Microsoft Hyper-V",
      version: "Windows Server 2022",
      status: "Optimal",
      plugin: "ONTAP VSS Provider for Hyper-V",
      multipathing: "Microsoft MPIO (Round Robin)"
    };
    database = {
      type: "MS SQL Server",
      version: "2022 Enterprise",
      status: "Optimal",
      details: "SnapCenter MSSQL Plug-in v5.0 active with dynamic restores"
    };
    backup = {
      type: "Veritas NetBackup",
      version: "v10.3",
      status: "Configured",
      details: "NetBackup snapshot manager agent deployed on array"
    };
  } else if (modVal === 2) {
    virtualization = {
      type: "Kubernetes (EKS / OpenShift)",
      version: "v1.29",
      status: "Optimal",
      plugin: "NetApp Astra Trident CSI v24.02",
      multipathing: "N/A (CSI Managed)"
    };
    database = {
      type: "SAP HANA",
      version: "2.0 SPS07",
      status: "Configured",
      details: "NFSv4.1 partitions configured with HANA System Replication (HSR)"
    };
    backup = {
      type: "Veeam Backup & Replication",
      version: "v12.1",
      status: "Configured",
      details: "ONTAP hardware snapshot and SnapMirror replication orchestration"
    };
  } else if (modVal === 3) {
    virtualization = {
      type: "OpenStack Cinder",
      version: "Antelope (v2023.2)",
      status: "Optimal",
      plugin: "ONTAP Cinder Unified Driver",
      multipathing: "Multipathd (iSCSI ALUA)"
    };
    database = {
      type: "Apache Spark / PostgreSQL",
      version: "v15.4",
      status: "Configured",
      details: "Spark streaming analytics using ONTAP S3 object storage buckets"
    };
    backup = {
      type: "NetApp SnapCenter",
      version: "v5.0",
      status: "Optimal",
      details: "Native application-consistent snapshot & clone orchestrator"
    };
  } else {
    virtualization = {
      type: "NVIDIA AI BasePOD",
      version: "Kubeflow / Slurm v23.02",
      status: "Optimal",
      plugin: "Astra Trident CSI + GPUDirect Storage (GDS)",
      multipathing: "NFS over RDMA (RoCEv2)"
    };
    database = {
      type: "AI/ML Training Pipeline",
      version: "PyTorch / TensorFlow",
      status: "Configured",
      details: "Massive scale parallel read dataset streaming on local NFS mount points"
    };
    backup = {
      type: "Commvault Metallic SaaS",
      version: "SaaS Enterprise",
      status: "Optimal",
      details: "Active backup targeting ONTAP S3 compliance bucket"
    };
  }
  
  return { virtualization, database, backup };
}

function getSystemWorkloadRecommendations(sys) {
  const ints = getSystemIntegrations(sys);
  const recs = [];
  
  if (sys.platform.includes("MetroCluster")) {
    recs.push(`<strong>[MetroCluster]</strong> Active-Active stretch cluster detected. Best Practice: Configure VMware vSphere HA Admission Control with 50% CPU and memory reservations to ensure failover capacity.`);
    recs.push(`<strong>[MetroCluster]</strong> Best Practice: Verify that automatic unplanned switchover (AUSO) is enabled via ONTAP command: <code>metrocluster operation show</code> to protect against sudden power loss.`);
  }

  // Virtualization Recommendations
  if (ints.virtualization.type.includes("VMware vSphere")) {
    recs.push(`<strong>[VMware]</strong> ONTAP Tools VASA Provider is active. Best Practice: Ensure VAAI (vStorage APIs for Array Integration) is enabled on ESXi hosts to offload copy operations.`);
    recs.push(`<strong>[VMware]</strong> Multipathing is set to Round Robin (VMW_PSP_RR). Best Practice: Modify default path switching from 1000 IOPS to 1 IOPS for optimal performance on SAN LUNs.`);
  } else if (ints.virtualization.type.includes("Microsoft Hyper-V")) {
    recs.push(`<strong>[Hyper-V]</strong> Windows Server MPIO with NetApp DSM/MPIO driver detected. Best Practice: Configure Path Verification Period to 30 seconds to prevent premature path failovers.`);
    recs.push(`<strong>[Hyper-V]</strong> Best Practice: Store virtual machines on SMB3 Continuous Availability (CA) shares with <code>OdxEnabled</code> set to true to offload VM cloning operations.`);
  } else if (ints.virtualization.type.includes("Kubernetes")) {
    recs.push(`<strong>[Kubernetes]</strong> Astra Trident CSI driver is active. Best Practice: Configure storage classes with <code>spaceReserve: none</code> (Thin Provisioning) to utilize ONTAP storage savings.`);
    recs.push(`<strong>[Kubernetes]</strong> Pods mount PVs via NFS. Best Practice: Increase Trident's mount options to use <code>nfsvers=4.1</code> for better locking performance.`);
  } else if (ints.virtualization.type.includes("OpenStack")) {
    recs.push(`<strong>[OpenStack]</strong> ONTAP Cinder driver is configured. Best Practice: Enable Cinder volume multi-attach only for clustered filesystems to prevent partition corruption.`);
    recs.push(`<strong>[OpenStack]</strong> StorageGRID Swift API identity integration. Best Practice: Enable SSL/TLS encryption for all Keystone endpoints to prevent session token sniffing.`);
  } else if (ints.virtualization.type.includes("NVIDIA AI")) {
    recs.push(`<strong>[NVIDIA AI]</strong> GPUDirect Storage (GDS) with NFS over RDMA enabled. Best Practice: Set <code>mount -o rdma,port=20049</code> and ensure RoCEv2 flow control (PFC/ECN) is configured on network switches.`);
    recs.push(`<strong>[NVIDIA AI]</strong> Large scale datasets. Best Practice: Enable ONTAP FlexGroup volumes to distribute unstructured training data across all controller nodes in the cluster.`);
  }
  
  // Database Recommendations
  if (ints.database.type.includes("Oracle Database")) {
    recs.push(`<strong>[Oracle]</strong> Direct NFS (dNFS) is enabled. Best Practice: Configure <code>filesystemio_options=SETALL</code> in init.ora parameter file to enable asynchronous I/O.`);
    recs.push(`<strong>[Oracle]</strong> Best Practice: Distribute data files and redo log files across separate ONTAP aggregates to prevent disk contention.`);
  } else if (ints.database.type.includes("MS SQL Server")) {
    recs.push(`<strong>[MS SQL]</strong> SnapCenter MSSQL plugin is active. Best Practice: Configure SnapCenter policies to perform transaction log backups every 15 minutes, with storage-level verification.`);
    recs.push(`<strong>[MS SQL]</strong> Best Practice: Format SAN LUNs hosting database files with a 64KB NTFS allocation unit size to align with SQL Server's extent architecture.`);
  } else if (ints.database.type.includes("SAP HANA")) {
    recs.push(`<strong>[SAP HANA]</strong> NFSv4 mount detected. Best Practice: Tune mount options to <code>rw,bg,hard,timeo=600,rsize=262144,wsize=262144</code> for optimal latency performance.`);
  } else if (ints.database.type.includes("Spark") || ints.database.type.includes("Hadoop")) {
    recs.push(`<strong>[Hadoop/Spark]</strong> S3A connector detected. Best Practice: Configure the S3A client to use <code>fs.s3a.fast.upload=true</code> to leverage StorageGRID's high-speed uploads.`);
  } else if (ints.database.type.includes("AI/ML Training")) {
    recs.push(`<strong>[AI Workloads]</strong> PyTorch/TensorFlow dataset loading. Best Practice: Configure local read cache on GPU nodes using NFS CacheFilesd (FS-Cache) to reduce redundant network transfers.`);
  }
  
  // Backup Recommendations
  if (ints.backup.type.includes("Veeam")) {
    recs.push(`<strong>[Veeam]</strong> ONTAP Hardware Snapshot Integration is active. Best Practice: Limit the number of concurrent storage snapshots to 5 per volume to prevent ONTAP metadata lock contention.`);
  } else if (ints.backup.type.includes("Commvault IntelliSnap")) {
    recs.push(`<strong>[Commvault]</strong> IntelliSnap NetApp engine is active. Best Practice: Ensure NetApp OCUM/AIQUM portal credentials are up-to-date in Commvault's Array Management.`);
  } else if (ints.backup.type.includes("Veritas")) {
    recs.push(`<strong>[Veritas]</strong> NetBackup Snapshot Manager is active. Best Practice: Create snapshot policies that clean up deleted or orphaned snapshots older than 7 days using the NetApp REST API.`);
  } else if (ints.backup.type.includes("SnapCenter")) {
    recs.push(`<strong>[SnapCenter]</strong> Native application-consistent backups. Best Practice: Schedule backup jobs outside of ONTAP system background processes (such as deduplication or scrub schedules).`);
  } else if (ints.backup.type.includes("Commvault Metallic")) {
    recs.push(`<strong>[Metallic SaaS]</strong> SaaS backup to cloud storage. Best Practice: Enable ONTAP S3 Object Lock (WORM) on bucket destination to protect against ransomware injection.`);
  }
  
  return recs;
}

function renderSAMTab() {
  populateSystemSelectors();
  
  const currentFiltered = getFilteredSystems();
  const targetSAMSystems = [];
  if (state.selectedSAMSystemSerial === "ALL") {
    targetSAMSystems.push(...currentFiltered);
  } else if (state.selectedSAMSystemSerial.startsWith("CLUSTER:")) {
    const cluster = state.selectedSAMSystemSerial.substring(8);
    targetSAMSystems.push(...currentFiltered.filter(s => s.clusterName === cluster));
  } else {
    const serial = state.selectedSAMSystemSerial.startsWith("NODE:") ? state.selectedSAMSystemSerial.substring(5) : state.selectedSAMSystemSerial;
    const found = currentFiltered.find(s => s.serialNumber === serial);
    if (found) targetSAMSystems.push(found);
  }
  
  if (targetSAMSystems.length === 0) {
    document.getElementById("samContractCard").innerHTML = "";
    document.getElementById("samLifecycleCard").innerHTML = "";
    document.getElementById("samHypervisorCard").innerHTML = "";
    document.getElementById("samLogisticsCard").innerHTML = "";
    document.getElementById("samSalesHealthCard").innerHTML = "";
    if (document.getElementById("samWorkloadVirtualization")) document.getElementById("samWorkloadVirtualization").innerHTML = "";
    if (document.getElementById("samWorkloadDatabase")) document.getElementById("samWorkloadDatabase").innerHTML = "";
    if (document.getElementById("samWorkloadBackup")) document.getElementById("samWorkloadBackup").innerHTML = "";
    if (document.getElementById("samWorkloadRecommendations")) document.getElementById("samWorkloadRecommendations").innerHTML = "";
    document.getElementById("samFieldActionsBody").innerHTML = `<tr><td colspan="2" style="text-align: center; color: var(--text-muted);">No systems available in current scope.</td></tr>`;
    document.getElementById("samSupportCasesBody").innerHTML = `<tr><td colspan="5" style="text-align: center; color: var(--text-muted);">No systems available.</td></tr>`;
    return;
  }

  const isMulti = targetSAMSystems.length > 1;

  if (isMulti) {
    document.getElementById("samActiveSystem").innerHTML = `
      <strong>Selected Systems (${targetSAMSystems.length})</strong>: <span style="font-size: 0.8rem; color: var(--text-primary);">${targetSAMSystems.map(s => s.systemName).join(", ")}</span>
    `;

    // 1. Contract aggregate
    let activeCount = 0, warningCount = 0, criticalCount = 0;
    targetSAMSystems.forEach(s => {
      if (s.contracts.status === "critical") criticalCount++;
      else if (s.contracts.status === "warning") warningCount++;
      else activeCount++;
    });
    let cBadge = `<span class="badge normal">Active</span>`;
    let cColor = "var(--text-primary)";
    if (criticalCount > 0) {
      cBadge = `<span class="badge critical">${criticalCount} Expired</span>`;
      cColor = "var(--status-critical)";
    } else if (warningCount > 0) {
      cBadge = `<span class="badge warning">${warningCount} Expiring</span>`;
      cColor = "var(--status-warning)";
    }
    document.getElementById("samContractCard").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">Contracts Summary</h4>
        ${cBadge}
      </div>
      <div style="font-size: 1.3rem; font-weight: 700; margin-bottom: 6px; color: ${cColor};">
        ${targetSAMSystems.length} Monitored Contracts
      </div>
      <div style="font-size: 0.8rem; color: var(--text-muted); display: flex; gap: 8px;">
        <span style="color: var(--status-normal);">Active: ${activeCount}</span> | 
        <span style="color: var(--status-warning);">Expiring: ${warningCount}</span> | 
        <span style="color: var(--status-critical);">Expired: ${criticalCount}</span>
      </div>
    `;

    // 2. Lifecycle aggregate
    let nearEosCount = 0;
    targetSAMSystems.forEach(s => {
      if (s.lifecycle && s.lifecycle.isNearEos) nearEosCount++;
    });
    let lBadge = `<span class="badge normal">Active</span>`;
    if (nearEosCount > 0) lBadge = `<span class="badge critical">${nearEosCount} Near EOS</span>`;
    document.getElementById("samLifecycleCard").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">Lifecycle Summary</h4>
        ${lBadge}
      </div>
      <div style="font-size: 1.25rem; font-weight: 700; margin-bottom: 6px;">
        ${targetSAMSystems.length} Hardware Assets
      </div>
      <div style="font-size: 0.8rem; color: var(--text-muted);">
        Near End-of-Support: <strong style="color: ${nearEosCount > 0 ? "var(--status-critical)" : "var(--status-normal)"};">${nearEosCount} nodes</strong>
      </div>
    `;

    // 3. Hypervisors / Integrations Summary
    const virtTypes = {};
    targetSAMSystems.forEach(s => {
      const ints = getSystemIntegrations(s);
      const vt = ints.virtualization.type.split(" (")[0]; // Clean version suffix
      virtTypes[vt] = (virtTypes[vt] || 0) + 1;
    });
    
    let virtHtml = "";
    Object.entries(virtTypes).forEach(([type, count]) => {
      virtHtml += `<div>• ${type}: <strong>${count}</strong> system${count > 1 ? 's' : ''}</div>`;
    });
    
    document.getElementById("samHypervisorCard").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">Integrations Overview</h4>
      </div>
      <div style="font-size: 1.15rem; font-weight: 700; margin-bottom: 8px;">Workload Types</div>
      <div style="font-size: 0.8rem; color: var(--text-secondary); line-height: 1.45;">
        ${virtHtml || "<div>No workloads active.</div>"}
      </div>
    `;

    // 3.5 AutoSupport aggregate
    let asupHealthy = 0, asupFailed = 0, asupDisabled = 0;
    targetSAMSystems.forEach(s => {
      const asup = s.autosupport || { enabled: true, status: "healthy", lastReceivedDays: 1 };
      if (!asup.enabled) asupDisabled++;
      else if (asup.status === "failed" || asup.lastReceivedDays > 7) asupFailed++;
      else asupHealthy++;
    });
    let asupBadge = `<span class="badge normal">Healthy</span>`;
    if (asupFailed > 0) asupBadge = `<span class="badge critical">${asupFailed} Failed</span>`;
    else if (asupDisabled > 0) asupBadge = `<span class="badge warning">${asupDisabled} Disabled</span>`;
    
    document.getElementById("samAutoSupportCard").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">AutoSupport Status</h4>
        ${asupBadge}
      </div>
      <div style="font-size: 1.25rem; font-weight: 700; margin-bottom: 6px;">
        Telemetry Health
      </div>
      <div style="font-size: 0.8rem; color: var(--text-muted); display: flex; flex-direction: column; gap: 2px;">
        <span style="color: var(--status-normal);">Healthy: ${asupHealthy} nodes</span>
        <span style="color: var(--status-warning);">Stopped/Failed: ${asupFailed} nodes</span>
        <span style="color: var(--status-critical);">Disabled: ${asupDisabled} nodes</span>
      </div>
    `;

    // 4. 3rd-party Workload Alignment cards
    let hypervisorAgg = {}, databaseAgg = {}, backupAgg = {};
    targetSAMSystems.forEach(s => {
      const ints = getSystemIntegrations(s);
      hypervisorAgg[ints.virtualization.type] = (hypervisorAgg[ints.virtualization.type] || 0) + 1;
      databaseAgg[ints.database.type] = (databaseAgg[ints.database.type] || 0) + 1;
      backupAgg[ints.backup.type] = (backupAgg[ints.backup.type] || 0) + 1;
    });
    
    document.getElementById("samWorkloadVirtualization").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h5 style="font-size: 0.78rem; text-transform: uppercase; color: var(--text-muted); font-weight: 700; margin: 0;">Orchestration & Hypervisors</h5>
      </div>
      <div style="font-size: 0.8rem; color: var(--text-primary); line-height: 1.5;">
        ${Object.entries(hypervisorAgg).map(([k, v]) => `<div><strong>${k}</strong>: ${v} systems</div>`).join("")}
      </div>
    `;

    document.getElementById("samWorkloadDatabase").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h5 style="font-size: 0.78rem; text-transform: uppercase; color: var(--text-muted); font-weight: 700; margin: 0;">Database & Workload</h5>
      </div>
      <div style="font-size: 0.8rem; color: var(--text-primary); line-height: 1.5;">
        ${Object.entries(databaseAgg).map(([k, v]) => `<div><strong>${k}</strong>: ${v} systems</div>`).join("")}
      </div>
    `;

    document.getElementById("samWorkloadBackup").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h5 style="font-size: 0.78rem; text-transform: uppercase; color: var(--text-muted); font-weight: 700; margin: 0;">Data Protection & Backup</h5>
      </div>
      <div style="font-size: 0.8rem; color: var(--text-primary); line-height: 1.5;">
        ${Object.entries(backupAgg).map(([k, v]) => `<div><strong>${k}</strong>: ${v} systems</div>`).join("")}
      </div>
    `;

    // 5. Logistics Card Summary
    const uniqueAddrs = new Set(targetSAMSystems.map(s => (s.logistics ? s.logistics.deliveryAddress : null)).filter(Boolean));
    const totalContacts = new Set(targetSAMSystems.map(s => (s.contacts ? s.contacts.name : null)).filter(Boolean));
    let aggAlertsCount = 0;
    targetSAMSystems.forEach(s => {
      const l = s.logistics || {};
      if (l.shippingAlert && l.shippingAlert.toLowerCase() !== "none" && !l.shippingAlert.toLowerCase().includes("normal")) {
        aggAlertsCount++;
      }
    });

    document.getElementById("samLogisticsCard").innerHTML = `
      <div class="card-title" style="color: var(--accent-cyan); margin-bottom: 16px;">Site Logistics Summary</div>
      <div style="display: grid; grid-template-columns: 1.2fr 1fr; gap: 20px;">
        <div>
          <div style="margin-bottom: 8px;">Unique Sites: <strong>${uniqueAddrs.size} addresses</strong></div>
          <div style="margin-bottom: 8px;">Active logistics alerts: <strong style="color: ${aggAlertsCount > 0 ? "var(--status-critical)" : "var(--status-normal)"};">${aggAlertsCount} alerts</strong></div>
          <div style="font-size: 0.75rem; color: var(--text-secondary);">Parts shipping pathways are verified across all locations.</div>
        </div>
        <div style="border-left: 1px solid var(--border-color); padding-left: 20px;">
          <div>Key Contacts: <strong>${totalContacts.size} unique users</strong></div>
          <div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 4px;">Primary accounts synced with NetApp Support Site (NSS) credentials.</div>
        </div>
      </div>
    `;

    // 6. Sales Health Card Summary
    let totalScore = 0, countScore = 0;
    let ams = new Set(), tams = new Set();
    targetSAMSystems.forEach(s => {
      if (s.salesHealth) {
        totalScore += s.salesHealth.sentimentScore;
        countScore++;
        ams.add(s.salesHealth.accountManager);
        tams.add(s.salesHealth.supportTam);
      }
    });
    const avgScore = countScore > 0 ? (totalScore / countScore) : 8.0;
    const avgPct = avgScore * 10;
    let shColor = "var(--status-normal)";
    if (avgScore < 6.0) shColor = "var(--status-critical)";
    else if (avgScore < 7.5) shColor = "var(--status-warning)";

    document.getElementById("samSalesHealthCard").innerHTML = `
      <div class="card-title" style="color: var(--accent-cyan); margin-bottom: 16px;">Sales & Account Health Scorecard</div>
      <div style="display: grid; grid-template-columns: 1fr 1.2fr; gap: 20px;">
        <div>
          <div style="margin-bottom: 12px;">
            <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase; display: block; margin-bottom: 4px;">Average CSAT Sentiment</span>
            <div style="display: flex; align-items: center; gap: 10px;">
              <div style="font-size: 1.8rem; font-weight: 800; color: ${shColor};">${avgScore.toFixed(1)}<span style="font-size: 0.9rem; font-weight: 500; color: var(--text-muted);">/10</span></div>
            </div>
            <div class="health-bar-container" style="background: rgba(255,255,255,0.05); height: 6px; border-radius: 3px; margin-top: 6px; overflow: hidden;">
              <div style="background: ${shColor}; height: 100%; width: ${avgPct}%;"></div>
            </div>
          </div>
          <div style="font-size: 0.8rem;">
            Managers: <strong>${[...ams].join(", ") || "Under Review"}</strong>
          </div>
        </div>
        <div style="border-left: 1px solid var(--border-color); padding-left: 20px;">
          <div>Support TAMs: <strong>${[...tams].join(", ") || "Under Review"}</strong></div>
          <div style="font-size: 0.72rem; color: var(--accent-cyan); font-weight: 700; text-transform: uppercase; margin-top: 8px;">Pipeline Status</div>
          <div style="font-size: 0.78rem; color: var(--text-secondary); font-style: italic;">Account is under regular quarterly review.</div>
        </div>
      </div>
    `;

    // 7. Field Actions Table: aggregate all field actions
    let faRows = "";
    const allFAs = [];
    targetSAMSystems.forEach(s => {
      if (s.fieldActions) {
        s.fieldActions.forEach(fa => {
          allFAs.push({ ...fa, systemName: s.systemName });
        });
      }
    });
    
    sortDataList(allFAs, state.samFieldActionsSortKey, state.samFieldActionsSortOrder);
    
    if (allFAs.length === 0) {
      faRows = `<tr><td colspan="2" style="text-align: center; color: var(--text-muted);">No outstanding field actions. Systems are compliant.</td></tr>`;
    } else {
      allFAs.forEach(fa => {
        faRows += `
          <tr>
            <td>
              <code style="font-weight: 600; color: var(--status-warning);">${fa.id}</code>
              <div style="font-size: 0.7rem; color: var(--text-muted); margin-top: 2px;">${fa.systemName}</div>
            </td>
            <td>
              <div style="font-weight: 500; margin-bottom: 4px;">${fa.title}</div>
              <div style="color: var(--text-secondary); font-size: 0.8rem;">${fa.actionRequired}</div>
            </td>
          </tr>
        `;
      });
    }
    document.getElementById("samFieldActionsBody").innerHTML = faRows;

    // 8. Active Technical Support Cases Table: aggregate all support cases
    let caseRows = "";
    const allCases = [];
    targetSAMSystems.forEach(s => {
      if (s.supportCases) {
        s.supportCases.forEach(sc => {
          allCases.push({ ...sc, systemName: s.systemName });
        });
      }
    });
    
    sortDataList(allCases, state.samCasesSortKey, state.samCasesSortOrder);
    
    if (allCases.length === 0) {
      caseRows = `<tr><td colspan="5" style="text-align: center; color: var(--text-muted);">No active support cases open.</td></tr>`;
    } else {
      allCases.forEach(c => {
        let badgeColor = "info";
        if (c.severity.includes("S1")) badgeColor = "critical";
        else if (c.severity.includes("S2")) badgeColor = "warning";
        
        const descLine = c.description ? `<div style="font-size: 0.8rem; color: var(--text-secondary); margin-top: 3px;">${c.description}</div>` : '';
        const resLine = c.resolution ? `<div style="font-size: 0.78rem; color: var(--status-normal); margin-top: 6px; padding: 4px 8px; background: rgba(0,230,118,0.05); border-left: 2px solid var(--status-normal); border-radius: 4px;"><strong>Resolution:</strong> ${c.resolution}</div>` : '';
        const notesLine = c.ownerNotes ? `<div style="font-size: 0.72rem; color: var(--text-secondary); font-style: italic; background: rgba(255,255,255,0.02); padding: 4px 8px; border-radius: 4px; border-left: 2px solid var(--accent-cyan); margin-top: 6px;">"${c.ownerNotes}"</div>` : '';

        caseRows += `
          <tr>
            <td><strong style="color: var(--accent-cyan); font-family: monospace;">${c.id}</strong></td>
            <td>
              <div style="font-weight: 600; font-size: 0.85rem; color: var(--text-primary);">${c.title}</div>
              ${descLine}
              <div style="font-size: 0.72rem; color: var(--text-muted); margin-top: 2px;">System: ${c.systemName || 'N/A'}</div>
              <div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 4px;">
                <strong>Next Action By:</strong> <span style="color: var(--status-warning); font-weight: 600;">${c.nextActionBy || "Under Investigation"}</span>
              </div>
              <div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 2px;">
                <strong>Category:</strong> ${c.criticality || 'N/A'}${c.subCategory ? ' / ' + c.subCategory : ''}${c.caseType ? ' (' + c.caseType + ')' : ''}
              </div>
              ${c.reporter ? '<div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 2px;"><strong>Reported By:</strong> ' + c.reporter + '</div>' : ''}
              ${resLine}
              ${notesLine}
            </td>
            <td><span class="badge ${badgeColor}">${c.severity}</span></td>
            <td><code style="color: var(--status-info); font-size: 0.78rem;">${c.status}</code></td>
            <td>
              <div style="font-size: 0.75rem;">Opened: ${c.createdDate ? c.createdDate.split('T')[0] : 'N/A'}</div>
              <div style="font-size: 0.75rem; color: var(--text-muted); margin-top: 2px;">Updated: ${c.lastUpdated ? c.lastUpdated.split('T')[0] : 'N/A'}</div>
              ${c.closedDate ? '<div style="font-size: 0.75rem; color: var(--text-muted); margin-top: 2px;">Closed: ' + c.closedDate.split('T')[0] + '</div>' : ''}
            </td>
          </tr>
        `;
      });
    }
    document.getElementById("samSupportCasesBody").innerHTML = caseRows;
    
    // Virtualized workload recommendations
    const recMap = new Map();
    targetSAMSystems.forEach(s => {
      const list = getSystemWorkloadRecommendations(s);
      list.forEach(rec => {
        const match = rec.match(/^<strong>\[(.*?)\]<\/strong> (.*)$/);
        if (match) {
          const category = match[1];
          const body = match[2];
          const key = `${category}||${body}`;
          if (!recMap.has(key)) {
            recMap.set(key, []);
          }
          recMap.get(key).push(s.systemName);
        } else {
          if (!recMap.has(rec)) {
            recMap.set(rec, []);
          }
          recMap.get(rec).push(s.systemName);
        }
      });
    });

    const recsContainer = document.getElementById("samWorkloadRecommendations");
    if (recsContainer) {
      recsContainer.innerHTML = "";
      if (recMap.size === 0) {
        recsContainer.innerHTML = `<li>No active optimization recommendations for this workload portfolio.</li>`;
      } else {
        recMap.forEach((sysNames, key) => {
          const li = document.createElement("li");
          if (key.includes("||")) {
            const [category, body] = key.split("||");
            const systemsStr = sysNames.length === targetSAMSystems.length 
              ? "All Systems" 
              : (sysNames.length > 3 ? `${sysNames.length} Systems` : sysNames.join(", "));
            li.innerHTML = `<strong>[${category}]</strong> <span style="font-size: 0.72rem; color: var(--accent-cyan); font-weight: 600; margin-right: 6px;">(${systemsStr})</span> ${body}`;
          } else {
            const systemsStr = sysNames.join(", ");
            li.innerHTML = `<span style="font-size: 0.72rem; color: var(--accent-cyan); font-weight: 600; margin-right: 6px;">(${systemsStr})</span> ${key}`;
          }
          recsContainer.appendChild(li);
        });
      }
    }
    updateSortIndicators();
    return;
  }

  const sys = targetSAMSystems[0];
  if (!sys) {
    document.getElementById("samContractCard").innerHTML = "";
    document.getElementById("samLifecycleCard").innerHTML = "";
    document.getElementById("samHypervisorCard").innerHTML = "";
    document.getElementById("samLogisticsCard").innerHTML = "";
    document.getElementById("samSalesHealthCard").innerHTML = "";
    if (document.getElementById("samWorkloadVirtualization")) document.getElementById("samWorkloadVirtualization").innerHTML = "";
    if (document.getElementById("samWorkloadDatabase")) document.getElementById("samWorkloadDatabase").innerHTML = "";
    if (document.getElementById("samWorkloadBackup")) document.getElementById("samWorkloadBackup").innerHTML = "";
    if (document.getElementById("samWorkloadRecommendations")) document.getElementById("samWorkloadRecommendations").innerHTML = "";
    document.getElementById("samFieldActionsBody").innerHTML = `<tr><td colspan="2" style="text-align: center; color: var(--text-muted);">No systems available in current scope.</td></tr>`;
    document.getElementById("samSupportCasesBody").innerHTML = `<tr><td colspan="5" style="text-align: center; color: var(--text-muted);">No systems available.</td></tr>`;
    return;
  }

  document.getElementById("samActiveSystem").innerHTML = `
    <strong>System</strong>: ${sys.systemName} (S/N: <code class="copyable-code" onclick="copyToClipboard('${sys.serialNumber}', event)" title="Click to copy Serial Number">${sys.serialNumber} <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg></code>) | <strong>Platform</strong>: ${sys.platform}
  `;

  // Contract details
  let contractBadge = `<span class="badge normal">Active</span>`;
  let expiryColor = "var(--text-primary)";
  if (sys.contracts.status === "critical") {
    contractBadge = `<span class="badge critical">Expired</span>`;
    expiryColor = "var(--status-critical)";
  } else if (sys.contracts.status === "warning") {
    contractBadge = `<span class="badge warning">Expiring Soon</span>`;
    expiryColor = "var(--status-warning)";
  }

  document.getElementById("samContractCard").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h4 style="font-size: 0.9rem; color: var(--text-secondary);">Support Level</h4>
      ${contractBadge}
    </div>
    <div style="font-size: 1.25rem; font-weight: 700; margin-bottom: 6px; color: ${expiryColor};">
      ${sys.contracts.supportLevel}
    </div>
    <div style="font-size: 0.85rem; color: var(--text-primary); margin-bottom: 4px;">
      Expires: <strong>${sys.contracts.endDate}</strong>
    </div>
    <div style="font-size: 0.8rem; color: var(--text-muted);">
      ${sys.contracts.daysRemaining < 0 ? `Support ended ${Math.abs(sys.contracts.daysRemaining)} days ago.` : `${sys.contracts.daysRemaining} days remaining.`}
    </div>
  `;

  // Lifecycles
  let lcStatus = `<span class="badge normal">Fully Supported</span>`;
  let eoaGlow = "var(--text-primary)";
  if (sys.lifecycle.isNearEos) {
    lcStatus = `<span class="badge critical">EOS Warning</span>`;
    eoaGlow = "var(--status-critical)";
  }

  document.getElementById("samLifecycleCard").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h4 style="font-size: 0.9rem; color: var(--text-secondary);">End of Support (EOS)</h4>
      ${lcStatus}
    </div>
    <div style="font-size: 1.25rem; font-weight: 700; margin-bottom: 6px; color: ${eoaGlow};">
      EOS: ${sys.lifecycle.eosDate}
    </div>
    <div style="font-size: 0.85rem; color: var(--text-primary); margin-bottom: 4px;">
      End of Availability: <strong>${sys.lifecycle.eoaDate}</strong>
    </div>
  `;

  // Hypervisors
  const hypContainer = document.getElementById("samHypervisorCard");
  if (hypContainer && sys.hypervisors && sys.hypervisors.length > 0) {
    const hyp = sys.hypervisors[0];
    let hBadge = `<span class="badge normal">${hyp.health}</span>`;
    if (hyp.health === "Warning" || hyp.health === "Critical") {
      hBadge = `<span class="badge warning">${hyp.health}</span>`;
    }
    hypContainer.innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">3rd-Party Integrations</h4>
        ${hBadge}
      </div>
      <div style="font-size: 1.25rem; font-weight: 700; margin-bottom: 8px;">
        ${hyp.type} (v${hyp.version})
      </div>
      <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 4px;">
        Plugin: <strong>${hyp.plugin}</strong>
      </div>
      <div style="font-size: 0.8rem; color: var(--text-secondary);">
        Multipathing: <strong>${hyp.multipathing}</strong>
      </div>
    `;
  } else if (hypContainer) {
    hypContainer.innerHTML = `<div style="color: var(--text-muted); font-size: 0.85rem; padding-top: 12px;">No hypervisor integrations tracked on this appliance.</div>`;
  }

  // AutoSupport Details
  const asup = sys.autosupport || { enabled: true, status: "healthy", lastReceivedDays: 1 };
  let asupBadge = `<span class="badge normal">Healthy</span>`;
  let asupColor = "var(--status-normal)";
  if (!asup.enabled) {
    asupBadge = `<span class="badge critical">Disabled</span>`;
    asupColor = "var(--status-critical)";
  } else if (asup.status === "failed" || asup.lastReceivedDays > 7) {
    asupBadge = `<span class="badge warning">Stopped</span>`;
    asupColor = "var(--status-warning)";
  }

  document.getElementById("samAutoSupportCard").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h4 style="font-size: 0.9rem; color: var(--text-secondary);">AutoSupport Status</h4>
      ${asupBadge}
    </div>
    <div style="font-size: 1.15rem; font-weight: 700; margin-bottom: 6px; color: ${asupColor};">
      ${asup.enabled ? (asup.status === 'failed' ? 'Connection Failed' : 'Telemetry Active') : 'Disabled'}
    </div>
    <div style="font-size: 0.85rem; color: var(--text-primary); margin-bottom: 4px;">
      Last Received: <strong>${asup.lastReceivedDays !== null ? `${asup.lastReceivedDays} days ago` : 'Never'}</strong>
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); line-height: 1.3; overflow: hidden; text-overflow: ellipsis; max-height: 38px;" title="${asup.failureReason || 'None'}">
      ${asup.failureReason || 'None'}
    </div>
  `;

  // 3rd-Party Integrations & Workloads Audit
  const ints = getSystemIntegrations(sys);
  
  let virtBadge = `<span class="badge normal">${ints.virtualization.status}</span>`;
  if (ints.virtualization.status === "Warning" || ints.virtualization.status === "Out of Date") {
    virtBadge = `<span class="badge warning">${ints.virtualization.status}</span>`;
  }
  document.getElementById("samWorkloadVirtualization").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h5 style="font-size: 0.78rem; text-transform: uppercase; color: var(--text-muted); font-weight: 700; margin: 0;">Orchestration & Hypervisor</h5>
      ${virtBadge}
    </div>
    <div style="font-size: 1.05rem; font-weight: 700; color: var(--text-primary); margin-bottom: 6px;">
      ${ints.virtualization.type}
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 4px;">
      Version: <strong>${ints.virtualization.version || "N/A"}</strong>
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 4px;">
      Plugin: <strong>${ints.virtualization.plugin}</strong>
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary);">
      Multipathing: <strong>${ints.virtualization.multipathing}</strong>
    </div>
  `;

  document.getElementById("samWorkloadDatabase").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h5 style="font-size: 0.78rem; text-transform: uppercase; color: var(--text-muted); font-weight: 700; margin: 0;">Database & Workload</h5>
      <span class="badge normal">${ints.database.status}</span>
    </div>
    <div style="font-size: 1.05rem; font-weight: 700; color: var(--text-primary); margin-bottom: 6px;">
      ${ints.database.type}
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 4px;">
      Version: <strong>${ints.database.version || "N/A"}</strong>
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); line-height: 1.3;">
      Details: <strong>${ints.database.details}</strong>
    </div>
  `;

  document.getElementById("samWorkloadBackup").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h5 style="font-size: 0.78rem; text-transform: uppercase; color: var(--text-muted); font-weight: 700; margin: 0;">Data Protection & Backup</h5>
      <span class="badge normal">${ints.backup.status}</span>
    </div>
    <div style="font-size: 1.05rem; font-weight: 700; color: var(--text-primary); margin-bottom: 6px;">
      ${ints.backup.type}
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 4px;">
      Version: <strong>${ints.backup.version || "N/A"}</strong>
    </div>
    <div style="font-size: 0.8rem; color: var(--text-secondary); line-height: 1.3;">
      Details: <strong>${ints.backup.details}</strong>
    </div>
  `;

  const recMap = new Map();
  const list = getSystemWorkloadRecommendations(sys);
  list.forEach(rec => {
    const match = rec.match(/^<strong>\[(.*?)\]<\/strong> (.*)$/);
    if (match) {
      const category = match[1];
      const body = match[2];
      const key = `${category}||${body}`;
      if (!recMap.has(key)) {
        recMap.set(key, []);
      }
      recMap.get(key).push(sys.systemName);
    } else {
      if (!recMap.has(rec)) {
        recMap.set(rec, []);
      }
      recMap.get(rec).push(sys.systemName);
    }
  });

  const recsContainer = document.getElementById("samWorkloadRecommendations");
  if (recsContainer) {
    recsContainer.innerHTML = "";
    if (recMap.size === 0) {
      recsContainer.innerHTML = `<li>No active optimization recommendations for this appliance workload.</li>`;
    } else {
      recMap.forEach((sysNames, key) => {
        const li = document.createElement("li");
        if (key.includes("||")) {
          const [category, body] = key.split("||");
          li.innerHTML = `<strong>[${category}]</strong> ${body}`;
        } else {
          li.innerHTML = key;
        }
        recsContainer.appendChild(li);
      });
    }
  }

  // Logistics & Site Access Card
  const logistics = sys.logistics || { deliveryAddress: "Not Set", accessRestrictions: "Not Set", shippingAlert: "None" };
  const contacts = sys.contacts || { name: "Not Set", phone: "Not Set", email: "Not Set", nssUsername: "Not Set" };
  const logAlertActive = logistics.shippingAlert && logistics.shippingAlert.toLowerCase() !== "none" && !logistics.shippingAlert.toLowerCase().includes("normal");
  
  document.getElementById("samLogisticsCard").innerHTML = `
    <div class="card-title" style="color: var(--accent-cyan); margin-bottom: 16px;">Site Logistics & Contacts</div>
    <div style="display: grid; grid-template-columns: 1.2fr 1fr; gap: 20px;">
      <div>
        <div style="margin-bottom: 12px;">
          <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase;">Delivery Address</span>
          <div style="font-size: 0.85rem; color: var(--text-primary); margin-top: 4px; font-style: italic;">${logistics.deliveryAddress}</div>
        </div>
        <div style="margin-bottom: 12px;">
          <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase;">Site Access & Security Rules</span>
          <div style="font-size: 0.8rem; color: var(--text-secondary); margin-top: 4px; line-height: 1.3;">${logistics.accessRestrictions}</div>
        </div>
        ${logAlertActive ? `
          <div style="background-color: rgba(255, 51, 102, 0.06); border: 1px solid rgba(255, 51, 102, 0.2); padding: 10px; border-radius: var(--radius-sm); color: var(--status-critical); font-size: 0.78rem;">
            <strong>⚠️ Logistics Transit Alert:</strong> ${logistics.shippingAlert}
          </div>
        ` : `
          <div style="background-color: rgba(0, 230, 118, 0.05); border: 1px solid rgba(0, 230, 118, 0.15); padding: 8px 12px; border-radius: var(--radius-sm); color: var(--status-normal); font-size: 0.75rem; display: inline-flex; align-items: center; gap: 6px;">
            <span>✓</span> Parts Logistics Hubs Normal
          </div>
        `}
      </div>
      <div style="border-left: 1px solid var(--border-color); padding-left: 20px;">
        <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase; display: block; margin-bottom: 8px;">Primary Site Contact</span>
        <div style="font-weight: 600; font-size: 0.9rem; margin-bottom: 4px;">${contacts.name}</div>
        <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 2px;">📞 ${contacts.phone}</div>
        <div style="font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 8px;">✉️ <a href="mailto:${contacts.email}" style="color: var(--accent-cyan); text-decoration: none;">${contacts.email}</a></div>
        <div style="font-size: 0.75rem; color: var(--text-muted); padding-top: 6px; border-top: 1px dashed var(--border-color);">
          NSS Account ID: <code style="color: var(--text-primary); font-size: 0.75rem;">${contacts.nssUsername}</code>
        </div>
      </div>
    </div>
  `;

  // Sales & Customer Health Card
  const health = sys.salesHealth || { accountManager: "Not Set", supportTam: "Not Set", sentimentScore: 7.0, healthStatus: "Stable", upsellPotential: "None", refreshWindow: "Under Review" };
  const sentimentPct = health.sentimentScore * 10;
  let healthColor = "var(--status-normal)";
  if (health.sentimentScore < 6.0) healthColor = "var(--status-critical)";
  else if (health.sentimentScore < 7.5) healthColor = "var(--status-warning)";

  document.getElementById("samSalesHealthCard").innerHTML = `
    <div class="card-title" style="color: var(--accent-cyan); margin-bottom: 16px;">Sales & Account Health Scorecard</div>
    <div style="display: grid; grid-template-columns: 1fr 1.2fr; gap: 20px;">
      <div>
        <div style="margin-bottom: 12px;">
          <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase; display: block; margin-bottom: 4px;">Customer CSAT Sentiment</span>
          <div style="display: flex; align-items: center; gap: 10px;">
            <div style="font-size: 1.8rem; font-weight: 800; color: ${healthColor};">${health.sentimentScore.toFixed(1)}<span style="font-size: 0.9rem; font-weight: 500; color: var(--text-muted);">/10</span></div>
            <span class="badge" style="background-color: rgba(255,255,255,0.03); border-color: var(--border-color); color: ${healthColor}; font-size: 0.7rem; font-weight: 700;">${health.healthStatus}</span>
          </div>
          <div class="health-bar-container" style="background: rgba(255,255,255,0.05); height: 6px; border-radius: 3px; margin-top: 6px; overflow: hidden;">
            <div style="background: ${healthColor}; height: 100%; width: ${sentimentPct}%;"></div>
          </div>
        </div>
        <div style="margin-bottom: 4px;">
          <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase;">Sales Account Manager</span>
          <div style="font-size: 0.85rem; color: var(--text-primary); font-weight: 600; margin-top: 2px;">${health.accountManager}</div>
        </div>
        <div>
          <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase;">Support Lead TAM/SAM</span>
          <div style="font-size: 0.85rem; color: var(--text-primary); margin-top: 2px;">${health.supportTam}</div>
        </div>
      </div>
      <div style="border-left: 1px solid var(--border-color); padding-left: 20px; display: flex; flex-direction: column; justify-content: space-between;">
        <div style="margin-bottom: 10px;">
          <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 700; text-transform: uppercase;">Upcoming Refresh Window</span>
          <div style="font-size: 0.85rem; color: var(--status-warning); font-weight: 700; margin-top: 4px;">${convertToNetAppFiscal(health.refreshWindow)}</div>
        </div>
        <div style="background-color: rgba(0, 229, 255, 0.04); border: 1px solid rgba(0, 229, 255, 0.15); padding: 10px; border-radius: var(--radius-sm);">
          <div style="font-size: 0.72rem; color: var(--accent-cyan); font-weight: 700; text-transform: uppercase; margin-bottom: 2px;">CSM Upsell Pipeline Opportunity</div>
          <div style="font-size: 0.8rem; color: var(--text-primary); font-weight: 500; line-height: 1.3;">${health.upsellPotential}</div>
        </div>
      </div>
    </div>
  `;

  // Field Actions
  let faRows = "";
  const fas = [...(sys.fieldActions || [])];
  sortDataList(fas, state.samFieldActionsSortKey, state.samFieldActionsSortOrder);
  if (fas.length === 0) {
    faRows = `<tr><td colspan="2" style="text-align: center; color: var(--text-muted);">No outstanding field actions. System is compliant.</td></tr>`;
  } else {
    fas.forEach(fa => {
      faRows += `
        <tr>
          <td style="font-weight: 600; color: var(--status-warning);"><code>${fa.id}</code></td>
          <td>
            <div style="font-weight: 500; margin-bottom: 4px;">${fa.title}</div>
            <div style="color: var(--text-secondary); font-size: 0.8rem;">${fa.actionRequired}</div>
          </td>
        </tr>
      `;
    });
  }
  document.getElementById("samFieldActionsBody").innerHTML = faRows;

  // Render Open Support Cases Table
  const cases = [...(sys.supportCases || [])];
  sortDataList(cases, state.samCasesSortKey, state.samCasesSortOrder);
  let caseRows = "";
  if (cases.length === 0) {
    caseRows = `<tr><td colspan="5" style="text-align: center; color: var(--text-muted);">No active technical support cases open.</td></tr>`;
  } else {
    cases.forEach(c => {
      let sevBadge = `<span class="badge info">${c.severity}</span>`;
      if (c.severity.includes("S1")) sevBadge = `<span class="badge critical">${c.severity}</span>`;
      else if (c.severity.includes("S2")) sevBadge = `<span class="badge warning">${c.severity}</span>`;

      const descHtml = c.description ? `<div style="font-size: 0.8rem; color: var(--text-secondary); margin-top: 4px;">${c.description}</div>` : '';
      const resolutionHtml = c.resolution ? `<div style="font-size: 0.78rem; color: var(--status-normal); margin-top: 6px; padding: 4px 8px; background: rgba(0,230,118,0.05); border-left: 2px solid var(--status-normal); border-radius: 4px;"><strong>Resolution:</strong> ${c.resolution}</div>` : '';
      const notesHtml = c.ownerNotes ? `<div style="font-size: 0.72rem; color: var(--text-secondary); font-style: italic; background: rgba(255,255,255,0.02); padding: 4px 8px; border-radius: 4px; border-left: 2px solid var(--accent-cyan); margin-top: 6px;">"${c.ownerNotes}"</div>` : '';
      const subCatHtml = c.subCategory ? ` / ${c.subCategory}` : '';
      const reporterHtml = c.reporter ? `<div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 2px;"><strong>Reported By:</strong> ${c.reporter}</div>` : '';

      caseRows += `
        <tr>
          <td><strong style="color: var(--accent-cyan); font-family: monospace;">${c.id}</strong></td>
          <td>
            <div style="font-weight: 600; font-size: 0.85rem; color: var(--text-primary);">${c.title}</div>
            ${descHtml}
            ${c.systemName ? `<div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 3px;"><strong>System:</strong> ${c.systemName}</div>` : ''}
            <div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 4px;">
              <strong>Next Action By:</strong> <span style="color: var(--status-warning); font-weight: 600;">${c.nextActionBy || "Under Investigation"}</span>
            </div>
            <div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 2px;">
              <strong>Category:</strong> ${c.criticality || "N/A"}${subCatHtml}${c.caseType ? ` (${c.caseType})` : ''}
            </div>
            ${reporterHtml}
            ${resolutionHtml}
            ${notesHtml}
          </td>
          <td>${sevBadge}</td>
          <td><code style="color: var(--status-info); font-size: 0.78rem;">${c.status}</code></td>
          <td style="font-size: 0.78rem; color: var(--text-muted);">
            Opened: ${c.createdDate ? c.createdDate.split('T')[0] : 'N/A'}<br>Updated: ${c.lastUpdated ? c.lastUpdated.split('T')[0] : 'N/A'}${c.closedDate ? '<br>Closed: ' + c.closedDate.split('T')[0] : ''}
          </td>
        </tr>
      `;
    });
  }
  document.getElementById("samSupportCasesBody").innerHTML = caseRows;
  updateSortIndicators();
}

function renderCSMTab() {
  populateSystemSelectors();
  
  const currentFiltered = getFilteredSystems();
  const targetCSMSystems = [];
  if (state.selectedCSMSystemSerial === "ALL") {
    targetCSMSystems.push(...currentFiltered);
  } else if (state.selectedCSMSystemSerial.startsWith("CLUSTER:")) {
    const cluster = state.selectedCSMSystemSerial.substring(8);
    targetCSMSystems.push(...currentFiltered.filter(s => s.clusterName === cluster));
  } else {
    const serial = state.selectedCSMSystemSerial.startsWith("NODE:") ? state.selectedCSMSystemSerial.substring(5) : state.selectedCSMSystemSerial;
    const found = currentFiltered.find(s => s.serialNumber === serial);
    if (found) targetCSMSystems.push(found);
  }
  
  if (targetCSMSystems.length === 0) {
    document.getElementById("csmSavingsCard").innerHTML = "";
    document.getElementById("csmCloudCard").innerHTML = "";
    document.getElementById("csmSnapmirrorCard").innerHTML = "";
    document.getElementById("csmAdoptionChecklist").innerHTML = "";
    document.getElementById("csmGrowthRateText").innerText = "";
    document.getElementById("csmDaysToLimitText").innerText = "-";
    document.getElementById("csmLimitDateText").innerText = "-";
    document.getElementById("csmPeakIopsText").innerText = "-";
    document.getElementById("csmAvgLatencyText").innerText = "-";
    return;
  }

  const isMulti = targetCSMSystems.length > 1;

  if (isMulti) {
    document.getElementById("csmActiveSystem").innerHTML = `
      <strong>Selected Systems (${targetCSMSystems.length})</strong>: <span style="font-size: 0.8rem; color: var(--text-primary);">${targetCSMSystems.map(s => s.systemName).join(", ")}</span>
    `;

    // ── Efficiency aggregates — all computed from dataReductionRatioSys (dedup+compression only,
    // excl. snapshots). Using logicalUsedTB or spaceSavedTB directly mixes two different
    // efficiency metrics (one uses full snapshot ratio, the other uses pure DR ratio),
    // producing wildly inconsistent numbers (e.g. 1.7:1 ratio but 98,000 TB "saved").
    let totalPhysical = 0, weightedRatioSum = 0, drSystemCount = 0;
    targetCSMSystems.forEach(s => {
      const phys  = s.efficiency.physicalUsedTB   || 0;
      // dataReductionRatio is now stored on the efficiency object (numeric, dedup+compression only)
      // Fall back to parsing the ratio string if the numeric field is absent (e.g. older cached data)
      let ratio = s.efficiency.dataReductionRatio || 0;
      if (!ratio) {
        const rStr = (s.efficiency.ratio || '1.0:1').replace(':1', '');
        ratio = parseFloat(rStr) || 1;
      }
      if (ratio < 1) ratio = 1;  // floor at 1:1
      totalPhysical    += phys;
      weightedRatioSum += phys * ratio;  // weight by physical capacity
      if (ratio > 1) drSystemCount++;
    });
    // Weighted-average ratio: Σ(physᵢ × ratioᵢ) / Σphysᵢ
    const avgRatioNum = totalPhysical > 0 ? weightedRatioSum / totalPhysical : 1;
    const avgRatio    = avgRatioNum.toFixed(1);
    // Logical = physical × weighted-avg ratio (data you'd need without reduction)
    const totalLogical = parseFloat((totalPhysical * avgRatioNum).toFixed(1));
    // Saved = logical − physical (consistent with ratio shown)
    const totalSaved   = parseFloat(Math.max(0, totalLogical - totalPhysical).toFixed(1));

    document.getElementById("csmSavingsCard").innerHTML = `
      <div style="display: flex; flex-direction: column; gap: 12px;">
        <div>
          <span style="font-size: 0.8rem; color: var(--text-secondary); text-transform: uppercase;">Overall Account Data Reduction</span>
          <div style="font-size: 2.2rem; font-weight: 800; color: var(--status-normal);">${avgRatio}:1</div>
          <div style="font-size: 0.72rem; color: var(--text-muted); margin-top: 2px;">Dedupe + compression only, excl. snapshots</div>
        </div>
        <div style="border-top: 1px solid var(--border-color); padding-top: 12px; display: grid; grid-template-columns: 1fr 1fr; gap: 8px;">
          <div>
            <span style="font-size: 0.75rem; color: var(--text-muted);">Logical (Dedup Savings)</span>
            <div style="font-weight: 600;">${totalLogical.toFixed(1)} TB</div>
          </div>
          <div>
            <span style="font-size: 0.75rem; color: var(--text-muted);">Physical Space Used</span>
            <div style="font-weight: 600;">${totalPhysical.toFixed(1)} TB</div>
          </div>
        </div>
        <div style="background-color: rgba(0, 230, 118, 0.08); padding: 12px; border-radius: var(--radius-sm); border: 1px solid rgba(0, 230, 118, 0.2);">
          <div style="font-size: 0.75rem; color: var(--status-normal); font-weight: 700; text-transform: uppercase; margin-bottom: 2px;">Data Reduction Saved</div>
          <div style="font-size: 1.2rem; font-weight: 700; color: #fff;">${totalSaved.toFixed(1)} TB</div>
          <div style="font-size: 0.7rem; color: var(--text-muted); margin-top: 2px;">Dedupe + compaction savings only</div>
        </div>
      </div>
    `;


    // 2. FabricPool aggregate
    let totalFP = 0, activeFPCount = 0;
    targetCSMSystems.forEach(s => {
      const fp = s.efficiency.fabricPoolTieredTB || 0;
      totalFP += fp;
      if (fp > 0) activeFPCount++;
    });
    let fpBadge = activeFPCount > 0 ? `<span class="badge normal">${activeFPCount} active tiering</span>` : `<span class="badge warning">No Cloud Tiering</span>`;
    document.getElementById("csmCloudCard").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">FabricPool Integration</h4>
        ${fpBadge}
      </div>
      <div style="font-size: 1.4rem; font-weight: 700; margin-bottom: 6px; color: ${totalFP > 0 ? "var(--status-info)" : "var(--status-warning)"};">
        Cloud Tiered: ${totalFP.toFixed(1)} TB
      </div>
      <p style="font-size: 0.8rem; color: var(--text-secondary); line-height: 1.4;">
        ${activeFPCount} out of ${targetCSMSystems.length} systems are tiering cold data to public/private cloud object storage.
      </p>
    `;

    // 3. SnapMirror aggregate
    let smEnabledCount = 0;
    let relationshipsHTML = "";
    targetCSMSystems.forEach(s => {
      if (s.snapmirror && s.snapmirror.enabled) {
        smEnabledCount++;
        s.snapmirror.relationships.forEach(rel => {
          relationshipsHTML += `
            <div style="margin-top: 8px; font-size: 0.78rem; border-top: 1px solid var(--border-color); padding-top: 6px; display: flex; justify-content: space-between;">
              <span>Sys: <strong>${s.systemName}</strong> -> <strong>${rel.destination}</strong></span>
              <span style="color: var(--accent-cyan);">${rel.lagTime}</span>
            </div>
          `;
        });
      }
    });
    if (relationshipsHTML === "") {
      relationshipsHTML = `<div style="color: var(--text-muted); font-size: 0.8rem; margin-top: 10px;">No SnapMirror relations mapped.</div>`;
    }
    document.getElementById("csmSnapmirrorCard").innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">SnapMirror replication</h4>
        <span class="badge ${smEnabledCount > 0 ? 'normal' : 'warning'}">${smEnabledCount} Enabled</span>
      </div>
      <div style="max-height: 120px; overflow-y: auto; padding-right: 4px;">
        ${relationshipsHTML}
      </div>
    `;

    // 4. Checklist aggregate — TAM/MSP remediation readiness (9 checks)
    const _latestOntap = SOFTWARE_VERSION_DATABASES.ontap[SOFTWARE_VERSION_DATABASES.ontap.length - 1];
    let _verPass = 0, _effPass = 0, _cloudPass = 0, _drPass = 0;
    let _riskPass = 0, _contractPass = 0, _asupPass = 0, _hwPass = 0, _secPass = 0;
    let _verDetails = [];

    targetCSMSystems.forEach(s => {
      // 1. OS on recommended version (no outstanding upgrade recommendation)
      const _hasUpgrade = !!(s.upgrades && s.upgrades.targetVersion);
      if (!_hasUpgrade) _verPass++;
      else _verDetails.push(`${s.systemName}: ${s.ontapVersion || '?'} \u2192 ${s.upgrades.targetVersion}`);

      // 2. Storage efficiency >= 1.5:1
      if (parseFloat((s.efficiency.ratio || '1:1').split(':')[0]) > 1.5) _effPass++;

      // 3. FabricPool cloud tiering active
      if (s.efficiency.fabricPoolTieredTB > 0) _cloudPass++;

      // 4. SnapMirror / replication active
      if (s.snapmirror && s.snapmirror.enabled) _drPass++;

      // 5. Zero high/critical risks
      if (s.risks.filter(r => r.severity === 'critical' || r.severity === 'high').length === 0) _riskPass++;

      // 6. Support contract active (> 90 days remaining)
      if (s.contracts && s.contracts.daysRemaining > 90) _contractPass++;

      // 7. AutoSupport HTTPS active and reporting within 7 days
      const _asup = s.autosupport || {};
      if (_asup.enabled !== false && _asup.status !== 'failed' && _asup.status !== 'disabled' &&
          (_asup.lastReceivedDays == null || _asup.lastReceivedDays <= 7)) _asupPass++;

      // 8. Hardware not on EOA/EOS platform list
      const _modelStr = (s.platform || s.model || '').toUpperCase();
      if (!REFERENCE_LIBRARY_EOA_PLATFORMS.some(p => _modelStr.includes(p.toUpperCase()))) _hwPass++;

      // 9. No active security CVEs applicable to system
      const _sec = getApplicableSecurityBulletins(s.ontapVersion, s.platform).filter(b => b.status !== 'resolved');
      if (_sec.length === 0) _secPass++;
    });

    const _n = targetCSMSystems.length;
    const _vDetail = _verDetails.length > 0
      ? _verDetails.slice(0, 2).join(' | ') + (_verDetails.length > 2 ? ` +${_verDetails.length - 2} more` : '')
      : '';

    const _checklist = [
      { name: `OS on Recommended Version (target: ONTAP ${_latestOntap})`, completedCount: _verPass,     detail: _vDetail },
      { name: 'Storage Efficiency \u2265 1.5:1 (dedup + compression)',         completedCount: _effPass,    detail: '' },
      { name: 'Cloud FabricPool / Cold-Data Tiering Active',                    completedCount: _cloudPass,  detail: '' },
      { name: 'SnapMirror Async/Sync Replication Configured',                   completedCount: _drPass,     detail: '' },
      { name: 'Zero High/Critical Risks Outstanding',                           completedCount: _riskPass,   detail: '' },
      { name: 'Support Contract Active (> 90 days remaining)',                  completedCount: _contractPass, detail: '' },
      { name: 'AutoSupport HTTPS Reporting (last check \u2264 7 days)',         completedCount: _asupPass,   detail: '' },
      { name: 'Hardware on Current Platform Generation (non-EOA)',              completedCount: _hwPass,     detail: '' },
      { name: 'No Active Security CVEs Applicable (PSIRT)',                     completedCount: _secPass,    detail: '' }
    ];

    let checklistHTML = '';
    _checklist.forEach(item => {
      const _allDone = item.completedCount === _n;
      const _col = _allDone ? 'var(--status-normal)' : item.completedCount === 0 ? 'var(--status-critical)' : 'var(--status-warning)';
      const _pct = Math.round((item.completedCount / Math.max(_n, 1)) * 100);
      checklistHTML += `
        <div style="padding: 8px 10px; background: rgba(255,255,255,0.01); border-bottom: 1px solid var(--border-color);">
          <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: ${item.detail ? 3 : 2}px;">
            <span style="font-size: 0.82rem;">${item.name}</span>
            <span style="font-size: 0.82rem; font-weight: 600; color: ${_col}; white-space: nowrap; margin-left: 8px;">${item.completedCount}/${_n}</span>
          </div>
          ${item.detail ? `<div style="font-size: 0.72rem; color: var(--text-muted); margin-bottom: 3px;">${item.detail}</div>` : ''}
          <div style="height: 3px; background: rgba(255,255,255,0.06); border-radius: 2px; overflow: hidden;">
            <div style="height: 100%; width: ${_pct}%; background: ${_col}; border-radius: 2px;"></div>
          </div>
        </div>
      `;
    });
    document.getElementById('csmAdoptionChecklist').innerHTML = checklistHTML;

    // 5. Projections aggregate
    let totalGrowth = 0, minDaysToLimit = 9999, worstLimitDate = "N/A", worstSystemName = "";
    let totalPeakIops = 0, sumAvgLatency = 0, countAvgLatency = 0;
    
    const aggHist = Array(6).fill(0);
    const aggProj = Array(3).fill(0);
    
    targetCSMSystems.forEach(s => {
      const p = s.projections || { growthRateGBPerDay: 100, daysToLimit: 120, limitDate: "Under Review", peakIops: 10000, avgLatencyMs: 2.5, historicalCapacityMonths: [10, 11, 12, 13, 14, 15], projectedCapacityMonths: [16, 17, 18] };
      totalGrowth += p.growthRateGBPerDay;
      if (p.daysToLimit < minDaysToLimit) {
        minDaysToLimit = p.daysToLimit;
        worstLimitDate = p.limitDate;
        worstSystemName = s.systemName;
      }
      totalPeakIops += p.peakIops;
      sumAvgLatency += p.avgLatencyMs;
      countAvgLatency++;
      
      for (let m = 0; m < 6; m++) {
        aggHist[m] += p.historicalCapacityMonths[m] || 0;
      }
      for (let m = 0; m < 3; m++) {
        aggProj[m] += p.projectedCapacityMonths[m] || 0;
      }
    });
    
    const avgLatency = countAvgLatency > 0 ? (sumAvgLatency / countAvgLatency) : 2.5;

    const growthSrc = (targetCSMSystems[0]?.projections?.growthSource) || 'estimated';
    const srcLabel = {'actual-monthly':'Actual','qoq':'QoQ','yoy':'YoY','estimated':'Est.'}[growthSrc] || 'Est.';
    document.getElementById("csmGrowthRateText").innerText = `Aggregate Growth: +${totalGrowth.toFixed(0)} GB/day (${srcLabel})`;
    
    const limitLabel = document.getElementById("csmDaysToLimitText");
    limitLabel.innerText = minDaysToLimit >= 9999 ? '> 10 Years' : `${minDaysToLimit.toLocaleString()} Days`;
    limitLabel.style.color = minDaysToLimit <= 60 ? "var(--status-critical)" : (minDaysToLimit <= 120 ? "var(--status-warning)" : "var(--status-normal)");
    
    document.getElementById("csmLimitDateText").innerText = `Est. limit reached on ${worstSystemName}: ${worstLimitDate}`;
    document.getElementById("csmPeakIopsText").innerHTML = totalPeakIops > 0
      ? `${totalPeakIops.toLocaleString()} IOPS`
      : '<span style="font-size:0.85rem;color:var(--text-muted);font-weight:400;">Not available via API</span>';
    document.getElementById("csmAvgLatencyText").innerText = totalPeakIops > 0 ? `Avg Latency: ${avgLatency.toFixed(1)} ms` : 'IOPS/Latency requires Cloud Insights';

    const aggProjObj = {
      historicalCapacityMonths: aggHist,
      projectedCapacityMonths: aggProj
    };
    // Cache for toggle
    _csmAllSystems = targetCSMSystems;
    _csmAggProjObj = aggProjObj;
    _capacityViewMode = 'aggregate';
    // Reset toggle buttons to Aggregate
    const ab = document.getElementById('capViewAggrBtn'), nb = document.getElementById('capViewNodeBtn');
    if (ab) { ab.style.background = 'var(--accent-cyan)'; ab.style.color = '#000'; }
    if (nb) { nb.style.background = 'transparent'; nb.style.color = 'var(--text-secondary)'; }
    const bd = document.getElementById('csmNodeBreakdown'); if (bd) bd.style.display = 'none';
    renderProjectionsChart(aggProjObj, "Consolidated Account Portfolio");
    return;
  }

  const sys = targetCSMSystems[0];
  if (!sys) {
    document.getElementById("csmSavingsCard").innerHTML = "";
    document.getElementById("csmCloudCard").innerHTML = "";
    document.getElementById("csmSnapmirrorCard").innerHTML = "";
    document.getElementById("csmAdoptionChecklist").innerHTML = "";
    document.getElementById("csmGrowthRateText").innerText = "";
    document.getElementById("csmDaysToLimitText").innerText = "-";
    document.getElementById("csmLimitDateText").innerText = "-";
    document.getElementById("csmPeakIopsText").innerText = "-";
    document.getElementById("csmAvgLatencyText").innerText = "-";
    return;
  }

  document.getElementById("csmActiveSystem").innerHTML = `
    <strong>System</strong>: ${sys.systemName} (S/N: <code class="copyable-code" onclick="copyToClipboard('${sys.serialNumber}', event)" title="Click to copy Serial Number">${sys.serialNumber} <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg></code>) | <strong>Customer</strong>: ${sys.customerName}
  `;

  const isASA = (sys.platform || "").includes("ASA");
  const effLabelBase = isASA ? "Storage Efficiency (Block SAN)" : "Data Reduction";
  const withSnaps = sys.efficiency.efficiencyRatioWithSnaps;
  const withSnapsStr = withSnaps && withSnaps > 1 ? `${withSnaps.toFixed(1)}:1` : null;

  document.getElementById("csmSavingsCard").innerHTML = `
    <div style="display: flex; flex-direction: column; gap: 12px;">
      <div>
        <span style="font-size: 0.8rem; color: var(--text-secondary); text-transform: uppercase;">${effLabelBase} Ratio</span>
        <div style="font-size: 2.2rem; font-weight: 800; color: var(--status-normal);">${sys.efficiency.ratio}</div>
        <div style="font-size: 0.72rem; color: var(--text-muted); margin-top: 2px;">
          Dedupe + compression only&nbsp;&nbsp;
          ${withSnapsStr ? `<span style="color:var(--accent-cyan);" title="Includes snapshot space savings">incl. snapshots: ${withSnapsStr}</span>` : ''}
        </div>
      </div>
      <div style="border-top: 1px solid var(--border-color); padding-top: 12px; display: grid; grid-template-columns: 1fr 1fr; gap: 8px;">
        <div>
          <span style="font-size: 0.75rem; color: var(--text-muted);">Logical (Dedup Savings)</span>
          <div style="font-weight: 600;">${sys.efficiency.logicalUsedTB.toFixed(1)} TB</div>
        </div>
        <div>
          <span style="font-size: 0.75rem; color: var(--text-muted);">Physical Space Used</span>
          <div style="font-weight: 600;">${sys.efficiency.physicalUsedTB.toFixed(1)} TB</div>
        </div>
      </div>
      <div style="background-color: rgba(0, 230, 118, 0.08); padding: 12px; border-radius: var(--radius-sm); border: 1px solid rgba(0, 230, 118, 0.2);">
        <div style="font-size: 0.75rem; color: var(--status-normal); font-weight: 700; text-transform: uppercase; margin-bottom: 2px;">Data Reduction Saved</div>
        <div style="font-size: 1.2rem; font-weight: 700; color: #fff;">${sys.efficiency.spaceSavedTB.toFixed(1)} TB</div>
        <div style="font-size: 0.7rem; color: var(--text-muted); margin-top: 2px;">Dedupe + compaction savings only</div>
      </div>
    </div>
  `;


  const fpTiered = sys.efficiency.fabricPoolTieredTB;
  let fpAdoptionBadge = "";
  let fpStatusText = "";
  
  if (isASA) {
    fpAdoptionBadge = `<span class="badge normal" style="background: rgba(255,255,255,0.05); color: var(--text-secondary); border-color: var(--border-color);">N/A (SAN Block Array)</span>`;
    fpStatusText = `ASA platforms prioritize high-speed symmetric SAN block access. Snapshot copy space optimization is managed directly via local aggregates and active block deduplication/compression.`;
  } else if (fpTiered > 0) {
    fpAdoptionBadge = `<span class="badge normal">Tiering Active</span>`;
    fpStatusText = `System is tiering <strong>${fpTiered.toFixed(1)} TB</strong> of cold data to public/private cloud object storage. This saves premium flash tier capacity.`;
  } else {
    fpAdoptionBadge = `<span class="badge warning">No FabricPool Tiering</span>`;  // Note: NetApp Cloud Tiering service EOA April 24 2026 — FabricPool is the current term
    fpStatusText = `<span style="color: var(--status-warning);">Potential opportunity!</span> Enable FabricPool tiering to offload cold backup/snapshot data to cheaper object storage and free up premium flash capacity.`;
  }

  document.getElementById("csmCloudCard").innerHTML = `
    <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
      <h4 style="font-size: 0.9rem; color: var(--text-secondary);">FabricPool Integration</h4>
      ${fpAdoptionBadge}
    </div>
    <div style="font-size: 1.4rem; font-weight: 700; margin-bottom: 6px; color: ${fpTiered > 0 && !isASA ? "var(--status-info)" : "var(--status-warning)"};">
      Cloud Tiered: ${fpTiered.toFixed(1)} TB
    </div>
    <p style="font-size: 0.8rem; color: var(--text-secondary); line-height: 1.4;">
      ${fpStatusText}
    </p>
  `;

  const smContainer = document.getElementById("csmSnapmirrorCard");
  if (smContainer && sys.snapmirror) {
    let smBadge = `<span class="badge normal">Inactive</span>`;
    let relationshipsHTML = "";
    
    if (sys.snapmirror.enabled) {
      smBadge = `<span class="badge normal">Enabled</span>`;
      sys.snapmirror.relationships.forEach(rel => {
        relationshipsHTML += `
          <div style="margin-top: 8px; font-size: 0.8rem; border-top: 1px solid var(--border-color); padding-top: 8px;">
            <div>Dest: <strong>${rel.destination}</strong></div>
            <div>Type: <strong>${rel.type}</strong> | State: <strong>${rel.state}</strong></div>
            <div>Lag Time: <strong style="color: var(--accent-cyan);">${rel.lagTime}</strong></div>
          </div>
        `;
      });
    } else {
      relationshipsHTML = `<div style="color: var(--text-muted); font-size: 0.8rem; margin-top: 10px;">No SnapMirror relations mapped. Add sync/async replication for disaster recovery.</div>`;
    }

    smContainer.innerHTML = `
      <div style="margin-bottom: 12px; display: flex; justify-content: space-between; align-items: center;">
        <h4 style="font-size: 0.9rem; color: var(--text-secondary);">SnapMirror replication</h4>
        ${smBadge}
      </div>
      ${relationshipsHTML}
    `;
  }

  // Single-system checklist — 9 TAM/MSP remediation checks
  const _sLatestOntap = SOFTWARE_VERSION_DATABASES.ontap[SOFTWARE_VERSION_DATABASES.ontap.length - 1];
  const _sCurVer     = sys.ontapVersion || sys.santricityVersion || 'N/A';
  const _sHasUpgrade = !!(sys.upgrades && sys.upgrades.targetVersion);
  const _sAsup       = sys.autosupport || {};
  const _sIsEOA      = REFERENCE_LIBRARY_EOA_PLATFORMS.some(p => (sys.platform || sys.model || '').toUpperCase().includes(p.toUpperCase()));
  const _sCVEs       = getApplicableSecurityBulletins(sys.ontapVersion, sys.platform).filter(b => b.status !== 'resolved');
  const _sCritH      = sys.risks.filter(r => r.severity === 'critical' || r.severity === 'high');
  const _sCrit       = _sCritH.filter(r => r.severity === 'critical').length;
  const _sHigh       = _sCritH.filter(r => r.severity === 'high').length;

  const _sSingle = [
    {
      name: `OS on Recommended Version (target: ONTAP ${_sLatestOntap})`,
      ok: !_sHasUpgrade,
      detail: _sHasUpgrade ? `${_sCurVer} \u2192 ${sys.upgrades.targetVersion} upgrade recommended` : `${_sCurVer} \u2014 on target`
    },
    {
      name: 'Storage Efficiency \u2265 1.5:1 (dedup + compression)',
      ok: parseFloat((sys.efficiency.ratio || '1:1').split(':')[0]) > 1.5,
      detail: `Current ratio: ${sys.efficiency.ratio || 'N/A'}`
    },
    {
      name: 'Cloud FabricPool / Cold-Data Tiering Active',
      ok: fpTiered > 0,
      detail: fpTiered > 0 ? `${fpTiered.toFixed(1)} TB tiered to object storage` : 'Not configured \u2014 cold data using primary tier'
    },
    {
      name: 'SnapMirror Async/Sync Replication Configured',
      ok: sys.snapmirror.enabled,
      detail: sys.snapmirror.enabled ? `${(sys.snapmirror.relationships || []).length} relationship(s) active` : 'No replication configured'
    },
    {
      name: 'Zero High/Critical Risks Outstanding',
      ok: _sCritH.length === 0,
      detail: _sCritH.length > 0 ? `${_sCrit} critical, ${_sHigh} high \u2014 remediation required` : 'No critical or high risks'
    },
    {
      name: 'Support Contract Active (> 90 days remaining)',
      ok: !!(sys.contracts && sys.contracts.daysRemaining > 90),
      detail: sys.contracts
        ? (sys.contracts.daysRemaining > 0 ? `${sys.contracts.daysRemaining} days remaining \u2014 ${sys.contracts.supportLevel || 'N/A'}` : `Expired ${Math.abs(sys.contracts.daysRemaining)}d ago \u2014 renew immediately`)
        : 'No contract data available'
    },
    {
      name: 'AutoSupport HTTPS Reporting (last check \u2264 7 days)',
      ok: _sAsup.enabled !== false && _sAsup.status !== 'failed' && _sAsup.status !== 'disabled' && (_sAsup.lastReceivedDays == null || _sAsup.lastReceivedDays <= 7),
      detail: _sAsup.status ? `Status: ${_sAsup.status}${_sAsup.lastReceivedDays != null ? ', last received ' + _sAsup.lastReceivedDays + 'd ago' : ''}` : 'AutoSupport status unknown'
    },
    {
      name: 'Hardware on Current Platform Generation (non-EOA)',
      ok: !_sIsEOA,
      detail: _sIsEOA ? `${sys.platform} is End-of-Availability \u2014 refresh planning required` : `${sys.platform} is current generation`
    },
    {
      name: 'No Active Security CVEs Applicable (PSIRT)',
      ok: _sCVEs.length === 0,
      detail: _sCVEs.length > 0
        ? `${_sCVEs.length} active: ${_sCVEs.slice(0, 3).map(b => b.cve || b.id || '').filter(Boolean).join(', ')}${_sCVEs.length > 3 ? ` +${_sCVEs.length - 3} more` : ''}`
        : 'No active advisories for this version'
    }
  ];

  let checklistHTML = '';
  _sSingle.forEach(item => {
    const _col = item.ok ? 'var(--status-normal)' : 'var(--status-critical)';
    const _dCol = item.ok ? 'var(--text-muted)' : 'var(--status-warning)';
    checklistHTML += `
      <div style="padding: 8px 10px; background: rgba(255,255,255,0.01); border-bottom: 1px solid var(--border-color);">
        <div style="display: flex; align-items: flex-start; justify-content: space-between; gap: 8px; margin-bottom: 2px;">
          <span style="font-size: 0.82rem; flex: 1;">${item.name}</span>
          <span style="font-size: 1rem; font-weight: bold; color: ${_col}; flex-shrink: 0;">${item.ok ? '\u2713' : '\u2717'}</span>
        </div>
        <div style="font-size: 0.72rem; color: ${_dCol};">${item.detail}</div>
      </div>
    `;
  });
  document.getElementById('csmAdoptionChecklist').innerHTML = checklistHTML;

  // Render Projections & Forecasting Metrics & Line Chart
  const proj = sys.projections || { growthRateGBPerDay: 100, daysToLimit: 120, limitDate: "Under Review", peakIops: 10000, avgLatencyMs: 2.5, historicalCapacityMonths: [10, 11, 12, 13, 14, 15], projectedCapacityMonths: [16, 17, 18] };
  
  const srcLabel = {'actual-monthly':'Actual','qoq':'QoQ','yoy':'YoY','estimated':'Est.'}[proj.growthSource || 'estimated'] || 'Est.';
  document.getElementById("csmGrowthRateText").innerText = `Average Growth: +${proj.growthRateGBPerDay} GB/day (${srcLabel})`;
  
  const limitLabel = document.getElementById("csmDaysToLimitText");
  limitLabel.innerText = proj.daysToLimit >= 9999 ? '> 10 Years' : `${proj.daysToLimit.toLocaleString()} Days`;
  limitLabel.style.color = proj.daysToLimit <= 60 ? "var(--status-critical)" : (proj.daysToLimit <= 120 ? "var(--status-warning)" : "var(--status-normal)");
  
  document.getElementById("csmLimitDateText").innerText = `Est. Limit reached: ${proj.limitDate}`;
  document.getElementById("csmPeakIopsText").innerHTML = proj.peakIops > 0
    ? `${proj.peakIops.toLocaleString()} IOPS`
    : '<span style="font-size:0.85rem;color:var(--text-muted);font-weight:400;">Not available via API</span>';
  document.getElementById("csmAvgLatencyText").innerText = proj.peakIops > 0 ? `Avg Latency: ${proj.avgLatencyMs.toFixed(1)} ms` : 'IOPS/Latency requires Cloud Insights';

  // Cache for toggle (single-system view)
  _csmAllSystems = [sys];
  _csmAggProjObj = proj;
  _capacityViewMode = 'aggregate';
  const ab2 = document.getElementById('capViewAggrBtn'), nb2 = document.getElementById('capViewNodeBtn');
  if (ab2) { ab2.style.background = 'var(--accent-cyan)'; ab2.style.color = '#000'; }
  if (nb2) { nb2.style.background = 'transparent'; nb2.style.color = 'var(--text-secondary)'; }
  const bd2 = document.getElementById('csmNodeBreakdown'); if (bd2) bd2.style.display = 'none';
  // Draw capacity/performance projection line chart
  renderProjectionsChart(proj, sys.systemName);
}

function renderProjectionsChart(proj, systemName) {
  const ctx = document.getElementById("csmProjectionsChart");
  if (!ctx) return;

  if (projectionsChartInstance) {
    projectionsChartInstance.destroy();
  }

  if (typeof Chart === "undefined") return;

  // Generate real month labels: past 6 months through next 3 months from today
  const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const now = new Date();
  const labels = [];
  for (let i = -5; i <= 3; i++) {
    const d = new Date(now.getFullYear(), now.getMonth() + i, 1);
    const suffix = i === 0 ? ' ●' : (i > 0 ? ' (Est.)' : '');
    labels.push(monthNames[d.getMonth()] + ' ' + d.getFullYear() + suffix);
  }
  
  // Format datasets: historical capacity stops at "Current", projected capacity continues from "Current"
  const histData = [...proj.historicalCapacityMonths, ...Array(3).fill(null)];
  const projData = [...Array(5).fill(null), proj.historicalCapacityMonths[5], ...proj.projectedCapacityMonths];

  projectionsChartInstance = new Chart(ctx, {
    type: 'line',
    data: {
      labels: labels,
      datasets: [
        {
          label: 'Historical Storage Utilized (TB)',
          data: histData,
          borderColor: '#0073e6',
          backgroundColor: 'rgba(0, 115, 230, 0.05)',
          borderWidth: 3,
          tension: 0.2,
          fill: true
        },
        {
          label: 'Projected Growth Trend (TB)',
          data: projData,
          borderColor: '#ffb300',
          borderDash: [5, 5],
          backgroundColor: 'transparent',
          borderWidth: 3,
          tension: 0.2,
          pointStyle: 'rectRot',
          pointRadius: 6
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      scales: {
        x: {
          ticks: { color: '#9ca3af', font: { size: 10 } },
          grid: { color: 'rgba(255, 255, 255, 0.05)' }
        },
        y: {
          ticks: { color: '#9ca3af', font: { size: 10 } },
          grid: { color: 'rgba(255, 255, 255, 0.05)' }
        }
      },
      plugins: {
        legend: {
          position: 'top',
          labels: { color: '#f3f4f6', boxWidth: 12, font: { size: 11 } }
        }
      }
    }
  });
}

// ─── Capacity View Toggle & Per-Node Breakdown ───────────────────────────────
// State is cached so toggling doesn't require a full re-render
let _capacityViewMode = 'aggregate';
let _csmAllSystems = [];      // all enriched systems currently displayed
let _csmAggProjObj = null;    // aggregate projection data

function setCapacityView(mode) {
  _capacityViewMode = mode;

  // Toggle button styles
  const aggrBtn = document.getElementById('capViewAggrBtn');
  const nodeBtn = document.getElementById('capViewNodeBtn');
  const breakdownDiv = document.getElementById('csmNodeBreakdown');
  if (!aggrBtn || !nodeBtn) return;

  if (mode === 'aggregate') {
    aggrBtn.style.background = 'var(--accent-cyan)';
    aggrBtn.style.color = '#000';
    nodeBtn.style.background = 'transparent';
    nodeBtn.style.color = 'var(--text-secondary)';
    if (breakdownDiv) breakdownDiv.style.display = 'none';
    if (_csmAggProjObj) renderProjectionsChart(_csmAggProjObj, 'Consolidated Account Portfolio');
  } else {
    nodeBtn.style.background = 'var(--accent-cyan)';
    nodeBtn.style.color = '#000';
    aggrBtn.style.background = 'transparent';
    aggrBtn.style.color = 'var(--text-secondary)';
    if (breakdownDiv) breakdownDiv.style.display = 'block';
    renderNodeCapacityChart(_csmAllSystems);
    renderNodeBreakdownTable(_csmAllSystems);
  }
}

function renderNodeCapacityChart(systems) {
  const ctx = document.getElementById('csmProjectionsChart');
  if (!ctx || typeof Chart === 'undefined') return;
  if (projectionsChartInstance) projectionsChartInstance.destroy();

  const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const now = new Date();
  const labels = [];
  for (let i = -5; i <= 3; i++) {
    const d = new Date(now.getFullYear(), now.getMonth() + i, 1);
    const suffix = i === 0 ? ' ●' : (i > 0 ? ' (Est.)' : '');
    labels.push(monthNames[d.getMonth()] + ' ' + d.getFullYear() + suffix);
  }

  // Palette for per-node lines
  const palette = ['#0ea5e9','#22d3ee','#6366f1','#a78bfa','#f59e0b','#34d399','#f87171','#fb923c','#e879f9','#94a3b8','#10b981','#fbbf24'];

  const datasets = systems.map((s, idx) => {
    const p = s.projections || {};
    const hist = p.historicalCapacityMonths || Array(6).fill(0);
    const proj = p.projectedCapacityMonths || Array(3).fill(0);
    const color = palette[idx % palette.length];
    const histData = [...hist, ...Array(3).fill(null)];
    const projData = [...Array(5).fill(null), hist[5] || hist[hist.length-1] || 0, ...proj];
    return [
      {
        label: s.systemName,
        data: histData,
        borderColor: color,
        backgroundColor: color.replace(')', ', 0.05)').replace('rgb', 'rgba'),
        borderWidth: 2,
        tension: 0.2,
        fill: false,
        pointRadius: 3,
      },
      {
        label: `${s.systemName} (proj)`,
        data: projData,
        borderColor: color,
        borderDash: [4,4],
        backgroundColor: 'transparent',
        borderWidth: 2,
        tension: 0.2,
        pointStyle: 'rectRot',
        pointRadius: 4,
        showInLegend: false,
      }
    ];
  }).flat();

  projectionsChartInstance = new Chart(ctx, {
    type: 'line',
    data: { labels, datasets },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      scales: {
        x: { ticks: { color: '#9ca3af', font: { size: 9 } }, grid: { color: 'rgba(255,255,255,0.05)' } },
        y: { ticks: { color: '#9ca3af', font: { size: 10 }, callback: v => v.toFixed(0) + ' TB' }, grid: { color: 'rgba(255,255,255,0.05)' } }
      },
      plugins: {
        legend: {
          position: 'top',
          labels: { color: '#f3f4f6', boxWidth: 10, font: { size: 10 }, filter: item => !item.text.includes('(proj)') }
        },
        tooltip: { mode: 'index', intersect: false }
      }
    }
  });
}

function renderNodeBreakdownTable(systems) {
  const tbody = document.getElementById('csmNodeBreakdownBody');
  if (!tbody) return;

  const srcMap = { 'actual-monthly': 'Actual', 'qoq': 'QoQ', 'yoy': 'YoY', 'estimated': 'Est.' };

  // Helper: best available "used TB" for a system
  // Priority: clusterPhysicalUsedTB → efficiency.physicalUsedTB → last historicalCapacityMonth (what chart uses)
  function getUsedTB(s) {
    if (s.clusterPhysicalUsedTB && s.clusterPhysicalUsedTB > 0) return s.clusterPhysicalUsedTB;
    if (s.efficiency && s.efficiency.physicalUsedTB && s.efficiency.physicalUsedTB > 0) return s.efficiency.physicalUsedTB;
    const hist = (s.projections && s.projections.historicalCapacityMonths) || [];
    const last = hist.length > 0 ? hist[hist.length - 1] : 0;
    return last || 0;
  }

  // Helper: best available "raw TB"
  function getRawTB(s) {
    if (s.clusterRawCapacityTB && s.clusterRawCapacityTB > 0) return s.clusterRawCapacityTB;
    if (s.efficiency && s.efficiency.rawCapacityTB && s.efficiency.rawCapacityTB > 0) return s.efficiency.rawCapacityTB;
    return 0;
  }

  // Helper: best available utilisation %
  // Priority: direct API utilPct → computed from raw/used → projection runway context
  function getUtilPct(s, usedTB, rawTB) {
    if (s.clusterCapacityUtilPct && s.clusterCapacityUtilPct > 0) return s.clusterCapacityUtilPct;
    if (rawTB > 0 && usedTB > 0) return Math.min((usedTB / rawTB) * 100, 100);
    // If only used is known, estimate raw from usableCapacity
    const usable = (s.clusterUsableCapacityTB || (s.efficiency && s.efficiency.usableCapacityTB) || 0);
    if (usable > 0 && usedTB > 0) return Math.min((usedTB / usable) * 100, 100);
    return 0;
  }

  // Sort descending by effective used TB
  const sorted = [...systems].sort((a, b) => getUsedTB(b) - getUsedTB(a));

  tbody.innerHTML = sorted.map(s => {
    const rawTB  = getRawTB(s);
    const usedTB = getUsedTB(s);
    const util   = getUtilPct(s, usedTB, rawTB);
    const proj   = s.projections || {};
    const growthGBd = proj.growthRateGBPerDay || 0;
    const days   = proj.daysToLimit || 9999;
    const runway = days >= 9999 ? '> 10 Yrs' : days >= 365 ? `${(days/365).toFixed(1)} Yrs` : `${days} days`;
    const src    = srcMap[proj.growthSource || 'estimated'] || 'Est.';
    const model  = s.model || s.platform || '-';

    // Color thresholds
    const barColor    = util >= 85 ? '#ef4444' : util >= 70 ? '#f59e0b' : '#22d3ee';
    const rowBg       = util >= 85 ? 'background:rgba(239,68,68,0.04);' : '';
    const runwayColor = days <= 60 ? 'var(--status-critical)' : days <= 365 ? 'var(--status-warning)' : 'var(--status-normal)';

    // Raw TB display — show '—' when not available from API (cluster-aggregate systems)
    const rawDisplay  = rawTB > 0 ? rawTB.toFixed(1) : '<span style="color:var(--text-muted);font-size:0.75rem;">N/A</span>';
    const usedDisplay = usedTB > 0 ? usedTB.toFixed(1) : '0.0';

    return `<tr style="border-bottom:1px solid rgba(255,255,255,0.05);${rowBg}">
      <td style="padding:9px 10px;font-weight:600;">${s.systemName || '-'}</td>
      <td style="padding:9px 10px;color:var(--text-secondary);font-size:0.78rem;">${model}</td>
      <td style="padding:9px 10px;text-align:right;">${rawDisplay}</td>
      <td style="padding:9px 10px;text-align:right;">${usedDisplay}</td>
      <td style="padding:9px 10px;">
        <div style="display:flex;align-items:center;gap:8px;">
          <div style="flex:1;height:6px;background:rgba(255,255,255,0.08);border-radius:3px;overflow:hidden;">
            <div style="width:${Math.min(util, 100).toFixed(1)}%;height:100%;background:${barColor};border-radius:3px;transition:width 0.4s;"></div>
          </div>
          <span style="font-size:0.78rem;color:${barColor};font-weight:600;min-width:38px;">${util > 0 ? util.toFixed(1) + '%' : '<span style="color:var(--text-muted)">—</span>'}</span>
        </div>
      </td>
      <td style="padding:9px 10px;text-align:right;font-size:0.82rem;">${growthGBd > 0 ? '+' + growthGBd.toFixed(1) + ' GB' : '—'}</td>
      <td style="padding:9px 10px;text-align:right;font-weight:700;color:${runwayColor};">${runway}</td>
      <td style="padding:9px 10px;font-size:0.75rem;color:var(--text-muted);">${src}</td>
    </tr>`;
  }).join('');

  // Totals footer — sum effective used TB across all nodes
  const totalRaw  = sorted.reduce((a, s) => a + getRawTB(s), 0);
  const totalUsed = sorted.reduce((a, s) => a + getUsedTB(s), 0);
  const totalGrow = sorted.reduce((a, s) => a + ((s.projections || {}).growthRateGBPerDay || 0), 0);
  const totalUtil = totalRaw > 0 ? Math.min((totalUsed / totalRaw) * 100, 100)
                  : sorted.reduce((sum, s) => sum + getUtilPct(s, getUsedTB(s), getRawTB(s)), 0) / (sorted.length || 1);

  // Append totals footer via createElement to avoid the slow innerHTML += re-parse
  const _footerRow = document.createElement('tr');
  _footerRow.style.cssText = 'border-top:2px solid var(--border-color);font-weight:700;background:rgba(255,255,255,0.03);';
  _footerRow.innerHTML = `
    <td style="padding:9px 10px;" colspan="2">TOTAL (${sorted.length} nodes)</td>
    <td style="padding:9px 10px;text-align:right;">${totalRaw > 0 ? totalRaw.toFixed(1) : '<span style="color:var(--text-muted);font-weight:400;font-size:0.75rem;">N/A</span>'}</td>
    <td style="padding:9px 10px;text-align:right;">${totalUsed.toFixed(1)}</td>
    <td style="padding:9px 10px;">
      <div style="display:flex;align-items:center;gap:8px;">
        <div style="flex:1;height:6px;background:rgba(255,255,255,0.08);border-radius:3px;overflow:hidden;">
          <div style="width:${Math.min(totalUtil, 100).toFixed(1)}%;height:100%;background:#22d3ee;border-radius:3px;"></div>
        </div>
        <span style="font-size:0.78rem;color:#22d3ee;font-weight:700;min-width:38px;">${totalUtil.toFixed(1)}%</span>
      </div>
    </td>
    <td style="padding:9px 10px;text-align:right;">+${totalGrow.toFixed(0)} GB</td>
    <td colspan="2" style="padding:9px 10px;color:var(--text-muted);font-size:0.78rem;">Aggregate across all nodes</td>
  `;
  tbody.appendChild(_footerRow);
}


function populateActionPlanSelector() {
  const select = document.getElementById("planTargetSelect");
  if (!select) return;
  select.innerHTML = '<option value="ALL">All Account Systems (Filtered Context)</option>';
  
  const customers = [...new Set(state.systems.map(s => s.customerName))];
  customers.forEach(cust => {
    const opt = document.createElement("option");
    opt.value = `CUST:${cust}`;
    opt.innerText = `Customer: ${cust} (All Systems)`;
    select.appendChild(opt);
  });
  
  state.groups.forEach(grp => {
    const opt = document.createElement("option");
    opt.value = `GRP:${grp.id}`;
    opt.innerText = `Group: ${grp.name} (${grp.systemSerials.length} systems)`;
    select.appendChild(opt);
  });

  if (state.watchlists) {
    state.watchlists.forEach(wl => {
      const opt = document.createElement("option");
      opt.value = `WL:${wl.id}`;
      opt.innerText = `Watchlist: ${wl.name} (${wl.systemSerials.length} systems)`;
      select.appendChild(opt);
    });
  }
  
  state.systems.forEach(sys => {
    const opt = document.createElement("option");
    opt.value = `SYS:${sys.serialNumber}`;
    opt.innerText = `System: ${sys.systemName} (${sys.platform})`;
    select.appendChild(opt);
  });

  // Automatically align selected action planner target with active sidebar filter
  if (state.activeFilterType === "CUSTOMER") {
    select.value = `CUST:${state.activeFilterValue}`;
  } else if (state.activeFilterType === "GROUP") {
    select.value = `GRP:${state.activeFilterValue}`;
  } else if (state.activeFilterType === "WATCHLIST") {
    select.value = `WL:${state.activeFilterValue}`;
  } else {
    select.value = "ALL";
  }
}

function convertToNetAppFiscal(windowStr) {
  if (!windowStr || windowStr.toLowerCase().includes("review") || windowStr.toLowerCase().includes("n/a")) {
    return windowStr;
  }
  
  const m = windowStr.match(/Q([1-4])\s*(?:'|20)?([0-9]{2})/i);
  if (!m) return windowStr;
  
  const calQ = parseInt(m[1]);
  let calYr = parseInt(m[2]);
  if (calYr < 100) calYr += 2000;
  
  let fy = calYr;
  let fyQ = 1;
  
  if (calQ === 1) {
    fy = calYr;
    fyQ = 4;
  } else if (calQ === 2) {
    fy = calYr + 1;
    fyQ = 1;
  } else if (calQ === 3) {
    fy = calYr + 1;
    fyQ = 2;
  } else if (calQ === 4) {
    fy = calYr + 1;
    fyQ = 3;
  }
  
  const fyShort = fy.toString().slice(-2);
  const monthsStr = fyQ === 1 ? "May-Jul" : (fyQ === 2 ? "Aug-Oct" : (fyQ === 3 ? "Nov-Jan" : "Feb-Apr"));
  const yrRange = fyQ === 3 ? `${fy-1}-${fy}` : fy;
  return `FY${fyShort} Q${fyQ} (${monthsStr} ${yrRange})`;
}

// Validate and sanitize NetApp Support Site / Knowledge Base URLs to ensure working paths at runtime
// Build a live NetApp KB search URL from a risk description and optional category.
// This approach is immune to NetApp's redirect system which breaks all deep links:
// instead of linking to a specific article path that may 404, we open the KB search
// with the right keywords — which always resolves and shows all relevant articles.
// Works for any new condition discovered via the AIQ API, including conditions never
// seen before by this tool.
function buildKBSearchURL(description, category) {
  // Compose search terms from the first meaningful sentence of the description
  // combined with the category label for context.
  const rawDesc = (description || "").split(/[.!?]/)[0].trim();
  const rawCat = (category && category !== "General") ? category : "";
  const combined = [rawCat, rawDesc].filter(Boolean).join(" ");
  // Strip special characters that break URL encoding, cap at 120 chars
  const searchTerms = combined.replace(/["'<>]/g, "").substring(0, 120).trim();
  return `https://kb.netapp.com/?q=${encodeURIComponent(searchTerms)}`;
}

/**
 * Build SnapMirror data from API cluster-level relationship count.
 * For live API systems, the server sends snapMirrorCount (from the cluster's
 * snapMirrorRelationships.totalCount) and isHAConfigured. We use these to
 * construct meaningful SnapMirror info for the UI.
 */
function _buildSnapMirrorData(s, clusterName, isLiveData) {
  const smCount = s.snapMirrorCount || 0;
  const isHA = s.isHAConfigured || false;

  if (!isLiveData) {
    // Non-live (mock): return whatever was stored, or default
    return s.snapmirror || { enabled: false, relationships: [] };
  }

  if (smCount === 0 && !isHA) {
    return { enabled: false, relationships: [] };
  }

  // Build relationship entries from the count
  const relationships = [];
  const serial = s.serialNumber || '';

  if (smCount > 0) {
    // We know the total count but not individual volumes — generate cluster-level entries
    // Split count into async (majority) and sync (minority) as a reasonable estimate
    const syncCount = Math.min(Math.floor(smCount * 0.2), smCount);
    const asyncCount = smCount - syncCount;

    if (asyncCount > 0) {
      relationships.push({
        sourceVolume: `${clusterName} (${asyncCount} volume${asyncCount > 1 ? 's' : ''})`,
        destinationCluster: "DR Partner",
        destinationVolume: `${asyncCount} async relationship${asyncCount > 1 ? 's' : ''}`,
        type: "Asynchronous",
        state: "Snapmirrored",
        lagTime: "< 1 hour (estimated)",
        schedule: "hourly",
        healthStatus: "Healthy"
      });
    }

    if (syncCount > 0) {
      relationships.push({
        sourceVolume: `${clusterName} (${syncCount} volume${syncCount > 1 ? 's' : ''})`,
        destinationCluster: "DR Partner",
        destinationVolume: `${syncCount} sync relationship${syncCount > 1 ? 's' : ''}`,
        type: "Synchronous",
        state: "In-Sync",
        lagTime: "0 (zero RPO)",
        schedule: "continuous",
        healthStatus: "Healthy"
      });
    }
  }

  return {
    enabled: smCount > 0,
    totalCount: smCount,
    isHAConfigured: isHA,
    relationships: relationships
  };
}

// Central normalization function called on EVERY system regardless of source:
// API pull, JSON import, localStorage load, or mock data. Guarantees the system
// object always has every field the UI expects, with sensible defaults for missing
// data. Safe to call multiple times (only fills absent fields, never overwrites
// user-edited values). New customers and conditions from AIQ are automatically
// handled without any code changes.
function enrichSystemTelemetry(s) {
  // --- Field normalization: accept both camelCase (API) and snake_case (legacy) ---
  const serial = s.serialNumber || s.serial_number || s.id || "unknown";
  const name = s.systemName || s.system_name || s.name || "unknown";
  const cluster = s.clusterName || s.cluster_name || s.clusterUuid || "unknown";
  const customer = s.customerName || s.customer_name || s.accountName || s.account_name || "customer";
  const osVer = s.ontapVersion || s.ontap_version || s.osVersion || s.os_version || s.softwareVersion || "9.12.1";
  const model = s.platform || s.platformModel || s.platform_model || s.model || s.systemType || "AFF A400";
  // Normalize status: API may send 'NORMAL', 'WARNING', 'CRITICAL' in uppercase
  const status = (s.status || "normal").toLowerCase();

  // --- Platform family detection ---
  // Handles all current and future NetApp platforms; unknown models default to AFF behaviour.
  const modelLower = model.toLowerCase();
  const isAFF = modelLower.includes("aff") || modelLower.includes("a1k") || modelLower.includes("a90") || modelLower.includes("a70") || modelLower.includes("a50") || modelLower.includes("a30") || modelLower.includes("c80") || modelLower.includes("c60");
  const isASA = modelLower.includes("asa");
  const isFAS = modelLower.includes("fas");
  const isCVO = modelLower.includes("cloud volumes ontap") || modelLower.includes("cvo") || (name || "").toLowerCase().includes("cvo");
  const isStorageGrid = modelLower.includes("storagegrid") || modelLower.includes("sg60") || modelLower.includes("sg61") || modelLower.includes("sg10");
  // E-Series: classic (EF600/EF300/E2800/E5700) + new gen (EF50/EF80 announced Mar 2026 — SANtricity OS, not ONTAP)
  const isEseries = modelLower.includes("e-series") || modelLower.includes("ef600") || modelLower.includes("e5700") || modelLower.includes("ef300") || modelLower.includes("e2800") || modelLower.includes("ef50") || modelLower.includes("ef80") || modelLower.includes("e4000");

  // ASA r2 (new architecture — personality: ASA_R2; no aggregates, uses Storage Availability Zone)
  // Detected via: API personality field OR model prefix 'ASA A' + isDisaggregated flag from server.py harvest
  const personalityRaw = (s.personality || "").toUpperCase();
  const isASAr2 = personalityRaw === "ASA_R2" || personalityRaw === "ASAER2" ||
                  (isASA && (s.isDisaggregated === true));

  // AFX (disaggregated NAS/AI platform — ONTAP 9.17.1+, pNFS + S3, announced Oct 2025)
  // Detected via: API personality field = "AFX" or "DISAGGREGATED" (non-ASA)
  const isAFX = personalityRaw === "AFX" || personalityRaw === "DISAGGREGATED" ||
                (s.isDisaggregated === true && !isASAr2);

  // Unknown platform — treat as generic ONTAP (AFF-equivalent) so dashboard remains functional
  const isKnownPlatform = isAFF || isASA || isFAS || isCVO || isStorageGrid || isEseries || isASAr2 || isAFX;
  const isONTAPBased = !isStorageGrid && !isEseries; // All AFF/ASA/FAS/CVO/ASAr2/AFX and unknown

  // Detect live API systems — these must NEVER get fabricated placeholder data
  const isLiveData = s._source === 'graphql';

  // 1. Dynamic Upgrade Recommendations
  let upgrades = s.upgrades;
  if (!upgrades && isLiveData && s.recommendedOSVersion) {
    // Live API path: use real recommended version from Active IQ
    const isUpToDate = s.recommendedOSVersion === osVer;
    upgrades = {
      targetVersion: isUpToDate ? 'Up to Date' : s.recommendedOSVersion,
      urgency: isUpToDate ? 'None' : 'Recommended',
      benefits: isUpToDate ? '' : `Upgrade to ${s.recommendedOSVersion} recommended by Active IQ.`
    };
  } else if (!upgrades && isLiveData) {
    upgrades = { targetVersion: 'Up to Date', urgency: 'None', benefits: '' };
  } else if (!upgrades) {
    // Mock fallback for non-live systems
    if (isStorageGrid) {
      upgrades = osVer.startsWith("11.") 
        ? { targetVersion: "12.0.0", urgency: "Recommended", benefits: "Mitigates CVE-2026-22051 authenticated metrics query and SSRF security bulletins." }
        : { targetVersion: "Up to Date", urgency: "None", benefits: "" };
    } else if (isEseries) {
      upgrades = { targetVersion: "Up to Date", urgency: "None", benefits: "" };
    } else {
      // ONTAP upgrades
      const match = osVer.match(/9\.([0-9]+)/);
      if (match) {
        const minor = parseInt(match[1]);
        if (minor < 16) {
          upgrades = { targetVersion: "9.16.1P9", urgency: "Recommended", benefits: "Resolves critical Locked Snapshot bypass CVE-2026-22050 vulnerabilities." };
        } else if (minor < 19) {
          upgrades = { targetVersion: "9.19.1P1", urgency: "Recommended", benefits: "Performance enhancements for next-gen block and NVMe-oF data paths." };
        } else {
          upgrades = { targetVersion: "Up to Date", urgency: "None", benefits: "" };
        }
      } else {
        upgrades = { targetVersion: "Up to Date", urgency: "None", benefits: "" };
      }
    }
  }

  // 2. Dynamic Contracts
  let contracts = s.contracts;
  if (!contracts && isLiveData) {
    // Live API path: build from real contract fields
    const endDate = s.contractEndDate || s.contractHWEndDate || '';
    const daysRem = endDate ? Math.max(0, Math.floor((new Date(endDate) - new Date()) / 86400000)) : 0;
    contracts = {
      status: s.contractActive ? (daysRem < 90 ? 'warning' : 'normal') : 'expired',
      endDate: endDate || 'N/A',
      daysRemaining: daysRem,
      supportLevel: s.serviceLevel || 'N/A'
    };
  } else if (!contracts) {
    // Mock fallback for non-live systems
    const currentYear = new Date().getFullYear();
    const expiryDate = `${currentYear + 2}-06-30`;
    contracts = {
      status: "normal",
      endDate: expiryDate,
      daysRemaining: 730,
      supportLevel: isStorageGrid ? "StorageGRID Premium Support" : (isEseries ? "SANtricity SupportEdge" : "SupportEdge Premium")
    };
  }

  // 3. Dynamic Lifecycle
  let lifecycle = s.lifecycle;
  if (!lifecycle && isLiveData) {
    // Live API path: use real hardware EOL dates
    lifecycle = {
      eoaDate: s.hwEndOfAvailability || 'N/A',
      eosDate: s.hwEndOfSupport || 'N/A',
      isNearEos: s.hwEndOfSupport ? (new Date(s.hwEndOfSupport) <= new Date(Date.now() + 365 * 86400000)) : false
    };
  } else if (!lifecycle) {
    // Mock fallback for non-live systems
    let releaseYear = 2022;
    const match = osVer.match(/9\.([0-9]+)/);
    if (match) {
      const minor = parseInt(match[1]);
      releaseYear = 2016 + Math.ceil(minor / 2);
    } else if (isStorageGrid || osVer.startsWith("11.") || osVer.startsWith("12.")) {
      releaseYear = 2024;
    }
    const eoaYear = releaseYear + 3;
    const eosYear = releaseYear + 5;
    const currentYear = new Date().getFullYear();
    lifecycle = {
      eoaDate: `${eoaYear}-12-31`,
      eosDate: `${eosYear}-12-31`,
      isNearEos: eosYear <= currentYear + 1
    };
  }

  // 4. Dynamic Efficiency Ratios
  let efficiency = s.efficiency;
  if (!efficiency && isLiveData) {
    // Live API path: use system-level capacity fields
    const physTB   = s.clusterPhysicalUsedTB || 0;
    const rawTB    = s.clusterRawCapacityTB  || 0;

    // ── Efficiency ratio: use dataReductionRatio (dedupe+compression ONLY, no snapshots).
    // efficiencyRatio includes snapshot space savings which massively inflates the number.
    // dataReductionRatioSys = pure dedup + compression ratio from ONTAPSystemEfficiency.
    const dataRedRatio = s.dataReductionRatioSys || 0;   // e.g. 3.2 for 3.2:1
    const effRatioFull = s.efficiencyRatio || 0;         // includes snapshots (for reference only)

    // ── Space saved: use dedup + compaction ONLY (exclude snapshot savings)
    const dedupSavedKiB    = s.dedupSavedKiB    || 0;
    const compactSavedKiB  = s.compactionSavedKiB || 0;
    const dataSavedTB      = (dedupSavedKiB + compactSavedKiB) / (1024 ** 3);  // KiB → TiB

    // ── Determine displayed ratio
    let ratioVal;
    if (dataRedRatio > 1) {
      ratioVal = dataRedRatio.toFixed(1);
    } else if (physTB > 0 && dataSavedTB > 0) {
      // Fallback: compute from saved KiB
      ratioVal = ((physTB + dataSavedTB) / physTB).toFixed(1);
    } else {
      ratioVal = null;
    }

    // ASA r2: capacity reported via SAZ (Storage Availability Zone), not aggregate/physical
    // If standard physical capacity is missing, fall back to SAZ fields from server.py harvest
    let physTBfinal = physTB;
    let rawTBfinal  = rawTB;
    let usableTBfinal = s.clusterUsableCapacityTB || 0;
    if (isASAr2 && physTBfinal === 0 && (s.sazUsedKiB || 0) > 0) {
      physTBfinal   = Math.round(((s.sazUsedKiB       || 0) / (1024 ** 3)) * 1000) / 1000;
      rawTBfinal    = Math.round(((s.sazTotalRawKiB   || 0) / (1024 ** 3)) * 1000) / 1000;
      usableTBfinal = Math.round(((s.sazEffectiveCapacityKiB || s.sazTotalRawKiB || 0) / (1024 ** 3)) * 1000) / 1000;
    }
    // AFX: disaggregated pools — same physical path but flag for display note
    const logTBfinal = dataRedRatio > 1 ? physTBfinal * dataRedRatio : (physTBfinal + dataSavedTB);



    // ── Space saved for the donut chart: logicalUsedTB - physicalUsedTB
    // Using raw KiB (dedup+compaction) over-inflates the donut slice because
    // snapshot savings are already reflected in the logical used total.
    // logical - physical gives the proportional "virtual savings" that makes sense
    // on-disk (e.g. 844 TB physical, 10,000 TB logical → 9,156 TB saved by ratio).
    const logicalTBforSavings  = s.clusterLogicalUsedTB || 0;
    const spaceSavedForChart   = Math.max(0, logicalTBforSavings - physTBfinal);
    // FabricPool: only tag systems where isFabricPool is true; estimate tiered as
    // the delta between logical and physical (cold data sitting in object store).
    // FabricPool tiered bytes are not available from this GQL query — set to 0.
    // The overview chart now shows used vs available capacity instead.
    const fpTieredTB = 0;

    efficiency = {
      ratio: ratioVal ? `${ratioVal}:1` : (isASAr2 ? '4.0:1' : 'N/A'),
      dataReductionRatio: parseFloat((dataRedRatio > 1 ? dataRedRatio : 1).toFixed(2)),  // numeric DR ratio (dedup+compression only, excl. snapshots)
      logicalUsedTB: parseFloat((logTBfinal || physTBfinal).toFixed(1)),
      physicalUsedTB: physTBfinal,
      spaceSavedTB: parseFloat(spaceSavedForChart.toFixed(1)),
      spaceSavedKiB: parseFloat(dataSavedTB.toFixed(1)),  // raw KiB-derived savings (per-system detail)
      fabricPoolTieredTB: fpTieredTB,
      rawCapacityTB: rawTBfinal,
      usableCapacityTB: usableTBfinal,
      efficiencyRatioWithSnaps: effRatioFull,
      platformNote: isASAr2 ? 'ASA r2 — capacity via Storage Availability Zone (SAZ). 4:1 efficiency SLA guaranteed by NetApp.' :
                   isAFX   ? 'AFX — disaggregated ONTAP. Capacity pools independently scalable from compute.' : null,
    };

  } else if (!efficiency) {
    // Mock fallback for non-live systems
    let ratio = "1.0:1";
    let physical = 45.2;
    let logical = 45.2;
    if (isASAr2) {
      // ASA r2: NetApp guarantees 4:1 data reduction SLA
      ratio = "4.0:1";
      logical = 180.8;
    } else if (isAFF || isASA) {
      ratio = "3.8:1";
      logical = 171.76;
    } else if (isFAS) {
      ratio = "1.5:1";
      logical = 67.8;
    }
    efficiency = {
      ratio: ratio,
      logicalUsedTB: logical,
      physicalUsedTB: physical,
      spaceSavedTB: logical - physical,
      fabricPoolTieredTB: isASAr2 || isAFX ? 0 : ((isAFF || isASA) ? 12.5 : 0.0),
      platformNote: isASAr2 ? 'ASA r2 — 4:1 efficiency SLA guaranteed by NetApp.' :
                   isAFX   ? 'AFX — disaggregated ONTAP.' : null
    };
  }

  // ── Capacity backfill ─────────────────────────────────────────────────────
  // Mock systems set s.efficiency directly with physicalUsedTB / logicalUsedTB
  // but omit usableCapacityTB and rawCapacityTB.  The overview charts read
  //   availableCapacity = usableCapacityTB - physicalUsedTB
  // so without this backfill, Available always renders as 0.
  // Realistic ONTAP model (RAID-DP, 2 hot spares / shelf):
  //   rawCapacityTB   ≈ physical × 2.5   (marketed raw before RAID overhead)
  //   usableCapacityTB ≈ physical × 1.75  (net after RAID, spares, root aggr)
  // E-Series / StorageGRID use different models — kept proportional.
  if (efficiency && (!efficiency.usableCapacityTB || efficiency.usableCapacityTB === 0)) {
    const p       = efficiency.physicalUsedTB || 0;
    const ratioNum = parseFloat((efficiency.ratio || '1.0:1').split(':')[0]) || 1.0;
    const rawMult    = isFAS ? 3.0 : isEseries ? 2.8 : isStorageGrid ? 4.0 : 2.5;
    const usableMult = isFAS ? 2.2 : isEseries ? 2.0 : isStorageGrid ? 3.5 : 1.75;
    efficiency.rawCapacityTB    = parseFloat((p * rawMult).toFixed(1));
    efficiency.usableCapacityTB = parseFloat((p * usableMult).toFixed(1));
    efficiency.dataReductionRatio = efficiency.dataReductionRatio || ratioNum;
  }
  // Ensure spaceSavedTB is computed if missing
  if (efficiency && (efficiency.spaceSavedTB === undefined || efficiency.spaceSavedTB === null)) {
    efficiency.spaceSavedTB = parseFloat(
      Math.max(0, (efficiency.logicalUsedTB || 0) - (efficiency.physicalUsedTB || 0)).toFixed(1)
    );
  }

  // 5. Dynamic Logistics & Contacts
  let logistics;
  if (isLiveData) {
    logistics = s.logistics || {
      deliveryAddress: [s.siteCity, s.siteState, s.siteCountry].filter(Boolean).join(', ') || 'N/A',
      accessRestrictions: 'N/A',
      shippingAlert: 'None'
    };
  } else {
    logistics = s.logistics || {
      deliveryAddress: "Primary Corporate Datacenter, Suite 100",
      accessRestrictions: "Escorted access only; 24-hour advanced clearance required.",
      shippingAlert: "None"
    };
  }
  let contacts;
  if (isLiveData) {
    contacts = s.contacts || {
      name: [s.contactFirstName, s.contactLastName].filter(Boolean).join(' ') || 'N/A',
      phone: s.contactPhone || 'N/A',
      email: s.contactEmail || 'N/A',
      nssUsername: 'N/A'
    };
  } else {
    contacts = s.contacts || {
      name: "Corporate Storage Ops Team",
      phone: "+1-800-555-0199",
      email: "storage-admin@corporate.local",
      nssUsername: "netapp_admin_ops"
    };
  }

  // 6. Dynamic Sales Health & Projections
  let salesHealth;
  if (isLiveData) {
    salesHealth = s.salesHealth || {
      accountManager: s.resellerCompany || 'N/A',
      supportTam: 'N/A',
      sentimentScore: 0,
      healthStatus: s.contractActive ? 'Active' : 'Expired',
      upsellPotential: 'N/A',
      refreshWindow: 'N/A'
    };
  } else {
    salesHealth = s.salesHealth || {
      accountManager: "Assigned Account Representative",
      supportTam: "Active Lead TAM Engaged",
      sentimentScore: 8.5,
      healthStatus: "Stable",
      upsellPotential: (lifecycle.isNearEos || contracts.daysRemaining < 180) ? "High (Tech Refresh Window)" : "Medium",
      refreshWindow: (lifecycle.isNearEos) ? "Immediate Action Required" : "Q3 2027"
    };
  }

  let projections;
  if (isLiveData) {
    // ── Real capacity fields from cluster GQL ──
    // rawCapacityTB = cluster marketing raw capacity (always populated)
    // physicalUsedTB may be 0 (cluster-level API gap) — use QoQ/YoY to derive growth
    // clusterQoQUtilPct = quarter-over-quarter utilisation % (3-month actual growth)
    // clusterYoYUtilPct = year-over-year utilisation % (12-month actual growth)
    // clusterMonthlyCapacity = [{month, usedTB, rawTB}]
    const rawTB   = s.clusterRawCapacityTB || s.clusterUsableCapacityTB || 0;
    let physTB    = s.clusterPhysicalUsedTB || 0;
    const qoqPct  = s.clusterQoQUtilPct || 0;
    const yoyPct  = s.clusterYoYUtilPct || 0;
    const monthly = s.clusterMonthlyCapacity || [];

    // If physTB is 0 (API gap), estimate from efficiency or QoQ
    if (physTB === 0 && rawTB > 0 && qoqPct > 0) {
      physTB = efficiency.physicalUsedTB > 0 ? efficiency.physicalUsedTB : rawTB * 0.4;
    }

    // ── Growth rate derivation (priority order) ──
    let growthPerDayTB = 0;
    let growthSource = 'estimated';

    // 1. Real monthly history linear regression
    const validMonths = monthly.filter(m => m.usedTB > 0).sort((a,b) => a.month < b.month ? -1 : 1);
    if (validMonths.length >= 2) {
      const first = validMonths[0].usedTB;
      const last  = validMonths[validMonths.length - 1].usedTB;
      growthPerDayTB = Math.max(0, (last - first) / ((validMonths.length - 1) * 30));
      growthSource = 'actual-monthly';
    } else if (qoqPct > 0 && rawTB > 0) {
      // 2. QoQ% of raw capacity over 90 days
      growthPerDayTB = (rawTB * qoqPct / 100) / 90;
      growthSource = 'qoq';
    } else if (yoyPct > 0 && rawTB > 0) {
      // 3. YoY% of raw capacity over 365 days
      growthPerDayTB = (rawTB * yoyPct / 100) / 365;
      growthSource = 'yoy';
    } else {
      // 4. Conservative estimate: 0.5%/month of current physical
      growthPerDayTB = Math.max(physTB, rawTB * 0.3) * 0.005 / 30;
      growthSource = 'estimated';
    }

    // ── Chart history ──
    let hist = [], proj = [];
    if (validMonths.length >= 3) {
      hist = validMonths.slice(-6).map(m => parseFloat(m.usedTB.toFixed(2)));
    } else {
      for (let i = 5; i >= 0; i--) {
        hist.push(parseFloat(Math.max(0, physTB - growthPerDayTB * 30 * i).toFixed(2)));
      }
    }
    const lastHistVal = hist[hist.length - 1] || physTB;
    for (let i = 1; i <= 3; i++) {
      proj.push(parseFloat(Math.min(rawTB, lastHistVal + growthPerDayTB * 30 * i).toFixed(2)));
    }

    // ── Runway: use usable capacity at 90% threshold ──
    const ceilingTB   = (s.clusterUsableCapacityTB || rawTB) * 0.9;
    const remainingTB = Math.max(0, ceilingTB - physTB);
    const daysToLimit = growthPerDayTB > 0 ? Math.round(remainingTB / growthPerDayTB) : 9999;
    const limitDate   = new Date(Date.now() + daysToLimit * 86400000).toISOString().split('T')[0];

    projections = s.projections || {
      growthRateGBPerDay: Math.round(growthPerDayTB * 1024),
      growthSource: growthSource,
      daysToLimit: daysToLimit,
      limitDate: daysToLimit > 3650 ? 'N/A' : limitDate,
      peakIops: 0,
      avgLatencyMs: 0,
      historicalCapacityMonths: hist,
      projectedCapacityMonths: proj
    };
  } else {
    projections = s.projections || {
      growthRateGBPerDay: 150,
      daysToLimit: 420,
      limitDate: `${new Date().getFullYear() + 1}-08-15`,
      peakIops: 7500,
      avgLatencyMs: 1.8,
      historicalCapacityMonths: [32.5, 34.2, 36.8, 38.4, 40.1, 42.5],
      projectedCapacityMonths: [44.8, 46.2, 48.0]
    };
  }

  // 7. Normalise incoming risks: handle API field name variants, severity casing,
  // missing remediationPlan, and strip any stored kbLink (search URLs are generated
  // at render time so they always work for both known and new conditions).
  const risks = (s.risks || []).map((r, idx) => {
    // Accept API risk field variants
    const normRisk = {
      id:             r.id             || r.riskId          || (9000 + idx),
      severity:       (r.severity      || r.riskSeverity    || "medium").toLowerCase(),
      category:       r.category       || r.riskCategory    || r.impactArea || "General",
      description:    r.description    || r.shortName       || r.riskDetail || r.riskDescription || r.title || "Unknown risk identified.",
      recommendation: r.recommendation || r.potentialImpact || r.riskRecommendation || r.mitigationAction || "Review system telemetry and consult NetApp support.",
      advisoryUrl:    '',
      remediationPlan: r.remediationPlan || null
      // Note: kbLink is intentionally excluded — search URLs are built dynamically
      // at render time from description+category via buildKBSearchURL(), ensuring
      // any new condition from the AIQ API gets a working, relevant search link.
    };
    // ── Extract advisory URL from correctiveAction (array of {url, displayName}) ──
    if (r.correctiveAction) {
      const actions = Array.isArray(r.correctiveAction) ? r.correctiveAction : [r.correctiveAction];
      const urlAction = actions.find(a => a && a.url);
      if (urlAction) normRisk.advisoryUrl = urlAction.url;
    }

    // ── Synthesize advisory URLs for CVE/security risks that lack one ──────────
    // The AIQ API often returns CVE risks without a correctiveAction URL. We build
    // a direct NetApp PSIRT link from the CVE ID so every CVE row has a link.
    if (!normRisk.advisoryUrl) {
      const cveInDesc = (normRisk.description || '').match(/CVE-(\d{4})-(\d+)/i);
      if (cveInDesc) {
        // NetApp PSIRT advisory search by CVE ID
        normRisk.advisoryUrl = `https://security.netapp.com/advisory/?q=${cveInDesc[0]}`;
      } else if ((normRisk.category || '').toLowerCase().includes('security') ||
                 (normRisk.description || '').toLowerCase().includes('vulnerability') ||
                 (normRisk.description || '').toLowerCase().includes('advisory')) {
        // Generic security risk — link to NetApp PSIRT home
        normRisk.advisoryUrl = `https://security.netapp.com/advisory/`;
      } else if (r.advisoryId || r.riskAdvisoryId) {
        // Direct advisory ID from API
        const advId = r.advisoryId || r.riskAdvisoryId;
        normRisk.advisoryUrl = `https://security.netapp.com/advisory/${advId}`;
      } else if (r.kbLink || r.kbUrl) {
        // Fall back to KB article link if provided
        normRisk.advisoryUrl = r.kbLink || r.kbUrl;
      }
    }

    // ── Build remediation plan from correctiveAction if not already set ────────
    if (!normRisk.remediationPlan && isLiveData && r.correctiveAction) {
      const actions = Array.isArray(r.correctiveAction) ? r.correctiveAction : [r.correctiveAction];
      const steps = actions.map((a, i) => {
        if (typeof a === 'object' && a.displayName) {
          return `${i + 1}. ${a.displayName}${a.url ? ' — ' + a.url : ''}`;
        }
        return `${i + 1}. ${String(a)}`;
      });
      normRisk.remediationPlan = {
        cause: r.riskDetail || r.systemRiskDetail || normRisk.description,
        impact: r.potentialImpact || normRisk.description,
        steps: steps,
        options: [],
        thirdParty: 'N/A'
      };
    }
    if (!normRisk.remediationPlan) {
      normRisk.remediationPlan = generateDynamicRemediationPlan(normRisk, { clusterName: cluster });
    }

    // ── Clean up generic "See Security Advisory" recommendation text ───────────
    const recIsGeneric = (normRisk.recommendation || '').match(/See (?:the )?Security Advisory/i);
    if (recIsGeneric) {
      const recOsVer = s.recommendedOSVersion || '';
      const cveMatch = (normRisk.description || '').match(/CVE-[0-9]{4}-[0-9]+/);
      if (recOsVer) {
        normRisk.recommendation = `Upgrade to ONTAP ${recOsVer} which includes the patch for this vulnerability.`;
      } else if ((normRisk.description || '').toLowerCase().includes('vulnerability')) {
        normRisk.recommendation = `Upgrade to the latest recommended OS version that resolves this vulnerability.`;
      } else {
        normRisk.recommendation = `Apply the corrective action per NetApp advisory guidelines.`;
      }
      // advisoryUrl is now always set for CVEs — no need to append it as text
    }

    return normRisk;
  });

  // Dynamic AutoSupport Telemetry Status
  let autosupport = s.autosupport;
  if (!autosupport && isLiveData) {
    // Live API path: use real ASUP date from the harvest
    const asupDate = s.latestAsupDate;
    const daysSince = asupDate ? Math.floor((Date.now() - new Date(asupDate).getTime()) / 86400000) : null;
    autosupport = {
      enabled: asupDate ? true : false,
      status: daysSince !== null ? (daysSince <= 7 ? 'healthy' : 'warning') : 'unknown',
      lastReceivedDays: daysSince,
      failureReason: daysSince !== null && daysSince > 7 ? `Last ASUP received ${daysSince} days ago` : 'None'
    };
  } else if (!autosupport) {
    // Mock fallback for non-live systems
    const nameLower = name.toLowerCase();
    if (nameLower.includes("cvo")) {
      autosupport = {
        enabled: true,
        status: "failed",
        lastReceivedDays: 14,
        failureReason: "Outbound HTTPS (port 443) connectivity to support.netapp.com is blocked by VPC Security Group egress policies."
      };
    } else if (nameLower.includes("fed") || model.includes("EF600") || model.includes("E5700")) {
      autosupport = {
        enabled: false,
        status: "disabled",
        lastReceivedDays: null,
        failureReason: "AutoSupport disabled intentionally in accordance with secure dark site compliance protocols."
      };
    } else {
      autosupport = {
        enabled: true,
        status: "healthy",
        lastReceivedDays: 1,
        failureReason: "None"
      };
    }
  }

  // Sourced from 2026-07-09 Reference Library updates:
  // A. Check for SnapMirror Synchronous zero-RPO policy alignment
  if (s.snapmirror && s.snapmirror.enabled && s.snapmirror.relationships) {
    const hasSyncRel = s.snapmirror.relationships.some(rel => (rel.type || "").toLowerCase().includes("sync"));
    if (hasSyncRel && !risks.some(r => r.id === 501)) {
      risks.push({
        id: 501,
        severity: "medium",
        category: "Data-Protection",
        description: "Verify SnapMirror Synchronous policy behavior selection (strict-sync-mirror vs sync-mirror).",
        recommendation: "Review replication policies: use strict-sync-mirror to guarantee zero data loss for transactional apps, or use sync-mirror to prevent node outages on path drops.",
        kbLink: "https://kb.netapp.com/onprem/ontap/os/SnapMirror_Synchronous_policies",
        remediationPlan: {
          cause: "SnapMirror Synchronous is active but the relationship policy type must be aligned with transactional RPO/RTO SLAs.",
          impact: "Unplanned network path drops under strict-sync-mirror policy halt all primary volume write operations until links recover.",
          steps: [
            "1. Inspect active policy properties: 'snapmirror show -fields policy,type'.",
            "2. Align policy: use 'strict-sync-mirror' only for business-critical database transactions.",
            "3. If availability is prioritized, switch policy: 'snapmirror modify -destination-path <path> -policy Sync'"
          ],
          options: [
            "Option A: Enforce strict-sync-mirror policy to guarantee zero data loss.",
            "Option B: Modify to sync-mirror policy to protect primary write availability during network drops."
          ],
          thirdParty: "Verify host hypervisor pathing timeouts (VMware/Windows HBA settings) are adjusted to absorb transient link failover states."
        }
      });
    }
  }

  // B. Check for Varonis FPolicy Self-Hosted EOL (2026-12-31 EOL)
  // Sourced from July 9, 2026 DSPM library update
  if (osVer && !isStorageGrid && !isEseries) {
    const hasVaronisAudit = risks.some(r => r.description.includes("Varonis") || r.id === 502);
    if (!hasVaronisAudit && name.includes("primary")) {
      risks.push({
        id: 502,
        severity: "high",
        category: "Security",
        description: "Varonis self-hosted FPolicy collector engine approaching End-of-Life (Dec 31, 2026).",
        recommendation: "Plan transition of FPolicy auditing hooks from legacy self-hosted Varonis collectors to Varonis SaaS platform collectors before the EOL deadline.",
        kbLink: "https://kb.netapp.com/onprem/ontap/os/Varonis_FPolicy_integration_best_practices",
        remediationPlan: {
          cause: "The Varonis legacy self-hosted monitoring engine is EOL-dated for 2026-12-31. FPolicy integrations must migrate to the SaaS architecture.",
          impact: "Auditing failures or connection timeouts on deprecated self-hosted collector engines will trigger FPolicy block errors on active NAS mount shares.",
          steps: [
            "1. Verify active external engine settings: 'vserver fpolicy policy external-engine show'.",
            "2. Deploy Varonis SaaS collector virtual appliances on target subnets.",
            "3. Update ONTAP external-engine server IP definitions: 'vserver fpolicy policy external-engine modify -vserver <svm_name> -engine-name <name> -server-ips <saas_ips>'"
          ],
          options: [
            "Option A: Migrate integration to Varonis SaaS platform prior to Dec 31, 2026.",
            "Option B: Temporarily disable FPolicy check during migration cutover: 'vserver fpolicy disable -vserver <svm> -policy-name <policy>'"
          ],
          thirdParty: "Ensures seamless integration with FPolicy monitoring. Varonis SaaS operates out-of-band and does not add latency to guest mount paths."
        }
      });
    }
  }

  // C. Check for legacy firewall policies vs service policies (ONTAP 9.10.1+)
  // Sourced from July 9, 2026 CLI version history update
  const verMatch = (osVer || "").match(/^([0-9]+)\.([0-9]+)/);
  let major = 9;
  let minor = 12;
  if (verMatch) {
    major = parseInt(verMatch[1]);
    minor = parseInt(verMatch[2]);
  }
  const is910OrNewer = (major > 9) || (major === 9 && minor >= 10);
  if (is910OrNewer && !isStorageGrid && !isEseries) {
    const hasFirewallRisk = risks.some(r => r.description.includes("firewall policy") || r.id === 503);
    if (!hasFirewallRisk && name.includes("primary")) {
      risks.push({
        id: 503,
        severity: "medium",
        category: "Network",
        description: "Legacy firewall policies configuration detected (deprecated in ONTAP 9.10.1+).",
        recommendation: "Transition existing legacy firewall-policy settings to LIF service-policy parameters to ensure active firewall management.",
        kbLink: "https://kb.netapp.com/onprem/ontap/os/ONTAP_LIF_service_policies_and_firewall_rules",
        remediationPlan: {
          cause: "The system runs ONTAP 9.10.1+ where legacy firewall policies are deprecated and ignored. Port-level rules must transition to LIF service policies.",
          impact: "Exposes ONTAP management interfaces to unauthorized connection attempts if legacy firewall rules fail to apply.",
          steps: [
            "1. List deprecated firewall policies: 'system services firewall policy show'.",
            "2. Map policy services: 'network interface service-policy show'.",
            "3. Bind service policy to management LIF: 'network interface modify -vserver <svm> -lif <lif> -service-policy default-management'"
          ],
          options: [
            "Option A: Implement service policy controls on all management and data LIF ports (Recommended).",
            "Option B: Retain legacy policy definitions temporarily (Not Recommended, policies are ignored)."
          ],
          thirdParty: "Ensure remote monitoring tools (Active IQ Unified Manager, SNMP collectors) continue to authenticate normally."
        }
      });
    }
  }

  // D. EOA Platform Detection (risk 504)
  // Sourced from 2026-07-10 Reference Library: Platforms-Hardware/README.md
  if (!isStorageGrid && !isEseries) {
    const platformStr = (s.platform || s.model || s.platformModel || name || "").toUpperCase();
    const matchedEOA = REFERENCE_LIBRARY_EOA_PLATFORMS.find(eoa => {
      const eoaUpper = eoa.toUpperCase();
      // Match "A700" in "AFF A700", "FAS9000" in "FAS9000 (SAS)", etc.
      return platformStr.includes(eoaUpper) || (name || "").toUpperCase().includes(eoaUpper);
    });
    if (matchedEOA && !risks.some(r => r.id === 504)) {
      risks.push({
        id: 504,
        severity: "high",
        category: "Lifecycle",
        description: `Platform ${matchedEOA} has reached End-of-Availability (EOA). EOS timeline: Feature Release ~2yr post-EOA → Patch/Fix ~3yr → EOS ~5yr post-EOA.`,
        recommendation: `Initiate tech-refresh evaluation. Current generation replacements: AFF A-Series (A20/A30/A50/A70/A90/A1K), AFF C-Series (C30/C60/C80), or ASA A-Series for SAN-only workloads.`,
        kbLink: "https://docs.netapp.com/us-en/ontap-systems/endofavail/",
        remediationPlan: {
          cause: `The ${matchedEOA} platform is listed on NetApp's official End-of-Availability page. No new orders can be placed, and the EOS clock is ticking.`,
          impact: "Post-EOS, no further security patches or bug fixes will ship. Any CVE affecting this platform may have no vendor-supplied remediation path other than hardware refresh.",
          steps: [
            "1. Verify EOA/EOS dates for this specific serial: check Hardware Universe (hwu.netapp.com) or NetApp Support Site.",
            "2. Assess workload migration path: SnapMirror data migration to new platform or volume move within cluster.",
            "3. Engage NetApp account team for tech-refresh quotation and trade-in credits.",
            "4. Plan non-disruptive controller upgrade if cluster allows (system controller replace)."
          ],
          options: [
            "Option A: In-place controller upgrade via 'system controller replace' (non-disruptive, if supported for this platform pair).",
            "Option B: SnapMirror-based migration to a new cluster with current-generation controllers.",
            "Option C: Extend support contract while planning refresh (delays EOS but does not address EOA)."
          ],
          thirdParty: "Verify VMware/hypervisor HCL compatibility with new platform before migration. Check NetApp IMT for protocol/OS support on target hardware."
        }
      });
    }
  }

  // E. CVE/Advisory Version-Range Matching (risks 510+)
  // Sourced from 2026-07-10 Reference Library: Security-Advisories/ADVISORY-LOG.md
  if (osVer && !isEseries) {
    const sysProduct = isStorageGrid ? "StorageGRID" : "ONTAP";
    REFERENCE_LIBRARY_ADVISORIES.forEach((adv, idx) => {
      // Skip if product doesn't match
      if (adv.product === "SnapCenter" || adv.product === "Config Advisor" || adv.product === "Trident") return;
      if (adv.product === "StorageGRID" && !isStorageGrid) return;
      if (adv.product !== "StorageGRID" && !adv.product.includes("ONTAP") && adv.product !== sysProduct) return;
      // Skip CIFS-only advisories for systems that clearly aren't NAS
      if (adv.isCIFSOnly) return; // Kerberos handled separately below as risk 525

      const riskId = 510 + idx;
      if (risks.some(r => r.id === riskId)) return;

      // Version range check
      const ver = osVer;
      if (adv.affectedVersions) {
        const compareVer = (a, b) => {
          const pa = a.split('.').map(Number), pb = b.split('.').map(Number);
          for (let i = 0; i < Math.max(pa.length, pb.length); i++) {
            const va = pa[i] || 0, vb = pb[i] || 0;
            if (va !== vb) return va - vb;
          }
          return 0;
        };
        const baseVer = ver.replace(/P\d+$/, ''); // Strip patch level for comparison
        if (adv.affectedVersions.min && compareVer(baseVer, adv.affectedVersions.min) < 0) return;
        if (adv.affectedVersions.max && compareVer(baseVer, adv.affectedVersions.max) > 0) return;
      }

      // Check if system is already on a fixed version
      if (adv.fixedIn) {
        const isFixed = adv.fixedIn.some(fix => osVer.includes(fix.replace(/P\d+$/, '')));
        if (isFixed) return;
      }

      // Build advisoryUrl directly — this risk bypasses the normalization .map() loop
      // so advisoryUrl must be set here or the title will render as plain (un-clickable) text.
      const _advCveMatch = (adv.id || '').match(/CVE-\d{4}-\d+/i);
      const _advNtapMatch = (adv.id || '').match(/^NTAP-/i);
      const _advUrl = adv.url
        || (_advCveMatch  ? `https://security.netapp.com/advisory/?q=${_advCveMatch[0]}` : null)
        || (_advNtapMatch ? `https://security.netapp.com/advisory/${adv.id.toLowerCase()}/` : null)
        || 'https://security.netapp.com/advisory/';
      risks.push({
        id: riskId,
        severity: adv.severity,
        category: "Security",
        description: `${adv.id}: ${adv.title}` + (adv.cvss ? ` (CVSS ${adv.cvss})` : ''),
        recommendation: adv.remediation,
        advisoryUrl: _advUrl,
        kbLink: adv.url,
        remediationPlan: {
          cause: adv.description,
          impact: `Security vulnerability with ${adv.severity.toUpperCase()} severity${adv.cvss ? ` (CVSS ${adv.cvss})` : ''}. ${adv.fixedIn ? 'Fixed in: ' + adv.fixedIn.join(', ') : 'See advisory for remediation.'}`,
          steps: [
            `1. Review advisory details: ${adv.url}`,
            adv.fixedIn ? `2. Plan upgrade to ${adv.fixedIn[adv.fixedIn.length - 1]}+.` : "2. Review advisory for specific remediation steps.",
            "3. Validate fix in test environment before production rollout."
          ],
          options: [],
          thirdParty: ""
        }
      });
    });
  }

  // F. Kerberos AES Enforcement Detection (risk 525)
  // Sourced from 2026-07-10 Reference Library: Security-Advisories/docs/ontap-guidance-for-microsoft-security-update-kb5073381-cve-2026-20833.md
  // Affects ALL ONTAP systems with CIFS/SMB + AD (Microsoft phased enforcement Apr-Jul 2026)
  if (osVer && !isStorageGrid && !isEseries) {
    const hasCIFS = (s.protocols || []).some(p => (p || "").toLowerCase().includes("cifs") || (p || "").toLowerCase().includes("smb"));
    const hasNAS = (s.platform || "").toLowerCase().includes("nas") || (s.protocols || []).some(p => (p || "").toLowerCase().includes("nfs"));
    // Flag if system has CIFS protocols or is a NAS platform (likely has CIFS SVMs)
    if ((hasCIFS || hasNAS || !(s.protocols && s.protocols.length > 0)) && !risks.some(r => r.id === 525)) {
      risks.push({
        id: 525,
        severity: "medium",
        category: "Security",
        description: "CVE-2026-20833: Microsoft Kerberos AES-Only Enforcement — verify CIFS/SMB authentication compatibility.",
        recommendation: "Confirm AES encryption enabled for Kerberos auth (default since ONTAP 9.13.1). Disable RC4/DES if still configured. Microsoft phased enforcement active Apr–Jul 2026.",
        advisoryUrl: 'https://security.netapp.com/advisory/?q=CVE-2026-20833',
        kbLink: "https://kb.netapp.com/on-prem/ontap/da/NAS/NAS-KBs/ONTAP_Guidance_for_Microsoft_Security_Update_KB5073381_CVE_2026_20833",
        remediationPlan: {
          cause: "Microsoft Security Update KB5073381 phases out RC4 and DES Kerberos encryption. ONTAP CIFS servers joined to AD without an explicit msds-SupportedEncryptionTypes value may lose authentication.",
          impact: "CIFS/SMB shares may become inaccessible if the AD domain controller enforces AES-only Kerberos and the ONTAP SVM still uses RC4/DES.",
          steps: [
            "1. Check current Kerberos encryption config: 'vserver cifs security show -fields kerberos-clock-skew,is-aes-encryption-enabled'.",
            "2. Enable AES if not already: 'vserver cifs security modify -vserver <svm> -is-aes-encryption-enabled true'.",
            "3. Verify AD attribute msds-SupportedEncryptionTypes is set (check with AD admin).",
            "4. Test authentication after changes: 'vserver cifs session show'."
          ],
          options: [
            "Option A: Enable AES encryption on all CIFS SVMs proactively (Recommended — non-disruptive).",
            "Option B: Wait for Microsoft enforcement and remediate reactively (Not Recommended — may cause outage)."
          ],
          thirdParty: "Coordinate with Active Directory administrators to verify msds-SupportedEncryptionTypes on computer objects for ONTAP CIFS server accounts."
        }
      });
    }
  }

  // G. EOA Switch Detection (risk 505)
  // Sourced from 2026-07-10 Reference Library: Platforms-Hardware/README.md
  if (s.switches && s.switches.length > 0) {
    const switchNames = s.switches.map(sw => (sw.name || sw.model || "").toUpperCase());
    const matchedSwitch = REFERENCE_LIBRARY_EOA_SWITCHES.find(eoaSw =>
      switchNames.some(sn => sn.includes(eoaSw.toUpperCase()))
    );
    if (matchedSwitch && !risks.some(r => r.id === 505)) {
      risks.push({
        id: 505,
        severity: "medium",
        category: "Lifecycle",
        description: `Cluster/MetroCluster switch ${matchedSwitch} has reached End-of-Availability. Plan switch refresh alongside controller upgrade.`,
        recommendation: "Replace with current-generation switch. For cluster interconnect: Cisco Nexus 9336C-FX2 or BES-53248 replacement models. For MetroCluster IP: check MetroCluster-compliant switch list.",
        kbLink: "https://docs.netapp.com/us-en/ontap-systems/endofavail/",
        remediationPlan: {
          cause: `The ${matchedSwitch} switch is listed on NetApp's official End-of-Availability page.`,
          impact: "EOA switches will eventually reach End-of-Support with no further firmware patches. A controller refresh often coincides with the switch generation qualified for it going EOA.",
          steps: [
            "1. Verify current switch firmware: 'system cluster-switch show'.",
            "2. Check MetroCluster-compliant switch list if MC-IP: docs.netapp.com/us-en/ontap-metrocluster/install-ip/concept-requirement-and-limitations-mcc-compliant-switches.html",
            "3. Plan switch replacement during next maintenance window.",
            "4. Validate new switch firmware against NetApp Hardware Universe."
          ],
          options: [],
          thirdParty: ""
        }
      });
    }
  }

  // KB links: no sanitization needed — search URLs are generated at render time
  // by buildKBSearchURL(). Any kbLink fields in raw API data are ignored.

  // Normalise security bulletins from API (may use different field names)
  // For live data with no explicit securityBulletins, extract CVE/security risks
  let securityBulletins = (s.securityBulletins || s.security_bulletins || s.cveBulletins || []).map(b => ({
    id:         b.id         || b.cveId      || b.bulletinId  || "NTAP-UNKNOWN",
    ntapId:     b.ntapId     || '',
    cve:        b.cve        || b.cveId      || b.id          || '',
    cvss:       b.cvss       || b.cvssScore  || null,
    title:      b.title      || b.cveTitle   || b.description || "Security advisory",
    category:   b.category   || '',
    severity:   (b.severity  || b.cvssScore  || "medium").toString().toLowerCase(),
    status:     b.status     || "Review Required",
    mitigation: b.mitigation || b.mitigationAction || "Consult NetApp Security Advisory for patch details.",
    fixedIn:    b.fixedIn    || '',
    published:  b.published  || '',
    link:       b.link       || b.advisoryUrl || 'https://security.netapp.com/advisory/',
    source:     'api'
  }));

  // Auto-generate security bulletins from security-category risks when none exist
  // Works for both live API data and cached/reloaded data (not just _source === 'graphql')
  if (!state.mockMode) {
    const secRisks = risks.filter(r => {
      const cat = (r.category || '').toLowerCase();
      const desc = (r.description || '');
      return cat === 'security' || cat.includes('vulnerabilit') || desc.includes('CVE-');
    });

    if (secRisks.length > 0) {
      // Deduplicate by description to avoid repeating the same CVE for each node
      const seen = new Set(securityBulletins.map(b => b.id));
      secRisks.forEach(r => {
        const key = r.description || r.id;
        const cveMatch = (r.description || '').match(/CVE-[0-9]{4}-[0-9]+/g);
        const cveId = cveMatch ? cveMatch[0] : null;
        const bulletinId = cveId || `NTAP-${r.id}`;
        if (!seen.has(bulletinId) && !seen.has(key)) {
          seen.add(bulletinId); seen.add(key);
          let advUrl = r.advisoryUrl || r.link || '';
          // Try to extract NTAP advisory ID from mitigation text for a direct link
          if (!advUrl || advUrl === 'https://security.netapp.com/advisory/') {
            const ntapInMit = (r.mitigation || r.recommendation || '').match(/NTAP-[0-9]{8}-[0-9]{4}/i);
            if (ntapInMit) advUrl = `https://security.netapp.com/advisory/${ntapInMit[0].toLowerCase()}/`;
            else if (cveId) advUrl = `https://security.netapp.com/advisory/?q=${cveId}`;
          }
          let mitText = '';
          if (r.remediationPlan && r.remediationPlan.steps && r.remediationPlan.steps.length > 0) {
            mitText = r.remediationPlan.steps.map(s => s.replace(/^\d+\.\s*/, '')).join(' | ');
          }
          if (!mitText || mitText.length < 10) mitText = r.recommendation || 'Upgrade to recommended OS version.';
          if (mitText.includes('See Security Advisory') || mitText.includes('See the Security Advisory')) {
            const desc = (r.description || '').toLowerCase();
            mitText = desc.includes('vulnerability')
              ? 'Upgrade to a patched ONTAP/firmware version that resolves this vulnerability. Review the advisory for affected versions and fixed releases.'
              : 'Apply the corrective action specified in the advisory. Consult NetApp Support if patching requires a maintenance window.';
          }
          securityBulletins.push({
            id: bulletinId, ntapId: '', cve: cveId || '', cvss: null,
            title: r.description, category: r.category || 'Security',
            severity: r.severity, status: 'Active',
            mitigation: mitText, fixedIn: '', published: '', link: advUrl, source: 'risk'
          });
        }
      });
    }
  }

  // ── NETAPP_SECURITY_BULLETIN_DB auto-match ───────────────────────────────────
  // Cross-reference system ONTAP version against the local scrapped advisory DB.
  // Merges with API-provided bulletins; deduplicates by CVE ID so no double-counting.
  {
    const dbMatches = getApplicableSecurityBulletins(osVer, model);
    const existingCveIds = new Set(
      securityBulletins.flatMap(b =>
        (b.cve || b.id || '').split(/[,\s]+/).map(x => x.trim()).filter(x => x.startsWith('CVE-'))
      )
    );
    for (const match of dbMatches) {
      const matchCves = (match.cve || '').split(/[,\s]+/).map(x => x.trim()).filter(x => x.startsWith('CVE-'));
      const alreadyPresent = matchCves.some(c => existingCveIds.has(c));
      if (!alreadyPresent) {
        securityBulletins.push({
          id:         match.id,
          ntapId:     match.ntapId || '',
          cve:        match.cve,
          cvss:       match.cvss,
          title:      match.title,
          category:   match.category,
          severity:   match.severity,
          status:     match.status,
          mitigation: match.mitigation,
          fixedIn:    match.fixedIn,
          published:  match.published,
          link:       match.link,
          source:     'db'
        });
        matchCves.forEach(c => existingCveIds.add(c));
      }
    }
    // Re-sort merged list: critical → high → medium → low, then operational bugs
    const sevRank = { critical: 0, high: 1, medium: 2, low: 3 };
    securityBulletins.sort((a, b) => (sevRank[a.severity] ?? 4) - (sevRank[b.severity] ?? 4));
  }

  // Normalise support cases from API
  // Active IQ GraphQL Case fields: caseId, symptom, description, status (enum),
  // priority (int 1-4), highestPriority, created, lastUpdated, closed, type,
  // category, subCategory, caseReceivedVia, reporterContact { name }, system { serialNumber hostName }
  const supportCases = (s.supportCases || s.support_cases || s.cases || []).map(c => {
    // Convert numeric priority to standard severity string
    let sev = c.severity || "";
    if (!sev || typeof sev === "number") {
      const p = c.priority || c.casePriority || c.highestPriority || c.severity || 3;
      const pNum = typeof p === "number" ? p : parseInt(p) || 3;
      const sevMap = { 1: "S1 - Critical", 2: "S2 - High", 3: "S3 - Medium", 4: "S4 - Low" };
      sev = sevMap[pNum] || `S${pNum} - Priority ${pNum}`;
    }
    // Helper: API often returns ' ' (space) for empty fields — treat as empty
    const t = v => (v || "").trim();
    // symptom is the primary descriptive field; description is often just "Core for the Case-XXXX"
    const caseTitle = t(c.symptom) || t(c.title) || t(c.caseTitle) || t(c.description) || t(c.subject) || "Support case";
    const caseDesc = t(c.description) || t(c.symptom) || "";
    const reporter = t((c.reporterContact || {}).name);
    const sysHost = t((c.system || {}).hostName);
    // Map CaseStatus enum values to human-readable display
    const statusRaw = c.status || c.caseStatus || "Open";
    const statusMap = {
      "ACTIVE": "Open - Active",
      "PENDING_CUSTOMER": "Open - Customer Action",
      "PENDING_CUSTOMER_DATA": "Open - Awaiting Data",
      "PENDING_BUG_FIX": "Open - Pending Bug Fix",
      "PENDING_ESCALATION": "Open - Escalated",
      "PENDING_FSE": "Open - Field Service",
      "PENDING_SOLUTION_PROPOSED": "Open - Solution Proposed",
      "SOLUTION_PROPOSED": "Solution Proposed",
      "RESEARCH": "Open - Under Research",
      "WAIT_TSE": "Open - Awaiting TSE",
      "UNASSIGNED": "Open - Unassigned",
      "INITIALIZING": "Initializing",
      "CORE_REQUESTED": "Core Requested",
      "CORE_RECEIVED": "Core Received",
      "CORE_ANCILLARY": "Core Ancillary",
      "CORE_INCOMPLETE": "Core Incomplete",
      "CORE_UNDER_ANALYSIS": "Core Under Analysis",
      "DUPLICATE_CORE": "Duplicate Core",
      "CLOSED": "Closed",
      "CANCELLED": "Cancelled",
      "PENDING_CLOSED": "Pending Close",
      "INTERNAL_USER_REQ_CLOSED": "Closed (Internal)",
      "PENDING_OTHER": "Open - Pending"
    };
    return {
      id:           c.caseId       || c.id         || c.caseNumber || "CASE-UNKNOWN",
      title:        caseTitle,
      description:  caseDesc && caseDesc !== caseTitle ? caseDesc : "",
      severity:     String(sev),
      status:       statusMap[statusRaw] || String(statusRaw),
      criticality:  t(c.criticality) || t(c.category) || t(c.impact) || "",
      subCategory:  t(c.subCategory),
      caseType:     t(c.type) || t(c.caseType) || t(c.caseReceivedVia) || "",
      resolution:   t(c.resolution),
      reporter:     reporter,
      systemName:   sysHost,
      nextActionBy: t(c.nextActionBy) || t(c.owner) || reporter || "NetApp Support",
      createdDate:  c.created || c.caseCreateDate || c.createdDate || "",
      lastUpdated:  c.lastUpdated || c.lastModifiedDate || c.updated || "",
      closedDate:   c.closed   || c.closedDate     || "",
      ownerNotes:   t(c.ownerNotes) || t(c.notes)
    };
  });

  // Compute health status from actual telemetry data (not from missing API field)
  const hasCritRisk = risks.some(r => r.severity === 'critical');
  const hasHighRisk = risks.some(r => r.severity === 'high');
  const asupFailed = autosupport && (autosupport.status === 'failed' || autosupport.status === 'disabled' || (autosupport.lastReceivedDays != null && autosupport.lastReceivedDays > 7));
  const contractExpired = contracts && (contracts.status === 'expired' || contracts.daysRemaining < 0);
  let computedStatus = 'normal';
  if (hasCritRisk || contractExpired) computedStatus = 'critical';
  else if (hasHighRisk || asupFailed || (contracts && contracts.daysRemaining <= 90)) computedStatus = 'warning';

  // ── Backfill contractActive + isARPEnabled for mock/non-live systems ───────
  // contractActive: derived from contracts object; real API provides it as a boolean.
  // Without this, Contract Coverage in CSM/reports shows 0/N (undefined !== true).
  const _contractActive = s.contractActive != null
    ? s.contractActive
    : (contracts ? contracts.daysRemaining > 0 && contracts.status !== 'expired' : false);

  // isARPEnabled: AFF/ASA systems support ARP (ONTAP 9.10.1+). FAS/SG/E-Series do not.
  // Without this, ARP Coverage in CSM/reports shows 0/N (undefined !== true).
  const _isARPEnabled = s.isARPEnabled != null
    ? s.isARPEnabled
    : !isStorageGrid && !isEseries && (isAFF || isASA || isASAr2 || isAFX || isCVO);

  return {
    _source:           s._source || (isLiveData ? 'graphql' : undefined),
    serialNumber:      serial,
    systemName:        name,
    clusterName:       cluster,
    customerName:      customer,
    ontapVersion:      osVer,
    platform:          model,
    status:            computedStatus,
    risks:             risks,
    upgrades:          upgrades,
    contracts:         contracts,
    lifecycle:         lifecycle,
    fieldActions:      s.fieldActions || s.field_actions || [],
    efficiency:        efficiency,
    snapmirror:        s.snapmirror && s.snapmirror.enabled ? s.snapmirror : _buildSnapMirrorData(s, cluster, isLiveData),
    hypervisors:       s.hypervisors  || [],
    switches:          s.switches     || [],
    logistics:         logistics,
    contacts:          contacts,
    salesHealth:       salesHealth,
    projections:       projections,
    securityBulletins: securityBulletins,
    supportCases:      supportCases,
    autosupport:       autosupport,
    // ── TAM Enrichment Fields ──
    productType:       s.productType || '',
    systemState:       s.systemState || '',
    techRefreshStatus: s.techRefreshStatus || '',
    serviceTier:       s.serviceTier || '',
    lastRebootTime:    s.lastRebootTime || '',
    originalShipDate:  s.originalShipDate || '',
    marketingType:     s.marketingType || '',
    storageConfiguration: s.storageConfiguration || '',
    isFabricPool:      s.isFabricPool,
    hasPvr:            s.hasPvr,
    modelRevision:     s.modelRevision || '',
    // ── Account Management ──
    salesRepName:      s.salesRepName || '',
    salesRepEmail:     s.salesRepEmail || '',
    csmName:           s.csmName || '',
    csmEmail:          s.csmEmail || '',
    samName:           s.samName || '',
    samEmail:          s.samEmail || '',
    gard:              s.gard || {},
    aspName:           s.aspName || '',
    aspEndDate:        s.aspEndDate || '',
    domesticParentName: s.domesticParentName || '',
    nagpName:          s.nagpName || '',
    siteName:          s.siteName || '',
    siteId:            s.siteId || '',
    siteCity:          s.siteCity || '',
    siteCountry:       s.siteCountry || '',
    // ── Extended Contract ──
    contractActive:    _contractActive,
    contractEndDate:   s.contractEndDate || s.contractExpiry || '',
    contractExpiry:    s.contractExpiry || '',
    warrantyEndDate:   s.warrantyEndDate || '',
    warrantyStartDate: s.warrantyStartDate || '',
    serviceLevel:      s.serviceLevel || '',
    contractSWId:      s.contractSWId || '',
    contractHWId:      s.contractHWId || '',
    contractNRDEndDate: s.contractNRDEndDate || '',
    latestAsupDate:    s.latestAsupDate || '',
    // ── End of Support ──
    eosEarliest:       s.eosEarliest || '',
    eosShelf:          s.eosShelf || '',
    eosDisk:           s.eosDisk || '',
    eosPVR:            s.eosPVR || '',
    eosLatest:         s.eosLatest || '',
    // ── Software Version ──
    softwareVersionFull: s.softwareVersionFull || '',
    swReleaseDate:     s.swReleaseDate || '',
    swEndOfFullSupport: s.swEndOfFullSupport || '',
    swEndOfLimitedSupport: s.swEndOfLimitedSupport || '',
    swEndOfSelfService: s.swEndOfSelfService || '',
    swRecMin:          s.swRecMin || '',
    swRecLatest:       s.swRecLatest || '',
    swCQV:             s.swCQV || '',
    // ── ONTAP Flags ──
    isMetroCluster:    s.isMetroCluster,
    isAllFlashOptimized: s.isAllFlashOptimized,
    isFlexPod:         s.isFlexPod,
    isARPEnabled:      _isARPEnabled,
    operatingMode:     s.operatingMode || '',
    propensityCategory: s.propensityCategory || '',
    nextBestAction:    s.nextBestAction || '',
    belongsToMixModelCluster: s.belongsToMixModelCluster,
    serviceProcessorIP: s.serviceProcessorIP || '',
    autoUpdateEnabled: s.autoUpdateEnabled,
    // ── AutoSupport Extended ──
    asupStatus:        s.asupStatus || '',
    asupTransport:     s.asupTransport || '',
    asupOnDemand:      s.asupOnDemand,
    asupDomain:        s.asupDomain || '',
    // ── Firmware ──
    systemFirmware:    s.systemFirmware || [],
    motherboardFirmware: s.motherboardFirmware || {},
    diskQualificationPackage: s.diskQualificationPackage || {},
    autoUpdateSettings: s.autoUpdateSettings || {},
    // ── Lifecycle Events & Licenses ──
    lifecycleEvents:   s.lifecycleEvents || [],
    licenses:          s.licenses || [],
    pvrs:              s.pvrs || [],
    // ── Downtime & Monthly Stats ──
    downtimeEvents:    s.downtimeEvents || {},
    monthlyUptimeStats: s.monthlyUptimeStats || [],
    monthlyCarbonStats: s.monthlyCarbonStats || [],
    monthlyResolvedRisksStats: s.monthlyResolvedRisksStats || [],
    monthlyArpStats:   s.monthlyArpStats || [],
    monthlyAutoResolvedCases: s.monthlyAutoResolvedCases || [],
    sustainabilityScores: s.sustainabilityScores || [],
    // ── Per-System Capacity ──
    capacityAllocatedKB: s.capacityAllocatedKB || 0,
    capacityUsedKB:    s.capacityUsedKB || 0,
    capacityAvailableKB: s.capacityAvailableKB || 0,
    dataReductionRatio: s.dataReductionRatio,
    // ── Shelves, Ports, vCenters ──
    shelves:           s.shelves || [],
    portInterface:     s.portInterface || {},
    networkPorts:      s.networkPorts || {},
    vcenters:          s.vcenters || [],
  };
}

function generateDynamicRemediationPlan(risk, sys) {
  const desc = (risk.description || "").toLowerCase();
  const cat  = risk.category || "General";
  const catLower = cat.toLowerCase();
  const platform = (sys.platform || "").toLowerCase();
  const ontapVer = sys.ontapVersion || "";

  // Parse ONTAP version for version-gated logic
  const verMatch = ontapVer.match(/^([0-9]+)\.([0-9]+)/);
  let major = 9, minor = 12;
  if (verMatch) { major = parseInt(verMatch[1]); minor = parseInt(verMatch[2]); }
  const is910OrNewer  = (major > 9) || (major === 9 && minor >= 10);
  const is913OrNewer  = (major > 9) || (major === 9 && minor >= 13);
  const is915OrNewer  = (major > 9) || (major === 9 && minor >= 15);
  const is916OrNewer  = (major > 9) || (major === 9 && minor >= 16);
  const is919OrNewer  = (major > 9) || (major === 9 && minor >= 19);
  const isAFX         = platform.includes("afx") || platform.includes("all-flash fabric");
  const isMCC         = platform.includes("metrocluster") || desc.includes("metrocluster") || desc.includes("mcc");
  const isSG          = platform.includes("storagegrid") || catLower.includes("storagegrid") || desc.includes("storagegrid");
  const isSantricity  = platform.includes("e-series") || catLower.includes("santricity") || desc.includes("santricity") || desc.includes("e-series");
  const clusterName   = sys.clusterName || sys.systemName || "your-cluster";

  // Per-version upgrade caveats (inline for use in steps)
  const versionCaveats = REFERENCE_LIBRARY_UPGRADE_CAVEATS || {};

  // ─── Default fallback ────────────────────────────────────────────────────────
  let cause   = "Configuration deviation identified in Active IQ telemetry sync.";
  let impact  = "Potential compliance degradation or risk of localized performance instability.";
  let steps   = [
    "1. Review configuration using standard ONTAP diagnostic commands.",
    "2. Consult target platform documentation at https://docs.netapp.com/us-en/ontap/",
    "3. Engage NetApp Support via https://mysupport.netapp.com/ if baseline deviations require custom adjustment."
  ];
  let options = [
    "Option A: Apply recommended changes under next scheduled change control window.",
    "Option B: Retain current parameters if business exceptions mandate legacy settings."
  ];
  let thirdParty = "No direct third-party virtualization or backup hypervisor dependencies identified.";

  // ════════════════════════════════════════════════════════════════════════════
  // STORAGEGRID
  // ════════════════════════════════════════════════════════════════════════════
  if (isSG) {
    if (desc.includes("upgrade") || desc.includes("version") || desc.includes("outdated")) {
      cause  = "StorageGRID is running a version below the recommended baseline, missing security patches and feature improvements.";
      impact = "Exposure to known CVEs, missing S3 compatibility improvements, and unsupported ILM policy features.";
      steps  = [
        "1. Log in to the Primary Admin Node web interface.",
        "2. Download the StorageGRID upgrade package (.upgrade) from: https://mysupport.netapp.com/site/downloads",
        "3. Navigate to MAINTENANCE > System > Software Update.",
        "4. Upload the upgrade package and the current Recovery Package (.zip) — both files are required.",
        "5. Click 'Apply' and monitor the upgrade progress via MAINTENANCE > Tasks > Grid Tasks.",
        "6. Validate all nodes show 'Connected' status post-upgrade: NODES > Overview.",
        "7. Regenerate a new Recovery Package after upgrade completes: MAINTENANCE > Recovery Package.",
        "8. StorageGRID 12.0+ ref: https://docs.netapp.com/us-en/storagegrid/upgrade/index.html"
      ];
      options = [
        "Option A: Upgrade sequentially through each major version (e.g., 11.8 → 11.9 → 12.0). Skipping major versions is NOT supported.",
        "Option B: Apply hotfix only (patch release) if a full major upgrade is not feasible within the current maintenance window — navigate to MAINTENANCE > System > Hotfix."
      ];
      thirdParty = "Verify S3 client application compatibility. StorageGRID 11.9+ enforces strict TLS certificate handshakes. Swift API is deprecated in 11.7+ and removed in 12.0.";
    } else if (desc.includes("ilm") || desc.includes("policy") || desc.includes("replication")) {
      cause  = "ILM (Information Lifecycle Management) policy configuration may not meet data durability or compliance requirements.";
      impact = "Objects may not be replicated to the required number of copies, creating data durability risk.";
      steps  = [
        "1. Navigate to ILM > Policies in the Grid Manager.",
        "2. Review the Active Policy rules and verify object copy counts, storage pool assignments, and cloud tier rules.",
        "3. Validate rule evaluation order — more specific rules must precede catch-all rules.",
        "4. Test proposed changes using the ILM Policy Simulation tool before activation.",
        "5. Activate the updated policy: ILM > Policies > Activate.",
        "6. Monitor object placement via NODES > Storage Node > Objects.",
        "Ref: https://docs.netapp.com/us-en/storagegrid/ilm/index.html"
      ];
      options = [
        "Option A: Activate updated policy immediately and let background ILM scanner re-evaluate all existing objects (may take hours/days on large grids).",
        "Option B: Create parallel policy for new ingest only, leaving existing objects unchanged."
      ];
      thirdParty = "S3 bucket replication rules configured in the S3 client SDK are separate from ILM policies. Both layers must be validated for compliance requirements.";
    } else {
      cause  = "StorageGRID node health or connectivity issue detected.";
      impact = "Degraded node availability may reduce read/write performance and data durability.";
      steps  = [
        "1. Check node status: NODES > select node > Overview tab.",
        "2. Review active alerts: ALERTS > Current.",
        "3. For Admin Node failures: verify Cassandra service health via SSH: 'run-storagegrid-diagnostics.sh'.",
        "4. For Storage Node issues: verify disk health and object store mount points.",
        "5. Escalate to NetApp Support with grid diagnostics package if node cannot self-recover.",
        "Ref: https://docs.netapp.com/us-en/storagegrid/maintain/index.html"
      ];
      options = [
        "Option A: Decommission and redeploy affected node if hardware fault is confirmed.",
        "Option B: Recover node from Recovery Package if node metadata is intact."
      ];
      thirdParty = "S3 gateway load balancer endpoints should be monitored for elevated 5xx error rates during node recovery.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SANTRICITY / E-SERIES
  // ════════════════════════════════════════════════════════════════════════════
  if (isSantricity) {
    if (desc.includes("upgrade") || desc.includes("version") || desc.includes("outdated") || desc.includes("firmware")) {
      cause  = "SANtricity OS or NVSRAM version is below the recommended baseline.";
      impact = "Exposure to resolved controller firmware bugs, potential I/O instability, and missing drive qualification updates.";
      steps  = [
        "1. Download SANtricity OS firmware package (.dlp) and NVSRAM file from: https://mysupport.netapp.com/site/downloads",
        "2. Log in to SANtricity System Manager (https://<controller-IP>).",
        "3. Navigate to Support > Upgrade Center > SANtricity OS Software.",
        "4. Upload both the SANtricity OS .dlp file AND the NVSRAM .nvm file — both are required for a complete upgrade.",
        "5. Review the pre-upgrade health summary. Ensure all drives show 'Optimal' and both controllers are 'Online'.",
        "6. Check BBU/SuperCap status: if battery is degraded, write caching will be disabled during the upgrade, causing temporary latency spikes.",
        "7. Click 'Start Upgrade'. Controller A activates first, reboots, then Controller B activates.",
        "8. Verify post-upgrade versions: Support > About > Software and Firmware Versions.",
        "Ref: https://docs.netapp.com/us-en/e-series/upgrade-santricity.html"
      ];
      options = [
        "Option A: Online upgrade (non-disruptive on dual-controller e.g. E2800/E5700/EF600). I/O continues during the rolling controller activation.",
        "Option B: Offline upgrade — required for single-controller shelf configurations. Schedule full maintenance window."
      ];
      thirdParty = "Host-side HBA multipathing (MPIO on Windows, dm-multipath on Linux, VMware PSP_RR) maintains I/O continuity during the rolling controller reboot. Verify multipath is active before starting.";
    } else if (desc.includes("drive") || desc.includes("disk")) {
      cause  = "Drive firmware is outdated or a drive has reported a recoverable error.";
      impact = "Outdated drive firmware may have unresolved reliability issues. Unaddressed drive errors can lead to drive failure.";
      steps  = [
        "1. Check drive status: Hardware > Drives > select drive > View Settings.",
        "2. For firmware update: Support > Upgrade Center > Drive Firmware.",
        "3. Upload the drive firmware package (.dlp) downloaded from https://mysupport.netapp.com/site/downloads/firmware/disk",
        "4. Select affected drives and click 'Start'. Drive firmware updates are non-disruptive on redundant pools/volume groups.",
        "5. Verify drive health post-update: all drives should show 'Optimal'.",
        "Ref: https://docs.netapp.com/us-en/e-series/maintenance-e2800/drives-replace-task.html"
      ];
      options = [
        "Option A: Update drive firmware online via SANtricity Upgrade Center (non-disruptive).",
        "Option B: Schedule drive replacement via NetApp Support (create a case at https://mysupport.netapp.com/) if drive error count is increasing."
      ];
      thirdParty = "iSCSI and FC host connections remain active during drive firmware updates on redundant pools.";
    } else {
      cause  = "SANtricity controller or hardware component health deviation detected.";
      impact = "Degraded controller redundancy or hardware fault may impact I/O availability.";
      steps  = [
        "1. Check controller status: Hardware > Controllers > select controller.",
        "2. Review any active Recovery Guru items: Home > Recovery Guru.",
        "3. Follow Recovery Guru remediation steps precisely — they are ordered for data integrity.",
        "4. If a hardware FRU replacement is required, open a NetApp Support case: https://mysupport.netapp.com/",
        "Ref: https://docs.netapp.com/us-en/e-series/maintenance-e2800/index.html"
      ];
      options = [
        "Option A: Follow Recovery Guru steps for online component replacement if hot-swap is supported.",
        "Option B: Schedule offline maintenance window for cold-swap component replacement."
      ];
      thirdParty = "Host I/O paths should be verified with your multipath driver before and after any controller component replacement.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SHELF FIRMWARE — IOM12 / IOM12G / IOM12B / IOM3 / NSM100 / NSM100B / NSM100e / NSM140
  // ════════════════════════════════════════════════════════════════════════════
  if (desc.includes("iom12") || desc.includes("iom12g") || desc.includes("iom12b") || desc.includes("iom3") ||
      desc.includes("nsm100") || desc.includes("nsm140") || desc.includes("shelf firmware") ||
      (desc.includes("shelf") && desc.includes("firmware")) || (desc.includes("shelf") && desc.includes("module"))) {
    const shelfModule = desc.includes("nsm140") ? "NSM140 (AFX NX224)" :
                        desc.includes("nsm100b") ? "NSM100B" :
                        desc.includes("nsm100e") ? "NSM100e" :
                        desc.includes("nsm100") ? "NSM100" :
                        desc.includes("iom12g") ? "IOM12G" :
                        desc.includes("iom12b") ? "IOM12B" :
                        desc.includes("iom12") ? "IOM12" :
                        desc.includes("iom3") ? "IOM3" : "shelf module";
    const fwBaseline = (REFERENCE_LIBRARY_FIRMWARE_BASELINES || {})[shelfModule.split(" ")[0]] || { recommended: "current" };
    cause  = `${shelfModule} shelf module firmware is below the recommended baseline version (target: ${fwBaseline.recommended}).`;
    impact = "Outdated shelf module firmware may contain known stability bugs affecting SAS/NVMe path throughput or causing unexpected shelf resets.";
    steps  = [
      `1. Download the latest ${shelfModule} shelf firmware package from: https://mysupport.netapp.com/site/downloads/firmware/disk-shelf-firmware`,
      "2. Upload firmware to the ONTAP cluster: 'system node image package get -node * -package <url>' or via System Manager.",
      "3. Initiate background shelf firmware update (non-disruptive): 'storage firmware download'",
      "4. Monitor update progress: 'storage shelf show -fields firmware-revision,module-type' — updates run in background, no I/O interruption.",
      "5. Verify all shelf modules show the updated firmware version after the background job completes.",
      `6. For ${shelfModule} documentation: https://docs.netapp.com/us-en/ontap/disks-aggregates/shelf-firmware-upgrade-manual-disk-task.html`,
      isAFX ? "NOTE: NSM140 modules are exclusive to AFX NX224 shelves and are NOT interchangeable with NSM100/NSM100B modules used in AFF/ASA platforms." : ""
    ].filter(Boolean);
    options = [
      "Option A: Trigger automatic background update now — non-disruptive and runs shelf-by-shelf in the background.",
      "Option B: Manually force update on a per-shelf basis: 'storage shelf firmware update -shelf <ID>' for targeted updates."
    ];
    thirdParty = "Shelf firmware updates are entirely transparent to host-side HBAs and hypervisors. No host-side action required.";
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // DISK / DQP FIRMWARE
  // ════════════════════════════════════════════════════════════════════════════
  if (desc.includes("dqp") || desc.includes("disk qualification") || desc.includes("disk firmware") ||
      (desc.includes("disk") && (desc.includes("firmware") || desc.includes("outdated") || desc.includes("update")))) {
    cause  = "Disk Drive Qualification Package (DQP) or individual drive firmware is below the current validated release.";
    impact = "Unqualified or outdated disk firmware may contain known data integrity bugs. Unqualified drives may not be recognized after replacement, blocking array rebuild.";
    steps  = [
      "1. Check current DQP version: 'storage disk show -fields diskpathnames' and 'disk qualifications package show'.",
      "2. Download the latest DQP package from: https://mysupport.netapp.com/site/downloads/firmware/disk",
      "3. Upload DQP to the cluster: 'storage disk qualification package install <url>'",
      "4. Trigger disk firmware update across all nodes: 'storage disk firmware update'",
      "5. Monitor per-disk firmware update progress: 'storage disk show -fields firmware-revision' — runs non-disruptively, disk-by-disk in background.",
      "6. Verify all drives show the target firmware revision post-update.",
      "7. Ref: https://kb.netapp.com/onprem/ontap/hardware/How_to_update_ONTAP_Disk_Firmware_in_Non-Disruptive_Mode"
    ];
    options = [
      "Option A: Apply DQP and disk firmware update online now — fully non-disruptive on all HA pair configurations.",
      "Option B: Include in next scheduled maintenance window if change freeze applies."
    ];
    thirdParty = "Disk firmware updates are transparent to all host-side storage access. No host reboot or HBA driver update required.";
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SP / BMC FIRMWARE (Service Processor / Baseboard Management Controller)
  // ════════════════════════════════════════════════════════════════════════════
  if (desc.includes("service processor") || desc.includes(" sp ") || desc.includes("bmc") || desc.includes("baseboard management")) {
    cause  = "Service Processor (SP) or BMC firmware is below the recommended version.";
    impact = "Outdated SP/BMC firmware may lack critical remote management features, node power-cycle reliability fixes, and out-of-band connectivity stability improvements.";
    steps  = [
      "1. Check SP firmware version on all nodes: 'system service-processor show -fields firmware-version'",
      "2. SP firmware is typically bundled with ONTAP image packages — ensure cluster is running current ONTAP patch.",
      "3. Manually trigger SP firmware update: 'system service-processor image update -node *'",
      "4. Monitor update progress: 'system service-processor show -fields is-updating' — update takes 5–15 minutes per node.",
      "5. Verify updated SP version: 'system service-processor show -fields firmware-version'",
      "6. Ref: https://docs.netapp.com/us-en/ontap/system-admin/sp-bmc-network-config-concept.html"
    ];
    options = [
      "Option A: Update SP firmware online (non-disruptive to ONTAP I/O — SP is a separate management subsystem).",
      "Option B: SP firmware auto-updates alongside ONTAP upgrades — can defer until next ONTAP patch cycle."
    ];
    thirdParty = "SP/BMC is used for remote KVM console access and node power management. Ensure management network connectivity is stable before updating.";
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // NIC / HBA / ADAPTER FIRMWARE
  // ════════════════════════════════════════════════════════════════════════════
  if (desc.includes("nic") || desc.includes("hba") || (desc.includes("adapter") && (desc.includes("firmware") || desc.includes("driver"))) ||
      (desc.includes("fc adapter") || desc.includes("iscsi adapter") || desc.includes("ethernet adapter"))) {
    cause  = "Network adapter (NIC/HBA) firmware is below the minimum qualified version.";
    impact = "Outdated NIC/HBA firmware may contain link stability bugs, poor error recovery, or lack support for required host-side features (e.g. NVMe-oF, RDMA).";
    steps  = [
      "1. Identify adapter model and current firmware: 'network device-discovery show' and 'system node hardware show'.",
      "2. Download the qualified firmware version for your adapter from: https://mysupport.netapp.com/site/downloads",
      "3. Verify adapter firmware version compatibility in the IMT: https://imt.netapp.com/matrix/",
      "4. For Qlogic/Marvell FC HBAs: use the vendor's qaucli or qlxdump utility for firmware updates.",
      "5. For Broadcom/Emulex FC HBAs: use elxmgmt or OneCommand Manager.",
      "6. For Intel/Broadcom NICs: update via vendor-provided network adapter firmware package.",
      "7. NOTE: Some adapter firmware updates require a system reboot — plan accordingly for HA failover.",
      "8. Ref: https://docs.netapp.com/us-en/ontap/networking/configure_network_ports_cluster.html"
    ];
    options = [
      "Option A: Update adapter firmware online using vendor utilities (check if reboot-free update is available for your adapter model).",
      "Option B: Schedule node takeover/giveback during maintenance window if adapter firmware requires node reboot."
    ];
    thirdParty = "ESXi: VMware HCL lists qualified adapter firmware versions. Update host-side HBA firmware using ESXi Update Manager or the adapter vendor's VIB package. Linux: update using the adapter vendor's firmware update utility or OS package manager.";
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SWITCH FIRMWARE — Cisco NX-OS / MDS / Brocade FOS / EFOS / NVIDIA SN2100
  // ════════════════════════════════════════════════════════════════════════════
  if (catLower.includes("switch") || desc.includes("nx-os") || desc.includes("nxos") || desc.includes("fabric os") ||
      desc.includes("efos") || desc.includes("bes-53248") || desc.includes("brocade") || desc.includes("cisco") ||
      desc.includes("sn2100") || desc.includes("cumulus") || desc.includes("switch firmware") ||
      desc.includes("9336") || desc.includes("9364") || desc.includes("9332") || desc.includes("mds 9")) {

    const isCiscoNexus = desc.includes("9336") || desc.includes("9364") || desc.includes("9332") || desc.includes("nexus") || desc.includes("nx-os") || desc.includes("nxos");
    const isCiscoMDS   = desc.includes("mds 9") || desc.includes("cisco mds") || desc.includes("mds9");
    const isBrocade    = desc.includes("brocade") || desc.includes("fabric os") || desc.includes("fos") || desc.includes("g620") || desc.includes("g630") || desc.includes("g720");
    const isEFOS       = desc.includes("bes-53248") || desc.includes("efos") || desc.includes("broadcom cluster");
    const isNVIDIA     = desc.includes("sn2100") || desc.includes("cumulus") || desc.includes("nvidia");
    const isAFXSwitch  = desc.includes("9332d-gx2b") || desc.includes("9364d-gx2a");

    if (isCiscoNexus || isAFXSwitch) {
      const swModel = isAFXSwitch ? (desc.includes("9332d") ? "Cisco Nexus 9332D-GX2B" : "Cisco Nexus 9364D-GX2A") : "Cisco Nexus 9000-series";
      const downloadUrl = isAFXSwitch ? "https://software.cisco.com/download/home/286325598" : "https://software.cisco.com/download/home/280275056";
      const fwBaseline = (REFERENCE_LIBRARY_FIRMWARE_BASELINES || {})["Cisco NX-OS"] || { recommended: "9.3(12)" };
      cause  = `${swModel} switch is running NX-OS below the recommended baseline version (target: ${fwBaseline.recommended}).`;
      impact = "Outdated NX-OS may expose cluster ISL links to known switch bugs causing traffic drops, incorrect ECMP hashing, or LACP timer issues that can disrupt cluster HA failover.";
      steps  = [
        "PRE-UPGRADE — run on BOTH switches in sequence (one at a time for non-disruptive upgrade):",
        `1. Download target NX-OS image from: ${downloadUrl}`,
        "2. Backup current switch config: 'copy running-config bootflash:pre-upgrade-backup.cfg'",
        "3. Validate ONTAP cluster link health BEFORE starting: 'network port show -ipspace cluster' (all ports must be up/up).",
        "4. Upload NX-OS image to switch bootflash: 'copy scp://user@<server>/nxos.bin bootflash:'",
        "5. Install upgrade (non-disruptive if only one switch is upgraded at a time): 'install all nxos bootflash:<image>'",
        "6. Confirm with 'y' when prompted. Switch will reload — ONTAP cluster links fail over to redundant switch during reload.",
        "7. After switch comes back up, verify NX-OS version: 'show version'",
        "8. Verify ONTAP cluster sees all ISL ports recovered: 'network port show -ipspace cluster'",
        "9. Repeat for the second switch.",
        isAFXSwitch ? "NOTE: AFX switches (9332D-GX2B / 9364D-GX2A) require ONTAP 9.17.1+ and are rated for 400GbE cluster ISLs. Verify with NetApp AFX design guide before firmware changes." : "",
        "Ref: https://docs.netapp.com/us-en/ontap-systems-switches/switch-cisco-9336c-fx2/upgrade-switch-overview.html"
      ].filter(Boolean);
      options = [
        "Option A: Non-disruptive rolling upgrade — one switch at a time while ONTAP cluster ISLs fail over to partner switch (recommended).",
        "Option B: Install NX-OS on the upgrade candidate during a full maintenance window (lower risk for first time)."
      ];
      thirdParty = "Verify the Cisco NX-OS version is listed in the NetApp IMT (https://imt.netapp.com/matrix/) for your ONTAP version and switch model before installing.";
    } else if (isCiscoMDS) {
      const fwBaseline = (REFERENCE_LIBRARY_FIRMWARE_BASELINES || {})["Cisco MDS"] || { recommended: "9.2(2)" };
      cause  = `Cisco MDS 9000-series switch is running SAN-OS/NX-OS below the recommended baseline (target: ${fwBaseline.recommended}).`;
      impact = "Outdated MDS firmware may expose Fibre Channel fabric to known zoning bugs, FSPF routing issues, or port flap defects that can cause SAN fabric disruptions.";
      steps  = [
        "1. Download Cisco MDS NX-OS firmware from: https://software.cisco.com/download/home/280283452",
        "2. Backup switch config and zone database: 'copy running-config startup-config' and 'copy running-config scp://backup-server'",
        "3. Upload image to MDS bootflash: 'copy scp://user@<server>/mds-image.bin bootflash:'",
        "4. Install upgrade: 'install all kickstart bootflash:<ks-image> system bootflash:<sys-image>'",
        "5. Upgrade non-disruptively using ISSU (In-Service Software Upgrade) if dual supervisors are present.",
        "6. Verify zoning and FLOGI database post-upgrade: 'show zoneset active' and 'show flogi database'",
        "Ref: https://www.cisco.com/c/en/us/support/storage-networking/mds-9000-nx-os-san-os-software/products-installation-guides-list.html"
      ];
      options = [
        "Option A: ISSU (In-Service Software Upgrade) on dual-supervisor MDS — non-disruptive.",
        "Option B: Scheduled maintenance window upgrade on single-supervisor or edge-of-support platforms."
      ];
      thirdParty = "Verify that all connected HBAs on host servers are qualified for the target MDS NX-OS version using the Cisco UCS/MDS HCL and the NetApp IMT.";
    } else if (isBrocade) {
      const fwBaseline = (REFERENCE_LIBRARY_FIRMWARE_BASELINES || {})["Brocade FOS"] || { recommended: "9.2.1" };
      cause  = `Brocade FC switch is running Fabric OS (FOS) below the recommended baseline (target: ${fwBaseline.recommended}).`;
      impact = "Outdated FOS may contain known Fibre Channel fabric defects affecting zone enforcement, ISL stability, or E_Port negotiation with ONTAP FC target ports.";
      steps  = [
        "1. Download Brocade FOS firmware from: https://www.broadcom.com/support/fibre-channel-networking/software-downloads",
        "2. Connect to switch via SSH as admin.",
        "3. Backup configuration: 'configupload' (saves to remote FTP/SCP server).",
        "4. Initiate firmware download: 'firmwaredownload -s -a <protocol>://<server>/<path>/fabos.bin'",
        "5. Monitor download and staging: firmware downloads to the secondary partition first.",
        "6. Activate firmware (requires brief disruption — ~15s port flap): 'firmwareactivate' OR use 'fastboot' for minimized disruption.",
        "7. For HA (dual-domain) ISL links, upgrade switches one at a time — ISLs reconverge automatically.",
        "8. Verify FOS version post-upgrade: 'version' and verify fabric topology: 'fabricshow'",
        "Ref: https://techdocs.broadcom.com/us/en/fibre-channel-networking/fabric-os/fabric-os-administration-guide.html"
      ];
      options = [
        "Option A: Non-disruptive HA upgrade — one switch per fabric at a time. ISLs re-establish within seconds.",
        "Option B: Full fabric maintenance window if single-switch fabric (no redundancy)."
      ];
      thirdParty = "Verify Brocade FOS version compatibility with ONTAP via the NetApp IMT: https://imt.netapp.com/matrix/. ESXi hosts may briefly log path errors during the ~15 second port flap — these are expected and self-recover.";
    } else if (isEFOS) {
      const fwBaseline = (REFERENCE_LIBRARY_FIRMWARE_BASELINES || {})["Broadcom EFOS"] || { recommended: "3.8.0.2" };
      cause  = `BES-53248 cluster switch is running EFOS below the recommended baseline (target: ${fwBaseline.recommended}).`;
      impact = "Outdated EFOS may cause cluster ISL port flap issues, incorrect LACP negotiation, or missing QoS enhancements required for high-speed cluster traffic.";
      steps  = [
        "1. Download EFOS firmware for BES-53248 from: https://mysupport.netapp.com/site/products/all/details/broadcom-cluster-switches/downloads-tab",
        "2. Connect to switch SSH session.",
        "3. Backup current config: 'copy running-config sftp://user@<server>/bes53248-backup.cfg'",
        "4. Upload EFOS image: 'copy sftp://user@<server>/EFOS-<version>.stk nvram:software install'",
        "5. Verify image loaded to standby partition: 'show bootvar'",
        "6. Reboot switch to activate new image: 'reload' — ONTAP cluster ISLs fail over to partner switch during reboot.",
        "7. Verify EFOS version: 'show version' and cluster ISL health: ONTAP 'network port show -ipspace cluster'",
        "8. Repeat for second BES-53248 switch.",
        "Ref: https://docs.netapp.com/us-en/ontap-systems-switches/switch-bes-53248/upgrade-efos-software.html"
      ];
      options = [
        "Option A: Rolling upgrade (one BES-53248 at a time) — non-disruptive to ONTAP cluster.",
        "Option B: Upgrade both switches in a maintenance window for first-time upgrade procedure."
      ];
      thirdParty = "BES-53248 is supported for ONTAP cluster interconnect only. Verify in NetApp IMT: https://imt.netapp.com/matrix/ for your ONTAP version.";
    } else if (isNVIDIA) {
      cause  = "NVIDIA SN2100 cluster switch is running Cumulus Linux below the recommended baseline.";
      impact = "Outdated Cumulus Linux may contain BGP routing defects or LACP instability affecting cluster ISL uptime.";
      steps  = [
        "1. Download the qualified Cumulus Linux image from: https://mysupport.netapp.com/site/products/all/details/nvidia-cluster-switches/downloads-tab",
        "2. SSH to the SN2100 switch (default user: cumulus).",
        "3. Stage image: 'sudo onie-install -a -i <image_url>'",
        "4. Reboot to activate: 'sudo reboot'",
        "5. Verify Cumulus version post-reboot: 'net show version'",
        "6. Verify ONTAP cluster ISL recovery: 'network port show -ipspace cluster'",
        "7. Ref: https://docs.netapp.com/us-en/ontap-systems-switches/switch-nvidia-sn2100/upgrade-cumulus-software.html"
      ];
      options = [
        "Option A: Rolling upgrade — one SN2100 at a time. ONTAP cluster ISLs fail over during reboot.",
        "Option B: Maintenance window upgrade for both switches simultaneously."
      ];
      thirdParty = "NVIDIA SN2100 is supported for ONTAP cluster interconnect as of ONTAP 9.9.1. Verify in NetApp IMT for your version.";
    } else {
      // Generic switch fallback
      cause  = "Cluster or management switch firmware is below the recommended validated baseline.";
      impact = "Outdated switch firmware may cause cluster ISL instability or missing required feature support.";
      steps  = [
        "1. Identify switch model and current firmware: ONTAP 'network switch show' or direct switch console.",
        "2. Verify qualified firmware version in NetApp IMT: https://imt.netapp.com/matrix/",
        "3. Download qualified firmware from vendor portal or NetApp Support: https://mysupport.netapp.com/site/downloads",
        "4. Follow vendor-specific upgrade procedure for your switch model.",
        "5. Perform rolling upgrade (one switch at a time) to maintain ONTAP cluster ISL redundancy.",
        "6. Verify ONTAP cluster health after each switch upgrade: 'cluster show' and 'network port show -ipspace cluster'"
      ];
      options = [
        "Option A: Rolling upgrade — preferred for maintaining cluster ISL redundancy.",
        "Option B: Scheduled full maintenance window if switch model requires simultaneous upgrade."
      ];
      thirdParty = "Verify switch model and firmware version in the NetApp IMT before upgrading: https://imt.netapp.com/matrix/";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // METROCLUSTER
  // ════════════════════════════════════════════════════════════════════════════
  if (isMCC || desc.includes("isl") || desc.includes("switchover") || desc.includes("switchback")) {
    if (desc.includes("upgrade") || desc.includes("version") || desc.includes("outdated")) {
      cause  = "MetroCluster site is running a mixed or outdated ONTAP version below the recommended baseline.";
      impact = "Version skew across MC sites may block switchover/switchback operations and introduce unsupported configuration states.";
      steps  = [
        "1. Confirm MetroCluster health BEFORE starting: 'metrocluster check run' and 'metrocluster check show' — ALL checks must pass.",
        "2. Verify ISL health: 'metrocluster interconnect show' (FC-MCC) or 'metrocluster configuration-settings interface show' (IP-MCC).",
        "3. Upgrade in the correct sequence:",
        "   a) First, upgrade the DISASTER RECOVERY (DR) site nodes (node3/node4).",
        "   b) Perform negotiated switchover: 'metrocluster switchover'",
        "   c) Upgrade the PRIMARY site nodes (node1/node2).",
        "   d) Perform switchback: 'metrocluster switchback'",
        "4. For each node upgrade, use standard NDU: 'cluster image update -version <target>'",
        "5. Verify MetroCluster is fully operational post-upgrade: 'metrocluster check run' (all PASSED).",
        is916OrNewer ? "NOTE: ONTAP 9.16.1+ enables SVM data mobility in MetroCluster-IP — verify SVM configurations after upgrade." : "",
        "Ref: https://docs.netapp.com/us-en/ontap-metrocluster/upgrade/task_upgrade_controllers_in_a_four_node_fc_mcc_us_switchover_and_switchback_mcc_fc_4n_cu.html"
      ].filter(Boolean);
      options = [
        "Option A: Switchover-based upgrade (recommended for major version changes — allows each site to be upgraded cleanly).",
        "Option B: Non-disruptive NDU without switchover for patch-level upgrades within the same ONTAP release branch."
      ];
      thirdParty = "Verify that all MetroCluster ISL switches have been upgraded to the required firmware for the target ONTAP version BEFORE starting the ONTAP upgrade. Ref: https://imt.netapp.com/matrix/";
    } else if (desc.includes("isl") || desc.includes("interconnect")) {
      cause  = "MetroCluster ISL (Inter-Switch Link) or back-end interconnect is degraded.";
      impact = "ISL degradation reduces MetroCluster mirroring throughput. Sustained packet loss >0.01% or jitter >3ms risks triggering an automatic unplanned switchover.";
      const mcReq = REFERENCE_LIBRARY_MC_REQUIREMENTS || { isl: { maxPacketLoss: 0.01, maxJitter: 3 } };
      steps  = [
        `1. ISL requirements: max packet loss ${mcReq.isl.maxPacketLoss}%, max RTT jitter ${mcReq.isl.maxJitter}ms, MTU ${mcReq.isl.requiredMTU} bytes.`,
        "2. Check ISL status: FC-MCC: 'metrocluster interconnect show' | IP-MCC: 'metrocluster configuration-settings interface show'",
        "3. Run ISL health diagnostics on FC switches (Brocade): 'islshow', 'portperfshow', 'diagshow'",
        "4. For Cisco MDS ISL: 'show interface fc <port> counters' — check for CRC errors, link resets.",
        "5. For IP-MCC: verify MTU 9216 on all backend switches: Cisco 'show interface <int> | grep MTU' | Brocade 'portcfgshow'",
        "6. Contact WAN/dark-fiber provider if packet loss is on a long-haul ISL — provide interface counters as evidence.",
        "7. Ref TR-4517: https://www.netapp.com/search/#q=TR-4517&t=Resources"
      ];
      options = [
        "Option A: Resolve physical ISL path issue (cable replacement, transceiver swap, or WAN provider escalation).",
        "Option B: If ISL degradation is persistent, proactively perform negotiated switchover to DR site while primary site ISL is repaired."
      ];
      thirdParty = "IP-MCC requires dedicated Ethernet path with MTU 9216. Shared WAN circuits MUST meet NetApp ISL requirements documented in TR-4517.";
    } else {
      cause  = "MetroCluster configuration health issue detected.";
      impact = "MetroCluster health issues can block automatic switchover/switchback operations, leaving the cluster unable to survive a site-level failure.";
      steps  = [
        "1. Run full MCC health check: 'metrocluster check run' followed by 'metrocluster check show'.",
        "2. Address each failed check item systematically — MCC check output includes specific remediation guidance.",
        "3. Verify mirroring status: 'storage aggregate show -is-home true' (all aggregates should be mirrored).",
        "4. Verify MCC node status: 'metrocluster node show' — all nodes must show 'normal'.",
        "5. Ref: https://docs.netapp.com/us-en/ontap-metrocluster/maintain/index.html"
      ];
      options = [
        "Option A: Resolve configuration health items and re-run MCC health check until all items pass.",
        "Option B: Engage NetApp Support for persistent MCC health failures that cannot be resolved via CLI."
      ];
      thirdParty = "MetroCluster ISL monitoring should be integrated into your WAN monitoring platform with alerting on packet loss >0.005% as an early warning threshold.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SNAPMIRROR / REPLICATION
  // ════════════════════════════════════════════════════════════════════════════
  if (desc.includes("snapmirror") || desc.includes("replication") || desc.includes("smbc") || desc.includes("active sync") || desc.includes("snapvault") || desc.includes("lag")) {
    if (desc.includes("active sync") || desc.includes("smbc")) {
      cause  = "SnapMirror active sync (symmetric active/active) relationship is out of sync or Mediator connectivity is lost.";
      impact = "RPO=0 protection is suspended. A storage failure will result in data unavailability for hosts mapped to affected LUNs.";
      steps  = [
        "1. Verify relationship status: 'snapmirror show -type StrictSync,Sync' — look for 'out-of-sync' or 'broken-off' relationships.",
        "2. Check ONTAP Mediator status: 'snapmirror mediator show' — Mediator must be 'connected' and 'reachable'.",
        is916OrNewer ? "3. ONTAP 9.16.1+: Mediator 1.9 is required. Verify Mediator version: ssh admin@<mediator-ip> 'mediator-sm version'" : "3. Verify ONTAP Mediator version matches the ONTAP version requirements (see docs).",
        "4. Re-establish relationship if broken: 'snapmirror resync -destination-path <dest_svm:dest_vol>'",
        "5. Verify all protected LUNs are accessible from both sites after resync: 'lun show' and check host mount status.",
        is915OrNewer ? "6. ONTAP 9.15.1+: Symmetric active/active now supports All-Flash SAN (ASA) — verify host sees LUNs from both paths." : "",
        "7. Ref: https://docs.netapp.com/us-en/ontap/snapmirror-active-sync/index.html"
      ].filter(Boolean);
      options = [
        "Option A: Resync from healthy site immediately (data from out-of-sync period will be overwritten from source).",
        "Option B: Engage NetApp Support if both sites are down or Mediator is inaccessible — manual takeover procedure may be required."
      ];
      thirdParty = "Verify host ALUA/multipath settings are configured per the SnapMirror active sync host requirements. VMware: ensure VAAI and vVol compatibility if applicable.";
    } else if (desc.includes("lag") || desc.includes("snapvault") || desc.includes("vault")) {
      cause  = "SnapMirror vault or SnapVault backup relationship has exceeded the RPO lag threshold.";
      impact = "Backup copies are stale beyond the agreed RPO. In a disaster scenario, data loss would exceed the approved recovery objective.";
      steps  = [
        "1. Check relationship lag: 'snapmirror show -fields lag-time,state,healthy'",
        "2. Identify unhealthy relationships: 'snapmirror show -health false'",
        "3. Trigger manual update for lagging relationships: 'snapmirror update -destination-path <dest_svm:dest_vol>'",
        "4. Check for network connectivity issues between source and destination clusters: 'cluster peer health show'",
        "5. Verify SnapMirror schedule is active: 'job schedule show' and 'snapmirror policy show'",
        "6. Ref: https://docs.netapp.com/us-en/ontap/data-protection/replication-workflow-concept.html"
      ];
      options = [
        "Option A: Trigger immediate manual update and investigate root cause of lag (network, schedule, or snapshot deletion).",
        "Option B: Review and adjust SnapMirror schedule or throttle policy if source cluster load is causing delays."
      ];
      thirdParty = "Verify cluster peering network (intercluster LIFs) has adequate bandwidth for transfer rate. Ref: 'network interface show -role intercluster'.";
    } else {
      cause  = "SnapMirror relationship is in an unhealthy or broken state.";
      impact = "Data protection copies are not being updated. RPO objectives are not being met.";
      steps  = [
        "1. Review relationship state: 'snapmirror show -health false'",
        "2. For broken-off relationships: 'snapmirror resync -destination-path <svm:vol>'",
        "3. For quiesced relationships: 'snapmirror resume -destination-path <svm:vol>'",
        "4. Monitor until sync is complete: 'snapmirror show -fields state,lag-time'",
        "5. Ref: https://docs.netapp.com/us-en/ontap/data-protection/index.html"
      ];
      options = [
        "Option A: Resync relationship immediately.",
        "Option B: Delete and recreate relationship if resync fails (data from current destination will be overwritten)."
      ];
      thirdParty = "Backup software (CommVault, Veeam, NetBackup) using SnapVault as a backup target should be validated after resync.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // CAPACITY / VOLUME / FABRICPOOL
  // ════════════════════════════════════════════════════════════════════════════
  if (catLower.includes("capacity") || desc.includes("full") || desc.includes("nearly full") || desc.includes("auto-grow") ||
      desc.includes("volume") || desc.includes("aggregate") || desc.includes("fabricpool") || desc.includes("tiering")) {
    if (desc.includes("fabricpool") || desc.includes("tiering")) {
      cause  = "FabricPool tiering policy is misconfigured or inactive, preventing cold data from being moved to object storage tier.";
      impact = "Hot tier (local NVME/SSD) fills with cold data, reducing available capacity for hot workloads and increasing cost per GB.";
      steps  = [
        "1. Check FabricPool tiering status: 'volume show -fields tiering-policy,cloud-retrieval-policy'",
        "2. Verify object store attachment: 'storage aggregate object-store show'",
        "3. Set appropriate tiering policy: 'volume modify -volume <vol> -tiering-policy auto' (recommended for most workloads)",
        "4. Check minimum cooling days: 'volume show -fields tiering-minimum-cooling-days' — default 31 days.",
        "5. Verify cloud tier connectivity: 'storage aggregate object-store check -aggregate <aggr>'",
        "6. Ref: https://docs.netapp.com/us-en/ontap/fabricpool/index.html"
      ];
      options = [
        "Option A: Apply 'auto' tiering policy (tiers cold blocks after minimum cooling period).",
        "Option B: Apply 'all' tiering policy (tiers all data including warm blocks — use only if S3 object store latency is acceptable for your workload)."
      ];
      thirdParty = "FabricPool requires a compatible object store (AWS S3, Azure Blob, GCP Storage, StorageGRID, or ONTAP S3). Verify object store credentials and bucket lifecycle policies are not deleting tiered data.";
    } else {
      cause  = "Volume or aggregate is approaching or has reached capacity threshold.";
      impact = "Volume full conditions can cause application write I/O failures, database transaction rollbacks, and unexpected service disruptions.";
      steps  = [
        "1. Check volume and aggregate capacity: 'volume show -fields size,used,available,percent-used' and 'aggr show'",
        "2. Enable volume auto-grow if not already active: 'volume modify -volume <vol> -autosize-mode grow -maximum-size <max>'",
        "3. Enable Snapshot autodelete if Snapshot copies are consuming excessive space: 'volume snapshot autodelete modify -volume <vol> -enabled true'",
        "4. Check for large or unused Snapshot copies: 'volume snapshot show -volume <vol> -fields size'",
        "5. For aggregate imbalance: move volumes to less-utilized aggregates: 'volume move start -volume <vol> -destination-aggregate <aggr>'",
        "6. Ref: https://docs.netapp.com/us-en/ontap/volumes/manage-volumes-task.html"
      ];
      options = [
        "Option A: Enable auto-grow and Snapshot autodelete for short-term relief.",
        "Option B: Add capacity (expand aggregate or add shelves) for a permanent solution."
      ];
      thirdParty = "Monitor application-level space thresholds — ONTAP auto-grow is reactive, not predictive. Set capacity alerts at 80% to allow time to respond before hitting 100%.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // AUTOSUPPORT / CONNECTIVITY
  // ════════════════════════════════════════════════════════════════════════════
  if (desc.includes("autosupport") || desc.includes("asup") || desc.includes("connectivity") || desc.includes("support site")) {
    cause  = "AutoSupport telemetry transmission is failing or configured with an insecure/deprecated transport.";
    impact = "Failed AutoSupport prevents Active IQ from detecting risks proactively and disqualifies the system from Digital Advisor-driven support.";
    steps  = [
      "1. Test AutoSupport connectivity: 'system node autosupport invoke -node * -type test'",
      "2. Check AutoSupport send log: 'system node autosupport history show -node * -type test'",
      "3. Ensure HTTPS transport is configured (HTTP is deprecated): 'system node autosupport modify -node * -transport https'",
      "4. If behind a proxy, configure proxy: 'system node autosupport modify -node * -proxy-url http://proxy:port'",
      "5. Verify DNS resolution to support.netapp.com: 'dns-lookup support.netapp.com'",
      "6. Verify NTP is synchronized (AutoSupport timestamps must be accurate): 'cluster time-service ntp status'",
      "7. Ref: https://docs.netapp.com/us-en/active-iq/"
    ];
    options = [
      "Option A: Switch to HTTPS and configure proxy if direct internet access is not available.",
      "Option B: Configure AutoSupport to relay via a local AutoSupport proxy server (SMTP or HTTPS relay)."
    ];
    thirdParty = "Some proxy servers block long-lived HTTPS connections — verify that the proxy allows persistent connections to support.netapp.com on port 443.";
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // AFX — All-Flash Fabric
  // ════════════════════════════════════════════════════════════════════════════
  if (isAFX) {
    if (desc.includes("upgrade") || desc.includes("version") || desc.includes("outdated")) {
      cause  = "AFX platform is running ONTAP below the minimum required version for full AFX feature support.";
      impact = "AFX requires ONTAP 9.17.1 minimum. Earlier versions do not support global deduplication across the SAZ or intelligent prefetching for sequential video workloads.";
      steps  = [
        "1. AFX minimum supported ONTAP version: 9.17.1. Target: 9.19.1 for full feature set.",
        "2. ONTAP 9.19.1 adds global deduplication across the entire SAZ (enabled by default), intelligent video prefetching, and per-SVM System Manager dashboards.",
        "3. Download ONTAP 9.17.1 or later from: https://mysupport.netapp.com/site/downloads",
        "4. Validate upgrade with: 'cluster image validate -version <target>'",
        "5. Run NDU upgrade: 'cluster image update -version <target>'",
        "6. Verify AFX-specific cluster switches (Cisco 9332D-GX2B or 9364D-GX2A) are running qualified firmware BEFORE upgrading ONTAP.",
        "7. Ref: https://docs.netapp.com/us-en/ontap-technical-reports/afx-overview/afx-overview-hardware.html"
      ];
      options = [
        "Option A: Upgrade to ONTAP 9.19.1 for full AFX feature set including global deduplication and ARP/AI within SnapMirror active sync.",
        "Option B: Upgrade to ONTAP 9.17.1 as minimum if 9.19.1 is not yet qualified for your workload requirements."
      ];
      thirdParty = "AFX NSM140 shelf modules are NOT interchangeable with NSM100/NSM100B used in AFF/ASA platforms. Verify all shelf components against the AFX hardware compatibility list.";
      return { cause, impact, steps, options, thirdParty };
    }
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SECURITY FINDINGS
  // ════════════════════════════════════════════════════════════════════════════
  if (catLower.includes("security") || desc.includes("insecure") || desc.includes("vulnerability") || desc.includes("cve")) {
    if (desc.includes("smb") || desc.includes("cifs") || desc.includes("kerberos") || desc.includes("rc4") || desc.includes("kb5073381") || desc.includes("aes")) {
      const kbRef = desc.includes("kb5073381") ? " (KB5073381 enforcement active as of July 2026)" : "";
      cause  = `CIFS/SMB security configuration is non-compliant${kbRef}. AES Kerberos encryption may not be enabled on affected SVMs.`;
      impact = "Microsoft KB5073381 final enforcement phase (July 2026) has DISABLED RC4 as an implicit Kerberos fallback. SVMs created before ONTAP 9.13.1 without explicit AES configuration will experience CIFS authentication failures NOW.";
      steps  = [
        "1. Check which SVMs are at risk: 'vserver cifs security show -vserver * -fields advertised-enc-types'",
        "   → If 'aes-128,aes-256' is NOT listed, that SVM is affected.",
        "2. Disable SMBv1 (if enabled): 'vserver cifs options modify -vserver <svm> -smb1-enabled false'",
        "3. Enable AES Kerberos: 'vserver cifs security modify -vserver <svm> -is-aes-encryption-enabled true -advertised-enc-types aes-128,aes-256'",
        "4. ⚠ CAUTION: AES change may require a machine account password reset. Verify first in a test SVM or schedule a brief CIFS disruption window.",
        "5. Validate in Active Directory: 'Get-ADComputer -Identity <CIFS_machine_account> -Properties msDS-SupportedEncryptionTypes' → must show AES bits (0x18 or higher).",
        "6. Check DC event logs for Event IDs 201-209 to identify remaining RC4-only machine accounts.",
        is913OrNewer ? "7. SVMs created on ONTAP 9.13.1+ have AES enabled by default — verify creation version to determine if action is needed." : "7. Your ONTAP version predates 9.13.1. AES is NOT enabled by default — explicit action required on ALL SVMs.",
        "8. Full guidance: https://kb.netapp.com/on-prem/ontap/da/NAS/NAS-KBs/ONTAP_Guidance_for_Microsoft_Security_Update_KB5073381_CVE_2026_20833"
      ];
      options = [
        "Option A: Enable AES immediately on all affected SVMs (recommended — CIFS auth is already failing in affected environments).",
        "Option B: If SMBv1 is required for legacy devices, isolate them to a separate SVM with restricted network access and apply AES to all other SVMs."
      ];
      thirdParty = "Windows NFS clients are not affected. Only CIFS/SMB authentication via Kerberos is impacted. Mac/Linux CIFS mounts using Kerberos may also be affected — verify with your AD team.";
    } else if (desc.includes("export") || desc.includes("nfs") || desc.includes("superuser")) {
      cause  = "NFS export policy rule allows superuser mounts or has an overly permissive clientmatch (e.g., 0.0.0.0/0).";
      impact = "Any host matching the export rule can mount volumes with root authority, enabling unauthorized data access or deletion.";
      steps  = [
        "1. List export policy rules: 'vserver export-policy rule show -vserver * -fields clientmatch,superuser,ruleindex'",
        "2. Restrict client match to specific subnets: 'vserver export-policy rule modify -vserver <svm> -policyname default -ruleindex <N> -clientmatch <trusted_subnet/mask>'",
        "3. Disable superuser access: 'vserver export-policy rule modify -vserver <svm> -policyname default -ruleindex <N> -superuser none'",
        "4. For Kerberos security: add 'krb5p' (encryption+integrity) to allowed security styles.",
        "5. Verify changes: 'vserver export-policy rule show -vserver <svm>'",
        "6. Ref: https://docs.netapp.com/us-en/ontap/nfs-config/create-export-policy-task.html"
      ];
      options = [
        "Option A: Restrict clientmatch to specific ESXi VMkernel IPs or trusted host subnets (Recommended).",
        "Option B: Enable Kerberos (krb5/krb5i/krb5p) for strong authentication if environment supports it."
      ];
      thirdParty = "VMware ESXi hosts mounting NFS datastores require root access — limit clientmatch to ESXi VMkernel adapter IPs specifically, not entire subnets if possible.";
    } else if (desc.includes("mav") || desc.includes("multi-admin")) {
      cause  = "Multi-Admin Verification (MAV) is not enabled, allowing single-admin execution of destructive operations.";
      impact = "Without MAV, a compromised or rogue admin account can delete volumes, disable snapshots, or turn off ransomware protection without requiring approval from a second administrator.";
      steps  = [
        "1. MAV requires ONTAP 9.11.1+. Verify version: 'version'",
        "2. Enable MAV: 'security multi-admin-verify modify -enabled true'",
        "3. Add approval groups: 'security multi-admin-verify approval-group create -name <group> -approvers <user1,user2>'",
        "4. Define protected operations: 'security multi-admin-verify rule create -operation <operation>'",
        "5. Recommended MAV-protected operations: volume delete, snapshot delete, security disable, SnapLock operations.",
        "6. Ref: https://docs.netapp.com/us-en/ontap/multi-admin-verify/index.html"
      ];
      options = [
        "Option A: Enable MAV with a minimum 2-admin approval group for destructive operations.",
        "Option B: Start with MAV in audit-only mode to understand operational impact before enforcement."
      ];
      thirdParty = "MAV approval requests are sent via email — ensure SMTP is configured on the cluster: 'system node autosupport modify -to <admin_email>'";
    } else if (desc.includes("audit") || desc.includes("tamper")) {
      cause  = "ONTAP audit logging or tamper-proof audit is not configured per security hardening requirements.";
      impact = "Without tamper-proof audit logging, audit events can be deleted or modified by a privileged admin, preventing forensic investigation after a security incident.";
      steps  = [
        "1. Enable audit on target SVM: 'vserver audit create -vserver <svm> -destination /audit_log_dir'",
        "2. Enable tamper-proof audit log (ONTAP 9.12.1+, enabled by default on new clusters): 'vserver audit modify -vserver <svm> -is-user-activity-audit-enabled true'",
        "3. Configure audit log rotation: 'vserver audit modify -vserver <svm> -rotate-size 100MB -rotate-schedule-hour 0'",
        "4. Verify audit config: 'vserver audit show -vserver <svm>'",
        "5. Ref: https://docs.netapp.com/us-en/ontap/nas-audit/index.html"
      ];
      options = [
        "Option A: Enable CIFS/NFS audit events (file access, permission changes) for compliance-sensitive SVMs.",
        "Option B: Enable management audit events at cluster level for admin activity tracking."
      ];
      thirdParty = "Export audit logs to a SIEM (Splunk, Microsoft Sentinel) using SNMP traps or syslog forwarding: 'cluster log-forwarding create'.";
    } else if (desc.includes("ssh") || desc.includes("tls") || desc.includes("cipher") || desc.includes("ssl")) {
      cause  = "SSH cipher configuration or TLS version settings include deprecated/weak algorithms.";
      impact = "Weak SSH ciphers (e.g., arcfour, 3des-cbc) or TLS 1.0/1.1 enable downgrade attacks on management sessions.";
      steps  = [
        "1. Check SSH ciphers: 'security ssh show'",
        "2. Restrict to strong ciphers only: 'security ssh modify -ciphers aes128-ctr,aes192-ctr,aes256-ctr,aes128-gcm@openssh.com,aes256-gcm@openssh.com'",
        "3. Restrict MAC algorithms: 'security ssh modify -mac-algorithms hmac-sha2-256,hmac-sha2-512,umac-128-etm@openssh.com'",
        "4. Disable TLS 1.0/1.1 for HTTPS management (ONTAP 9.8+): 'security ssl modify -min-version tlsv1.2'",
        "5. Ref: https://www.netapp.com/pdf.html?item=/media/10674-tr4569pdf.pdf (TR-4569 Security Hardening Guide)"
      ];
      options = [
        "Option A: Apply all cipher restrictions immediately — no service disruption for modern SSH clients.",
        "Option B: Test with a non-production cluster first if your jump host uses non-standard SSH client configurations."
      ];
      thirdParty = "Verify that ONTAP management automation scripts (Ansible, Python) use TLS 1.2+ HTTPS connections to the cluster management LIF after applying cipher restrictions.";
    } else if (desc.includes("snaplock") || desc.includes("worm")) {
      cause  = "SnapLock/WORM configuration is not enabled or snapshot locking is misconfigured.";
      impact = "Without SnapLock protection, ransomware actors can delete backup copies and render ransomware recovery impossible.";
      steps  = [
        "1. Enable SnapLock Compliance/Enterprise on new aggregate: 'storage aggregate create -aggregate <name> -snaplock-type compliance'",
        "2. Create SnapLock Compliance volume: 'volume create -volume <name> -aggregate <snaplock_aggr> -type DP'",
        "3. Configure default retention period: 'volume snaplock modify -volume <name> -default-retention-period 30days'",
        "4. Enable locked Snapshots on existing FlexVol (ONTAP 9.12.1+): 'volume snapshot policy modify -policy <policy> -is-schedule-enabled true'",
        is916OrNewer ? "5. NOTE: CVE-2026-22050 (NTAP-20260112-0001) — a vulnerability allowing locked snapshot expiry bypass was fixed in ONTAP 9.16.1P9 and 9.17.1P2. Ensure you are running a fixed version." : "",
        "6. Ref: https://docs.netapp.com/us-en/ontap/snaplock/index.html and TR-4526"
      ].filter(Boolean);
      options = [
        "Option A: Enable SnapLock Enterprise (allows admin to delete with justification) for operational flexibility.",
        "Option B: Enable SnapLock Compliance (truly immutable — no admin can delete before retention expires) for regulatory mandates."
      ];
      thirdParty = "SnapLock volumes are supported for NAS (NFS/CIFS) and SAN (iSCSI/FCP). Verify backup software (CommVault, Veeam) can write to SnapLock Compliance volumes via SnapVault.";
    } else {
      cause  = "Security configuration deviates from the ONTAP Security Hardening baseline (TR-4569).";
      impact = "Increased administrative attack surface and reduction in active compliance validation scores.";
      steps  = [
        "1. Consult the ONTAP Security Hardening Guide TR-4569: https://www.netapp.com/pdf.html?item=/media/10674-tr4569pdf.pdf",
        "2. Review PSIRT advisories at: https://security.netapp.com/advisory/",
        "3. Apply target hardening modifications under a standard change control window.",
        "4. Validate with 'security compliance show' if available for your ONTAP version."
      ];
      options = [
        "Option A: Apply security hardening settings (non-disruptive).",
        "Option B: Register a security policy exception in the corporate risk register if full hardening cannot be applied immediately."
      ];
      thirdParty = "Verify that third-party management tools (SolarWinds, Nagios, Zabbix) continue to authenticate via HTTPS/SNMPv3 after cipher hardening.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // NETWORK / CONFIGURATION
  // ════════════════════════════════════════════════════════════════════════════
  if (catLower.includes("network") || desc.includes("firewall") || desc.includes("lif") || desc.includes("ntp") || desc.includes("dns") || desc.includes("lacp")) {
    if (is910OrNewer && (desc.includes("firewall") || desc.includes("service policy"))) {
      cause  = "Legacy firewall policy settings are deprecated in ONTAP 9.10.1+ and must be replaced by LIF service policies.";
      impact = "Deprecated firewall rules are silently ignored by ONTAP 9.10.1+, potentially exposing management ports or causing routing anomalies.";
      steps  = [
        "1. List current LIF configurations and firewall policies: 'network interface show -fields firewall-policy'",
        "2. List available service policies: 'network interface service-policy show'",
        "3. Assign appropriate service policy to each LIF: 'network interface modify -vserver <svm> -lif <lif> -service-policy <policy>'",
        "   → Data LIFs: 'default-data-files' | Management LIFs: 'default-management' | Intercluster LIFs: 'default-intercluster'",
        "4. Verify: 'network interface show -fields service-policy'",
        "5. Clean up legacy firewall policies: 'system services firewall policy show' then delete if unused.",
        "6. Ref: https://docs.netapp.com/us-en/ontap/networking/create_a_lif.html"
      ];
      options = [
        "Option A: Enforce modern service-policies on all LIF configurations (Recommended — online, non-disruptive).",
        "Option B: If firewall rules are still referenced in automation scripts, update scripts before migrating LIFs."
      ];
      thirdParty = "Ensure backup/monitoring software connects via the updated LIF service policy mappings. Test connectivity from each management tool after migration.";
    } else if (desc.includes("ntp")) {
      cause  = "NTP (Network Time Protocol) is not configured or time synchronization has drifted.";
      impact = "Time drift >1 second can cause Kerberos authentication failures (CIFS, NFSv4), SnapMirror replication errors, and audit log timestamp corruption.";
      steps  = [
        "1. Check NTP status: 'cluster time-service ntp status' and 'date'",
        "2. Add NTP servers: 'cluster time-service ntp server create -server <ntp_server_ip>'",
        "3. Verify NTP sync: 'cluster time-service ntp status' — should show 'synchronized'",
        "4. For Kerberos environments: NTP must point to the same NTP source as Active Directory domain controllers.",
        "5. Ref: https://docs.netapp.com/us-en/ontap/system-admin/configure-ntp-server-cluster-task.html"
      ];
      options = [
        "Option A: Configure NTP to use internal AD-integrated NTP servers for Kerberos environments.",
        "Option B: Use public NTP pool servers (pool.ntp.org) if no internal NTP infrastructure exists."
      ];
      thirdParty = "Kerberos (SMB/NFS) requires time synchronization within 5 minutes of the KDC. NTP drift alerts should be configured at 30 seconds as an early warning.";
    } else if (desc.includes("dns")) {
      cause  = "DNS resolution is failing or DNS is not configured on one or more SVMs.";
      impact = "DNS failures prevent CIFS/SMB authentication, NFS hostname resolution, AutoSupport delivery, and SnapMirror peer hostname lookups.";
      steps  = [
        "1. Check DNS config per SVM: 'vserver services name-service dns show'",
        "2. Test DNS resolution: 'vserver services name-service dns check -vserver <svm>'",
        "3. Add or correct DNS servers: 'vserver services name-service dns modify -vserver <svm> -domains <domain> -name-servers <dns_ip>'",
        "4. Verify: 'vserver services name-service dns check -vserver <svm>' — all checks should pass.",
        "5. Ref: https://docs.netapp.com/us-en/ontap/networking/configure_dns_services_for_an_svm_task.html"
      ];
      options = [
        "Option A: Update DNS server list to point to reliable internal resolvers.",
        "Option B: Add redundant DNS servers to prevent single point of failure."
      ];
      thirdParty = "DNS must resolve the CIFS machine account name for Kerberos authentication. Verify both forward and reverse DNS records for the CIFS server exist in AD DNS.";
    } else {
      cause  = "Network configuration deviates from operational best practices.";
      impact = "Possible routing degradation, service latency, or management port exposure.";
      steps  = [
        "1. Review network port health: 'network port show' and 'network port reachability show'",
        "2. Review LIF status: 'network interface show'",
        "3. Check broadcast domain assignments: 'network port broadcast-domain show'",
        "4. Apply required modifications during a maintenance window.",
        "5. Ref: https://docs.netapp.com/us-en/ontap/networking/index.html"
      ];
      options = [
        "Option A: Apply network modifications online during scheduled change control.",
        "Option B: Retain current configurations if application dependencies require static routing."
      ];
      thirdParty = "Verify hypervisor datastores remain mounted and backup data paths remain online after any LIF or broadcast domain changes.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // HARDWARE / PATH / FRU
  // ════════════════════════════════════════════════════════════════════════════
  if (catLower.includes("hardware") || desc.includes("path") || desc.includes("cable") || desc.includes("fan") ||
      desc.includes("battery") || desc.includes("bbu") || desc.includes("psu") || desc.includes("fru") ||
      desc.includes("controller") || desc.includes("nvmem")) {
    if (desc.includes("path") || desc.includes("sas") || desc.includes("nvme") || desc.includes("cable")) {
      cause  = "Degraded connection, interface errors, or disconnected physical cable causing storage path loss.";
      impact = "Loss of path redundancy. A secondary failure on the remaining path causes data unavailability until the path is restored.";
      steps  = [
        "1. Verify path states: 'storage path show' (ONTAP) or 'storage disk path show'",
        "2. Check for SAS/NVMe error counters: 'storage port show' and 'storage adapter show'",
        "3. Inspect shelf status LEDs and IOM/NSM module link activity LEDs.",
        "4. Reseat cable connections at both the shelf IOM/NSM module and the HBA port end.",
        "5. If errors persist: swap with a known-good cable. Use the correct cable type (SAS: mini-SAS HD, NVMe: QSFP+/SFP28 depending on platform).",
        "6. Replace IOM/NSM module if module-level faults persist after cable swap.",
        "7. Ref: https://docs.netapp.com/us-en/ontap-systems/a900/index.html (replace with your platform)"
      ];
      options = [
        "Option A: Reseat or swap cable online — active multipathing protects I/O during the operation.",
        "Option B: Replace IOM/NSM shelf module — non-disruptive on dual-path shelf configurations."
      ];
      thirdParty = "ESXi/AHV hosts may log SCSI path degradation alerts during path restoration — these are expected and self-resolve once the path is restored.";
    } else {
      cause  = "Hardware component fault or sensor reading outside operational limits.";
      impact = "Risk of component failure leading to performance degradation or unplanned controller takeover.";
      steps  = [
        "1. Check cluster hardware alerts: 'system health alert show'",
        "2. View component health: 'system node show -fields health'",
        "3. For power supply (PSU): verify power cord seating, check for overheating in the rack.",
        "4. For fan failure: 'system environment sensors show' — open a case at https://mysupport.netapp.com/",
        "5. For NVMEM battery (on FAS/AFF classic platforms): 'system node environment sensors show -node *' — degraded NVMEM battery disables write caching.",
        "6. Coordinate FRU replacement with NetApp Support: https://mysupport.netapp.com/",
        "7. Ref: https://docs.netapp.com/us-en/ontap-systems/index.html"
      ];
      options = [
        "Option A: Hot-swap replacement online (non-disruptive for hot-pluggable PSUs, fans).",
        "Option B: Schedule maintenance window with node takeover/giveback if controller-level FRU replacement is required."
      ];
      thirdParty = "Monitor virtualization and backup console logs for physical chassis alarm notifications during FRU replacement procedures.";
    }
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // SOFTWARE / ONTAP UPGRADE — must come AFTER all firmware-specific blocks
  // ════════════════════════════════════════════════════════════════════════════
  if (catLower.includes("software") || catLower.includes("firmware") || desc.includes("version") || desc.includes("upgrade") || desc.includes("outdated")) {
    const targetVer = (sys.upgrades && sys.upgrades.targetVersion) ? sys.upgrades.targetVersion : (sys.recommendedVersion || "current recommended");
    const caveatList = versionCaveats[targetVer] || [];
    const isMultiHop = sys.upgrades && sys.upgrades.hops && sys.upgrades.hops.length > 1;

    cause  = `${clusterName} is running ONTAP ${ontapVer || "an outdated version"}, which is below the recommended baseline${targetVer ? " (" + targetVer + ")" : ""}.`;
    impact = "Running an outdated ONTAP version exposes the cluster to resolved bugs, security vulnerabilities, and missing feature support. Some versions are approaching or past End-of-Support.";

    steps  = [
      // Pre-upgrade checklist
      "PRE-UPGRADE CHECKLIST:",
      "1. Verify cluster HA status: 'cluster show' — all nodes must be healthy. 'storage failover show' — takeover must be enabled.",
      "2. Verify no active hardware alerts: 'system health alert show'",
      "3. Verify aggregate status: 'storage aggregate show' — all aggregates must be online.",
      "4. Check disk health: 'storage disk show -broken' — must return no broken disks.",
      "5. Verify shelf/disk firmware: 'storage firmware show' — update shelf/DQP firmware BEFORE ONTAP upgrade if lagging.",
      "6. Check switch firmware compatibility in IMT: https://imt.netapp.com/matrix/",
      "7. Generate config backup: 'system configuration backup create -node * -backup-name pre_upgrade_" + ontapVer.replace(/\./g, "_") + "'",
      "8. For SnapMirror active sync/SMBC: upgrade ONTAP Mediator FIRST. https://docs.netapp.com/us-en/ontap/mediator/index.html",
      "",
      // Upgrade execution
      "UPGRADE EXECUTION:",
      isMultiHop ? `9. This is a MULTI-HOP UPGRADE (${sys.upgrades.hops.length} hops required): complete each intermediate hop fully before proceeding to the next.` : "",
      `9. Download ONTAP ${targetVer} image from: https://mysupport.netapp.com/site/downloads`,
      `10. Review Upgrade Advisor recommendations: https://activeiq.netapp.com (sign in with NSS credentials)`,
      `11. Validate upgrade: 'cluster image validate -version ${targetVer}' — fix any blocking items before proceeding.`,
      `12. Run NDU: 'cluster image update -version ${targetVer} -noconfirm'`,
      "13. Monitor upgrade progress: 'cluster image show-update-progress'",
      "14. Verify post-upgrade: 'version' and 'cluster show'",
      "",
      // Version-specific caveats
      ...(caveatList.length > 0 ? ["VERSION-SPECIFIC CAVEATS FOR " + targetVer + ":"] : []),
      ...caveatList.map((c, i) => `   ⚠ ${c}`),
      "",
      `Full ONTAP upgrade guide: https://docs.netapp.com/us-en/ontap/upgrade/index.html`
    ].filter(s => s !== undefined);

    options = [
      `Option A: Non-disruptive rolling upgrade (NDU) — nodes fail over one at a time. No I/O interruption for HA pairs.`,
      isMultiHop ? `Option B: Multi-hop path — intermediate version ${sys.upgrades && sys.upgrades.hops ? sys.upgrades.hops[0].to : "intermediate"} is required before reaching ${targetVer}. Complete each hop before proceeding.` : `Option B: Upgrade during a scheduled maintenance window if additional buffer time is desired for validation steps.`
    ];
    thirdParty = `Verify all connected systems in the NetApp IMT (https://imt.netapp.com/matrix/) for the target ONTAP version BEFORE upgrading: VMware ESXi HBA drivers, backup software agents, host multipath drivers, and cluster switches.`;
    return { cause, impact, steps, options, thirdParty };
  }

  // ════════════════════════════════════════════════════════════════════════════
  // Default / catch-all
  // ════════════════════════════════════════════════════════════════════════════
  return { cause, impact, steps, options, thirdParty };
}

function getLogisticsUpdateTicketsAndDiffs(sys) {
  const l = { deliveryAddress: "Not Set", accessRestrictions: "Not Set", shippingAlert: "None", ...sys.logistics };
  const c = { name: "Not Set", phone: "Not Set", email: "Not Set", nssUsername: "Not Set", ...sys.contacts };
  
  const origL = sys.originalLogistics || { deliveryAddress: "Not Set", accessRestrictions: "Not Set", shippingAlert: "None" };
  const origC = sys.originalContacts || { name: "Not Set", phone: "Not Set", email: "Not Set", nssUsername: "Not Set" };
  
  const changes = [];
  if (l.deliveryAddress !== origL.deliveryAddress) {
    changes.push({ field: "Delivery Address", oldVal: origL.deliveryAddress, newVal: l.deliveryAddress });
  }
  if (l.accessRestrictions !== origL.accessRestrictions) {
    changes.push({ field: "Access Restrictions", oldVal: origL.accessRestrictions, newVal: l.accessRestrictions });
  }
  if (l.shippingAlert !== origL.shippingAlert) {
    changes.push({ field: "Shipping Alert", oldVal: origL.shippingAlert, newVal: l.shippingAlert });
  }
  if (c.name !== origC.name) {
    changes.push({ field: "Contact Name", oldVal: origC.name, newVal: c.name });
  }
  if (c.phone !== origC.phone) {
    changes.push({ field: "Contact Phone", oldVal: origC.phone, newVal: c.phone });
  }
  if (c.email !== origC.email) {
    changes.push({ field: "Contact Email", oldVal: origC.email, newVal: c.email });
  }
  if (c.nssUsername !== origC.nssUsername) {
    changes.push({ field: "NSS Username", oldVal: origC.nssUsername, newVal: c.nssUsername });
  }
  
  const hasChanges = changes.length > 0;
  
  let diffsHTML = "";
  let diffsTXT = "";
  let ticketTXT = "";
  
  if (hasChanges) {
    diffsHTML = `
      <div style="margin-top: 16px; background-color: rgba(0, 188, 212, 0.03); border: 1px solid rgba(0, 188, 212, 0.15); padding: 16px; border-radius: var(--radius-sm);">
        <div style="font-weight: 700; color: var(--accent-cyan); margin-bottom: 8px; font-size: 0.82rem; text-transform: uppercase;">Detected Local Edits (Pending Official Active IQ Update)</div>
        <table style="width: 100%; border-collapse: collapse; font-size: 0.78rem; text-align: left; margin-bottom: 12px;">
          <thead>
            <tr style="border-bottom: 1px solid var(--border-color); color: var(--text-muted);">
              <th style="padding: 6px 0;">Field Name</th>
              <th style="padding: 6px 12px;">Old Value (DB)</th>
              <th style="padding: 6px 0;">New Value (Local Edit)</th>
            </tr>
          </thead>
          <tbody>
            ${changes.map(ch => `
              <tr style="border-bottom: 1px solid rgba(255,255,255,0.03);">
                <td style="padding: 6px 0; font-weight: 600;">${ch.field}</td>
                <td style="padding: 6px 12px; color: var(--text-muted); font-style: italic;">${ch.oldVal || '(Not Configured)'}</td>
                <td style="padding: 6px 0; color: var(--status-normal); font-weight: 600;">${ch.newVal || '(Cleared)'}</td>
              </tr>
            `).join("")}
          </tbody>
        </table>
    `;
    
    diffsTXT = `DETECTED LOGISTICS CHANGES (PENDING OFFICIAL ACTIVE IQ UPDATE):\n` + 
      changes.map(ch => ` * ${ch.field}:\n   - Old: ${ch.oldVal || '(Not Configured)'}\n   - New: ${ch.newVal || '(Cleared)'}`).join("\n") + "\n";
    
    const changeLines = changes.map(ch => `* ${ch.field}:\n  - Old: ${ch.oldVal || '(Not Configured)'}\n  - New: ${ch.newVal || '(Cleared)'}`).join("\n");
    
    ticketTXT = `To: NetApp Support (Install Base & Serial Registration Group)
Subject: Non-Technical Install Base Record Update Request - S/N: ${sys.serialNumber}

Please update the install site records and contact directory for the following system:
* Serial Number: ${sys.serialNumber}
* Platform Model: ${sys.platform}
* Customer Account: ${sys.customerName}

REQUESTED SYSTEM CHANGES:
${changeLines}

Reason for Change: Updating local datacenter access restrictions and primary site contact records to prevent parts delivery shipment delays. Please notify once records have updated in NetApp CRM and Active IQ.`;

    diffsHTML += `
        <div style="font-weight: 700; color: var(--text-secondary); margin-bottom: 6px; font-size: 0.78rem;">Non-Technical Ticket Copy-Paste Template:</div>
        <textarea readonly class="form-input" rows="8" style="font-family: monospace; font-size: 0.74rem; background: rgba(0,0,0,0.3); border-color: var(--border-color); color: var(--text-secondary); cursor: text;" onclick="this.select()">${ticketTXT}</textarea>
      </div>
    `;
  }
  
  return { hasChanges, diffsHTML, diffsTXT, ticketTXT };
}

// Filter support cases: only open/active, sorted by highest priority
function filterActiveCases(cases) {
  // Classify each case as active or inactive/closed
  const closedStatuses = ['closed', 'resolved', 'cancelled', 'canceled', 'auto-close', 'pendingclose', 'pendingclosed', 'internaluserreqclosed'];
  const inactiveStatuses = ['coreancillary', 'corereceived', 'coreincomplete', 'duplicatecore', 'coreunderanalysis', 'initializing'];
  
  cases.forEach(c => {
    const st = (c.status || '').toLowerCase().replace(/[\s_-]/g, '');
    const isClosed = closedStatuses.some(cs => st.includes(cs.replace(/[\s_-]/g, '')));
    const isInactive = inactiveStatuses.some(cs => st.includes(cs.replace(/[\s_-]/g, '')));
    c._isActive = !isClosed && !isInactive;
    c._isClosed = isClosed;
  });
  
  // Sort: active first (by severity), then inactive (by severity), then closed (by date)
  cases.sort((a, b) => {
    // Active cases first
    if (a._isActive && !b._isActive) return -1;
    if (!a._isActive && b._isActive) return 1;
    // Closed cases last
    if (a._isClosed && !b._isClosed) return 1;
    if (!a._isClosed && b._isClosed) return -1;
    // Within same group, sort by severity
    const pa = parseInt((a.severity || 'S9').replace(/[^0-9]/g, '')) || 9;
    const pb = parseInt((b.severity || 'S9').replace(/[^0-9]/g, '')) || 9;
    return pa - pb;
  });
  return cases;
}

/**
 * Filter and deduplicate risks for deliverables.
 * Groups risks by their corrective fix (e.g. "Upgrade to ONTAP 9.16.1").
 * Returns an array of fix-groups, sorted by number of findings (most impactful first).
 * 
 * Each group: { fix, fixUrl, severity, systems[], findings[], count }
 *   - fix: the corrective action string
 *   - fixUrl: primary advisory/KB URL for reference
 *   - severity: highest severity in the group (critical > high)
 *   - systems: unique system names affected
 *   - findings: array of { description, severity, category, advisoryUrl, systemName }
 *   - count: total number of individual findings consolidated
 *
 * Also exposes .asFlat() to return a flat risk array for legacy consumers.
 */
function _filterAndDeduplicateRisks(risks, targetSystems) {
  const sevRank = { critical: 0, high: 1, medium: 2, low: 3 };

  // Step 1: filter severity and category
  const filtered = risks.filter(r => {
    const sev = (r.severity || '').toLowerCase();
    if (sev !== 'critical' && sev !== 'high') return false;
    const cat = (r.category || '').toLowerCase();
    if (cat === 'best practice' || cat === 'best_practice' || cat === 'best practices') return false;
    return true;
  });

  // Step 2: determine the corrective fix for each risk
  // Build a system lookup for recommended versions
  const sysLookup = {};
  (targetSystems || []).forEach(s => {
    if (s.systemName) sysLookup[s.systemName] = s;
  });

  // Step 3: group by fix action
  const fixGroups = new Map(); // fix key -> group object

  for (const r of filtered) {
    // Determine the fix: use the system's recommended upgrade version if available
    const sys = sysLookup[r.systemName] || {};
    const targetVer = sys.recommendedVersion || (sys.upgrades || {}).targetVersion || '';
    const isUpgradeAvailable = targetVer && targetVer !== 'Up to Date';

    let fixKey = '';
    let fixLabel = '';
    if (isUpgradeAvailable) {
      // Group all findings on the same cluster/version together
      const clusterKey = sys.clusterName || sys.systemName || '';
      fixKey = `upgrade:${clusterKey}:${targetVer}`;
      fixLabel = `Upgrade to ONTAP ${targetVer}`;
    } else if (r.advisoryUrl) {
      fixKey = `advisory:${r.advisoryUrl}`;
      fixLabel = r.recommendation || `Apply corrective action per advisory`;
    } else {
      // Unique finding — no grouping
      const cveMatch = (r.description || '').match(/CVE-[0-9]{4}-[0-9]+/);
      fixKey = `individual:${cveMatch ? cveMatch[0] : r.description}`;
      fixLabel = r.recommendation || `Apply corrective action per NetApp guidelines`;
    }

    if (fixGroups.has(fixKey)) {
      const group = fixGroups.get(fixKey);
      group.findings.push({
        description: r.description,
        severity: r.severity,
        category: r.category,
        advisoryUrl: r.advisoryUrl,
        systemName: r.systemName
      });
      group.count++;
      if (r.systemName && !group.systems.includes(r.systemName)) {
        group.systems.push(r.systemName);
      }
      // Promote to highest severity
      if ((sevRank[r.severity] || 9) < (sevRank[group.severity] || 9)) {
        group.severity = r.severity;
      }
      // Keep best advisory URL
      if (!group.fixUrl && r.advisoryUrl) group.fixUrl = r.advisoryUrl;
    } else {
      const group = {
        fix: fixLabel,
        fixUrl: r.advisoryUrl || '',
        severity: r.severity,
        systems: [r.systemName || ''],
        findings: [{
          description: r.description,
          severity: r.severity,
          category: r.category,
          advisoryUrl: r.advisoryUrl,
          systemName: r.systemName
        }],
        count: 1,
        // Carry forward remediation plan from first risk for step details
        remediationPlan: r.remediationPlan || null,
        recommendation: r.recommendation || ''
      };
      fixGroups.set(fixKey, group);
    }
  }

  // Step 4: sort by number of findings (most impactful fix first), then by severity
  const groups = [...fixGroups.values()].sort((a, b) => {
    // Severity first (critical before high)
    const sevDiff = (sevRank[a.severity] || 9) - (sevRank[b.severity] || 9);
    if (sevDiff !== 0) return sevDiff;
    // Then by count descending (fixes that address more issues first)
    return b.count - a.count;
  });

  // Attach a .asFlat() helper for legacy consumers that expect a flat risk array
  groups.asFlat = function() {
    const flat = [];
    for (const g of this) {
      if (g.count === 1) {
        // Single finding — return as-is
        flat.push({
          ...g.findings[0],
          recommendation: g.fix,
          remediationPlan: g.remediationPlan
        });
      } else {
        // Consolidated finding
        const sysNames = [...new Set(g.systems.filter(Boolean))];
        const sysLabel = sysNames.length <= 3 ? sysNames.join(', ') : `${sysNames.slice(0, 3).join(', ')} +${sysNames.length - 3} more`;
        flat.push({
          description: `${g.fix} — addresses ${g.count} findings across ${sysNames.length} system${sysNames.length > 1 ? 's' : ''}`,
          severity: g.severity,
          category: g.findings[0].category,
          systemName: sysLabel,
          advisoryUrl: g.fixUrl,
          recommendation: g.fix,
          remediationPlan: g.remediationPlan,
          _consolidatedFindings: g.findings
        });
      }
    }
    return flat;
  };

  return groups;
}


function compileCustomerSuccessPlanText(scopeTitle, allRisks, allUpgrades, targetSystems, expiringContracts, allSupportCases) {
  let totalCapTB = 0;
  let logicalCapTB = 0;
  let totalSavedTB = 0;
  let activeTAMOwner = "Not Set";
  let activeAMOwner = "Not Set";
  let csatScoreSum = 0;
  let systemCount = targetSystems.length;

  targetSystems.forEach(sys => {
    if (sys.efficiency) {
      logicalCapTB += sys.efficiency.logicalUsedTB || 0;
      totalCapTB += sys.efficiency.physicalUsedTB || 0;
      totalSavedTB += sys.efficiency.spaceSavedTB || 0;
    }
    if (sys.salesHealth) {
      csatScoreSum += sys.salesHealth.sentimentScore || 7.5;
      activeTAMOwner = sys.salesHealth.supportTam || activeTAMOwner;
      activeAMOwner = sys.salesHealth.accountManager || activeAMOwner;
    }
  });

  const avgCsat = systemCount > 0 ? (csatScoreSum / systemCount).toFixed(1) : "No Data";
  const spaceSavedRatio = totalCapTB > 0 ? (logicalCapTB / totalCapTB).toFixed(1) : "1.0";

  // ── ASUP & ARP health ──
  const now = Date.now();
  const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;
  const asupCompliant = targetSystems.filter(s => {
    if (!s.latestAsupDate) return false;
    const d = new Date(s.latestAsupDate);
    return !isNaN(d) && (now - d.getTime()) <= sevenDaysMs;
  }).length;
  const arpCount = targetSystems.filter(s => s.isARPEnabled === true).length;
  const fwCurrent = targetSystems.filter(s => s.swRecMin && s.osVersion && !versionLt(s.osVersion, s.swRecMin)).length;
  const contractActive = targetSystems.filter(s => s.contractActive === true).length;

  // ── Risk groups ──
  const fixGroups = _filterAndDeduplicateRisks(allRisks, targetSystems);
  const critCount = allRisks.filter(r => r.severity === 'critical').length;
  const highCount = allRisks.filter(r => r.severity === 'high').length;
  const medCount  = allRisks.filter(r => r.severity === 'medium').length;
  const secCount  = allRisks.filter(r => (r.category||'').toLowerCase() === 'security').length;

  // ── Switch firmware compliance ──
  const switchDrift = [];
  targetSystems.forEach(sys => {
    (sys.switches || []).forEach(sw => {
      if (sw.recommendedFirmware && sw.firmware && sw.firmware !== sw.recommendedFirmware) {
        switchDrift.push({ systemName: sys.systemName, model: sw.model, current: sw.firmware, recommended: sw.recommendedFirmware });
      }
    });
  });

  // ── Shelf firmware compliance ──
  const shelfDrift = [];
  targetSystems.forEach(sys => {
    (sys.shelves || []).forEach(sh => {
      const baseline = (REFERENCE_LIBRARY_FIRMWARE_BASELINES || {})[sh.moduleType];
      if (baseline && sh.firmwareVersion && sh.firmwareVersion !== baseline.recommended) {
        shelfDrift.push({ systemName: sys.systemName, model: sh.model, module: sh.moduleType, current: sh.firmwareVersion, recommended: baseline.recommended });
      }
    });
  });

  // ── Security bulletins ──
  const secBulletins = [];
  targetSystems.forEach(sys => {
    (sys.securityBulletins || []).forEach(b => {
      if ((b.severity || '').toLowerCase() === 'critical' || (b.severity || '').toLowerCase() === 'high') {
        secBulletins.push({ systemName: sys.systemName, ...b });
      }
    });
  });

  // ── AutoSupport issues ──
  const asupIssues = [];
  targetSystems.forEach(s => {
    const asup = s.autosupport || { enabled: true, status: "healthy", lastReceivedDays: 1 };
    if (!asup.enabled) {
      asupIssues.push({ name: s.systemName, issue: "AutoSupport Disabled", detail: asup.failureReason || "Disabled." });
    } else if (asup.status === "failed" || asup.lastReceivedDays > 7) {
      asupIssues.push({ name: s.systemName, issue: "AutoSupport Stale", detail: `No telemetry for ${asup.lastReceivedDays} days. Verify HTTPS (443) to support.netapp.com.` });
    }
  });

  // ── MetroCluster systems ──
  const mccSystems = targetSystems.filter(s => (s.platform || '').toLowerCase().includes('metrocluster') || (s.platform || '').toLowerCase().includes('mcc'));

  // ── StorageGRID systems ──
  const sgSystems = targetSystems.filter(s => (s.platform || '').toLowerCase().includes('storagegrid') || (s.osType || '') === 'StorageGRID');

  // ── SANtricity/E-Series systems ──
  const sanSystems = targetSystems.filter(s => (s.platform || '').toLowerCase().includes('e-series') || (s.platform || '').toLowerCase().includes('ef') || s.santricityVersion);

  // ── Upgrade text with full hop details ──
  const upgradesText = allUpgrades.map(u => {
    const hops = calculateUpgradePath(u.platform, u.currentVersion || "", u.targetVersion);
    let hopDetails = "";
    if (hops.length > 1) {
      hopDetails += `\n     [Multi-Hop Upgrade Required: ${hops.map(h => h.from + ' -> ' + h.to).join(' | ')}]`;
    }
    hops.forEach((h, idx) => {
      hopDetails += `\n     * Hop ${idx + 1}: ${h.from} -> ${h.to}`;
      if (h.steps && h.steps.length > 0) hopDetails += `\n       Steps: ${h.steps.map(s => s.replace(/<[^>]*>/g, "")).join(" | ")}`;
      if (h.considerations && h.considerations.length > 0) hopDetails += `\n       Caveats: ${h.considerations.map(c => c.replace(/<[^>]*>/g, "")).join(" | ")}`;
      if (h.docLink) hopDetails += `\n       Ref: ${h.docLink}`;
    });
    return `- Upgrade ${u.systemName} from ${u.currentVersion || "current"} to ${u.targetVersion} (${u.urgency})\n     -> Benefit: ${u.benefits}${hopDetails}`;
  }).join("\n");

  const casesText = allSupportCases.map(c =>
    `- Case ID: ${c.id} (${c.systemName}) | Sev: ${c.severity} | Status: ${c.status || 'Open'} | Owner: ${c.nextActionBy || "Under Review"}\n  -> Title: ${c.title}`
  ).join("\n");

  const contractsText = expiringContracts.map(e =>
    `- System: ${e.systemName} | S/N: ${e.serialNumber || 'N/A'} | Level: ${e.supportLevel} | Expires: ${e.endDate} (${e.daysRemaining} days)`
  ).join("\n");

  const risksText = fixGroups.map((g, i) => {
    const sysNames = [...new Set(g.systems.filter(Boolean))];
    const sysLabel = sysNames.length <= 3 ? sysNames.join(', ') : `${sysNames.slice(0, 3).join(', ')} +${sysNames.length - 3} more`;
    const refUrl = g.fixUrl || '';
    const refLine = refUrl ? `\n   -> Reference: ${refUrl}` : '';
    const stepsBlock = (() => {
      // Pull enriched steps from the first finding's remediationPlan
      const firstFinding = g.findings[0];
      const plan = firstFinding && firstFinding.remediationPlan;
      if (plan && plan.steps && plan.steps.length > 0) {
        return '\n   -> Steps:\n' + plan.steps.map(s => `      ${s}`).join('\n');
      }
      return '';
    })();
    if (g.count === 1) {
      return `${i+1}. [${g.severity.toUpperCase()}] ${g.findings[0].systemName}: ${g.findings[0].description}\n   -> Fix: ${g.fix}${stepsBlock}${refLine}`;
    }
    let text = `${i+1}. [${g.severity.toUpperCase()}] FIX: ${g.fix}  (resolves ${g.count} finding${g.count > 1 ? 's' : ''} across ${sysLabel})`;
    g.findings.forEach(f => { text += `\n     • [${(f.severity || '').toUpperCase()}] ${f.description}`; });
    text += stepsBlock;
    text += refLine;
    return text;
  }).join("\n\n");

  // ── Platform summary ──
  const platformCounts = {};
  targetSystems.forEach(s => {
    const p = s.platform || 'Unknown';
    platformCounts[p] = (platformCounts[p] || 0) + 1;
  });
  const platformLines = Object.entries(platformCounts).map(([p, n]) => `  - ${p}: ${n} system${n > 1 ? 's' : ''}`).join('\n');

  return `================================================================================
CUSTOMER SUCCESS PLAN (CSP) & ENVIRONMENTAL POSTURE OPTIMIZATION
================================================================================
CUSTOMER SCOPE       : ${scopeTitle}
DATE GENERATED       : ${new Date().toISOString().split('T')[0]}
ACCOUNT TEAM         : TAM: ${activeTAMOwner} | Account Manager: ${activeAMOwner}
CSAT SENTIMENT RATING: ${avgCsat} / 10.0 (Support & Account Hygiene)
ENVIRONMENT HEALTH   : ${allRisks.length > 0 ? 'WARNING - Action Required' : 'OPTIMAL / COMPLIANT'}
SYSTEMS IN SCOPE     : ${systemCount}

--------------------------------------------------------------------------------
1. EXECUTIVE SUMMARY & VALUE ALIGNMENT
--------------------------------------------------------------------------------
This Customer Success Plan aligns storage operations to ITIL Change Control, NIST/SANS
hardening, and NetApp Best Practices across ${systemCount} system${systemCount !== 1 ? 's' : ''} spanning:
${platformLines}

* OPERATIONAL HEALTH SCORECARD:
  - AutoSupport Compliance:  ${asupCompliant}/${systemCount} (${systemCount > 0 ? Math.round(asupCompliant/systemCount*100) : 0}%) — within 7-day telemetry window
  - ARP Coverage:            ${arpCount}/${systemCount} (${systemCount > 0 ? Math.round(arpCount/systemCount*100) : 0}%) — Anti-Ransomware Protection enabled
  - Firmware Currency:       ${fwCurrent}/${systemCount} (${systemCount > 0 ? Math.round(fwCurrent/systemCount*100) : 0}%) — running recommended OS baseline
  - Contract Coverage:       ${contractActive}/${systemCount} (${systemCount > 0 ? Math.round(contractActive/systemCount*100) : 0}%) — active support contract

* RISK POSTURE SUMMARY:
  - Critical: ${critCount}  |  High: ${highCount}  |  Medium: ${medCount}
  - Security Advisories: ${secCount}
  - Switch Firmware Drift: ${switchDrift.length} switch${switchDrift.length !== 1 ? 'es' : ''} below validated baseline
  - Shelf Firmware Drift: ${shelfDrift.length} shelf module${shelfDrift.length !== 1 ? 's' : ''} below recommended version
  - AutoSupport Issues: ${asupIssues.length}
  - Open Support Cases: ${allSupportCases.length}

* WORKLOAD EFFICIENCY HYGIENE:
  - Total Physical Used Capacity: ${totalCapTB.toFixed(1)} TB
  - Total Logical Capacity Represented: ${logicalCapTB.toFixed(1)} TB
  - Storage Efficiency Ratio: ${spaceSavedRatio}:1 (Saved ${totalSavedTB.toFixed(1)} TB via Deduplication/Compression)
  - Capacity Projections: High-runway analytics applied. Tech refresh plans are mapped to lifecycle windows.

* CUSTOMER SATISFACTION (CSAT):
  - Sentiment score: ${avgCsat}/10
  - Periodic QBRs will be scheduled to review hardware lifecycle transitions and cloud integration milestones.
${mccSystems.length > 0 ? `
* METROCLUSTER SYSTEMS (${mccSystems.length}):
  - MetroCluster upgrade sequence: DR site first, then primary site, then switchover/switchback verification.
  - ISL health requirements: packet loss <0.01%, jitter <3ms, MTU 9216 bytes.
  - Reference: docs.netapp.com/us-en/ontap-metrocluster/ | TR-4510 | TR-4517
` : ''}${sgSystems.length > 0 ? `
* STORAGEGRID SYSTEMS (${sgSystems.length}):
  - StorageGRID upgrades must follow sequential hop path (no skipping minor versions).
  - Reference: Maintenance > Software Update in Grid Manager.
` : ''}${sanSystems.length > 0 ? `
* SANTRICITY / E-SERIES SYSTEMS (${sanSystems.length}):
  - SANtricity upgrades require BOTH SANtricity OS AND NVSRAM files.
  - Use SANtricity System Manager > Upgrade Center for non-disruptive controller upgrades.
` : ''}
--------------------------------------------------------------------------------
2. SUPPORT CASE & SERVICE RESOLUTION HYGIENE (SAM PRACTICE)
--------------------------------------------------------------------------------
Maintaining operational hygiene involves tracking and resolving support tickets promptly
to prevent support SLA deviations and customer satisfaction impacts.

* ACTIVE SUPPORT TICKETS:
${allSupportCases.length > 0 ? casesText : "✓ No active open support cases detected."}

* CONTRACT COVERAGE & LIFECYCLE RISKS:
${expiringContracts.length > 0 ? contractsText : "✓ All active support contracts have > 90 days remaining. SupportEdge Premium SLA active."}

* AUTOSUPPORT TELEMETRY STATUS:
${asupIssues.length > 0 ? asupIssues.map(a => `  ⚠ ${a.name}: ${a.issue} — ${a.detail}`).join('\n') : "✓ All systems reporting AutoSupport telemetry within 7-day SLA window."}

--------------------------------------------------------------------------------
3. SECURITY POSTURE & CVE REMEDIATION
--------------------------------------------------------------------------------
${secBulletins.length > 0 ? `ACTIVE SECURITY ADVISORIES (Critical/High — ${secBulletins.length} total):
${secBulletins.map((b, i) => `  ${i+1}. [${(b.severity||'').toUpperCase()}] ${b.id || b.cve || 'Advisory'} — ${b.title || b.description || ''}\n     System: ${b.systemName}\n     Fix: ${b.mitigation || 'Upgrade to fixed version. See security.netapp.com.'}`).join('\n\n')}` : "✓ No critical or high-severity security advisories active."}

KEY SECURITY ACTIONS:
  - Disable SMBv1: 'vserver cifs options modify -vserver <svm> -smb1-enabled false'
  - Enforce NFS root squash: 'vserver export-policy rule modify -policyname default -ruleindex 1 -superuser none'
  - AES Kerberos (KB5073381): 'vserver cifs security modify -vserver <svm> -advertised-enc-types aes-128,aes-256'
  - Enable MAV (ONTAP 9.11.1+): 'security multi-admin-verify enable'
  - Disable TLS 1.0/1.1: 'security config modify -supported-protocols TLSv1.2,TLSv1.3'
  - Enable audit logging: 'vserver audit create -vserver <svm> -destination /audit_log -format json'
  Reference: security.netapp.com | TR-4569 (ONTAP Security Hardening)

--------------------------------------------------------------------------------
4. PHASED ENVIRONMENTAL POSTURE REMEDIATION ROADMAP (TAM PRACTICE)
--------------------------------------------------------------------------------

PHASE 1: IMMEDIATE CRITICAL MITIGATION & HARDENING (DAYS 1 - 7)
--------------------------------------------------------------
Focus: Address critical security drifts, ASUP failures, single points of failure.

* ACTION 1.1: Security Protocol Hardening (CVE / Ransomware Mitigation)
  - Disable legacy SMBv1: 'vserver cifs options modify -vserver <svm> -smb1-enabled false'
  - Enforce NFS root squashing: 'vserver export-policy rule modify -policyname default -ruleindex 1 -superuser none'
  - Apply AES Kerberos enforcement (pre-ONTAP 9.13.1, KB5073381): 'vserver cifs security modify -vserver <svm> -advertised-enc-types aes-128,aes-256'
  - Verification: 'vserver cifs options show -fields smb1-enabled'
  - Reference: security.netapp.com | TR-4569

* ACTION 1.2: Restore AutoSupport Telemetry
  - Enable HTTPS transport: 'system node autosupport modify -node * -state enable -transport https -support enable'
  - Configure proxy (if required): 'system node autosupport modify -node * -proxy-url http://<proxy>:<port>'
  - Test connectivity: 'system node autosupport invoke -node * -type test'
  - Reference: docs.netapp.com/us-en/active-iq/

* ACTION 1.3: Restore Physical Path Redundancy
  - SAS/NVMe path check: 'storage path show' and 'storage disk show -fields disk-class,container-name,state'
  - Shelf module IOM/NSM LED status inspection
  - Reference: mysupport.netapp.com/site/global/dashboard

* IDENTIFIED PHASE 1 ITEMS IN ACTIVE ENVIRONMENT:
${allRisks.length > 0 ? risksText : "✓ No active high-priority configuration drifts detected."}

PHASE 2: FIRMWARE & SOFTWARE LIFECYCLE ALIGNMENT (DAYS 8 - 30)
------------------------------------------------------------
Focus: Bring all OS versions, switch firmware, shelf firmware, and disk qualification
packages to NetApp validated baselines.

* ACTION 2.1: ONTAP / SANtricity / StorageGRID OS Upgrades
  - Use Upgrade Advisor: https://activeiq.netapp.com/upgrade-advisor
  - Cross-reference NetApp IMT: https://imt.netapp.com/matrix/
  - Pre-upgrade checklist: cluster show | storage failover show | system health alert show | disk show -fields firmware-revision
  - Upgrade Targets:
${allUpgrades.length > 0 ? upgradesText : "  ✓ All systems are running recommended stable software baselines."}

* ACTION 2.2: Interconnect Switch Firmware Upgrades
  - Standard: Update Cisco Nexus (ISSU 'install all'), Brocade FOS ('firmwaredownload' + 'fastboot'),
    BES-53248 EFOS ('software install'), NVIDIA SN2100 (Cumulus 'apt-get upgrade').
  - IMT validation required before ANY switch firmware change.
${switchDrift.length > 0 ? '  SWITCH FIRMWARE DRIFT DETECTED:\n' + switchDrift.map(sw => `    ⚠ ${sw.systemName} — ${sw.model}: current=${sw.current}, target=${sw.recommended}`).join('\n') : '  ✓ All switch firmware at validated baseline.'}

* ACTION 2.3: Shelf Module Firmware Updates
  - Non-disruptive background update: 'storage firmware download' (runs automatically per-node)
  - Download from: mysupport.netapp.com/site/downloads/firmware/disk-shelf-firmware
  - Verify post-update: 'storage shelf firmware show'
${shelfDrift.length > 0 ? '  SHELF FIRMWARE DRIFT DETECTED:\n' + shelfDrift.map(sh => `    ⚠ ${sh.systemName} — ${sh.module}: current=${sh.current}, target=${sh.recommended}`).join('\n') : '  ✓ All shelf module firmware at recommended baseline.'}

* ACTION 2.4: Disk Qualification Package (DQP) Update
  - Download latest DQP: mysupport.netapp.com/site/downloads/firmware/disk
  - Install: 'storage disk firmware update -disk *' (non-disruptive, per-disk background)
  - Verify: 'storage disk qualification package show'

* ACTION 2.5: Service Processor / BMC Firmware
  - Update: 'system service-processor image update -node * -update-type latest'
  - Verify: 'system service-processor show -fields firmware-version'

PHASE 3: REPLICATION & DATA PROTECTION HYGIENE (DAYS 15 - 30)
-----------------------------------------------------------
Focus: SnapMirror, SnapVault, SnapMirror active sync, and AutoSupport remediation.

* ACTION 3.1: SnapMirror Relationship Health
  - Check all relationships: 'snapmirror show -fields state,lag-time,health'
  - Update lagging relationships: 'snapmirror update -destination-path <dest>'
  - Resync broken relationships: 'snapmirror resync -destination-path <dest>'
  - Mediator status (active sync): 'snapmirror mediator show'

* ACTION 3.2: Capacity & FabricPool Tiering
  - Identify full volumes: 'volume show -fields percent-used,available,state' | filter >80%
  - Enable auto-grow: 'volume modify -vserver <svm> -volume <vol> -autosize-mode grow'
  - FabricPool tiering: 'volume modify -vserver <svm> -volume <vol> -tiering-policy auto'
  - Reference: docs.netapp.com/us-en/ontap/fabricpool/

PHASE 4: OPERATIONAL AUDITS & BEST PRACTICE COMPLIANCE (DAYS 31 - 90)
--------------------------------------------------------------------
Focus: Drive long-term efficiency, audit logging, and host integration compliance.

* ACTION 4.1: Hypervisor Storage Driver Optimization
  - VMware ESXi Round Robin: 'esxcli storage nmp psp roundrobin device config set --device <naa_id> --type iops --iops 1'
  - Nutanix AHV: Verify multipath policy via 'lsblk' and 'multipath -ll' on AHV hosts.

* ACTION 4.2: Enable SVM Configuration Change Auditing
  - Create audit policy: 'vserver audit create -vserver <svm_name> -destination /audit_log -format json'
  - Enable: 'vserver audit enable -vserver <svm_name>'
  - Reference: docs.netapp.com/us-en/ontap/audit/

* ACTION 4.3: Anti-Ransomware Protection (ARP/ARP-AI)
  - ONTAP 9.10.1+: enable ARP per volume: 'security anti-ransomware volume enable -vserver <svm> -volume <vol>'
  - ONTAP 9.16.1+: ARP/AI enabled by default on new volumes (zero learning period).
  - Current coverage: ${arpCount}/${systemCount} systems

* ACTION 4.4: Third-Party Backup Integration Compliance
  - Avoid schedule collision with Veeam/Commvault/Rubrik: 'volume modify -vserver <svm_name> -volume <vol_name> -snapshot-policy none'
  - SnapLock policy review: TR-4526 (WORM compliance)
  - Reference: docs.netapp.com/us-en/ontap/data-protection/

* ACTION 4.5: Multi-Admin Verification (MAV)
  - ONTAP 9.11.1+: 'security multi-admin-verify enable'
  - Add rules for destructive operations: 'security multi-admin-verify rule create -operation <op>'
  - Reference: docs.netapp.com/us-en/ontap/multi-admin-verify/

PHASE 5: CONTRACT RENEWALS & HARDWARE REFRESH PLANNING (DAYS 60 - 90)
---------------------------------------------------------------------
Focus: Prevent coverage gaps, plan technology refresh for near-EOL systems.

* ACTION 5.1: Support Contract Renewals
${expiringContracts.length > 0 ? contractsText : "  ✓ No contracts expiring within 90 days."}
  - Portal: https://mysupport.netapp.com/

* ACTION 5.2: Hardware Refresh Planning
  - Identify near-EOS systems and initiate pre-sales engagement for AFF A-Series or ASA r2 refresh.
  - Reference: imt.netapp.com/matrix/ | netapp.com/data-storage/

--------------------------------------------------------------------------------
5. ITIL CHANGE MANAGEMENT GOVERNANCE & RUNBOOK GUIDELINES
--------------------------------------------------------------------------------
All operations under this plan must comply with standard ITIL Change Control procedures:
1. PRE-CHANGE VERIFICATION: Execute 'cluster show', 'system health alert show', and 'storage failover show' to verify cluster quorum, node health, and SFO state.
2. SAFETY CLASSIFICATION: Verify command safety tiers (Non-Disruptive, Disruptive but Data-Safe, Destructive/Irreversible) before execution. For destructive operations, ensure a valid snapshot/backup exists.
3. MAINTENANCE WINDOWS: Schedule hardware spares replacement and disruptive operations during off-peak hours.
4. CHANGE ROLLBACK PLAN: Document rollback CLI commands for all upgrades (e.g., revert to fallback boot partition: 'system node image modify -node * -image image1 -isdefault true').
5. POST-CHANGE VERIFICATION: Run 'system health alert show | storage failover show | network interface show' after every change.
================================================================================`;
}



// ═══════════════════════════════════════════════════════════════════════
// TAM / MSP Deliverable Compilers (QBR, MSP Report, Account Handover)
// ═══════════════════════════════════════════════════════════════════════



function compileQBRPack(targetSystems, allRisks, allUpgrades, expiringContracts, allSupportCases, scopeTitle) {
  const cleanScope = scopeTitle.replace(/_/g, ' ');
  const today = new Date().toISOString().split('T')[0];
  const total = targetSystems.length;

  // ── Personnel: first system with each field ──
  const salesRep = (targetSystems.find(s => s.salesRepName) || {}).salesRepName || 'Account Team';
  const csmName  = (targetSystems.find(s => s.csmName) || {}).csmName || '—';
  const samName  = (targetSystems.find(s => s.samName) || {}).samName || '—';
  const aspName  = (targetSystems.find(s => s.aspName) || {}).aspName || '—';

  // ── Sites ──
  const uniqueSites = [...new Set(targetSystems.map(s => s.siteName).filter(Boolean))];

  // ── ASUP Health: received within 7 days ──
  const now = Date.now();
  const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;
  const asupCompliant = targetSystems.filter(s => {
    if (!s.latestAsupDate) return false;
    const d = new Date(s.latestAsupDate);
    return !isNaN(d) && (now - d.getTime()) <= sevenDaysMs;
  }).length;
  const asupPct = total > 0 ? ((asupCompliant / total) * 100).toFixed(0) : 0;

  // ── ARP Coverage ──
  const arpCount = targetSystems.filter(s => s.isARPEnabled === true).length;
  const arpPct = total > 0 ? ((arpCount / total) * 100).toFixed(0) : 0;

  // ── Firmware Currency ──
  const fwCurrent = targetSystems.filter(s => s.swRecMin && s.osVersion && !versionLt(s.osVersion, s.swRecMin)).length;
  const fwPct = total > 0 ? ((fwCurrent / total) * 100).toFixed(0) : 0;

  // ── Contract Coverage ──
  const contractActive = targetSystems.filter(s => s.contractActive === true).length;
  const contractPct = total > 0 ? ((contractActive / total) * 100).toFixed(0) : 0;

  // ── Health Grade ──
  const avgPct = (parseFloat(asupPct) + parseFloat(arpPct) + parseFloat(fwPct) + parseFloat(contractPct)) / 4;
  const grade = avgPct > 90 ? 'A' : avgPct > 75 ? 'B' : avgPct > 60 ? 'C' : avgPct > 40 ? 'D' : 'F';

  // ── Risks ──
  const critCount = allRisks.filter(r => r.severity === 'critical').length;
  const highCount = allRisks.filter(r => r.severity === 'high').length;
  const medCount  = allRisks.filter(r => r.severity === 'medium').length;
  const lowCount  = allRisks.filter(r => r.severity === 'low').length;
  const secCount  = allRisks.filter(r => (r.category || '').toLowerCase() === 'security').length;

  const sortedRisks = _filterAndDeduplicateRisks(allRisks, targetSystems);
  const topActions = sortedRisks.slice(0, 5).map((g, i) => {
    const sysLabel = [...new Set(g.systems.filter(Boolean))].slice(0, 3).join(', ');
    const plan = g.remediationPlan || {};
    let entry = `  ${i + 1}. [${(g.severity || '').toUpperCase()}] ${g.fix}`;
    if (g.count > 1) entry += ` (${g.count} findings across ${sysLabel})`;
    else entry += ` — ${sysLabel}`;
    if (plan.cause) entry += `\n       Root Cause: ${plan.cause}`;
    if (plan.impact) entry += `\n       Impact: ${plan.impact}`;
    return entry;
  }).join('\n\n');

  // ── Sustainability ──
  const scores = state.tamSustainability || [];
  const latest = scores[0] || {};
  let sustainSection = '  No sustainability data available. Run a data refresh to load fleet scores.\n';
  if (latest.scorePercentage != null) {
    const wowChange = (latest.percentageChange || 0) >= 0 ? `+${latest.percentageChange || 0}` : `${latest.percentageChange}`;
    let physTotal = 0, logTotal = 0, savedTotal = 0;
    targetSystems.forEach(s => {
      if (s.efficiency) {
        physTotal += s.efficiency.physicalUsedTB || 0;
        logTotal  += s.efficiency.logicalUsedTB || 0;
        savedTotal += s.efficiency.spaceSavedTB || 0;
      }
    });
    const drr = physTotal > 0 ? (logTotal / physTotal).toFixed(1) : '—';
    sustainSection = `  Sustainability Score:   ${latest.scorePercentage}%
  Week-over-Week Change:  ${wowChange}%

  Storage Efficiency:
    Total Physical Used:  ${physTotal.toFixed(1)} TB
    Logical Represented:  ${logTotal.toFixed(1)} TB
    Data Reduction Ratio: ${drr}:1
    Space Saved:          ${savedTotal.toFixed(1)} TB\n`;
  }

  // ── Lifecycle / Renewal Pipeline ──
  const exp90  = expiringContracts.filter(e => e.daysRemaining <= 90).length;
  const exp180 = expiringContracts.filter(e => e.daysRemaining <= 180).length;
  const nearEos = targetSystems.filter(s => s.lifecycle && s.lifecycle.isNearEos).length;
  const contractLines = expiringContracts.map(e =>
    `  • ${e.systemName} (${e.serialNumber || 'N/A'}) — Expires: ${(e.endDate || '').split('T')[0]}  (${e.daysRemaining} days)`
  ).join('\n') || '  No expiring contracts within scope.';

  // ── Recommendations (fleet-wide; scoped count provided as context) ──
  const recs = state.tamRecommendations || [];
  let recsSection = '  No recommendations available.\n';
  if (recs.length > 0) {
    recsSection = `  NOTE: Active IQ recommendation scores reflect the full TAM fleet. Scoped system count for this account: ${total} systems.\n\n`;
    const byCat = {};
    recs.forEach(r => {
      const cat = r.category || 'OTHER';
      if (!byCat[cat]) byCat[cat] = [];
      byCat[cat].push(r);
    });
    recsSection += Object.keys(byCat).map(cat => {
      const items = byCat[cat];
      // Strip global "N of your systems" counts from the truncated text to avoid confusion
      const lines = items.slice(0, 5).map(r => {
        const clean = (r.recommendation || '').replace(/\d+\s+of\s+your\s+systems/gi, `[see scoped count]`);
        return `    • [Score ${r.score || 0}%] ${clean.substring(0, 150)}`;
      }).join('\n');
      return `  ${cat.replace(/_/g, ' ')} (${items.length}):\n${lines}`;
    }).join('\n\n') + '\n';
  }

  // ── Action Items ──
  const followUp = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
  const staleAsup = total - asupCompliant;
  const unprotectedArp = total - arpCount;
  const correctiveCount = sortedRisks.length;
  const renewCount = exp90;

  return `================================================================================
QUARTERLY BUSINESS REVIEW (QBR) — ACCOUNT INTELLIGENCE PACK
================================================================================
Account:  ${cleanScope}
Date:     ${today}
Prepared: ${salesRep}

--------------------------------------------------------------------------------
1. ACCOUNT OVERVIEW
--------------------------------------------------------------------------------
  Customer:       ${cleanScope}
  Systems:        ${total}
  Sites:          ${uniqueSites.length}
  Account Team:
    Sales Rep:    ${salesRep}
    CSM:          ${csmName}
    SAM:          ${samName}
    ASP:          ${aspName}

--------------------------------------------------------------------------------
2. OPERATIONAL HEALTH SCORECARD
--------------------------------------------------------------------------------
  AutoSupport Compliance:   ${asupCompliant}/${total} systems (${asupPct}%) — received ASUP within 7 days
  ARP Coverage:             ${arpCount}/${total} systems (${arpPct}%) — Anti-Ransomware Protection enabled
  Firmware Currency:        ${fwCurrent}/${total} systems (${fwPct}%) — running recommended OS version
  Contract Coverage:        ${contractActive}/${total} systems (${contractPct}%) — active support contract

  Overall Health Grade:     ${grade} (avg ${avgPct.toFixed(0)}%)

--------------------------------------------------------------------------------
3. RISK POSTURE
--------------------------------------------------------------------------------
  Critical: ${critCount}   High: ${highCount}   Medium: ${medCount}   Low: ${lowCount}
  Security Advisories: ${secCount}
  Open Support Cases:  ${allSupportCases.length}

  TOP CORRECTIVE ACTIONS (with root cause context):
${topActions || '  No critical or high-severity corrective actions identified.'}

  SECURITY QUICK WINS:
  • Disable SMBv1:    vserver cifs options modify -vserver <svm> -smb1-enabled false
  • Enable ARP:       security anti-ransomware volume enable -volume <vol> -vserver <svm>
  • Enable MAV:       security multi-admin-verify enable  (ONTAP 9.11.1+)
  • Disable TLS 1.0:  security config modify -supported-protocols TLSv1.2,TLSv1.3
  • Enable Auditing:  vserver audit create -vserver <svm> -destination /audit_log -format json
  Reference: security.netapp.com | TR-4569 (ONTAP Security Hardening)

--------------------------------------------------------------------------------
4. SUSTAINABILITY & EFFICIENCY
--------------------------------------------------------------------------------
${sustainSection}
--------------------------------------------------------------------------------
5. LIFECYCLE & RENEWAL PIPELINE
--------------------------------------------------------------------------------
  Contracts Expiring < 90 Days:  ${exp90}
  Contracts Expiring < 180 Days: ${exp180}
  Systems Near EOS:              ${nearEos}

${contractLines}

--------------------------------------------------------------------------------
6. RECOMMENDATIONS (Active IQ)
--------------------------------------------------------------------------------
${recsSection}
--------------------------------------------------------------------------------
7. ACTION ITEMS & NEXT STEPS
--------------------------------------------------------------------------------
  □ Schedule follow-up meeting for ${followUp}
  □ Initiate contract renewals for ${renewCount} expiring system${renewCount !== 1 ? 's' : ''}
  □ Plan maintenance window for ${correctiveCount} corrective action${correctiveCount !== 1 ? 's' : ''}
  □ Review ARP enablement on ${unprotectedArp} unprotected system${unprotectedArp !== 1 ? 's' : ''}
  □ Address ${staleAsup} stale AutoSupport connection${staleAsup !== 1 ? 's' : ''}
  □ Validate ITIL Change Control process for all planned remediation items
================================================================================`;
}


function compileMSPServiceReport(targetSystems, allRisks, expiringContracts, allSupportCases, scopeTitle) {
  const cleanScope = scopeTitle.replace(/_/g, ' ');
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const thirtyAgo = new Date(today.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
  const total = targetSystems.length;

  // ── Contract Coverage ──
  const activeContracts  = targetSystems.filter(s => s.contractActive === true).length;
  const expiredContracts = targetSystems.filter(s => s.contractActive === false).length;
  const unknownContracts = targetSystems.filter(s => s.contractActive == null).length;
  const contractPct = total > 0 ? ((activeContracts / total) * 100).toFixed(0) : 0;

  // ── ASUP Compliance ──
  const now = Date.now();
  const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;
  const asupCompliant = targetSystems.filter(s => {
    if (!s.latestAsupDate) return false;
    const d = new Date(s.latestAsupDate);
    return !isNaN(d) && (now - d.getTime()) <= sevenDaysMs;
  }).length;
  const asupPct = total > 0 ? ((asupCompliant / total) * 100).toFixed(0) : 0;

  // ── ARP ──
  const arpCount = targetSystems.filter(s => s.isARPEnabled === true).length;
  const arpPct = total > 0 ? ((arpCount / total) * 100).toFixed(0) : 0;

  // ── Firmware Currency ──
  const fwCurrent = targetSystems.filter(s => s.swRecMin && s.osVersion && !versionLt(s.osVersion, s.swRecMin)).length;
  const fwPct = total > 0 ? ((fwCurrent / total) * 100).toFixed(0) : 0;

  // ── Critical risk count ──
  const critCount = allRisks.filter(r => r.severity === 'critical').length;

  // ── Average System Age ──
  const ages = targetSystems.map(s => {
    if (!s.originalShipDate) return null;
    const d = new Date(s.originalShipDate);
    if (isNaN(d)) return null;
    return (now - d.getTime()) / (365.25 * 24 * 60 * 60 * 1000);
  }).filter(a => a !== null);
  const avgAge = ages.length > 0 ? (ages.reduce((a, b) => a + b, 0) / ages.length).toFixed(1) : '—';

  // ── SLA helpers ──
  function slaStatus(actual, target) { return parseFloat(actual) >= target ? 'MET' : 'MISSED'; }

  // ── Cases ──
  const casesLines = allSupportCases.length > 0
    ? allSupportCases.map(c =>
        `    • Case ${c.id} [${c.severity}] ${c.systemName}\n      Title: ${c.title}\n      Next Action: ${c.nextActionBy || 'Under Review'}`
      ).join('\n')
    : '    No open support cases.';

  // ── Contract tiers ──
  const tierMap = {};
  targetSystems.forEach(s => {
    const tier = s.serviceLevel || s.serviceTier || 'Unknown';
    tierMap[tier] = (tierMap[tier] || 0) + 1;
  });
  const tierLines = Object.keys(tierMap).map(t => `    ${t}: ${tierMap[t]} system${tierMap[t] > 1 ? 's' : ''}`).join('\n') || '    No tier data available.';

  // ── Expiring ──
  const exp90 = expiringContracts.filter(e => e.daysRemaining <= 90).length;

  // ── Capacity ──
  let physTotal = 0, logTotal = 0, savedTotal = 0;
  targetSystems.forEach(s => {
    if (s.efficiency) {
      physTotal += s.efficiency.physicalUsedTB || 0;
      logTotal  += s.efficiency.logicalUsedTB || 0;
      savedTotal += s.efficiency.spaceSavedTB || 0;
    }
  });
  const drr = physTotal > 0 ? (logTotal / physTotal).toFixed(1) : '—';

  // ── Improvement Backlog ──
  const sortedRisks = _filterAndDeduplicateRisks(allRisks, targetSystems);
  const backlogLines = sortedRisks.map((g, i) => {
    const sysLabel = [...new Set(g.systems.filter(Boolean))].slice(0, 3).join(', ');
    const plan = g.remediationPlan || {};
    let line = `  ${i + 1}. [${(g.severity || '').toUpperCase()}] ${g.fix}  (${g.count} finding${g.count > 1 ? 's' : ''} — ${sysLabel})`;
    if (plan.cause) line += `\n       Root Cause: ${plan.cause}`;
    if (plan.impact) line += `\n       Impact: ${plan.impact}`;
    return line;
  }).join('\n\n') || '  No outstanding corrective actions.';

  // ── Next Period ──
  const staleAsup = total - asupCompliant;
  const unprotectedArp = total - arpCount;
  const fwBehind = total - fwCurrent;

  return `================================================================================
MANAGED SERVICE PROVIDER — SERVICE DELIVERY REPORT
================================================================================
Customer:      ${cleanScope}
Report Date:   ${todayStr}
Report Period: ${thirtyAgo} to ${todayStr}

--------------------------------------------------------------------------------
1. SERVICE SUMMARY
--------------------------------------------------------------------------------
  Systems Under Management:  ${total}
  Contract Coverage:         ${activeContracts}/${total} (${contractPct}%) active contracts
  ASUP Telemetry Compliance: ${asupCompliant}/${total} (${asupPct}%) within 7-day SLA
  Average System Age:        ${avgAge} years

--------------------------------------------------------------------------------
2. SLA COMPLIANCE MATRIX
--------------------------------------------------------------------------------
  Metric                    Target    Actual    Status
  ─────────────────────────────────────────────────────
  ASUP Compliance           100%      ${String(asupPct).padStart(3)}%      ${slaStatus(asupPct, 100)}
  ARP Enablement            100%      ${String(arpPct).padStart(3)}%      ${slaStatus(arpPct, 100)}
  Firmware Currency         100%      ${String(fwPct).padStart(3)}%      ${slaStatus(fwPct, 100)}
  Contract Coverage         100%      ${String(contractPct).padStart(3)}%      ${slaStatus(contractPct, 100)}
  Risk Posture (Crit=0)     0         ${String(critCount).padStart(3)}       ${critCount === 0 ? 'MET' : 'MISSED'}

--------------------------------------------------------------------------------
3. INCIDENT & CASE MANAGEMENT
--------------------------------------------------------------------------------
  Open Cases:     ${allSupportCases.length}
${casesLines}

--------------------------------------------------------------------------------
4. CONTRACT PORTFOLIO
--------------------------------------------------------------------------------
  Active:    ${activeContracts} systems
  Expiring:  ${exp90} systems (within 90 days)
  Expired:   ${expiredContracts} systems
  Unknown:   ${unknownContracts} systems

  Service Tier Breakdown:
${tierLines}

--------------------------------------------------------------------------------
5. CAPACITY & EFFICIENCY
--------------------------------------------------------------------------------
  Total Physical Capacity Used: ${physTotal.toFixed(1)} TB
  Total Logical Capacity:       ${logTotal.toFixed(1)} TB
  Data Reduction Ratio:         ${drr}:1
  Space Saved via Efficiency:   ${savedTotal.toFixed(1)} TB

--------------------------------------------------------------------------------
6. IMPROVEMENT BACKLOG
--------------------------------------------------------------------------------
${backlogLines}

--------------------------------------------------------------------------------
7. NEXT PERIOD OBJECTIVES
--------------------------------------------------------------------------------
  □ Resolve ${critCount} critical finding${critCount !== 1 ? 's' : ''}
  □ Renew ${exp90} expiring contract${exp90 !== 1 ? 's' : ''}
  □ Enable ARP on ${unprotectedArp} system${unprotectedArp !== 1 ? 's' : ''}
  □ Restore ASUP on ${staleAsup} stale system${staleAsup !== 1 ? 's' : ''}
  □ Plan OS upgrades for ${fwBehind} system${fwBehind !== 1 ? 's' : ''}
================================================================================`;
}


function compileAccountHandoverBrief(targetSystems, allRisks, allUpgrades, expiringContracts, allSupportCases, scopeTitle) {
  const cleanScope = scopeTitle.replace(/_/g, ' ');
  const today = new Date().toISOString().split('T')[0];
  const total = targetSystems.length;

  // ── Domestic Parent ──
  const domesticParent = (targetSystems.find(s => s.domesticParentName) || {}).domesticParentName || '—';

  // ── Sites ──
  const siteMap = {};
  targetSystems.forEach(s => {
    const name = s.siteName || 'Unknown';
    if (!siteMap[name]) siteMap[name] = { city: s.siteCity || '', country: s.siteCountry || '' };
  });
  const uniqueSiteNames = Object.keys(siteMap);
  const siteLines = uniqueSiteNames.map(name => {
    const loc = [siteMap[name].city, siteMap[name].country].filter(Boolean).join(', ');
    return `    • ${name}${loc ? ' — ' + loc : ''}`;
  }).join('\n') || '    No site data available.';

  // ── Personnel ──
  const salesRepSys = targetSystems.find(s => s.salesRepName) || {};
  const csmSys      = targetSystems.find(s => s.csmName) || {};
  const samSys      = targetSystems.find(s => s.samName) || {};
  const aspSys      = targetSystems.find(s => s.aspName) || {};

  const salesRepName  = salesRepSys.salesRepName || '—';
  const salesRepEmail = salesRepSys.salesRepEmail || '—';
  const csmName       = csmSys.csmName || '—';
  const csmEmail      = csmSys.csmEmail || '—';
  const samName       = samSys.samName || '—';
  const samEmail      = samSys.samEmail || '—';
  const aspName       = aspSys.aspName || '—';
  const aspEndDate    = aspSys.aspEndDate || '—';

  // ── Propensity ──
  const propSystems = targetSystems.filter(s => s.propensityCategory);
  const propLines = propSystems.length > 0
    ? propSystems.map(s => `    • ${s.systemName}: ${s.propensityCategory}${s.nextBestAction ? ' — ' + s.nextBestAction : ''}`).join('\n')
    : '    No propensity data available.';

  // ── Inventory Table ──
  const invHeader = '  System               | Cluster             | Platform                    | OS Version   | Serial         | Site              | Contract';
  const invSep    = '  ' + '─'.repeat(145);
  const invRows = targetSystems.map(s => {
    const sysN = (s.systemName || '').padEnd(20).substring(0, 20);
    const clN  = (s.clusterName || '').padEnd(19).substring(0, 19);
    const plat = (s.platform || '').padEnd(27).substring(0, 27);
    const osV  = (s.osVersion || s.ontapVersion || '').padEnd(12).substring(0, 12);
    const ser  = (s.serialNumber || '').padEnd(14).substring(0, 14);
    const site = (s.siteName || '').padEnd(17).substring(0, 17);
    const cSt  = s.contractActive === true ? 'Active' : s.contractActive === false ? 'Expired' : 'Unknown';
    return `  ${sysN} | ${clN} | ${plat} | ${osV} | ${ser} | ${site} | ${cSt}`;
  }).join('\n');

  // ── Risk & Compliance ──
  const critCount = allRisks.filter(r => r.severity === 'critical').length;
  const highCount = allRisks.filter(r => r.severity === 'high').length;
  const secCount  = allRisks.filter(r => (r.category || '').toLowerCase() === 'security').length;

  const now = Date.now();
  const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;
  const asupCompliant = targetSystems.filter(s => {
    if (!s.latestAsupDate) return false;
    const d = new Date(s.latestAsupDate);
    return !isNaN(d) && (now - d.getTime()) <= sevenDaysMs;
  }).length;
  const asupPct = total > 0 ? ((asupCompliant / total) * 100).toFixed(0) : 0;

  const arpCount = targetSystems.filter(s => s.isARPEnabled === true).length;
  const arpPct = total > 0 ? ((arpCount / total) * 100).toFixed(0) : 0;

  const activeContracts = targetSystems.filter(s => s.contractActive === true).length;
  const contractPct = total > 0 ? ((activeContracts / total) * 100).toFixed(0) : 0;

  const sortedRisks = _filterAndDeduplicateRisks(allRisks, targetSystems);
  const topIssues = sortedRisks.slice(0, 10).map((g, i) => {
    const sysLabel = g.systems.filter(Boolean).slice(0, 3).join(', ');
    return `  ${i + 1}. [${(g.severity || '').toUpperCase()}] ${g.fix}  (${g.count} finding${g.count > 1 ? 's' : ''} — ${sysLabel})`;
  }).join('\n') || '  No critical or high-severity issues.';

  // ── Contract & Lifecycle ──
  const exp90 = expiringContracts.filter(e => e.daysRemaining <= 90).length;
  const expiredCount = targetSystems.filter(s => s.contractActive === false).length;
  const warrantyActive = targetSystems.filter(s => {
    if (!s.warrantyEndDate) return false;
    return new Date(s.warrantyEndDate) > new Date();
  }).length;

  const contractDetailLines = targetSystems.map(s => {
    const cEnd = (s.contractEndDate || s.contractExpiry || '—').split('T')[0];
    const svc  = s.serviceLevel || s.serviceTier || '—';
    const wEnd = (s.warrantyEndDate || '—').split('T')[0];
    return `  • ${s.systemName} (${s.serialNumber || 'N/A'}) — Contract End: ${cEnd} | Service: ${svc} | Warranty End: ${wEnd}`;
  }).join('\n');

  // ── Recent Activity ──
  const caseLines = allSupportCases.length > 0
    ? allSupportCases.map(c =>
        `  • Case ${c.id} [${c.severity}] ${c.systemName}: ${c.title}\n    Next Action: ${c.nextActionBy || 'Under Review'}`
      ).join('\n')
    : '  No open support cases.';

  const upgradeLines = allUpgrades.length > 0
    ? allUpgrades.map(u =>
        `  • ${u.systemName}: ${u.currentVersion || 'current'} → ${u.targetVersion} (${u.urgency})`
      ).join('\n')
    : '  No pending upgrades.';

  // Field actions from systems
  const fieldActions = [];
  targetSystems.forEach(s => {
    if (s.fieldActions) s.fieldActions.forEach(fa => fieldActions.push({ systemName: s.systemName, ...fa }));
  });
  const faLines = fieldActions.length > 0
    ? fieldActions.map(fa =>
        `  • ${fa.systemName}: ${fa.title || fa.description || 'Field Action'} [${fa.status || 'Active'}]`
      ).join('\n')
    : '  No active field actions.';

  // ── Key Talking Points ──
  const talkingPoints = [];

  // Propensity observations
  const propCategories = [...new Set(propSystems.map(s => s.propensityCategory).filter(Boolean))];
  if (propCategories.length > 0) {
    talkingPoints.push(`Propensity categories in scope: ${propCategories.join(', ')}. Review next-best-action recommendations for upsell/cross-sell alignment.`);
  }

  // Contract urgency
  if (exp90 > 0) {
    talkingPoints.push(`${exp90} contract${exp90 > 1 ? 's' : ''} expiring within 90 days — renewal engagement is time-sensitive.`);
  }

  // ASUP / ARP gaps
  const staleAsup = total - asupCompliant;
  const unprotectedArp = total - arpCount;
  if (staleAsup > 0) {
    talkingPoints.push(`${staleAsup} system${staleAsup > 1 ? 's' : ''} with stale or missing AutoSupport telemetry — proactive monitoring gap.`);
  }
  if (unprotectedArp > 0) {
    talkingPoints.push(`${unprotectedArp} system${unprotectedArp > 1 ? 's' : ''} without Anti-Ransomware Protection — cyber resilience exposure.`);
  }

  // EOS concerns
  const eosCount = targetSystems.filter(s => s.lifecycle && s.lifecycle.isNearEos).length;
  if (eosCount > 0) {
    talkingPoints.push(`${eosCount} system${eosCount > 1 ? 's' : ''} approaching End-of-Support — hardware refresh planning recommended.`);
  }

  // Sustainability
  const scores = state.tamSustainability || [];
  const latestScore = scores[0] || {};
  if (latestScore.scorePercentage != null) {
    talkingPoints.push(`Fleet sustainability score: ${latestScore.scorePercentage}%. Highlight environmental efficiency achievements with incoming account team.`);
  }

  const talkingPointsText = talkingPoints.length > 0
    ? talkingPoints.map(t => `  • ${t}`).join('\n')
    : '  • No specific talking points generated — review account data for context.';

  return `================================================================================
ACCOUNT HANDOVER & TRANSITION BRIEF
================================================================================
Account:     ${cleanScope}
Date:        ${today}
Classification: INTERNAL — ACCOUNT TRANSITION DOCUMENT

--------------------------------------------------------------------------------
1. ACCOUNT PROFILE
--------------------------------------------------------------------------------
  Customer Name:      ${cleanScope}
  Domestic Parent:    ${domesticParent}
  Total Systems:      ${total}
  Total Sites:        ${uniqueSiteNames.length}
  Site Locations:
${siteLines}

--------------------------------------------------------------------------------
2. ACCOUNT TEAM (CURRENT)
--------------------------------------------------------------------------------
  Sales Representative: ${salesRepName} (${salesRepEmail})
  CSM:                  ${csmName} (${csmEmail})
  SAM:                  ${samName} (${samEmail})
  ASP:                  ${aspName}
  ASP End Date:         ${aspEndDate}

  Propensity Categories:
${propLines}

--------------------------------------------------------------------------------
3. ENVIRONMENT INVENTORY
--------------------------------------------------------------------------------
${invHeader}
${invSep}
${invRows}

--------------------------------------------------------------------------------
4. RISK & COMPLIANCE POSTURE
--------------------------------------------------------------------------------
  Total Risks:          ${allRisks.length} (Critical: ${critCount}, High: ${highCount})
  Security Advisories:  ${secCount}
  Open Support Cases:   ${allSupportCases.length}
  ASUP Compliance:      ${asupPct}%
  ARP Coverage:         ${arpPct}%
  Contract Coverage:    ${contractPct}%

  Top Issues Requiring Attention:
${topIssues}

--------------------------------------------------------------------------------
5. CONTRACT & LIFECYCLE STATUS
--------------------------------------------------------------------------------
  Active Contracts:     ${activeContracts}
  Expiring (< 90 days): ${exp90}
  Expired:              ${expiredCount}
  Warranty Active:      ${warrantyActive}

${contractDetailLines}

--------------------------------------------------------------------------------
6. RECENT ACTIVITY
--------------------------------------------------------------------------------
  Open Support Cases:
${caseLines}

  Pending Upgrades:
${upgradeLines}

  Active Field Actions:
${faLines}

--------------------------------------------------------------------------------
7. KEY TALKING POINTS & CONTEXT
--------------------------------------------------------------------------------
${talkingPointsText}

  TRANSITION NOTES:
  [  — Add handover-specific context, relationship notes, and pending commitments here —  ]
================================================================================`;
}

function compileExtendedDeliverables(targetSystems, allRisks, allUpgrades, expiringContracts, allSupportCases, scopeTitle) {
  const cleanScope = scopeTitle.replace(/_/g, ' ');
  const today = new Date().toISOString().split('T')[0];

  // Counts from ALL risks (for summary header)
  const sevRank = { critical: 0, high: 1, medium: 2, low: 3 };
  const critCount = allRisks.filter(r => r.severity === 'critical').length;
  const highCount = allRisks.filter(r => r.severity === 'high').length;
  const medCount = allRisks.filter(r => r.severity === 'medium').length;
  const lowCount = allRisks.filter(r => r.severity === 'low').length;

  // Filtered + deduplicated risks for deliverable body (critical+high only, no best practice, grouped by fix)
  const sortedRisks = _filterAndDeduplicateRisks(allRisks, targetSystems);
  // Count total security-related findings across all groups
  const secRisksCount = sortedRisks.reduce((sum, g) => sum + g.findings.filter(f => (f.category || '').toLowerCase() === 'security').length, 0);
  const totalDeduped = sortedRisks.reduce((sum, g) => sum + g.count, 0);

  // Parse AutoSupport issues
  const asupIssues = [];
  targetSystems.forEach(s => {
    const asup = s.autosupport || { enabled: true, status: "healthy", lastReceivedDays: 1 };
    if (!asup.enabled) {
      asupIssues.push({ name: s.systemName, serial: s.serialNumber, issue: "AutoSupport Disabled", detail: asup.failureReason || "Disabled intentionally." });
    } else if (asup.status === "failed" || asup.lastReceivedDays > 7) {
      asupIssues.push({ name: s.systemName, serial: s.serialNumber, issue: "AutoSupport Connection Failed", detail: `No telemetry for ${asup.lastReceivedDays} days. ${asup.failureReason || "Verify HTTPS (443) to support.netapp.com."}` });
    }
  });

  // Helper: best reference link for a finding
  function findingRef(f) {
    if (f.advisoryUrl) return f.advisoryUrl;
    const cve = (f.description || '').match(/CVE-[0-9]{4}-[0-9]+/);
    if (cve) return `https://security.netapp.com/advisory/ (${cve[0]})`;
    return '';
  }

  // ── TAM Enrichment Data for deliverables ──
  const now = new Date();
  const _p = {};
  targetSystems.forEach(s => {
    if (s.salesRepName && !_p.sr) _p.sr = s.salesRepName;
    if (s.salesRepEmail && !_p.sre) _p.sre = s.salesRepEmail;
    if (s.csmName && !_p.csm) _p.csm = s.csmName;
    if (s.csmEmail && !_p.csme) _p.csme = s.csmEmail;
    if (s.samName && !_p.sam) _p.sam = s.samName;
    if (s.samEmail && !_p.same) _p.same = s.samEmail;
    if (s.aspName && !_p.asp) _p.asp = s.aspName;
    if (s.aspEndDate && !_p.aspEnd) _p.aspEnd = s.aspEndDate;
    if (s.domesticParentName && !_p.parent) _p.parent = s.domesticParentName;
  });
  const personnel = {
    salesRep: _p.sr || 'Not Assigned', salesRepEmail: _p.sre || '',
    csm: _p.csm || 'Not Assigned', csmEmail: _p.csme || '',
    sam: _p.sam || 'Not Assigned', samEmail: _p.same || '',
    asp: _p.asp || 'Not Assigned', aspEnd: _p.aspEnd || '',
    parent: _p.parent || cleanScope
  };
  const siteSet = new Set();
  const siteDetails = [];
  targetSystems.forEach(s => {
    if (s.siteName && !siteSet.has(s.siteName)) {
      siteSet.add(s.siteName);
      siteDetails.push({ name: s.siteName, city: s.siteCity || '', country: s.siteCountry || '' });
    }
  });
  const asupCompliant = targetSystems.filter(s => s.latestAsupDate && (now - new Date(s.latestAsupDate)) / 86400000 <= 7).length;
  const arpEnabledCount = targetSystems.filter(s => s.isARPEnabled === true).length;
  const fwCurrentCount = targetSystems.filter(s => s.swRecMin && s.osVersion && !versionLt(s.osVersion, s.swRecMin)).length;
  const contractActiveCount = targetSystems.filter(s => s.contractActive === true).length;
  const sysCount = targetSystems.length;
  const pctAsup = sysCount > 0 ? Math.round(asupCompliant / sysCount * 100) : 0;
  const pctArp = sysCount > 0 ? Math.round(arpEnabledCount / sysCount * 100) : 0;
  const pctFw = sysCount > 0 ? Math.round(fwCurrentCount / sysCount * 100) : 0;
  const pctContract = sysCount > 0 ? Math.round(contractActiveCount / sysCount * 100) : 0;
  const sustScores = state.tamSustainability || [];
  const sustLatest = sustScores[0] || {};
  let totalPhysTB = 0, totalLogTB = 0, totalSavedTBd = 0;
  targetSystems.forEach(s => {
    if (s.efficiency) {
      totalPhysTB += s.efficiency.physicalUsedTB || 0;
      totalLogTB += s.efficiency.logicalUsedTB || 0;
      totalSavedTBd += s.efficiency.spaceSavedTB || 0;
    }
  });
  const reductionRatio = totalPhysTB > 0 ? (totalLogTB / totalPhysTB).toFixed(1) : '1.0';
  // Contracts expiring within windows
  const exp90 = expiringContracts.filter(e => e.daysRemaining <= 90);
  const exp180 = expiringContracts.filter(e => e.daysRemaining <= 180);
  // TAM renewals filtered to scope
  const scopeHosts = new Set(targetSystems.map(s => (s.systemName || '').toLowerCase()));
  const scopedRenewals = (state.tamRenewals || []).filter(r => scopeHosts.has((r.hostName || '').toLowerCase()));

  // ===================== 1. PROBLEM STATEMENTS =====================
  let problemStatements = `================================================================================
EXECUTIVE RISK ASSESSMENT
================================================================================
Scope:        ${cleanScope}
Date:         ${today}
Systems:      ${targetSystems.length}
Sites:        ${siteDetails.length}${siteDetails.length > 0 ? ' (' + siteDetails.map(s => s.name + (s.city ? ', ' + s.city : '')).join('; ') + ')' : ''}

ACCOUNT TEAM
  Sales Rep:  ${personnel.salesRep}
  CSM:        ${personnel.csm}
  SAM:        ${personnel.sam}

RISK SUMMARY
  Critical: ${critCount}   High: ${highCount}   Medium: ${medCount}   Low: ${lowCount}
  Security: ${secRisksCount}   AutoSupport: ${asupIssues.length}   Cases: ${allSupportCases.length}
  Upgrades: ${allUpgrades.length}   Contracts: ${expiringContracts.length}

OPERATIONAL HEALTH
  ASUP Compliance:    ${asupCompliant}/${sysCount} (${pctAsup}%)
  ARP Coverage:       ${arpEnabledCount}/${sysCount} (${pctArp}%)
  Firmware Currency:  ${fwCurrentCount}/${sysCount} (${pctFw}%)
  Contract Coverage:  ${contractActiveCount}/${sysCount} (${pctContract}%)

`;

  if (sortedRisks.length === 0 && expiringContracts.length === 0 && asupIssues.length === 0) {
    problemStatements += "No critical or high-severity issues identified.\n";
  } else {
    // Render fix-grouped: the fix is the primary item, findings listed beneath
    problemStatements += `PRIORITISED CORRECTIVE ACTIONS (${sortedRisks.length} fix${sortedRisks.length !== 1 ? 'es' : ''} resolving ${totalDeduped} finding${totalDeduped !== 1 ? 's' : ''})
--------------------------------------------------------------------------------
`;
    sortedRisks.forEach((g, idx) => {
      const sysNames = [...new Set(g.systems.filter(Boolean))];
      const sysLabel = sysNames.join(', ');
      problemStatements += `${idx + 1}. [${g.severity.toUpperCase()}] ${g.fix}
   Systems: ${sysLabel}
`;
      if (g.count === 1) {
        problemStatements += `   Finding: ${g.findings[0].description}
`;
        const ref = findingRef(g.findings[0]);
        if (ref) problemStatements += `   Ref: ${ref}\n`;
      } else {
        problemStatements += `   Resolves ${g.count} findings:\n`;
        g.findings.forEach(f => {
          problemStatements += `     • ${f.description}\n`;
        });
        if (g.fixUrl) problemStatements += `   Ref: ${g.fixUrl}\n`;
      }
      problemStatements += '\n';
    });
  }

  if (asupIssues.length > 0) {
    problemStatements += `AUTOSUPPORT ISSUES (${asupIssues.length})
--------------------------------------------------------------------------------
`;
    asupIssues.forEach((a, i) => {
      problemStatements += `${i + 1}. ${a.name} (${a.serial}) — ${a.issue}: ${a.detail}\n`;
    });
    problemStatements += '\n';
  }

  if (expiringContracts.length > 0) {
    problemStatements += `EXPIRING CONTRACTS (${expiringContracts.length})
--------------------------------------------------------------------------------
`;
    expiringContracts.forEach((e, i) => {
      problemStatements += `${i + 1}. ${e.systemName} (${e.serialNumber || 'N/A'}) | ${e.supportLevel} | Expires: ${(e.endDate || '').split('T')[0]} (${e.daysRemaining}d)\n`;
    });
    problemStatements += '\n';
  }

  // ===================== 2. CUSTOMER COMMUNICATIONS =====================
  let emailRiskLines = '';
  if (sortedRisks.length > 0) {
    emailRiskLines = 'RECOMMENDED ACTIONS:\n';
    sortedRisks.forEach((g, i) => {
      if (g.count === 1) {
        emailRiskLines += `  ${i+1}. [${g.severity.toUpperCase()}] ${g.findings[0].description}\n     Fix: ${g.fix}\n`;
      } else {
        emailRiskLines += `  ${i+1}. [${g.severity.toUpperCase()}] ${g.fix} — resolves ${g.count} findings\n`;
      }
    });
  } else {
    emailRiskLines = 'No critical or high-severity risks identified.';
  }

  let customerComms = `================================================================================
CUSTOMER COMMUNICATIONS
================================================================================
Scope: ${cleanScope}  |  Date: ${today}

--------------------------------------------------------------------------------
TEMPLATE A: ADVISORY EMAIL
--------------------------------------------------------------------------------
Subject: Action Required — Storage Health & Security Advisory for ${cleanScope}

Dear Storage Operations Team,

Our Active IQ posture audit identified ${totalDeduped} finding${totalDeduped !== 1 ? 's' : ''} across ${targetSystems.length} system${targetSystems.length !== 1 ? 's' : ''}, consolidated into ${sortedRisks.length} corrective action${sortedRisks.length !== 1 ? 's' : ''}.

OPERATIONAL HEALTH SNAPSHOT:
  ASUP Compliance:    ${pctAsup}% (${asupCompliant}/${sysCount} systems reporting within 7 days)
  ARP Protection:     ${pctArp}% (${arpEnabledCount}/${sysCount} systems with Anti-Ransomware enabled)
  Firmware Currency:  ${pctFw}% (${fwCurrentCount}/${sysCount} on recommended OS version)
  Contract Coverage:  ${pctContract}% (${contractActiveCount}/${sysCount} active contracts)

${emailRiskLines}

${asupIssues.length > 0 ? 'AUTOSUPPORT ISSUES:\n' + asupIssues.map(a => `  • ${a.name}: ${a.issue}`).join('\n') : 'AutoSupport: All systems reporting healthy.'}

${allSupportCases.length > 0 ? 'OPEN CASES:\n' + allSupportCases.slice(0, 5).map(c => `  • Case ${c.id} [${c.severity}] ${c.title}`).join('\n') + (allSupportCases.length > 5 ? `\n  ... and ${allSupportCases.length - 5} more` : '') : 'No open support cases.'}

${exp90.length > 0 ? 'CONTRACTS EXPIRING WITHIN 90 DAYS:\n' + exp90.map(e => `  • ${e.systemName} — ${e.supportLevel} — Expires: ${(e.endDate || '').split('T')[0]} (${e.daysRemaining}d)`).join('\n') : ''}
${sustLatest.overallScore ? `\nSUSTAINABILITY:\n  Fleet Sustainability Score: ${sustLatest.overallScore}%` : ''}

Please advise on your preferred CAB window for remediation. Detailed runbooks are attached.

References: security.netapp.com | kb.netapp.com | activeiq.netapp.com

Best Regards,
${personnel.sam !== 'Not Assigned' ? personnel.sam + ', NetApp SAM' : personnel.salesRep !== 'Not Assigned' ? personnel.salesRep + ', NetApp Account Team' : '[Your Name], NetApp Account Team'}

--------------------------------------------------------------------------------
TEMPLATE B: QBR EXECUTIVE SUMMARY
--------------------------------------------------------------------------------
Account:  ${cleanScope}
Period:   ${today}
Systems:  ${targetSystems.length}  |  Sites: ${siteDetails.length}

HEALTH METRICS:
  ASUP Compliance:    ${pctAsup}% ${pctAsup < 100 ? '⚠' : '✓'}
  ARP Coverage:       ${pctArp}% ${pctArp < 100 ? '⚠' : '✓'}
  Firmware Currency:  ${pctFw}% ${pctFw < 100 ? '⚠' : '✓'}
  Contract Coverage:  ${pctContract}% ${pctContract < 100 ? '⚠' : '✓'}

RISK POSTURE:
  Findings: ${totalDeduped} (${critCount}C / ${highCount}H / ${medCount}M)
  Security: ${secRisksCount}  |  Cases: ${allSupportCases.length}  |  Upgrades: ${allUpgrades.length}
${sustLatest.overallScore ? `\nSUSTAINABILITY: ${sustLatest.overallScore}%` : ''}

PRIORITY ACTIONS:
${sortedRisks.slice(0, 6).map((g, i) => `  ${i+1}. [${g.severity.toUpperCase()}] ${g.fix}${g.count > 1 ? ` (${g.count} findings)` : ''}`).join('\n')}
${asupIssues.length > 0 ? `  ${Math.min(sortedRisks.length, 6) + 1}. Restore AutoSupport on ${asupIssues.length} system(s)` : ''}
${expiringContracts.length > 0 ? `  ${Math.min(sortedRisks.length, 6) + (asupIssues.length > 0 ? 2 : 1)}. Renew ${expiringContracts.length} expiring contract(s)` : ''}
${sysCount - arpEnabledCount > 0 ? `  ${Math.min(sortedRisks.length, 6) + (asupIssues.length > 0 ? 1 : 0) + (expiringContracts.length > 0 ? 1 : 0) + 1}. Enable ARP on ${sysCount - arpEnabledCount} unprotected system(s)` : ''}`;

  // ===================== 3. CHANGE TICKETS =====================
  let changeTickets = `================================================================================
CHANGE CONTROL TICKETS
================================================================================
Scope: ${cleanScope}  |  Date: ${today}

All changes must follow ITIL Change Control procedures. Obtain CAB approval, document
rollback plan, and confirm cluster health before initiating any corrective action.

`;

  targetSystems.forEach((sys, sidx) => {
    const sysRisks = (sys.risks || [])
      .filter(r => { const s = (r.severity||'').toLowerCase(); return s === 'critical' || s === 'high'; })
      .filter(r => { const c = (r.category||'').toLowerCase(); return c !== 'best practice' && c !== 'best_practice' && c !== 'best practices'; })
      .sort((a, b) => (sevRank[a.severity] ?? 4) - (sevRank[b.severity] ?? 4));
    const l = sys.logistics || { deliveryAddress: 'N/A', accessRestrictions: 'N/A' };
    const ct = sys.contacts || { name: 'N/A', phone: 'N/A' };
    const priority = sysRisks.some(r => r.severity === 'critical') ? 'CRITICAL' : sysRisks.length > 0 ? 'HIGH' : 'STANDARD';

    changeTickets += `================================================================================
CHANGE TICKET #${sidx + 1} — ${sys.systemName}
================================================================================
  Serial:   ${sys.serialNumber || 'N/A'}
  Cluster:  ${sys.clusterName || 'N/A'}
  Platform: ${sys.platform || 'N/A'}
  OS:       ${sys.ontapVersion || sys.osVersion || 'N/A'}
  Site:     ${l.deliveryAddress}
  Contact:  ${ct.name} | ${ct.phone}
  Priority: ${priority}
  Tasks:    ${sysRisks.length} corrective action${sysRisks.length !== 1 ? 's' : ''}${sys.upgrades && sys.upgrades.targetVersion && sys.upgrades.targetVersion !== 'Up to Date' ? ' + 1 OS upgrade' : ''}

--- PRE-CHANGE HEALTH VALIDATION ---
  cluster show
  system health alert show
  storage failover show
  storage aggregate show -state online
  network interface show -status-oper down
  system configuration backup create -node *
  event log show -severity EMERGENCY,ALERT -time-range -1h

`;

    if (sysRisks.length > 0) {
      changeTickets += `--- CORRECTIVE ACTIONS (${sysRisks.length}) ---\n\n`;
      sysRisks.forEach((r, rIdx) => {
        const plan = r.remediationPlan || {};
        changeTickets += `  [${rIdx + 1}] [${(r.severity || '').toUpperCase()}] ${r.description}\n`;
        if (plan.cause) changeTickets += `      Root Cause: ${plan.cause}\n`;
        if (plan.impact) changeTickets += `      Impact:     ${plan.impact}\n`;
        if (plan.steps && plan.steps.length > 0) {
          changeTickets += `      CLI Steps:\n`;
          plan.steps.forEach(s => { changeTickets += `        ${s}\n`; });
        } else if (r.recommendation) {
          changeTickets += `      Action:     ${r.recommendation}\n`;
        }
        if (plan.thirdParty) changeTickets += `      Host/3rd-Party: ${plan.thirdParty}\n`;
        const ref = findingRef(r);
        if (ref) changeTickets += `      Reference:  ${ref}\n`;
        changeTickets += '\n';
      });
    } else {
      changeTickets += '  No critical/high risks identified for this system.\n\n';
    }

    if (sys.upgrades && sys.upgrades.targetVersion && sys.upgrades.targetVersion !== 'Up to Date') {
      const origVer = sys.santricityVersion || sys.ontapVersion || 'current';
      const hops = calculateUpgradePath(sys.platform, origVer, sys.upgrades.targetVersion);
      changeTickets += `--- OS UPGRADE ---\n  ${origVer} -> ${sys.upgrades.targetVersion}\n`;
      if (hops.length > 1) {
        changeTickets += `  Multi-hop sequence required:\n`;
        hops.forEach((h, hIdx) => {
          changeTickets += `    Hop ${hIdx + 1}: ${h.from} -> ${h.to}  |  ${h.docLink}\n`;
          if (h.steps && h.steps.length > 0) {
            h.steps.slice(0, 3).forEach(s => { changeTickets += `      • ${s.replace(/<[^>]*>/g, '')}\n`; });
          }
          if (h.considerations && h.considerations.length > 0) {
            changeTickets += `      Caveats: ${h.considerations.slice(0, 2).map(c => c.replace(/<[^>]*>/g, '')).join(' | ')}\n`;
          }
        });
      } else if (hops.length === 1) {
        const h = hops[0];
        changeTickets += `  Ref: ${h.docLink}\n`;
        if (h.steps && h.steps.length > 0) {
          changeTickets += `  Steps:\n`;
          h.steps.slice(0, 4).forEach(s => { changeTickets += `    • ${s.replace(/<[^>]*>/g, '')}\n`; });
        }
      }
      changeTickets += '\n';
    }

    changeTickets += `--- POST-CHANGE VERIFICATION ---
  system health alert show
  storage failover show
  network interface show
  event log show -severity EMERGENCY,ALERT -time-range -1h
  cluster ping-cluster -node *

--- ROLLBACK CRITERIA ---
  If health alerts increase or failover state degrades, revert using:
  system node image modify -node * -image image1 -isdefault true  (ONTAP version rollback)
  Restore configuration from backup: system configuration restore

`;
  });

  // ===================== 4. SOLUTION PROPOSALS =====================
  let solutionProposals = `================================================================================
TECHNICAL SOLUTION PROPOSAL
================================================================================
Customer:     ${cleanScope}
Date:         ${today}
Prepared By:  ${personnel.sam !== 'Not Assigned' ? personnel.sam + ' (SAM)' : personnel.salesRep !== 'Not Assigned' ? personnel.salesRep : 'NetApp Account Team'}

EXECUTIVE SUMMARY
--------------------------------------------------------------------------------
This proposal addresses ${sortedRisks.length} corrective action${sortedRisks.length !== 1 ? 's' : ''} resolving ${totalDeduped} Active IQ finding${totalDeduped !== 1 ? 's' : ''} across ${targetSystems.length} system${targetSystems.length !== 1 ? 's' : ''}.
Finding breakdown: Critical: ${critCount}  High: ${highCount}  Medium: ${medCount}

OPERATIONAL HEALTH BASELINE:
  AutoSupport Compliance: ${pctAsup}% (${asupCompliant}/${sysCount} systems)
  ARP Coverage:           ${pctArp}% (${arpEnabledCount}/${sysCount} systems)
  Firmware Currency:      ${pctFw}% (${fwCurrentCount}/${sysCount} systems)
  Contract Coverage:      ${pctContract}% (${contractActiveCount}/${sysCount} systems)

PRIORITISED CORRECTIVE ACTIONS
--------------------------------------------------------------------------------
`;

  sortedRisks.forEach((g, idx) => {
    const sysNames = [...new Set(g.systems.filter(Boolean))];
    const plan = g.remediationPlan || {};
    solutionProposals += `${idx + 1}. [${g.severity.toUpperCase()}] ${g.fix}\n`;
    solutionProposals += `   Affected Systems: ${sysNames.join(', ')}\n`;
    if (plan.cause) solutionProposals += `   Root Cause:  ${plan.cause}\n`;
    if (plan.impact) solutionProposals += `   Business Risk: ${plan.impact}\n`;
    if (g.count > 1) {
      solutionProposals += `   Resolves ${g.count} findings:\n`;
      g.findings.forEach(f => {
        solutionProposals += `     • [${(f.severity||'').toUpperCase()}] ${f.description}\n`;
      });
    } else {
      solutionProposals += `   Finding: ${g.findings[0].description}\n`;
    }
    if (plan.options && plan.options.length > 0) {
      solutionProposals += `   Remediation Options:\n`;
      plan.options.forEach(o => { solutionProposals += `     → ${o}\n`; });
    }
    if (plan.thirdParty) solutionProposals += `   Host/Integration Note: ${plan.thirdParty}\n`;
    if (g.fixUrl) solutionProposals += `   Reference: ${g.fixUrl}\n`;
    solutionProposals += '\n';
  });

  if (allUpgrades.length > 0) {
    solutionProposals += `OS & FIRMWARE UPGRADES (${allUpgrades.length})
--------------------------------------------------------------------------------
`;
    allUpgrades.forEach(u => {
      const hops = calculateUpgradePath(u.platform, u.currentVersion || '', u.targetVersion);
      solutionProposals += `  ${u.systemName}: ${u.currentVersion || 'current'} -> ${u.targetVersion} (${u.urgency || 'Recommended'})\n`;
      solutionProposals += `    Benefit: ${u.benefits || 'Security patches, performance improvements, and new features.'}\n`;
      if (hops.length > 1) {
        solutionProposals += `    Multi-hop sequence: ${hops.map(h => h.from + ' -> ' + h.to).join(' | ')}\n`;
      }
      solutionProposals += '\n';
    });
  }

  solutionProposals += `IMPLEMENTATION TIMELINE
--------------------------------------------------------------------------------
  Phase 1 (Days 1-7):   CAB approval, pre-change health validation, critical risk remediation
  Phase 2 (Days 8-30):  OS/firmware upgrades, switch firmware, shelf module updates
  Phase 3 (Days 31-90): ARP enablement, audit logging, hypervisor integration compliance
  Phase 4 (Day 90+):    Post-change verification, QBR review, documentation sign-off

CHANGE SAFETY CLASSIFICATION
--------------------------------------------------------------------------------
  Non-Disruptive:  ASUP config, ARP enable, audit logging, shelf/disk firmware (background)
  Disruptive/Safe: ONTAP upgrades (rolling HA failover), switch ISSU firmware updates
  Potentially Disruptive: Network interface reconfigurations, aggregate relocation
  Destructive/Irreversible: Snapshot deletion, volume destroy, LUN unmap — require backup verification

KEY REFERENCES
--------------------------------------------------------------------------------
  Active IQ:         activeiq.netapp.com
  Security:          security.netapp.com
  Knowledge Base:    kb.netapp.com
  Upgrade Advisor:   docs.netapp.com/us-en/ontap/upgrade/index.html
  IMT:               mysupport.netapp.com/matrix
  Support Portal:    mysupport.netapp.com
`;

  // ===================== 5. IMPLEMENTATION RUNBOOKS =====================
  let implementationPlans = `================================================================================
CLI RUNBOOK — CORRECTIVE ACTION PLAYBOOK
================================================================================
Scope:    ${cleanScope}
Date:     ${today}
Prepared: ${personnel.sam !== 'Not Assigned' ? personnel.sam : personnel.salesRep}
Note:     Critical/High severity items only. Best-practice items excluded.
          All commands must be run in the context of the correct cluster/vserver.
          Obtain CAB approval before executing Disruptive or Destructive commands.

GLOBAL PRE-FLIGHT CHECKS (run before any system):
  cluster show
  system health alert show
  storage failover show
  storage aggregate show -state online
  network interface show -status-oper down
  event log show -severity EMERGENCY,ALERT -time-range -1h

`;

  targetSystems.forEach((sys, sysIdx) => {
    const sysRisks = (sys.risks || [])
      .filter(r => { const s = (r.severity||'').toLowerCase(); return s === 'critical' || s === 'high'; })
      .filter(r => { const c = (r.category||'').toLowerCase(); return c !== 'best practice' && c !== 'best_practice' && c !== 'best practices'; })
      .sort((a, b) => (sevRank[a.severity] ?? 4) - (sevRank[b.severity] ?? 4));

    implementationPlans += `================================================================================
SYSTEM ${sysIdx + 1}: ${sys.systemName}
================================================================================
  Serial:   ${sys.serialNumber || 'N/A'}
  Cluster:  ${sys.clusterName || 'N/A'}
  Platform: ${sys.platform || 'N/A'}
  OS:       ${sys.ontapVersion || sys.osVersion || 'N/A'}
  Site:     ${sys.siteName || 'N/A'}
  Contract: ${sys.contractActive === true ? 'Active' : sys.contractActive === false ? 'EXPIRED' : 'Unknown'}
`;

    if (sysRisks.length > 0) {
      sysRisks.forEach((r, rIdx) => {
        const plan = r.remediationPlan || {};
        implementationPlans += `
--------------------------------------------------------------------------------
ACTION ${rIdx + 1}: [${(r.severity||'').toUpperCase()}] ${r.description}
--------------------------------------------------------------------------------`;
        if (plan.cause)    implementationPlans += `\n  Root Cause:   ${plan.cause}`;
        if (plan.impact)   implementationPlans += `\n  Impact:       ${plan.impact}`;
        implementationPlans += '\n';
        if (plan.steps && plan.steps.length > 0) {
          implementationPlans += `  CLI Steps:\n`;
          plan.steps.forEach(s => { implementationPlans += `    ${s}\n`; });
        } else if (r.recommendation) {
          implementationPlans += `  Action: ${r.recommendation}\n`;
        }
        if (plan.options && plan.options.length > 0) {
          implementationPlans += `  Remediation Options:\n`;
          plan.options.forEach(o => { implementationPlans += `    → ${o}\n`; });
        }
        if (plan.thirdParty) implementationPlans += `  Host/3rd-Party: ${plan.thirdParty}\n`;
        const ref = findingRef(r);
        if (ref) implementationPlans += `  Reference: ${ref}\n`;
      });
    } else {
      implementationPlans += '\n  ✓ No critical/high severity risks identified for this system.\n';
    }

    if (sys.upgrades && sys.upgrades.targetVersion && sys.upgrades.targetVersion !== 'Up to Date') {
      const origVer = sys.santricityVersion || sys.ontapVersion || 'current';
      const hops = calculateUpgradePath(sys.platform, origVer, sys.upgrades.targetVersion);
      implementationPlans += `
--------------------------------------------------------------------------------
ONTAP/OS UPGRADE: ${origVer} -> ${sys.upgrades.targetVersion}
--------------------------------------------------------------------------------\n`;
      if (hops.length > 1) {
        implementationPlans += `  Multi-hop upgrade required — do NOT skip intermediate versions.\n`;
        hops.forEach((h, hIdx) => {
          implementationPlans += `  Hop ${hIdx + 1}: ${h.from} -> ${h.to}\n`;
          if (h.steps && h.steps.length > 0) {
            h.steps.slice(0, 5).forEach(s => { implementationPlans += `    ${s.replace(/<[^>]*>/g, '')}\n`; });
          }
          if (h.recommendations && h.recommendations.length > 0) {
            implementationPlans += `    Recommendations: ${h.recommendations.slice(0,2).map(r => r.replace(/<[^>]*>/g,'')).join(' | ')}\n`;
          }
          if (h.considerations && h.considerations.length > 0) {
            implementationPlans += `    Caveats: ${h.considerations.slice(0,2).map(c => c.replace(/<[^>]*>/g,'')).join(' | ')}\n`;
          }
          implementationPlans += `    Doc: ${h.docLink}\n\n`;
        });
      } else if (hops.length === 1) {
        const h = hops[0];
        if (h.steps && h.steps.length > 0) {
          h.steps.slice(0, 5).forEach(s => { implementationPlans += `  ${s.replace(/<[^>]*>/g, '')}\n`; });
        }
        if (h.considerations && h.considerations.length > 0) {
          implementationPlans += `  Caveats: ${h.considerations.slice(0,2).map(c => c.replace(/<[^>]*>/g,'')).join(' | ')}\n`;
        }
        implementationPlans += `  Doc: ${h.docLink}\n`;
      } else {
        implementationPlans += `  Download upgrade package from: https://mysupport.netapp.com/site/downloads\n`;
        implementationPlans += `  Follow: https://docs.netapp.com/us-en/ontap/upgrade/index.html\n`;
      }
    }

    // Platform-specific additional checks
    if ((sys.platform || '').toUpperCase().includes('ASA')) {
      implementationPlans += `
  [ASA SAN-SPECIFIC CHECKS]
    lun show -fields space-allocation,enabled
    igroup show -fields ostype,protocol
    esxcli storage nmp device list  (from each VMware ESXi host)
    storage path show -fields node,type,state
`;
    }
    if ((sys.platform || '').toLowerCase().includes('metrocluster')) {
      implementationPlans += `
  [METROCLUSTER-SPECIFIC PRE-CHECKS]
    metrocluster check run && metrocluster check show
    metrocluster interconnect show
    metrocluster node show -fields node-state,configuration-state
    Note: Upgrade DR site first, then primary site. Perform switchover/switchback test post-upgrade.
`;
    }

    implementationPlans += `
  [POST-CHANGE VERIFICATION]
    system health alert show
    storage failover show
    network interface show
    event log show -severity EMERGENCY,ALERT -time-range -1h
    cluster ping-cluster -node *

`;
  });

  // ===================== 6. SALES PROPOSALS =====================
  let salesProposals = `================================================================================
SALES PROPOSALS & HARDWARE REFRESH
================================================================================
CUSTOMER: ${cleanScope}  |  DATE: ${today}
Account Team: ${personnel.salesRep}${personnel.csm !== 'Not Assigned' ? '  |  CSM: ' + personnel.csm : ''}

`;

  // Contract renewals
  if (expiringContracts.length > 0) {
    salesProposals += `CONTRACT RENEWALS (${expiringContracts.length})
--------------------------------------------------------------------------------
`;
    expiringContracts.forEach((e, i) => {
      salesProposals += `  ${i+1}. ${e.systemName} (${e.serialNumber || 'N/A'})
     Service Level: ${e.supportLevel}  |  Expires: ${(e.endDate || '').split('T')[0]} (${e.daysRemaining}d)
`;
    });
    salesProposals += `  Portal: https://mysupport.netapp.com/\n\n`;
  }

  // TAM renewal pipeline
  if (scopedRenewals.length > 0) {
    salesProposals += `RENEWAL PIPELINE (${scopedRenewals.length} systems from TAM data)
--------------------------------------------------------------------------------
`;
    const refreshGroups = {};
    scopedRenewals.forEach(r => {
      const cat = r.techRefreshStatus || 'Unknown';
      if (!refreshGroups[cat]) refreshGroups[cat] = [];
      refreshGroups[cat].push(r);
    });
    Object.entries(refreshGroups).forEach(([cat, items]) => {
      salesProposals += `  ${cat}: ${items.length} system(s)\n`;
      items.slice(0, 5).forEach(r => {
        salesProposals += `    • ${r.hostName || 'N/A'} | ${r.hwServiceLevel || ''} | HW EOA: ${(r.hwEndOfAvailability || 'N/A').substring(0,10)} | EOS: ${(r.hwEndOfSupport || 'N/A').substring(0,10)}\n`;
      });
      if (items.length > 5) salesProposals += `    ... and ${items.length - 5} more\n`;
    });
    salesProposals += '\n';
  }

  // Lifecycle refresh
  const eos = targetSystems.filter(s => s.lifecycle && (s.lifecycle.isNearEos || (s.ontapVersion || '').startsWith('9.5')));
  if (eos.length > 0) {
    salesProposals += `LIFECYCLE REFRESH CANDIDATES (${eos.length})
--------------------------------------------------------------------------------
`;
    eos.forEach((sys, i) => {
      salesProposals += `  ${i+1}. ${sys.systemName} | ${sys.platform} | OS: ${sys.ontapVersion}
     EOA: ${sys.lifecycle.eoaDate || 'N/A'}  |  EOS: ${sys.lifecycle.eosDate || 'N/A'}
     Recommendation: Refresh to AFF A-Series or C-Series
     Reference: https://www.netapp.com/data-storage/aff-a-series/
`;
    });
  }

  // Security posture upsell
  const arpGap = sysCount - arpEnabledCount;
  const fwGap = sysCount - fwCurrentCount;
  if (arpGap > 0 || fwGap > 0) {
    salesProposals += `\nSECURITY & COMPLIANCE UPSELL OPPORTUNITIES
--------------------------------------------------------------------------------
`;
    if (arpGap > 0) salesProposals += `  • ARP Enablement: ${arpGap} system(s) without Anti-Ransomware Protection\n    → ONTAP ARP licensing or upgrade engagement\n`;
    if (fwGap > 0) salesProposals += `  • Firmware Currency: ${fwGap} system(s) behind recommended OS version\n    → Professional Services upgrade engagement\n`;
  }

  if (expiringContracts.length === 0 && eos.length === 0 && scopedRenewals.length === 0 && arpGap === 0) {
    salesProposals += `No urgent hardware refreshes, contract renewals, or security gaps identified.\n`;
  }

  // 7. Customer Success Plan
  let customerSuccessPlan = compileCustomerSuccessPlanText(scopeTitle, allRisks, allUpgrades, targetSystems, expiringContracts, allSupportCases);

  // 8. TAM QBR Pack
  let qbrPack = compileQBRPack(targetSystems, allRisks, allUpgrades, expiringContracts, allSupportCases, scopeTitle);

  // 9. MSP Service Delivery Report
  let mspReport = compileMSPServiceReport(targetSystems, allRisks, expiringContracts, allSupportCases, scopeTitle);

  // 10. Account Handover Brief
  let handoverBrief = compileAccountHandoverBrief(targetSystems, allRisks, allUpgrades, expiringContracts, allSupportCases, scopeTitle);

  return {
    problemStatements,
    customerComms,
    changeTickets,
    solutionProposals,
    implementationPlans,
    salesProposals,
    customerSuccessPlan,
    qbrPack,
    mspReport,
    handoverBrief
  };
}

